INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Acid Splash', 'You hurl a bubble of acid. Choose one creature within range, or choose two creatures within range that are within 5 feet of each other. A target must succeed on a dexterity saving throw or take 1d6 acid damage.
This spell''s damage increases by 1d6 when you reach 5th level (2d6), 11th level (3d6), and 17th level (4d6).', '', NULL
FROM public.spells WHERE external_index = 'acid-splash'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Bolha Ácida', 'Você lança uma bolha de ácido. Escolha uma ou duas criaturas à sua vista, dentro do alcance da magia. Se escolher duas, elas devem estar a 1,5 metro [5 ft.] uma da outra. Um alvo deve ser bem-sucedido em uma salvaguarda de Destreza. Se falhar, sofre 1d6 pontos de dano ácido.O dano desta magia aumenta em 1d6 quando você alcança o 5º nível (2d6), 11º nível (3d6) e 17º nível (4d6).', '', NULL
FROM public.spells WHERE external_index = 'acid-splash'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
