INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Aid', 'Your spell bolsters your allies with toughness and resolve. Choose up to three creatures within range. Each target''s hit point maximum and current hit points increase by 5 for the duration.', 'When you cast this spell using a spell slot of 3rd level or higher, a target''s hit points increase by an additional 5 for each slot level above 2nd.', 'A tiny strip of white cloth.'
FROM public.spells WHERE external_index = 'aid'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Auxílio', 'Esta magia reforça seus aliados com tenacidade e determinação. Escolha até três criaturas dentro do alcance. Os pontos de vida máximos e os pontos de vida atuais de cada alvo aumentam em 5 enquanto a magia durar.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 3º círculo ou superior, os pontos de vida do alvo aumentam em 5 pontos adicionais para cada círculo do espaço acima do 2º.', '', NULL
FROM public.spells WHERE external_index = 'aid'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
