INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Alarm', 'You set an alarm against unwanted intrusion. Choose a door, a window, or an area within range that is no larger than a 20-foot cube. Until the spell ends, an alarm alerts you whenever a Tiny or larger creature touches or enters the warded area. When you cast the spell, you can designate creatures that won''t set off the alarm. You also choose whether the alarm is mental or audible.
A mental alarm alerts you with a ping in your mind if you are within 1 mile of the warded area. This ping awakens you if you are sleeping.
An audible alarm produces the sound of a hand bell for 10 seconds within 60 feet.', '', 'A tiny bell and a piece of fine silver wire.'
FROM public.spells WHERE external_index = 'alarm'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Alarme', 'Você prepara um alarme contra intrusos indesejados. Escolha uma porta, uma janela ou uma área dentro do alcance que não seja maior que um cubo de 6 metros de lado [20-foot cube]. Enquanto a magia durar, um alarme o alerta quando uma criatura Minúscula ou maior tocar ou entrar na área protegida. Ao conjurar a magia, você pode escolher quais criaturas não dispararão o alarme. Você também pode escolher se o alarme é mental ou audível.Um alarme mental avisa com um sibilo em sua mente, se você estiver no alcance de 1,5 quilômetro [1 mile] da área protegida. Esse sibilo o desperta caso você esteja dormindo.Um alarme audível produz o som de uma sineta durante 10 segundos, dentro de um alcance de 18 metros [60 ft.].', '', NULL
FROM public.spells WHERE external_index = 'alarm'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Alter Self
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('alter-self', 2, 'transmutation', 'action', 1, NULL, 'self', 1, 'hour', true, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Alter Self', 'You assume a different form. When you cast the spell, choose one of the following options, the effects of which last for the duration of the spell. While the spell lasts, you can end one option as an action to gain the benefits of a different one.
***Aquatic Adaptation.*** You adapt your body to an aquatic environment, sprouting gills and growing webbing between your fingers. You can breathe underwater and gain a swimming speed equal to your walking speed.
***Change Appearance.*** You transform your appearance. You decide what you look like, including your height, weight, facial features, sound of your voice, hair length, coloration, and distinguishing characteristics, if any. You can make yourself appear as a member of another race, though none of your statistics change. You also can''t appear as a creature of a different size than you, and your basic shape stays the same; if you''re bipedal, you can''t use this spell to become quadrupedal, for instance. At any time for the duration of the spell, you can use your action to change your appearance in this way again.
***Natural Weapons.*** You grow claws, fangs, spines, horns, or a different natural weapon of your choice. Your unarmed strikes deal 1d6 bludgeoning, piercing, or slashing damage, as appropriate to the natural weapon you chose, and you are proficient with your unarmed strikes. Finally, the natural weapon is magic and you have a +1 bonus to the attack and damage rolls you make using it.', '', NULL
FROM public.spells WHERE external_index = 'alter-self'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Alterar-se', 'Você assume uma forma diferente. Quando conjurar a magia, escolha uma das opções a seguir, cujos efeitos persistem enquanto a magia durar. Dentro desse período, você pode usar uma ação para finalizar uma das opções escolhidas, e obter os benefícios de outra.Adaptação Aquática. Você adapta seu corpo para o ambiente aquático, com guelras crescendo e membranas nascendo entre seus dedos. Você pode respirar debaixo d''água e ganha deslocamento de natação com valor igual ao seu deslocamento de caminhada.Mudar Aparência. Você transforma sua aparência conforme desejar, alterando sua altura, peso, características raciais, som da voz, comprimento do cabelo, cor da pele e características peculiares, se existirem. Você pode adquirir a aparência de outra raça, embora nenhuma de suas estatísticas mude. Você não pode parecer com uma criatura de tamanho diferente do seu, e sua forma básica permanece a mesma; por exemplo, se você é bípede, você não pode usar a magia para se tornar quadrúpede. A qualquer momento, enquanto a magia durar, você pode usar sua ação para trocar de aparência novamente.Armas Naturais. Crescem em seu corpo garras, presas, espinhos, chifres ou uma arma natural diferente, à sua escolha. Seu ataque desarmado causa 1d6 pontos de dano contundente, cortante ou perfurante, conforme a arma natural escolhida, e você é proficiente com seus ataques desarmados. Por fim, sua arma natural é mágica e você tem um bônus de +1 em suas jogadas de ataque e dano quando usá-la.', '', NULL
FROM public.spells WHERE external_index = 'alter-self'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Animal Friendship
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('animal-friendship', 1, 'enchantment', 'action', 1, 30, 'feet', 24, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Animal Friendship', 'This spell lets you convince a beast that you mean it no harm. Choose a beast that you can see within range. It must see and hear you. If the beast''s Intelligence is 4 or higher, the spell fails. Otherwise, the beast must succeed on a wisdom saving throw or be charmed by you for the spell''s duration. If you or one of your companions harms the target, the spells ends.', '', 'A morsel of food.'
FROM public.spells WHERE external_index = 'animal-friendship'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Amizade Animal', 'Esta magia permite que você convença uma fera de que não pretende causar-lhe mal. Escolha uma fera à sua vista, no alcance da magia. Ela deve ser capaz de vê-lo e ouvi-lo. Se a Inteligência da fera for 4 ou maior, a magia falha. Caso contrário, a fera deve ser bem-sucedida em uma salvaguarda de Sabedoria ou fica enfeitiçada por você enquanto a magia durar. Se você ou qualquer um de seus companheiros causar dano ao alvo, a magia se encerra.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, você pode afetar uma fera adicional para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'animal-friendship'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Animal Messenger
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('animal-messenger', 2, 'enchantment', 'action', 1, 30, 'feet', 24, 'hour', false, true, ARRAY['V', 'S', 'M'], ARRAY['bard', 'druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Animal Messenger', 'By means of this spell, you use an animal to deliver a message. Choose a Tiny beast you can see within range, such as a squirrel, a blue jay, or a bat. You specify a location, which you must have visited, and a recipient who matches a general description, such as "a man or woman dressed in the uniform of the town guard" or "a red-haired dwarf wearing a pointed hat." You also speak a message of up to twenty-five words. The target beast travels for the duration of the spell toward the specified location, covering about 50 miles per 24 hours for a flying messenger, or 25 miles for other animals.
When the messenger arrives, it delivers your message to the creature that you described, replicating the sound of your voice. The messenger speaks only to a creature matching the description you gave. If the messenger doesn''t reach its destination before the spell ends, the message is lost, and the beast makes its way back to where you cast this spell.', 'If you cast this spell using a spell slot of 3nd level or higher, the duration of the spell increases by 48 hours for each slot level above 2nd.', 'A morsel of food.'
FROM public.spells WHERE external_index = 'animal-messenger'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Mensageiro Animal', 'Por meio desta magia, você usa um animal para entregar uma mensagem. Escolha uma fera Minúscula à sua vista e no alcance da magia, como um esquilo, uma gralha azul ou um morcego. Você especifica uma localização que já tenha visitado e um destinatário que combine com uma descrição geral, tal como: "uma mulher ou um homem vestido com o uniforme da guarda da cidade" ou "um anão ruivo usando um chapéu pontudo". Você também deve falar uma mensagem de até vinte e cinco palavras. Enquanto a magia durar, a fera alvo viaja em direção à localização especificada, cobrindo cerca de 80 quilômetros [50 miles] durante 24 horas para um mensageiro voador, ou 40 quilômetros [25 miles] para outros animais.
Quando o mensageiro chegar, ele entrega a mensagem para a criatura que você descreveu, replicando o som da sua voz. O mensageiro fala somente com a criatura que combina com a descrição que você forneceu. Se o mensageiro não alcançar o destino antes do fim da duração da magia, a mensagem se perde e a fera refaz o caminho de volta para o lugar onde você conjurou a magia.
Em Círculos Superiores. Se você conjurar essa magia usando um espaço de magia de 3º círculo ou superior, a duração da magia aumenta em 48 horas para cada círculo do espaço acima do 2º.', '', NULL
FROM public.spells WHERE external_index = 'animal-messenger'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Animal Shapes
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('animal-shapes', 8, 'transmutation', 'action', 1, 30, 'feet', 24, 'hour', true, false, ARRAY['V', 'S'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Animal Shapes', 'Your magic turns others into beasts. Choose any number of willing creatures that you can see within range. You transform each target into the form of a Large or smaller beast with a challenge rating of 4 or lower. On subsequent turns, you can use your action to transform affected creatures into new forms.
The transformation lasts for the duration for each target, or until the target drops to 0 hit points or dies. You can choose a different form for each target. A target''s game statistics are replaced by the statistics of the chosen beast, though the target retains its alignment and Intelligence, Wisdom, and Charisma scores. The target assumes the hit points of its new form, and when it reverts to its normal form, it returns to the number of hit points it had before it transformed. If it reverts as a result of dropping to 0 hit points, any excess damage carries over to its normal form. As long as the excess damage doesn''t reduce the creature''s normal form to 0 hit points, it isn''t knocked unconscious. The creature is limited in the actions it can perform by the nature of its new form, and it can''t speak or cast spells.
The target''s gear melds into the new form. The target can''t activate, wield, or otherwise benefit from any of its equipment.', '', NULL
FROM public.spells WHERE external_index = 'animal-shapes'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Formas Animais', 'Sua magia transforma outras criaturas em feras. Escolha qualquer número de criaturas voluntárias à sua vista e dentro do alcance. Você transforma cada alvo em uma fera Grande ou menor, cujo nível de desafio seja 4 ou menor. Nos turnos subsequentes, você pode usar uma ação para dar novas formas às criaturas afetadas.
A transformação persiste enquanto a magia durar ou até que o alvo fique com 0 pontos de vida ou morra. Você pode escolher uma forma diferente para cada alvo. As estatísticas de jogo de cada alvo são substituídas pelas estatísticas da fera escolhida, embora o alvo mantenha o alinhamento e valores de Inteligência, Sabedoria e Carisma originais. O alvo assume os pontos de vida da nova forma, e quando reverte para a forma original, retorna para a quantidade de pontos de vida que possuía antes da transformação. Se a transformação for revertida como resultado dos pontos de vida do alvo serem reduzidos a 0, todo o excesso de dano será transferido para a forma original. Contanto que esse excesso de dano não reduza a forma original do alvo a 0 pontos de vida, ele não fica inconsciente. As ações que a criatura pode executar estão limitadas pela nova forma, e ela não pode falar ou conjurar magias.
Os equipamentos do alvo se fundem à nova forma. O alvo não pode ativar, empunhar, ou receber quaisquer benefícios desses equipamentos.', '', NULL
FROM public.spells WHERE external_index = 'animal-shapes'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Animate Dead
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('animate-dead', 3, 'necromancy', 'minute', 1, 10, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Animate Dead', 'This spell creates an undead servant. Choose a pile of bones or a corpse of a Medium or Small humanoid within range. Your spell imbues the target with a foul mimicry of life, raising it as an undead creature. The target becomes a skeleton if you chose bones or a zombie if you chose a corpse (the GM has the creature''s game statistics).
On each of your turns, you can use a bonus action to mentally command any creature you made with this spell if the creature is within 60 feet of you (if you control multiple creatures, you can command any or all of them at the same time, issuing the same command to each one). You decide what action the creature will take and where it will move during its next turn, or you can issue a general command, such as to guard a particular chamber or corridor. If you issue no commands, the creature only defends itself against hostile creatures. Once given an order, the creature continues to follow it until its task is complete.
The creature is under your control for 24 hours, after which it stops obeying any command you''ve given it. To maintain control of the creature for another 24 hours, you must cast this spell on the creature again before the current 24-hour period ends. This use of the spell reasserts your control over up to four creatures you have animated with this spell, rather than animating a new one.', 'When you cast this spell using a spell slot of 4th level or higher, you animate or reassert control over two additional undead creatures for each slot level above 3rd. Each of the creatures must come from a different corpse or pile of bones.', 'A drop of blood, a piece of flesh, and a pinch of bone dust.'
FROM public.spells WHERE external_index = 'animate-dead'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Animar Mortos', 'Esta magia cria um servo morto-vivo. Escolha uma pilha de ossos ou o cadáver de um humanoide Médio ou Pequeno, dentro do alcance da magia. Você infunde o alvo com uma perversa imitação de vida, fazendo-o se erguer como uma criatura morta-viva. O alvo se torna um esqueleto, se você escolheu ossos, ou um zumbi, se você escolheu um cadáver (o DM fornece as estatísticas da criatura).
Em cada um de seus turnos, você pode usar uma ação bônus para comandar mentalmente qualquer criatura que tenha criado com esta magia, e que esteja a até 18 metros [60 ft.] de você (se controlar múltiplas criaturas, você pode comandar uma ou todas simultaneamente, emitindo o mesmo comando para todas). Você decide qual ação a criatura tomará e para onde ela se moverá durante o próximo turno dela, ou você pode emitir um comando mais genérico, como manter a guarda de uma câmara ou corredor. Se você não emitir nenhum comando, a criatura apenas se defende de criaturas hostis. Uma vez dada a ordem, a criatura continuará seguindo-a até que a tarefa esteja completa.
A criatura fica sob seu controle por 24 horas, período após o qual ela para de obedecer aos seus comandos. Para manter o controle por mais 24 horas, é necessário conjurar novamente esta magia na criatura antes que o período de controle atual de 24 horas acabe. Isso restabelece o seu controle sobre até quatro criaturas que você tenha animado com esta magia em vez de animar uma nova.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 4º círculo ou maior, você pode animar ou restabelecer o controle sobre mais dois mortos-vivos para cada círculo do espaço acima do 3º. Cada uma das criaturas precisa ter vindo de uma pilha de ossos ou cadáver único.', '', NULL
FROM public.spells WHERE external_index = 'animate-dead'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Animate Objects
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('animate-objects', 5, 'transmutation', 'action', 1, 120, 'feet', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Animate Objects', 'Objects come to life at your command. Choose up to ten nonmagical objects within range that are not being worn or carried. Medium targets count as two objects, Large targets count as four objects, Huge targets count as eight objects. You can''t animate any object larger than Huge. Each target animates and becomes a creature under your control until the spell ends or until reduced to 0 hit points.
As a bonus action, you can mentally command any creature you made with this spell if the creature is within 500 feet of you (if you control multiple creatures, you can command any or all of them at the same time, issuing the same command to each one). You decide what action the creature will take and where it will move during its next turn, or you can issue a general command, such as to guard a particular chamber or corridor. If you issue no commands, the creature only defends itself against hostile creatures. Once given an order, the creature continues to follow it until its task is complete.
##### Animated Object Statistics
| Size | HP | AC | Attack | Str | Dex |
|---|---|---|---|---|---|
| Tiny | 20 | 18 | +8 to hit, 1d4 + 4 damage | 4 | 18 |
| Small | 25 | 16 | +6 to hit, 1d8 + 2 damage | 6 | 14 |
| Medium | 40 | 13 | +5 to hit, 2d6 + 1 damage | 10 | 12 |
| Large | 50 | 10 | +6 to hit, 2d10 + 2 damage | 14 | 10 |
| Huge | 80 | 10 | +8 to hit, 2d12 + 4 damage | 18 | 6 |
An animated object is a construct with AC, hit points, attacks, Strength, and Dexterity determined by its size. Its Constitution is 10 and its Intelligence and Wisdom are 3, and its Charisma is 1. Its speed is 30 feet; if the object lacks legs or other appendages it can use for locomotion, it instead has a flying speed of 30 feet and can hover. If the object is securely attached to a surface or a larger object, such as a chain bolted to a wall, its speed is 0. It has blindsight with a radius of 30 feet and is blind beyond that distance. When the animated object drops to 0 hit points, it reverts to its original object form, and any remaining damage carries over to its original object form.
If you command an object to attack, it can make a single melee attack against a creature within 5 feet of it. It makes a slam attack with an attack bonus and bludgeoning damage determined by its size. The GM might rule that a specific object inflicts slashing or piercing damage based on its form.', 'If you cast this spell using a spell slot of 6th level or higher, you can animate two additional objects for each slot level above 5th.', NULL
FROM public.spells WHERE external_index = 'animate-objects'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Animar Objetos', 'Objetos ganham vida ao seu comando. Escolha até dez objetos não-mágicos no alcance da magia e que não estejam sendo usados ou carregados. Alvos de tamanho Médio contam como dois objetos, de tamanho Grande contam como quatro objetos e os de tamanho Enorme contam como oito objetos. Você não pode animar qualquer objeto maior que Enorme. Cada alvo se anima, tornando-se uma criatura sobre o seu controle enquanto a magia durar ou até ficar com 0 pontos de vida.Com uma ação bônus, você pode comandar mentalmente qualquer criatura que tenha criado com esta magia e que esteja a até 150 metros [500 ft.] de você (se controlar múltiplas criaturas, você pode comandar uma ou todas simultaneamente, emitindo o mesmo comando para todas). Você decide qual ação a criatura tomará e para onde ela se moverá durante o próximo turno dela, ou você pode emitir um comando mais genérico, como manter a guarda de uma câmara ou corredor. Se você não emitir nenhum comando, a criatura apenas se defende de criaturas hostis. Uma vez dada a ordem, a criatura continua seguindo-a até que a tarefa esteja completa.Estatísticas de Objeto AnimadoTamanho        PV   CA   Ataque                                      For DesMinúsculo        20   18   +8 para acertar, 1d4 + 4 pontos de dano    4     18Pequeno     25   16   +6 para acertar, 1d8 + 2 pontos de dano    6     14Médio 40   13  +5 para acertar, 2d6 + 1 pontos de dano    10   12Grande      50   10  +6 para acertar, 2d10 + 2 pontos de dano  14   10Enorme       80   10  +8 para acertar, 2d12 + 4 pontos de dano  18   6Um objeto animado é um constructo com CA, pontos de vida, ataques, Força e Destreza determinados pelo tamanho dele. A Constituição é 10, a Inteligência e Sabedoria são 3 e o Carisma é 1. O deslocamento é de 9 metros [30 ft.]; se o objeto não tiver pernas ou outros apêndices que possa usar para se locomover, ele tem um deslocamento de voo de 9 metros [30 ft.] e pode flutuar. Se o objeto estiver preso firmemente a uma superfície ou a um objeto maior, como uma corrente presa a uma parede, o deslocamento é 0. Ele tem percepção às cegas em um raio de 9 metros [30 ft.] e é cego além dessa distância. Quando o objeto animado ficar com 0 pontos de vida, ele reverte para a forma original e qualquer dano restante é transferido para a forma original de objeto.Se você ordenar a um objeto que ataque, ele faz um único ataque corpo a corpo contra uma criatura a até 1,5 metro [5 ft.] de distância dele. Ele ataca com uma pancada, cujo bônus de ataque e dano contundente são determinados pelo tamanho dele. O DM pode determinar que um objeto específico inflige dano cortante ou perfurante, dependendo da forma que ele possuir.Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 6º círculo ou superior, você pode animar mais dois objetos para cada círculo do espaço acima do 5º.', '', NULL
FROM public.spells WHERE external_index = 'animate-objects'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Antilife Shell
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('antilife-shell', 5, 'abjuration', 'action', 1, NULL, 'self', 1, 'hour', true, false, ARRAY['V', 'S'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Antilife Shell', 'A shimmering barrier extends out from you in a 10-foot radius and moves with you, remaining centered on you and hedging out creatures other than undead and constructs. The barrier lasts for the duration.
The barrier prevents an affected creature from passing or reaching through. An affected creature can cast spells or make attacks with ranged or reach weapons through the barrier.
If you move so that an affected creature is forced to pass through the barrier, the spell ends.', '', NULL
FROM public.spells WHERE external_index = 'antilife-shell'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Cúpula Antivida', 'Uma barreira cintilante estende-se a partir de você em um raio de 3 metros [10 ft.]. Ela permanece centrada em você e, portanto, acompanha-o aonde quer que vá, barrando a presença de criaturas que não sejam mortos-vivos e constructos. A barreira persiste enquanto a magia durar.
A barreira impede uma criatura afetada por ela de ultrapassá-la completa ou parcialmente. Tal criatura, contudo, pode conjurar magias, realizar ataques com armas de combate à distância ou armas de combate corpo a corpo que possuam a propriedade extensão, através da barreira.
Se você se mover de modo que uma criatura seja forçada a atravessar a barreira, a magia se encerra.', '', NULL
FROM public.spells WHERE external_index = 'antilife-shell'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Antimagic Field
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('antimagic-field', 8, 'abjuration', 'action', 1, NULL, 'self', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Antimagic Field', 'A 10-foot-radius invisible sphere of antimagic surrounds you. This area is divorced from the magical energy that suffuses the multiverse. Within the sphere, spells can''t be cast, summoned creatures disappear, and even magic items become mundane. Until the spell ends, the sphere moves with you, centered on you.
Spells and other magical effects, except those created by an artifact or a deity, are suppressed in the sphere and can''t protrude into it. A slot expended to cast a suppressed spell is consumed. While an effect is suppressed, it doesn''t function, but the time it spends suppressed counts against its duration.
***Targeted Effects.*** Spells and other magical effects, such as magic missile and charm person, that target a creature or an object in the sphere have no effect on that target.
***Areas of Magic.*** The area of another spell or magical effect, such as fireball, can''t extend into the sphere. If the sphere overlaps an area of magic, the part of the area that is covered by the sphere is suppressed. For example, the flames created by a wall of fire are suppressed within the sphere, creating a gap in the wall if the overlap is large enough.
***Spells.*** Any active spell or other magical effect on a creature or an object in the sphere is suppressed while the creature or object is in it.
***Magic Items.*** The properties and powers of magic items are suppressed in the sphere. For example, a +1 longsword in the sphere functions as a nonmagical longsword.
A magic weapon''s properties and powers are suppressed if it is used against a target in the sphere or wielded by an attacker in the sphere. If a magic weapon or a piece of magic ammunition fully leaves the sphere (for example, if you fire a magic arrow or throw a magic spear at a target outside the sphere), the magic of the item ceases to be suppressed as soon as it exits.
***Magical Travel.*** Teleportation and planar travel fail to work in the sphere, whether the sphere is the destination or the departure point for such magical travel. A portal to another location, world, or plane of existence, as well as an opening to an extradimensional space such as that created by the rope trick spell, temporarily closes while in the sphere.
***Creatures and Objects.*** A creature or object summoned or created by magic temporarily winks out of existence in the sphere. Such a creature instantly reappears once the space the creature occupied is no longer within the sphere.
***Dispel Magic.*** Spells and magical effects such as dispel magic have no effect on the sphere. Likewise, the spheres created by different antimagic field spells don''t nullify each other.', '', 'A pinch of powdered iron or iron filings.'
FROM public.spells WHERE external_index = 'antimagic-field'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Campo Antimagia', 'Você é circundado por uma esfera antimagia invisível, com 3 metros de raio [10-foot-radius sphere]. Essa área é separada da energia mágica que permeia o Multiverso. Dentro da esfera, magias não podem ser conjuradas, criaturas convocadas desaparecem e itens mágicos tornam-se mundanos. Enquanto a magia durar, a esfera, centrada em você, move-se para onde quer que você vá.
Magias e outros efeitos mágicos, exceto aqueles criados por um artefato ou uma divindade, são suprimidos na esfera e não podem penetrá-la. Um espaço de magia utilizado para conjurar uma magia suprimida é consumido normalmente. Enquanto um efeito é suprimido, ele não funciona, mas o tempo que passa suprimido conta para sua duração.
Áreas de Magias. A área de outra magia ou efeito mágico como Bola de Fogo, não se alastra para dentro da esfera. Se a esfera se sobrepuser a uma área de magia, a parte da área coberta pela esfera é suprimida. Por exemplo, as chamas criadas por Muralha de Fogo são suprimidas dentro da esfera, criando uma lacuna na muralha se a área sobreposta for grande o suficiente.
Criaturas e Objetos. Quaisquer criaturas ou objetos conjurados ou criados por magia desaparecem temporariamente da existência enquanto estiverem dentro da esfera, reaparecendo instantaneamente uma vez que o espaço ocupado por eles não esteja mais dentro da esfera.
Dissipar Magia. Magias e outros efeitos mágicos, como Dissipar Magia, não afetam a esfera. Da mesma forma, as esferas criadas por campos antimagia diferentes não anulam umas às outras.
Efeitos de Alvo. Magias e outros efeitos mágicos, como os de Mísseis Mágicos e Enfeitiçar Pessoa, que tenham como alvo uma criatura ou um objeto dentro da esfera não têm efeito sobre eles.
Itens Mágicos. As propriedades e poderes de itens mágicos são suprimidos dentro da esfera. Por exemplo, uma espada longa +1 dentro da esfera funciona como uma espada longa não-mágica.
As propriedades e poderes de uma arma mágica são suprimidos se usados contra um alvo dentro da esfera ou usados por um atacante dentro da esfera. Se uma arma ou munição mágica sair completamente da esfera (por exemplo, se você atirar uma flecha ou arremessar uma lança mágica em um alvo fora da esfera), a magia do item deixa de ser suprimida assim que este deixar a esfera.
Magias. Quaisquer magias ou outros efeitos mágicos ativos sobre uma criatura ou objeto dentro da esfera são suprimidos enquanto a criatura ou objeto estiver dentro dela.
Viagem Mágica. Teleporte e viagens planares falham dentro da esfera, seja esta o ponto de destino ou o ponto de partida de tal viagem mágica. Um portal para outra localidade, mundo ou plano de existência, assim como uma abertura para um espaço interdimensional, como o criado pela magia Corda Extradimensional, fecha-se temporariamente enquanto estiver dentro da esfera.', '', NULL
FROM public.spells WHERE external_index = 'antimagic-field'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Antipathy/Sympathy
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('antipathy-sympathy', 8, 'enchantment', 'hour', 1, 60, 'feet', 10, 'day', false, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Antipathy/Sympathy', 'This spell attracts or repels creatures of your choice. You target something within range, either a Huge or smaller object or creature or an area that is no larger than a 200-foot cube. Then specify a kind of intelligent creature, such as red dragons, goblins, or vampires. You invest the target with an aura that either attracts or repels the specified creatures for the duration. Choose antipathy or sympathy as the aura''s effect.
***Antipathy.*** The enchantment causes creatures of the kind you designated to feel an intense urge to leave the area and avoid the target. When such a creature can see the target or comes within 60 feet of it, the creature must succeed on a wisdom saving throw or become frightened. The creature remains frightened while it can see the target or is within 60 feet of it. While frightened by the target, the creature must use its movement to move to the nearest safe spot from which it can''t see the target. If the creature moves more than 60 feet from the target and can''t see it, the creature is no longer frightened, but the creature becomes frightened again if it regains sight of the target or moves within 60 feet of it.
***Sympathy.*** The enchantment causes the specified creatures to feel an intense urge to approach the target while within 60 feet of it or able to see it. When such a creature can see the target or comes within 60 feet of it, the creature must succeed on a wisdom saving throw or use its movement on each of its turns to enter the area or move within reach of the target. When the creature has done so, it can''t willingly move away from the target.
If the target damages or otherwise harms an affected creature, the affected creature can make a wisdom saving throw to end the effect, as described below.
***Ending the Effect.*** If an affected creature ends its turn while not within 60 feet of the target or able to see it, the creature makes a wisdom saving throw. On a successful save, the creature is no longer affected by the target and recognizes the feeling of repugnance or attraction as magical. In addition, a creature affected by the spell is allowed another wisdom saving throw every 24 hours while the spell persists.
A creature that successfully saves against this effect is immune to it for 1 minute, after which time it can be affected again.', '', 'Either a lump of alum soaked in vinegar for the antipathy effect or a drop of honey for the sympathy effect.'
FROM public.spells WHERE external_index = 'antipathy-sympathy'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Antipatia/Simpatia', 'Esta magia atrai ou repele criaturas à sua escolha. Você escolhe um alvo dentro do alcance da magia, seja uma criatura ou objeto Enorme ou menor, ou uma área que não seja maior do que um cubo de 60 metros de lado [200-foot cube]. Depois, especifique um tipo de criatura inteligente, como dragões vermelhos, goblins ou vampiros. Você confere ao alvo uma aura que atrai ou repele o tipo de criatura especificado, enquanto a magia durar. Escolha antipatia ou simpatia como efeito das auras.
Antipatia. O encantamento faz com que criaturas do tipo que você designou sintam um intenso desejo de deixar a área e evitar o alvo. Quando a criatura avistar o alvo ou aproximar-se a até 18 metros [60 ft.] ou menos dele, a criatura deve ser bem-sucedida em uma salvaguarda de Sabedoria ou fica amedrontada. A criatura permanece amedrontada enquanto puder ver o alvo ou estiver a até 18 metros [60 ft.] ou menos dele. Enquanto estiver amedrontada pelo alvo, a criatura deve usar seu deslocamento para mover-se para o local seguro mais próximo de onde não possa mais ver o alvo. Se a criatura mover-se para mais que 18 metros [60 ft.] do alvo e não puder mais vê-lo, ela não está mais amedrontada, mas fica amedrontada novamente se avistar o alvo ou ficar a até 18 metros [60 ft.] ou menos dele.
Simpatia. O encantamento faz com que as criaturas especificadas sintam um intenso desejo de se aproximar do alvo, enquanto estiverem a até 18 metros [60 ft.] dele ou puderem vê-lo. Quando a criatura vir o alvo, ou se aproximar a até 18 metros [60 ft.] ou menos dele, ela deve ser bem-sucedida em uma salvaguarda de Sabedoria ou usar o deslocamento em cada um dos turnos dela para entrar na área ou ficar sob alcance do alvo. Tendo feito isso, a criatura não pode afastar-se voluntariamente do alvo.
Se o alvo causar dano ou ferir de qualquer outra forma a criatura afetada por esta magia, esta pode fazer uma salvaguarda de Sabedoria para encerrar o efeito, como descrito adiante.
Encerrando o Efeito. Se uma criatura afetada por esta magia terminar o turno a uma distância maior do que 18 metros [60 ft.] do alvo ou sem poder vê-lo, ela deve fazer uma salvaguarda de Sabedoria. Em caso de sucesso, ela não está mais sob efeito desta magia e reconhece o sentimento de repugnância ou de atração como sendo mágico. Além disso, uma criatura sob este efeito pode realizar outra salvaguarda de Sabedoria a cada 24 horas que a magia persistir.
Uma criatura bem-sucedida na salvaguarda contra esse efeito fica imune a ele por 1 minuto, podendo voltar a ser afetada após esse período.', '', NULL
FROM public.spells WHERE external_index = 'antipathy-sympathy'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Arcane Eye
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('arcane-eye', 4, 'divination', 'action', 1, 30, 'feet', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Arcane Eye', 'You create an invisible, magical eye within range that hovers in the air for the duration.
You mentally receive visual information from the eye, which has normal vision and darkvision out to 30 feet. The eye can look in every direction.
As an action, you can move the eye up to 30 feet in any direction. There is no limit to how far away from you the eye can move, but it can''t enter another plane of existence. A solid barrier blocks the eye''s movement, but the eye can pass through an opening as small as 1 inch in diameter.', '', 'A bit of bat fur.'
FROM public.spells WHERE external_index = 'arcane-eye'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Olho Arcano', 'Você cria um olho mágico e invisível dentro do alcance da magia. Esse olho paira no ar enquanto a magia durar.Você recebe mentalmente as imagens vindas do olho, que conta com visão normal e visão no escuro de 9 metros [30 ft.]. O olho pode enxergar em qualquer direção.Com uma ação, você pode mover o olho por até 9 metros [30 ft.] em qualquer direção. Não há limites para quão longe de você o olho pode se mover, porém, ele não pode entrar em outro plano de existência. Qualquer barreira sólida bloqueará os movimentos do olho, mas ele pode passar por uma pequena abertura de pelo menos 2,5 centímetros [1 inch].', '', NULL
FROM public.spells WHERE external_index = 'arcane-eye'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Arcane Hand
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('arcane-hand', 5, 'evocation', 'action', 1, 120, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Arcane Hand', 'You create a Large hand of shimmering, translucent force in an unoccupied space that you can see within range. The hand lasts for the spell''s duration, and it moves at your command, mimicking the movements of your own hand.
The hand is an object that has AC 20 and hit points equal to your hit point maximum. If it drops to 0 hit points, the spell ends. It has a Strength of 26 (+8) and a Dexterity of 10 (+0). The hand doesn''t fill its space.
When you cast the spell and as a bonus action on your subsequent turns, you can move the hand up to 60 feet and then cause one of the following effects with it.
***Clenched Fist.*** The hand strikes one creature or object within 5 feet of it. Make a melee spell attack for the hand using your game statistics. On a hit, the target takes 4d8 force damage.
***Forceful Hand.*** The hand attempts to push a creature within 5 feet of it in a direction you choose. Make a check with the hand''s Strength contested by the Strength (Athletics) check of the target. If the target is Medium or smaller, you have advantage on the check. If you succeed, the hand pushes the target up to 5 feet plus a number of feet equal to five times your spellcasting ability modifier. The hand moves with the target to remain within 5 feet of it.
***Grasping Hand.*** The hand attempts to grapple a Huge or smaller creature within 5 feet of it. You use the hand''s Strength score to resolve the grapple. If the target is Medium or smaller, you have advantage on the check. While the hand is grappling the target, you can use a bonus action to have the hand crush it. When you do so, the target takes bludgeoning damage equal to 2d6 + your spellcasting ability modifier.
***Interposing Hand.*** The hand interposes itself between you and a creature you choose until you give the hand a different command. The hand moves to stay between you and the target, providing you with half cover against the target. The target can''t move through the hand''s space if its Strength score is less than or equal to the hand''s Strength score. If its Strength score is higher than the hand''s Strength score, the target can move toward you through the hand''s space, but that space is difficult terrain for the target.', 'When you cast this spell using a spell slot of 6th level or higher, the damage from the clenched fist option increases by 2d8 and the damage from the grasping hand increases by 2d6 for each slot level above 5th.', 'An eggshell and a snakeskin glove.'
FROM public.spells WHERE external_index = 'arcane-hand'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Mão Arcana', 'Você cria uma mão de tamanho Grande, feita de uma energia translúcida e reluzente, em um espaço desocupado à sua vista e dentro do alcance da magia. A mão persiste enquanto a magia durar e move-se ao seu comando, imitando os movimentos de sua própria mão.A mão é um objeto que tem CA 20 e pontos de vida iguais ao valor máximo de seus pontos de vida. Se ela cair para 0 pontos de vida, a magia se encerra. Ela tem Força 26 (+8) e Destreza 10 (+0), não preenchendo o espaço que parece ocupar.No turno em que você conjurar a magia e depois, usando uma ação bônus nos seus turnos subsequentes, você poderá movê-la por até 18 metros [60 ft.] e causar os seguintes efeitos:Punho Cerrado. A mão ataca uma criatura ou objeto a até 1,5 metro [5 ft.] dela. Faça um ataque mágico de combate corpo a corpo para a mão como se ela fizesse parte do seu corpo, ou seja, usando suas próprias estatísticas de jogo. Em caso de acerto, o alvo sofre 4d8 pontos de dano energético.Mão Vigorosa. A mão tenta empurrar uma criatura a até 1,5 metro [5 ft.] de distância em uma direção que você escolher. Faça um teste de Força da mão, resistido pela Força (Atletismo) do alvo. Se o alvo for Médio ou menor, você tem vantagem no teste. Se for bem-sucedido, a mão empurra o alvo a até 1,5 metro [5 ft.] de distância, mais 1,5 metro [5 ft.] multiplicado por cinco vezes o valor de seu modificador do atributo de conjuração. A mão se move com o alvo para permanecer a 1,5 metro [5 ft.] dele.Mão Esmagadora. A mão tenta agarrar uma criatura de tamanho Enorme ou menor dentro do alcance de 1,5 metro [5 ft.]. Você usa o valor da Força da mão para resolver o agarramento. Se o alvo for Médio ou menor, você tem vantagem no teste. Enquanto a mão estiver agarrando o alvo, você pode usar uma ação bônus para fazer com que a mão o esmague. Quando você faz isso, o alvo sofre dano contundente equivalente a 2d6 pontos de dano + o modificador de seu atributo de conjuração.Mão Interposta. A mão se interpõe entre você e uma criatura à sua escolha, até que você lhe dê um comando diferente. A mão se desloca até ficar entre você e o alvo, proporcionando a você meia cobertura contra o alvo. Este último não pode se mover através do espaço da mão se o valor de Força dele for menor ou igual ao da mão. Se o valor de Força do alvo for maior do que o valor de Força da mão, ele pode se mover em direção a você atravessando o espaço ocupado pela mão, mas esse espaço é considerado terreno difícil para o alvo.Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 6º círculo ou superior, o dano da opção Punho Cerrado aumenta em 2d8 e o da Mão Esmagadora aumenta em 2d6 para cada círculo do espaço acima do 5º.', '', NULL
FROM public.spells WHERE external_index = 'arcane-hand'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Arcane Lock
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('arcane-lock', 2, 'abjuration', 'action', 1, NULL, 'touch', NULL, 'special', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Arcane Lock', 'You touch a closed door, window, gate, chest, or other entryway, and it becomes locked for the duration. You and the creatures you designate when you cast this spell can open the object normally. You can also set a password that, when spoken within 5 feet of the object, suppresses this spell for 1 minute. Otherwise, it is impassable until it is broken or the spell is dispelled or suppressed. Casting knock on the object suppresses arcane lock for 10 minutes.
While affected by this spell, the object is more difficult to break or force open; the DC to break it or pick any locks on it increases by 10.', '', 'Gold dust worth at least 25gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'arcane-lock'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Tranca Arcana', 'Você toca uma porta, janela, portão, baú, ou outro tipo de entrada que já esteja fechada, tornando-a bloqueada enquanto a magia durar. Você e as criaturas que designar ao realizar a conjuração podem abrir o objeto normalmente. Você também pode definir uma senha que, quando dita a até 1,5 metro [5 ft.] do objeto, suprima esta magia durante 1 minuto. Caso contrário, o objeto fica trancado até que seja quebrado ou a magia seja dissipada ou suprimida. Conjurar Arrombar no objeto suprime a tranca arcana por 10 minutos.
Enquanto afetado por esta magia, o objeto é mais difícil de quebrar ou arrombar; a CD para quebrá-lo ou arrombar qualquer fechadura contida nele aumenta em 10.', '', NULL
FROM public.spells WHERE external_index = 'arcane-lock'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Arcane Sword
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('arcane-sword', 7, 'evocation', 'action', 1, 60, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Arcane Sword', 'You create a sword-shaped plane of force that hovers within range. It lasts for the duration.
When the sword appears, you make a melee spell attack against a target of your choice within 5 feet of the sword. On a hit, the target takes 3d10 force damage. Until the spell ends, you can use a bonus action on each of your turns to move the sword up to 20 feet to a spot you can see and repeat this attack against the same target or a different one.', '', 'A miniature platinum sword with a grip and pommel of copper and zinc, worth 250 gp.'
FROM public.spells WHERE external_index = 'arcane-sword'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Espada Arcana', 'Você cria um plano de força em forma de espada que paira dentro do intervalo. Dura pela duração.Quando a espada aparecer, você faz um ataque feitiço contra um alvo à sua escolha dentro de 5 pés da espada. Em um golpe, o alvo recebe 3d10 danos forçados. Até que a magia termine, você pode usar uma ação bônus em cada um dos seus turnos para mover a espada para um ponto que você pode ver e repetir esse ataque contra o mesmo alvo ou um diferente.', '', NULL
FROM public.spells WHERE external_index = 'arcane-sword'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Arcanist's Magic Aura
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('arcanists-magic-aura', 2, 'illusion', 'action', 1, NULL, 'touch', 24, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Arcanist''s Magic Aura', 'You place an illusion on a creature or an object you touch so that divination spells reveal false information about it. The target can be a willing creature or an object that isn''t being carried or worn by another creature.
When you cast the spell, choose one or both of the following effects. The effect lasts for the duration. If you cast this spell on the same creature or object every day for 30 days, placing the same effect on it each time, the illusion lasts until it is dispelled.
***False Aura.*** You change the way the target appears to spells and magical effects, such as detect magic, that detect magical auras. You can make a nonmagical object appear magical, a magical object appear nonmagical, or change the object''s magical aura so that it appears to belong to a specific school of magic that you choose. When you use this effect on an object, you can make the false magic apparent to any creature that handles the item.
***Mask.*** You change the way the target appears to spells and magical effects that detect creature types, such as a paladin''s Divine Sense or the trigger of a symbol spell. You choose a creature type and other spells and magical effects treat the target as if it were a creature of that type or of that alignment.', '', 'A small square of silk.'
FROM public.spells WHERE external_index = 'arcanists-magic-aura'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Aura Mágica do Arcanista', 'Você toca uma criatura ou objeto, criando uma ilusão sobre o alvo e fazendo com que magias de adivinhação revelem informações falsas sobre ele. O alvo pode ser uma criatura voluntária ou um objeto que não esteja sendo carregado ou usado por outra criatura.
Ao conjurar a magia, escolha um ou ambos os efeitos a seguir. O efeito fica ativo enquanto a magia durar. Se você conjurar esta magia na mesma criatura ou objeto todos os dias durante 30 dias, colocando o mesmo efeito toda vez, a ilusão dura até ser dissipada.
Falsa Aura. Você altera a maneira como o alvo parece para magias e efeitos mágicos, como Detectar Magia, que detectam auras mágicas. Você pode fazer um objeto não mágico parecer mágico, um objeto mágico parecer não mágico ou alterar a aura mágica do objeto, de modo que ele pareça pertencer a uma escola específica de magia que você escolher. Quando usar este efeito em um objeto, você pode fazer com que a magia falsa fique aparente para qualquer criatura que manipule o item.
Máscara. Você altera a maneira como o alvo parece para magias e efeitos mágicos que detectam tipos de criatura, como o Sentido Divino de um paladino ou o gatilho de uma magia Símbolo. Você escolhe um tipo de criatura e outras magias e efeitos mágicos passam a tratar o alvo como se este pertencesse ao tipo ou alinhamento da criatura escolhida.', '', NULL
FROM public.spells WHERE external_index = 'arcanists-magic-aura'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Astral Projection
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('astral-projection', 9, 'necromancy', 'hour', 1, 10, 'feet', NULL, 'special', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Astral Projection', 'You and up to eight willing creatures within range project your astral bodies into the Astral Plane (the spell fails and the casting is wasted if you are already on that plane). The material body you leave behind is unconscious and in a state of suspended animation; it doesn''t need food or air and doesn''t age.
Your astral body resembles your mortal form in almost every way, replicating your game statistics and possessions. The principal difference is the addition of a silvery cord that extends from between your shoulder blades and trails behind you, fading to invisibility after 1 foot. This cord is your tether to your material body. As long as the tether remains intact, you can find your way home. If the cord is cut--something that can happen only when an effect specifically states that it does--your soul and body are separated, killing you instantly.
Your astral form can freely travel through the Astral Plane and can pass through portals there leading to any other plane. If you enter a new plane or return to the plane you were on when casting this spell, your body and possessions are transported along the silver cord, allowing you to re-enter your body as you enter the new plane. Your astral form is a separate incarnation. Any damage or other effects that apply to it have no effect on your physical body, nor do they persist when you return to it.
The spell ends for you and your companions when you use your action to dismiss it. When the spell ends, the affected creature returns to its physical body, and it awakens.
The spell might also end early for you or one of your companions. A successful dispel magic spell used against an astral or physical body ends the spell for that creature. If a creature''s original body or its astral form drops to 0 hit points, the spell ends for that creature. If the spell ends and the silver cord is intact, the cord pulls the creature''s astral form back to its body, ending its state of suspended animation.
If you are returned to your body prematurely, your companions remain in their astral forms and must find their own way back to their bodies, usually by dropping to 0 hit points.', '', 'For each creature you affect with this spell, you must provide one jacinth worth at least 1,000gp and one ornately carved bar of silver worth at least 100gp, all of which the spell consumes.'
FROM public.spells WHERE external_index = 'astral-projection'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Projeção Astral', 'Você e até oito criaturas voluntárias dentro do alcance da magia projetam seus corpos astrais no Plano Astral (a magia falha e a conjuração é desperdiçada caso você já se encontre nesse plano). O corpo material que você deixa para trás fica inconsciente e em estado de animação suspensa; ele não precisa de comida ou ar e não envelhece.
Seu corpo astral se assemelha à sua forma mortal em quase todos os sentidos, replicando suas estatísticas de jogo e posses. A principal diferença é a adição de um cordão prateado que se estende das suas omoplatas e deixa um rastro para trás, desvanecendo até ficar invisível após 30 centímetros [1 foot]. Esse cordão é sua conexão com seu corpo material. Enquanto o cordão permanece intacto, você pode encontrar seu caminho de volta para casa. Se ele for cortado - algo que só pode acontecer quando um efeito especificamente declarar isto -, sua alma e o corpo são separados, matando-o instantaneamente.
Sua forma astral pode viajar livremente no Plano Astral e passar através de portais ali existentes, que levem a qualquer outro plano. Se você entrar em um novo plano ou voltar para o plano em que estava quando conjurou esta magia, seu corpo e posses são transportadas ao longo do cordão prateado, permitindo que você entre novamente em seu corpo, imediatamente ao ingressar no novo plano. Sua forma astral é uma encarnação separada. Qualquer dano ou outros efeitos que se apliquem a ela não têm nenhum efeito em seu corpo físico, nem persistem quando você retorna para ele.
A magia termina para você e seus companheiros quando você usa sua ação para encerrá-la. Quando a magia termina, a criatura afetada retorna ao próprio corpo físico e desperta.
A magia também pode terminar mais cedo para você ou para um de seus companheiros. Uma magia Dissipar Magia conjurada com sucesso contra um corpo astral ou físico encerra a magia para essa criatura. Se o corpo original da criatura ou de sua forma astral fica com 0 pontos de vida, a magia se encerra para essa criatura. Se a magia se encerrar e o cordão prateado estiver intacto, ele puxa a forma astral da criatura de volta para o próprio corpo, que sai do estado de animação suspensa.
Se você for devolvido ao seu corpo prematuramente, seus companheiros permanecem em suas formas astrais e devem encontrar um meio de voltar para seus corpos, geralmente ao ficarem com 0 pontos de vida.', '', NULL
FROM public.spells WHERE external_index = 'astral-projection'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Augury
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('augury', 2, 'divination', 'minute', 1, NULL, 'self', NULL, 'instantaneous', false, true, ARRAY['V', 'S', 'M'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Augury', 'By casting gem-inlaid sticks, rolling dragon bones, laying out ornate cards, or employing some other divining tool, you receive an omen from an otherworldly entity about the results of a specific course of action that you plan to take within the next 30 minutes. The GM chooses from the following possible omens:
- Weal, for good results
- Woe, for bad results
- Weal and woe, for both good and bad results
- Nothing, for results that aren''t especially good or bad
The spell doesn''t take into account any possible circumstances that might change the outcome, such as the casting of additional spells or the loss or gain of a companion.
If you cast the spell two or more times before completing your next long rest, there is a cumulative 25 percent chance for each casting after the first that you get a random reading. The GM makes this roll in secret.', '', 'Specially marked sticks, bones, or similar tokens worth at least 25gp.'
FROM public.spells WHERE external_index = 'augury'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Augúrio', 'Ao lançar varetas incrustadas com pedras preciosas, jogar ossos de dragão, dispor cartas ornamentadas ou empregar alguma outra ferramenta de adivinhação, você recebe um presságio de uma entidade de outro mundo sobre os resultados de um determinado curso de ação que você planeja tomar dentro dos próximos 30 minutos. O DM escolhe entre os seguintes presságios possíveis:
Prosperidade, para bons resultados
Infortúnio, para maus resultados
Prosperidade e Infortúnio, para resultados bons e maus
Nada, para resultados que não são especialmente bons ou maus
A magia não leva em conta quaisquer circunstâncias possíveis que possam mudar o resultado futuro, como a conjuração de magias adicionais ou a perda ou ganho de um companheiro.
Caso você conjure a magia duas ou mais vezes antes de concluir seu próximo descanso longo, há uma chance cumulativa de 25% para cada conjuração após a primeira de você obter uma resposta aleatória. O DM faz esta jogada em segredo.', '', NULL
FROM public.spells WHERE external_index = 'augury'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Awaken
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('awaken', 5, 'transmutation', 'hour', 8, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Awaken', 'After spending the casting time tracing magical pathways within a precious gemstone, you touch a Huge or smaller beast or plant. The target must have either no Intelligence score or an Intelligence of 3 or less. The target gains an Intelligence of 10. The target also gains the ability to speak one language you know. If the target is a plant, it gains the ability to move its limbs, roots, vines, creepers, and so forth, and it gains senses similar to a human''s. Your GM chooses statistics appropriate for the awakened plant, such as the statistics for the awakened shrub or the awakened tree.
The awakened beast or plant is charmed by you for 30 days or until you or your companions do anything harmful to it. When the charmed condition ends, the awakened creature chooses whether to remain friendly to you, based on how you treated it while it was charmed.', '', 'An agate worth at least 1,000 gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'awaken'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Despertar', 'Depois de gastar o tempo de conjuração traçando padrões mágicos com uma pedra preciosa, você toca em uma fera ou planta de tamanho Enorme ou menor. O alvo deve ter um valor de Inteligência igual a 3 ou menor ou não possuir Inteligência alguma. O alvo ganha um valor de Inteligência de 10. O alvo também ganha a habilidade de falar um idioma que você conheça. Se o alvo for uma planta, ela ganha a habilidade de mover seus galhos, raízes, cipós, trepadeiras e assim por diante, além de ganhar sentidos semelhantes aos de um humano. Seu DM escolhe as estatísticas adequadas a uma planta despertada, como as de um arbusto ou árvore despertados.
A fera ou planta despertada fica enfeitiçada por você durante 30 dias, ou até que você ou seus companheiros façam qualquer coisa que a prejudique. Quando a condição de enfeitiçada termina, a criatura despertada escolhe se quer permanecer amigável com você, com base em como foi tratada enquanto estava enfeitiçada.', '', NULL
FROM public.spells WHERE external_index = 'awaken'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Bane
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('bane', 1, 'enchantment', 'action', 1, 30, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Bane', 'Up to three creatures of your choice that you can see within range must make charisma saving throws. Whenever a target that fails this saving throw makes an attack roll or a saving throw before the spell ends, the target must roll a d4 and subtract the number rolled from the attack roll or saving throw.', 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', 'A drop of blood.'
FROM public.spells WHERE external_index = 'bane'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Perdição', 'Até três criaturas, à sua escolha, à sua vista e que estejam dentro do alcance da magia, devem realizar salvaguardas de Carisma. Enquanto a magia durar, sempre que um alvo que falhar nessa salvaguarda fizer uma jogada de ataque ou uma salvaguarda, ele deverá jogar 1d4 e subtrair o número obtido do resultado da jogada de ataque ou salvaguarda.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, você pode enfeitiçar uma criatura adicional para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'bane'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Banishment
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('banishment', 4, 'abjuration', 'action', 1, 60, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'paladin', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Banishment', 'You attempt to send one creature that you can see within range to another plane of existence. The target must succeed on a charisma saving throw or be banished.
If the target is native to the plane of existence you''re on, you banish the target to a harmless demiplane. While there, the target is incapacitated. The target remains there until the spell ends, at which point the target reappears in the space it left or in the nearest unoccupied space if that space is occupied.
If the target is native to a different plane of existence than the one you''re on, the target is banished with a faint popping noise, returning to its home plane. If the spell ends before 1 minute has passed, the target reappears in the space it left or in the nearest unoccupied space if that space is occupied. Otherwise, the target doesn''t return.', 'When you cast this spell using a spell slot of 5th level or higher, you can target one additional creature for each slot level above 4th.', 'An item distasteful to the target.'
FROM public.spells WHERE external_index = 'banishment'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Banimento', 'Você tenta enviar uma criatura à sua vista e que esteja dentro do alcance da magia para outro plano de existência. O alvo deve ser bem-sucedido em uma salvaguarda de Carisma ou será banido.
Se o alvo for nativo do plano em que você se encontra, ele é banido para um semiplano inofensivo. Enquanto permanecer lá, fica incapacitado. O alvo permanece banido enquanto a magia durar, quando, então, reaparece no espaço de onde partiu ou no espaço desocupado mais próximo, se o espaço original estiver ocupado.
Se o alvo for nativo de um plano de existência diferente daquele no qual você se encontra, ele é banido com um ligeiro estalo, voltando para o seu próprio plano de origem. Se a magia se encerrar antes que 1 minuto se passe, o alvo reaparece no espaço de onde partiu ou no espaço desocupado mais próximo, se o espaço original estiver ocupado. Caso contrário, o alvo não retorna.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 5º círculo ou maior, você pode atingir uma criatura adicional para cada círculo do espaço acima do 4º.', '', NULL
FROM public.spells WHERE external_index = 'banishment'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Barkskin
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('barkskin', 2, 'transmutation', 'action', 1, NULL, 'touch', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Barkskin', 'You touch a willing creature. Until the spell ends, the target''s skin has a rough, bark-like appearance, and the target''s AC can''t be less than 16, regardless of what kind of armor it is wearing.', '', 'A handful of oak bark.'
FROM public.spells WHERE external_index = 'barkskin'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Pele-casca', 'Você toca uma criatura voluntária. A magia transforma a pele do alvo, tornando-a áspera e com a aparência de casca de árvore. Enquanto a magia durar, o alvo tem uma CA que não pode ser menor do que 16, independente do tipo de armadura vestida.', '', NULL
FROM public.spells WHERE external_index = 'barkskin'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Beacon of Hope
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('beacon-of-hope', 3, 'abjuration', 'action', 1, 30, 'feet', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Beacon of Hope', 'This spell bestows hope and vitality. Choose any number of creatures within range. For the duration, each target has advantage on wisdom saving throws and death saving throws, and regains the maximum number of hit points possible from any healing.', '', NULL
FROM public.spells WHERE external_index = 'beacon-of-hope'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Sinal de Esperança', 'Esta magia concede esperança e vitalidade. Escolha qualquer número de criaturas dentro do alcance da magia. Durante a duração desta magia, cada alvo terá vantagem em salvaguardas de Sabedoria e contra a morte, além de recuperar a quantidade máxima de pontos de vida possível de qualquer fonte de cura.', '', NULL
FROM public.spells WHERE external_index = 'beacon-of-hope'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Bestow Curse
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('bestow-curse', 3, 'necromancy', 'action', 1, NULL, 'touch', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['bard', 'cleric', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Bestow Curse', 'You touch a creature, and that creature must succeed on a wisdom saving throw or become cursed for the duration of the spell. When you cast this spell, choose the nature of the curse from the following options:
- Choose one ability score. While cursed, the target has disadvantage on ability checks and saving throws made with that ability score.
- While cursed, the target has disadvantage on attack rolls against you.
- While cursed, the target must make a wisdom saving throw at the start of each of its turns. If it fails, it wastes its action that turn doing nothing.
- While the target is cursed, your attacks and spells deal an extra 1d8 necrotic damage to the target.
A remove curse spell ends this effect. At the GM''s option, you may choose an alternative curse effect, but it should be no more powerful than those described above. The GM has final say on such a curse''s effect.', 'If you cast this spell using a spell slot of 4th level or higher, the duration is concentration, up to 10 minutes. If you use a spell slot of 5th level or higher, the duration is 8 hours. If you use a spell slot of 7th level or higher, the duration is 24 hours. If you use a 9th level spell slot, the spell lasts until it is dispelled. Using a spell slot of 5th level or higher grants a duration that doesn''t require concentration.', NULL
FROM public.spells WHERE external_index = 'bestow-curse'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Rogar Maldição', 'Quando você toca uma criatura, ela deve ser bem-sucedida em uma salvaguarda de Sabedoria ou torna-se amaldiçoada enquanto a magia durar. Ao conjurar esta magia, você deve escolher a natureza da maldição, entre as seguintes opções:
Escolha um atributo. Enquanto amaldiçoado, o alvo tem desvantagem nos testes de atributo e salvaguardas feitas com este atributo.
Enquanto amaldiçoado, o alvo tem desvantagem nas jogadas de ataque contra você.
Enquanto amaldiçoado, o alvo deve fazer uma salvaguarda de Sabedoria no início de cada um dos turnos dele. Se falha, desperdiça a própria ação nesse turno, ficando sem fazer nada.
Enquanto o alvo está amaldiçoado, seus ataques e magias contra ele causam 1d8 pontos de dano necrótico extra.
Uma magia Remover Maldição encerra o efeito da magia. À escolha do DM, você pode optar por um efeito de maldição alternativo, mas ele não deve ser mais poderoso do que os descritos acima. O DM tem a palavra final sobre este efeito da maldição alternativa.
Em Círculos Superiores. Se você conjurar esta magia usando um espaço de magia de 4º círculo ou superior, a duração dela será Concentração, até 10 minutos. Se você usar um espaço de magia de 5º círculo ou superior, a duração passa a ser 8 horas. Se você usar um espaço de magia de 7º círculo ou superior, a duração passa a ser 24 horas. Se você usar um espaço de magia de 9º círculo, a magia dura até ser dissipada. Usar um espaço de magia de 5º círculo ou superior concede uma duração que não requer concentração.', '', NULL
FROM public.spells WHERE external_index = 'bestow-curse'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Black Tentacles
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('black-tentacles', 4, 'conjuration', 'action', 1, 90, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Black Tentacles', 'Squirming, ebony tentacles fill a 20-foot square on ground that you can see within range. For the duration, these tentacles turn the ground in the area into difficult terrain.
When a creature enters the affected area for the first time on a turn or starts its turn there, the creature must succeed on a Dexterity saving throw or take 3d6 bludgeoning damage and be restrained by the tentacles until the spell ends. A creature that starts its turn in the area and is already restrained by the tentacles takes 3d6 bludgeoning damage.
A creature restrained by the tentacles can use its action to make a Strength or Dexterity check (its choice) against your spell save DC. On a success, it frees itself.', '', 'A piece of tentacle from a giant octopus or a giant squid'
FROM public.spells WHERE external_index = 'black-tentacles'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Tentáculos Negros', 'Tentáculos negros se contorcem, preenchendo uma área de 6 metros quadrados [20-foot square] de solo à sua vista, no alcance da magia. Enquanto a magia durar, os tentáculos transformam o solo da área em terreno difícil.
Quando uma criatura entra pela primeira vez ou quando inicia o próprio turno na área afetada, ela deve fazer uma salvaguarda de Destreza. Se falhar, sofre 3d6 pontos de dano contundente, ficando @UUID[Compendium.dnd5e.rules.w7eitkpD7QQTB6j0.JournalEntryPage.cSVcyZyNe2iG1fIc]{contida} pelos tentáculos até que a magia encerre. Uma criatura que inicie o próprio turno na área e esteja @UUID[Compendium.dnd5e.rules.w7eitkpD7QQTB6j0.JournalEntryPage.cSVcyZyNe2iG1fIc]{contida} pelos tentáculos, sofre 3d6 pontos de dano contundente.
Uma criatura @UUID[Compendium.dnd5e.rules.w7eitkpD7QQTB6j0.JournalEntryPage.cSVcyZyNe2iG1fIc]{contida} pelos tentáculos pode usar a própria ação para fazer um teste de Força ou Destreza (à escolha dela) contra a CD para evitar sua magia. Em caso de sucesso, ela se liberta.', '', NULL
FROM public.spells WHERE external_index = 'black-tentacles'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Blade Barrier
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('blade-barrier', 6, 'evocation', 'action', 1, 90, 'feet', 10, 'minute', true, false, ARRAY['V', 'S'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Blade Barrier', 'You create a vertical wall of whirling, razor-sharp blades made of magical energy. The wall appears within range and lasts for the duration. You can make a straight wall up to 100 feet long, 20 feet high, and 5 feet thick, or a ringed wall up to 60 feet in diameter, 20 feet high, and 5 feet thick. The wall provides three-quarters cover to creatures behind it, and its space is difficult terrain.
When a creature enters the wall''s area for the first time on a turn or starts its turn there, the creature must make a dexterity saving throw. On a failed save, the creature takes 6d10 slashing damage. On a successful save, the creature takes half as much damage.', '', NULL
FROM public.spells WHERE external_index = 'blade-barrier'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Barreira de Lâminas', 'Você cria uma barreira vertical de lâminas rodopiantes e afiadas feitas de energia mágica. A barreira aparece dentro do alcance da magia e permanece enquanto a magia durar. Você pode fazer uma barreira reta de até 30 metros [100 ft.] de comprimento, 6 metros [20 ft.] de altura e 1,5 metro [5 ft.] de espessura, ou uma barreira circular de até 18 metros [60 ft.] de diâmetro, 6 metros [20 ft.] de altura e 1,5 metro [5 ft.] de espessura. A barreira fornece três quartos de cobertura para as criaturas atrás dela; o espaço dela é considerado terreno difícil.
Quando uma criatura entra na área da barreira pela primeira vez ou inicia o próprio turno ali, ela deve fazer uma salvaguarda de Destreza. Se falhar, sofre 6d10 pontos de dano cortante, ou metade do dano em caso de sucesso.', '', NULL
FROM public.spells WHERE external_index = 'blade-barrier'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
