INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Bless', 'You bless up to three creatures of your choice within range. Whenever a target makes an attack roll or a saving throw before the spell ends, the target can roll a d4 and add the number rolled to the attack roll or saving throw.', 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st.', 'A sprinkling of holy water.'
FROM public.spells WHERE external_index = 'bless'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Bênção', 'Você abençoa até três criaturas à sua escolha dentro do alcance da magia. Sempre que um alvo realiza um jogada de ataque ou uma salvaguarda antes da magia terminar, ele deve jogar 1d4 e adicionar o número obtido à jogada de ataque ou testes de salvaguarda.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, você pode escolher como alvo uma criatura adicional para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'bless'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Blight
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('blight', 4, 'necromancy', 'action', 1, 30, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['druid', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Blight', 'Necromantic energy washes over a creature of your choice that you can see within range, draining moisture and vitality from it. The target must make a constitution saving throw. The target takes 8d8 necrotic damage on a failed save, or half as much damage on a successful one. The spell has no effect on undead or constructs.
If you target a plant creature or a magical plant, it makes the saving throw with disadvantage, and the spell deals maximum damage to it.
If you target a nonmagical plant that isn''t a creature, such as a tree or shrub, it doesn''t make a saving throw; it simply withers and dies.', 'When you cast this spell using a spell slot of 5th level of higher, the damage increases by 1d8 for each slot level above 4th.', NULL
FROM public.spells WHERE external_index = 'blight'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Malogro', 'Energia necromântica envolve uma criatura à sua escolha, à sua vista e no alcance da magia, drenando a umidade e a vitalidade dela. O alvo deve fazer uma salvaguarda de Constituição. Se falhar, sofre 8d8 de dano necrótico, ou metade do dano em caso de sucesso. Esta magia não tem efeito sobre mortos-vivos ou constructos.
Se você escolher como alvo uma criatura do tipo planta ou uma planta mágica, ela faz a salvaguarda com desvantagem e a magia causa dano máximo.
Se você escolher como alvo uma planta não-mágica que não seja uma criatura, como uma árvore ou arbusto, ela não faz a salvaguarda e simplesmente murcha e morre.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 5º círculo ou superior, o dano aumenta em 1d8 para cada círculo do espaço acima do 4º.', '', NULL
FROM public.spells WHERE external_index = 'blight'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Blindness/Deafness
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('blindness-deafness', 2, 'necromancy', 'action', 1, 30, 'feet', 1, 'minute', false, false, ARRAY['V'], ARRAY['bard', 'cleric', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Blindness/Deafness', 'You can blind or deafen a foe. Choose one creature that you can see within range to make a constitution saving throw. If it fails, the target is either blinded or deafened (your choice) for the duration. At the end of each of its turns, the target can make a constitution saving throw. On a success, the spell ends.', 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.', NULL
FROM public.spells WHERE external_index = 'blindness-deafness'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Cegueira/Surdez', 'Você pode cegar ou ensurdecer um inimigo. Escolha um alvo à sua vista e que esteja no alcance desta magia. Ele deve fazer uma salvaguarda de Constituição. Se falhar, fica cego ou surdo (à sua escolha) enquanto a magia durar. No final de cada um dos turnos dele, o alvo pode realizar uma salvaguarda de Constituição. Se for bem-sucedido, a magia se encerra.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 3º círculo ou superior, você pode atingir uma criatura adicional para cada círculo do espaço acima do 2º.', '', NULL
FROM public.spells WHERE external_index = 'blindness-deafness'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Blink
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('blink', 3, 'transmutation', 'action', 1, NULL, 'self', 1, 'minute', false, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Blink', 'Roll a d20 at the end of each of your turns for the duration of the spell. On a roll of 11 or higher, you vanish from your current plane of existence and appear in the Ethereal Plane (the spell fails and the casting is wasted if you were already on that plane). At the start of your next turn, and when the spell ends if you are on the Ethereal Plane, you return to an unoccupied space of your choice that you can see within 10 feet of the space you vanished from. If no unoccupied space is available within that range, you appear in the nearest unoccupied space (chosen at random if more than one space is equally near). You can dismiss this spell as an action.
While on the Ethereal Plane, you can see and hear the plane you originated from, which is cast in shades of gray, and you can''t see anything there more than 60 feet away. You can only affect and be affected by other creatures on the Ethereal Plane. Creatures that aren''t there can''t perceive you or interact with you, unless they have the ability to do so.', '', NULL
FROM public.spells WHERE external_index = 'blink'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Piscar', 'Jogue 1d20 no final de cada um de seus turnos enquanto a magia durar. Com um resultado igual ou maior que 11, você desaparece do seu plano de existência atual e aparece no Plano Etéreo (a magia falha e a conjuração é desperdiçada se você já estiver nesse plano). No início do seu próximo turno, e quando a magia terminar, se você estiver no Plano Etéreo, você retorna para um espaço desocupado à sua escolha, à sua vista e que esteja a até 3 metros [10 ft.] do espaço de onde você desapareceu. Se não houver espaço desocupado disponível dentro desse alcance, você aparece no próximo espaço desocupado (escolhido aleatoriamente, se mais do que um espaço estiver igualmente próximo). Você pode encerrar esta magia com uma ação.
Enquanto estiver no Plano Etéreo, você pode ver (em tons de cinza, a uma distância de até 18 metros [60 ft.]) e ouvir seu plano de origem. Você só pode afetar e ser afetado por criaturas que estejam no Plano Etéreo. Criaturas que não estejam nesse plano não podem percebê-lo ou interagir com você, a menos que tenham uma habilidade específica que lhes permita fazê-lo.', '', NULL
FROM public.spells WHERE external_index = 'blink'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Blur
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('blur', 2, 'illusion', 'action', 1, NULL, 'self', 1, 'minute', true, false, ARRAY['V'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Blur', 'Your body becomes blurred, shifting and wavering to all who can see you. For the duration, any creature has disadvantage on attack rolls against you. An attacker is immune to this effect if it doesn''t rely on sight, as with blindsight, or can see through illusions, as with truesight.', '', NULL
FROM public.spells WHERE external_index = 'blur'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Turvar', 'Seu corpo torna-se turvo, mudando e oscilando para todos os que possam vê-lo. Ao longo da duração desta magia, qualquer criatura tem desvantagem em jogadas de ataque contra você. Um atacante é imune a este efeito se não depender da visão, como alguém com percepção às cegas, ou se puder ver através de ilusões, como alguém com visão verdadeira.', '', NULL
FROM public.spells WHERE external_index = 'blur'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Branding Smite
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('branding-smite', 2, 'evocation', 'bonus_action', 1, NULL, 'self', 1, 'minute', true, false, ARRAY['V'], ARRAY['paladin'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Branding Smite', 'The next time you hit a creature with a weapon attack before this spell ends, the weapon gleams with astral radiance as you strike. The attack deals an extra 2d6 radiant damage to the target, which becomes visible if it''s invisible, and the target sheds dim light in a 5-foot radius and can''t become invisible until the spell ends.', 'When you cast this spell using a spell slot of 3rd level or higher, the extra damage increases by 1d6 for each slot level above 2nd.', NULL
FROM public.spells WHERE external_index = 'branding-smite'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Marca da Punição', 'Enquanto durar esta magia, na próxima vez que você atingir uma criatura com uma arma, ela brilhará com radiação astral conforme você acerta. O ataque causa 2d6 pontos de dano radiante adicionais ao alvo, que torna-se visível (caso esteja invisível), emitindo uma luz fraca, criando meia-luz num raio de 1,5 metro [5 ft.] e não podendo retornar à condição invisível enquanto a magia durar.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 3º círculo ou superior, o dano aumenta em 1d6 para cada círculo do espaço acima do 2º.', '', NULL
FROM public.spells WHERE external_index = 'branding-smite'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Burning Hands
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('burning-hands', 1, 'evocation', 'action', 1, NULL, 'self', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Burning Hands', 'As you hold your hands with thumbs touching and fingers spread, a thin sheet of flames shoots forth from your outstretched fingertips. Each creature in a 15-foot cone must make a dexterity saving throw. A creature takes 3d6 fire damage on a failed save, or half as much damage on a successful one.
The fire ignites any flammable objects in the area that aren''t being worn or carried.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', NULL
FROM public.spells WHERE external_index = 'burning-hands'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Mãos Flamejantes', 'Enquanto você mantiver suas mãos com os polegares tocando um ao outro e os demais dedos abertos, uma fina camada de chamas parte da ponta de seus dedos estendidos. Cada criatura dentro de um cone de 4,5 metros [15-foot cone] deve fazer uma salvaguarda de Destreza. Se falhar, sofre 3d6 pontos de dano, ou metade do dano em caso de sucesso.
O fogo incendeia todos os objetos inflamáveis na área que não estejam sendo usados ou transportados.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, o dano aumenta em 1d6 para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'burning-hands'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Call Lightning
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('call-lightning', 3, 'conjuration', 'action', 1, 120, 'feet', 10, 'minute', true, false, ARRAY['V', 'S'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Call Lightning', 'A storm cloud appears in the shape of a cylinder that is 10 feet tall with a 60-foot radius, centered on a point you can see 100 feet directly above you. The spell fails if you can''t see a point in the air where the storm cloud could appear (for example, if you are in a room that can''t accommodate the cloud).
When you cast the spell, choose a point you can see within range. A bolt of lightning flashes down from the cloud to that point. Each creature within 5 feet of that point must make a dexterity saving throw. A creature takes 3d10 lightning damage on a failed save, or half as much damage on a successful one. On each of your turns until the spell ends, you can use your action to call down lightning in this way again, targeting the same point or a different one.
If you are outdoors in stormy conditions when you cast this spell, the spell gives you control over the existing storm instead of creating a new one. Under such conditions, the spell''s damage increases by 1d10.', 'When you cast this spell using a spell slot of 4th or higher level, the damage increases by 1d10 for each slot level above 3rd.', NULL
FROM public.spells WHERE external_index = 'call-lightning'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Convocar Relâmpagos', 'Uma nuvem de tempestade aparece na forma de um cilindro de 3 metros de altura [10 ft. tall cilinder] com um raio de 18 metros [60 ft. radius], centralizado em um ponto à sua vista, dentro do alcance diretamente acima de você. A magia falha se você não puder ver um ponto no ar onde a nuvem de tempestade possa aparecer (por exemplo, se você estiver em uma sala que não possa acomodar a nuvem).
Ao conjurar a magia, escolha um ponto que você possa ver sob a nuvem. Um raio de eletricidade parte da nuvem até esse ponto. Cada criatura a uma distância de até 1,5 metro [5 ft.] desse ponto deve fazer uma salvaguarda de Destreza. Se falhar, sofre 3d10 pontos de dano elétrico, ou metade do dano em caso de sucesso. Em cada um de seus turnos, enquanto a magia durar, você pode usar sua ação para convocar relâmpagos dessa maneira, atingindo o mesmo ponto ou outro.
Se você estiver ao ar livre e em condições tempestuosas ao conjurar esta magia, ela lhe confere o controle sobre a tempestade existente, em vez de criar uma nova. Sob essas condições, o dano da magia aumenta em 1d10.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 4º círculo ou superior, o dano aumenta em 1d10 para cada círculo do espaço acima do 3º.', '', NULL
FROM public.spells WHERE external_index = 'call-lightning'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Calm Emotions
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('calm-emotions', 2, 'enchantment', 'action', 1, 60, 'feet', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['bard', 'cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Calm Emotions', 'You attempt to suppress strong emotions in a group of people. Each humanoid in a 20-foot-radius sphere centered on a point you choose within range must make a charisma saving throw; a creature can choose to fail this saving throw if it wishes. If a creature fails its saving throw, choose one of the following two effects. You can suppress any effect causing a target to be charmed or frightened. When this spell ends, any suppressed effect resumes, provided that its duration has not expired in the meantime.
Alternatively, you can make a target indifferent about creatures of your choice that it is hostile toward. This indifference ends if the target is attacked or harmed by a spell or if it witnesses any of its friends being harmed. When the spell ends, the creature becomes hostile again, unless the GM rules otherwise.', '', NULL
FROM public.spells WHERE external_index = 'calm-emotions'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Acalmar Emoções', 'Você tenta suprimir emoções fortes em um grupo de criaturas. Cada humanoide dentro de uma esfera de 6 metros de raio [20-foot-radius sphere] centrada em um ponto dentro do alcance da magia deve fazer uma salvaguarda de Carisma; uma criatura pode escolher falhar nesta salvaguarda, caso deseje. Se uma criatura falhar na salvaguarda, escolha um dos dois efeitos a seguir. Você pode suprimir qualquer efeito que cause a um alvo as condições enfeitiçado ou amedrontado. Quando esta magia termina, qualquer efeito suprimido retorna, caso a duração não tenha expirado nesse meio-tempo.
Como alternativa, você pode tornar o alvo indiferente a criaturas, à sua escolha, contra as quais o alvo era hostil. Tal indiferença termina se o alvo for atacado ou ferido por uma magia, ou se testemunhar quaisquer de seus próprios amigos sendo feridos. Quando a magia termina, a criatura torna-se hostil novamente, a menos que o DM decida de outra forma.', '', NULL
FROM public.spells WHERE external_index = 'calm-emotions'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Chain Lightning
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('chain-lightning', 6, 'evocation', 'action', 1, 150, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Chain Lightning', 'You create a bolt of lightning that arcs toward a target of your choice that you can see within range. Three bolts then leap from that target to as many as three other targets, each of which must be within 30 feet of the first target. A target can be a creature or an object and can be targeted by only one of the bolts.
A target must make a dexterity saving throw. The target takes 10d8 lightning damage on a failed save, or half as much damage on a successful one.', 'When you cast this spell using a spell slot of 7th level or higher, one additional bolt leaps from the first target to another target for each slot level above 6th.', 'A bit of fur; a piece of amber, glass, or a crystal rod; and three silver pins.'
FROM public.spells WHERE external_index = 'chain-lightning'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Corrente de Relâmpagos', 'Você cria um raio de eletricidade que salta em direção a um alvo à sua escolha, o qual você possa ver e que esteja dentro do alcance da magia. Em seguida, três raios saltam do alvo na direção de até três outros alvos, que devem estar a até 9 metros [30 ft.] do primeiro. Cada alvo pode ser uma criatura ou um objeto, e só pode ser atingido por apenas um dos raios.
O alvo deve fazer uma salvaguarda de Constituição. Se falhar, sofre 10d8 de dano elétrico, ou metade do dano em caso de sucesso.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 7º círculo ou superior, um raio adicional salta do primeiro alvo em direção a outro, para cada círculo do espaço acima do 6º.', '', NULL
FROM public.spells WHERE external_index = 'chain-lightning'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Charm Person
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('charm-person', 1, 'enchantment', 'action', 1, 30, 'feet', 1, 'hour', false, false, ARRAY['V', 'S'], ARRAY['bard', 'druid', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Charm Person', 'You attempt to charm a humanoid you can see within range. It must make a wisdom saving throw, and does so with advantage if you or your companions are fighting it. If it fails the saving throw, it is charmed by you until the spell ends or until you or your companions do anything harmful to it. The charmed creature regards you as a friendly acquaintance. When the spell ends, the creature knows it was charmed by you.', 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each slot level above 1st. The creatures must be within 30 feet of each other when you target them.', NULL
FROM public.spells WHERE external_index = 'charm-person'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Enfeitiçar Pessoa', 'Você tenta enfeitiçar um humanoide à sua vista e dentro do alcance da magia. O alvo deve fazer uma salvaguarda de Sabedoria - com vantagem caso você ou seus companheiros estejam lutando contra ele. Se falhar, ele fica enfeitiçado por você enquanto a magia durar ou até que você ou seus companheiros lhe causem dano. A criatura enfeitiçada considera você como um conhecido amigável. Quando a magia termina, a criatura sabe que foi enfeitiçada por você.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, você pode enfeitiçar uma criatura adicional para cada círculo do espaço acima do 1º. As criaturas devem estar a até 9 metros [30 ft.] umas das outras quando você as escolher como alvo.', '', NULL
FROM public.spells WHERE external_index = 'charm-person'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Chill Touch
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('chill-touch', 0, 'necromancy', 'action', 1, 120, 'feet', 1, 'round', false, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Chill Touch', 'You create a ghostly, skeletal hand in the space of a creature within range. Make a ranged spell attack against the creature to assail it with the chill of the grave. On a hit, the target takes 1d8 necrotic damage, and it can''t regain hit points until the start of your next turn. Until then, the hand clings to the target.
If you hit an undead target, it also has disadvantage on attack rolls against you until the end of your next turn.
This spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', '', NULL
FROM public.spells WHERE external_index = 'chill-touch'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Toque Necrótico', 'Você cria uma mão esquelética e fantasmagórica no espaço ocupado por uma criatura que se encontre no alcance da magia. Faça um ataque mágico à distância contra a criatura para atingi-la com um calafrio sepulcral. Se o ataque for bem-sucedido, ela sofre 1d8 pontos de dano necrótico e não pode recuperar pontos de vida até o início do seu próximo turno. Até lá, a mão se agarra ao alvo.
Se você atacar um alvo morto-vivo, ele também terá desvantagem nas jogadas de ataque contra você até o final do seu próximo turno.
O dano desta magia aumenta em 1d8 quando você alcança o 5º nível (2d8), 11º nível (3d8) e 17º nível (4d8).', '', NULL
FROM public.spells WHERE external_index = 'chill-touch'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Circle of Death
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('circle-of-death', 6, 'necromancy', 'action', 1, 150, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Circle of Death', 'A sphere of negative energy ripples out in a 60-foot radius sphere from a point within range. Each creature in that area must make a constitution saving throw. A target takes 8d6 necrotic damage on a failed save, or half as much damage on a successful one.', 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 2d6 for each slot level above 6th.', 'The powder of a crushed black pearl worth at least 500 gp.'
FROM public.spells WHERE external_index = 'circle-of-death'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Círculo da Morte', 'Uma esfera de energia negativa emite ondulações em um raio de 18 metros [60-foot radius] a partir de um ponto dentro da área do alcance da magia. Cada criatura na área deve fazer uma salvaguarda de Constituição. Se falhar, sofre 8d6 de dano necrótico, ou metade do dano em caso de sucesso.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 7º círculo ou superior, o dano aumenta em 2d6 para cada círculo do espaço acima do 6º.', '', NULL
FROM public.spells WHERE external_index = 'circle-of-death'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Clairvoyance
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('clairvoyance', 3, 'divination', 'minute', 10, 1, 'mile', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Clairvoyance', 'You create an invisible sensor within range in a location familiar to you (a place you have visited or seen before) or in an obvious location that is unfamiliar to you (such as behind a door, around a corner, or in a grove of trees). The sensor remains in place for the duration, and it can''t be attacked or otherwise interacted with.
When you cast the spell, you choose seeing or hearing. You can use the chosen sense through the sensor as if you were in its space. As your action, you can switch between seeing and hearing.
A creature that can see the sensor (such as a creature benefiting from see invisibility or truesight) sees a luminous, intangible orb about the size of your fist.', '', 'A focus worth at least 100gp, either a jeweled horn for hearing or a glass eye for seeing.'
FROM public.spells WHERE external_index = 'clairvoyance'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Clarividência', 'Você cria um sensor invisível em um local que lhe seja familiar (um lugar que visitou ou que já tenha visto) ou em uma localidade óbvia, mas que não lhe seja familiar (como atrás de uma porta, contornando uma esquina ou em um bosque), ambos dentro do alcance da magia. O sensor permanece no local enquanto a magia durar, não podendo ser atacado nem ser alvo de qualquer outro tipo de interação.
Ao conjurar a magia, você escolhe ver ou ouvir. Você pode usar o sentido escolhido por meio do sensor como se estivesse no espaço ocupado por ele. Com uso de uma ação, você pode alternar entre ver e ouvir.
Uma criatura que possa ver o sensor (como aquelas que se beneficiam de Ver o Invisível ou visão verdadeira), enxerga um orbe luminoso e intangível do tamanho de um punho.', '', NULL
FROM public.spells WHERE external_index = 'clairvoyance'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Clone
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('clone', 8, 'necromancy', 'hour', 1, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Clone', 'This spell grows an inert duplicate of a living creature as a safeguard against death. This clone forms inside a sealed vessel and grows to full size and maturity after 120 days; you can also choose to have the clone be a younger version of the same creature. It remains inert and endures indefinitely, as long as its vessel remains undisturbed.
At any time after the clone matures, if the original creature dies, its soul transfers to the clone, provided that the soul is free and willing to return. The clone is physically identical to the original and has the same personality, memories, and abilities, but none of the original''s equipment. The original creature''s physical remains, if they still exist, become inert and can''t thereafter be restored to life, since the creature''s soul is elsewhere.', '', 'A diamond worth at least 1,000 gp and at least 1 cubic inch of flesh of the creature that is to be cloned, which the spell consumes, and a vessel worth at least 2,000 gp that has a sealable lid and is large enough to hold a Medium creature, such as a huge urn, coffin, mud-filled cyst in the ground, or crystal container filled with salt water.'
FROM public.spells WHERE external_index = 'clone'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Clone', 'Esta magia cria uma duplicata inerte de uma criatura viva, a título de garantia contra a morte. Esse clone forma-se dentro de um receptáculo selado, crescendo e amadurecendo completamente após 120 dias; também existe a opção de o clone ser a versão mais jovem da mesma criatura. Ele se mantém inerte e dura indefinidamente, contanto que o receptáculo não seja perturbado.A qualquer momento após o clone amadurecer, se a criatura original morrer, a alma dela é transferida para o clone, considerando que a alma seja livre e disposta a retornar. O clone é fisicamente idêntico ao original, tendo a mesma personalidade, memórias e habilidades, mas nenhum dos equipamentos da forma original. Os restos mortais da criatura original permanecem, se ainda existirem, ficam inertes e não podem ter a vida restaurada, já que a alma da criatura está em outro receptáculo.', '', NULL
FROM public.spells WHERE external_index = 'clone'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Cloudkill
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('cloudkill', 5, 'conjuration', 'action', 1, 120, 'feet', 10, 'minute', true, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Cloudkill', 'You create a 20-foot-radius sphere of poisonous, yellow-green fog centered on a point you choose within range. The fog spreads around corners. It lasts for the duration or until strong wind disperses the fog, ending the spell. Its area is heavily obscured.
When a creature enters the spell''s area for the first time on a turn or starts its turn there, that creature must make a constitution saving throw. The creature takes 5d8 poison damage on a failed save, or half as much damage on a successful one. Creatures are affected even if they hold their breath or don''t need to breathe.
The fog moves 10 feet away from you at the start of each of your turns, rolling along the surface of the ground. The vapors, being heavier than air, sink to the lowest level of the land, even pouring down openings.', 'When you cast this spell using a spell slot of 6th level or higher, the damage increases by 1d8 for each slot level above 5th.', NULL
FROM public.spells WHERE external_index = 'cloudkill'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Névoa Mortal', 'Você cria uma esfera com raio de 6 metros [20-foot-radius sphere], feita de uma névoa venenosa amarelo-esverdeada, centrada em um ponto à sua escolha e no alcance da magia. A névoa se alastra, contornando os cantos e a área afetada fica totalmente obscurecida. Ela persiste enquanto a magia durar ou até que um vento forte a disperse, encerrando a magia.
Quando uma criatura entra na área da magia pela primeira vez ou inicia o próprio turno ali, ela deve fazer uma salvaguarda de Constituição. Se falhar, sofre 5d8 de dano venenoso, ou metade do dano em caso de sucesso. As criaturas são afetadas mesmo se prenderem a respiração ou não precisarem respirar.
O nevoeiro se distancia 3 metros [10 ft.] de você no início de cada um de seus turnos, deslizando sobre o solo. Os vapores, por serem mais pesados que o ar, descem para o nível mais baixo da terra, esvaindo-se por eventuais aberturas.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 6º círculo ou superior, o dano aumenta em 1d8 para cada círculo do espaço acima do 5º.', '', NULL
FROM public.spells WHERE external_index = 'cloudkill'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Color Spray
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('color-spray', 1, 'illusion', 'action', 1, NULL, 'self', 1, 'round', false, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Color Spray', 'A dazzling array of flashing, colored light springs from your hand. Roll 6d10; the total is how many hit points of creatures this spell can effect. Creatures in a 15-foot cone originating from you are affected in ascending order of their current hit points (ignoring unconscious creatures and creatures that can''t see).
Starting with the creature that has the lowest current hit points, each creature affected by this spell is blinded until the spell ends. Subtract each creature''s hit points from the total before moving on to the creature with the next lowest hit points. A creature''s hit points must be equal to or less than the remaining total for that creature to be affected.', 'When you cast this spell using a spell slot of 2nd level or higher, roll an additional 2d10 for each slot level above 1st.', 'A pinch of powder or sand that is colored red, yellow, and blue.'
FROM public.spells WHERE external_index = 'color-spray'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Leque Cromático', 'Uma deslumbrante variedade de luzes ofuscantes e coloridas projeta-se da sua mão. Jogue 6d10; o resultado será a quantidade total de pontos de vida das criaturas que esta magia pode afetar. Criaturas em um cone de 4,5 metros [15-foot cone] com origem em você são afetadas em ordem crescente de seus pontos de vida atuais (ignorando criaturas inconscientes e criaturas que não possam enxergar).
Começando com a criatura com a menor quantidade de pontos de vida, cada criatura afetada por esta magia fica cega enquanto a magia durar. Subtraia os pontos de vida de cada criatura do total, antes de continuar para a próxima com os pontos de vida mais baixos. Os pontos de vida da criatura devem ser menores ou iguais ao total remanescente para que ela seja afetada.
Em Cïrculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, jogue 2d10 adicionais para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'color-spray'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Command
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('command', 1, 'enchantment', 'action', 1, 60, 'feet', 1, 'round', false, false, ARRAY['V'], ARRAY['cleric', 'paladin'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Command', 'You speak a one-word command to a creature you can see within range. The target must succeed on a wisdom saving throw or follow the command on its next turn. The spell has no effect if the target is undead, if it doesn''t understand your language, or if your command is directly harmful to it.
Some typical commands and their effects follow. You might issue a command other than one described here. If you do so, the GM determines how the target behaves. If the target can''t follow your command, the spell ends.
***Approach.*** The target moves toward you by the shortest and most direct route, ending its turn if it moves within 5 feet of you.
***Drop.*** The target drops whatever it is holding and then ends its turn.
***Flee.*** The target spends its turn moving away from you by the fastest available means.
***Grovel.*** The target falls prone and then ends its turn.
***Halt.*** The target doesn''t move and takes no actions. A flying creature stays aloft, provided that it is able to do so. If it must move to stay aloft, it flies the minimum distance needed to remain in the air.', 'When you cast this spell using a spell slot of 2nd level or higher, you can affect one additional creature for each slot level above 1st. The creatures must be within 30 feet of each other when you target them.', NULL
FROM public.spells WHERE external_index = 'command'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Comando', 'Você emite uma palavra de comando para uma criatura à sua vista e no alcance da magia. O alvo deve ser bemsucedido em uma salvaguarda de Sabedoria, ou passa a obedecer o comando no próximo turno dele. A magia não tem nenhum efeito se o alvo for um morto-vivo, se não entender seu idioma ou se o comando for diretamente prejudicial a ele.A seguir, veja alguns exemplos típicos de comandos e seus efeitos. Você pode emitir um comando diferente dos descritos aqui. Se fizer isso, o DM determina como o alvo se comporta. Se o alvo não puder seguir seu comando, a magia se encerra.Abaixar. O alvo fica caído e, em seguida, termina o próprio turno.Aproximar. O alvo se move em sua direção pela rota mais curta e direta, terminando o turno ao se aproximar a até 1,5 metro [5 ft.] de você.Fugir. O alvo gasta o próprio turno afastando-se de você pelo meio mais rápido disponível.Largar. O alvo deixa cair tudo o que está segurando e então termina o próprio turno.Parar. O alvo não se mexe e não executa nenhuma ação. Uma criatura voadora permanece no ar, desde que seja capaz de fazê-lo. Se precisar se mover para ficar no ar, ela voa a distância mínima necessária para fazê-lo.Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, você pode afetar uma criatura adicional para cada círculo do espaço acima do 1º. As criaturas devem estar a até 9 metros [30 ft.] umas das outras quando você as escolhe como alvo.', '', NULL
FROM public.spells WHERE external_index = 'command'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Commune
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('commune', 5, 'divination', 'minute', 1, NULL, 'self', 1, 'minute', false, true, ARRAY['V', 'S', 'M'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Commune', 'You contact your deity or a divine proxy and ask up to three questions that can be answered with a yes or no. You must ask your questions before the spell ends. You receive a correct answer for each question.
Divine beings aren''t necessarily omniscient, so you might receive "unclear" as an answer if a question pertains to information that lies beyond the deity''s knowledge. In a case where a one-word answer could be misleading or contrary to the deity''s interests, the GM might offer a short phrase as an answer instead.
If you cast the spell two or more times before finishing your next long rest, there is a cumulative 25 percent chance for each casting after the first that you get no answer. The GM makes this roll in secret.', '', 'Incense and a vial of holy or unholy water.'
FROM public.spells WHERE external_index = 'commune'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Comunhão', 'Você entra em contato com sua divindade ou com um representante dela, e faz até três perguntas que podem ser respondidas com sim ou não. É preciso fazer as perguntas antes da magia terminar. Você recebe uma resposta correta para cada pergunta.
Seres divinos não são, necessariamente, oniscientes, então você pode receber "indeterminado" como resposta, caso a pergunta se refira a uma informação que está além do conhecimento da divindade. No caso em que uma única palavra como resposta puder levar a uma interpretação errada ou contrária aos interesses da divindade, o DM pode responder com uma frase curta.
Se você conjurar a magia duas ou mais vezes antes de concluir seu próximo descanso longo, há uma chance cumulativa de 25% para cada conjuração após a primeira de você não obter uma resposta. O DM faz essa jogada em segredo.', '', NULL
FROM public.spells WHERE external_index = 'commune'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Commune With Nature
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('commune-with-nature', 5, 'divination', 'minute', 1, NULL, 'self', NULL, 'instantaneous', false, true, ARRAY['V', 'S'], ARRAY['druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Commune With Nature', 'You briefly become one with nature and gain knowledge of the surrounding territory. In the outdoors, the spell gives you knowledge of the land within 3 miles of you. In caves and other natural underground settings, the radius is limited to 300 feet. The spell doesn''t function where nature has been replaced by construction, such as in dungeons and towns.
You instantly gain knowledge of up to three facts of your choice about any of the following subjects as they relate to the area:
- terrain and bodies of water
- prevalent plants, minerals, animals, or peoples
- powerful celestials, fey, fiends, elementals, or undead
- influence from other planes of existence
- buildings
For example, you could determine the location of powerful undead in the area, the location of major sources of safe drinking water, and the location of any nearby towns.', '', NULL
FROM public.spells WHERE external_index = 'commune-with-nature'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Comprehend Languages
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('comprehend-languages', 1, 'divination', 'action', 1, NULL, 'self', 1, 'hour', false, true, ARRAY['V', 'S', 'M'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Comprehend Languages', 'For the duration, you understand the literal meaning of any spoken language that you hear. You also understand any written language that you see, but you must be touching the surface on which the words are written. It takes about 1 minute to read one page of text.
This spell doesn''t decode secret messages in a text or a glyph, such as an arcane sigil, that isn''t part of a written language.', '', 'A pinch of soot and salt.'
FROM public.spells WHERE external_index = 'comprehend-languages'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Compreender Idiomas', 'Enquanto a magia durar, você entende o significado literal de qualquer idioma falado que ouvir. Você tambem entende qualquer idioma escrito que veja, mas deve tocar a superfície sobre a qual as palavras estão escritas. Demora cerca de 1 minuto para ler uma página de texto.Esta magia não decodifica mensagens secretas em um texto ou um glifo, como um selo arcano, que não faça parte de um idioma escrito.', '', NULL
FROM public.spells WHERE external_index = 'comprehend-languages'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Compulsion
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('compulsion', 4, 'enchantment', 'action', 1, 30, 'feet', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['bard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Compulsion', 'Creatures of your choice that you can see within range and that can hear you must make a wisdom saving throw. A target automatically succeeds on this saving throw if it can''t be charmed. On a failed save, a target is affected by this spell. Until the spell ends, you can use a bonus action on each of your turns to designate a direction that is horizontal to you. Each affected target must use as much of its movement as possible to move in that direction on its next turn. It can take any action before it moves. After moving in this way, it can make another Wisdom save to try to end the effect.
A target isn''t compelled to move into an obviously deadly hazard, such as a fire or a pit, but it will provoke opportunity attacks to move in the designated direction.', '', NULL
FROM public.spells WHERE external_index = 'compulsion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Compulsão', 'Criaturas à sua escolha, à sua vista, que estejam dentro do alcance da magia e possam ouvi-lo devem fazer uma salvaguarda de Sabedoria. Um alvo é automaticamente bem-sucedido nessa salvaguarda se não puder ser enfeitiçado. Se falhar, o alvo é afetado por esta magia. Enquanto a magia durar, você pode usar sua ação bônus em cada um dos seus turnos para designar uma direção paralela ao solo. Cada alvo afetado deve usar tanto do próprio deslocamento quanto possível para mover-se naquela direção no próximo turno dele. Ele pode realizar a própria ação antes de mover-se. Depois de se deslocar dessa maneira, o alvo pode fazer outra salvaguarda de Sabedoria para tentar encerrar o efeito.
Um alvo não é compelido a mover-se em direção a um perigo obviamente mortal, como um incêndio ou fosso, mas provoca ataques de oportunidade enquanto se move na direção designada.', '', NULL
FROM public.spells WHERE external_index = 'compulsion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Cone of Cold
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('cone-of-cold', 5, 'evocation', 'action', 1, NULL, 'self', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Cone of Cold', 'A blast of cold air erupts from your hands. Each creature in a 60-foot cone must make a constitution saving throw. A creature takes 8d8 cold damage on a failed save, or half as much damage on a successful one.
A creature killed by this spell becomes a frozen statue until it thaws.', 'When you cast this spell using a spell slot of 6th level or higher, the damage increases by 1d8 for each slot level above 5th.', 'A small crystal or glass cone.'
FROM public.spells WHERE external_index = 'cone-of-cold'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Cone de Frio', 'Uma explosão de ar frio irrompe das suas mãos. Cada criatura dentro de um cone de 18 metros [60 ft.] deve fazer uma salvaguarda de Constituição. Se falhar, sofre 8d8 pontos de dano gélido, ou metade do dano em caso de sucesso.Uma criatura morta por esta magia torna-se uma estátua congelada até derreter.Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 6º círculo ou superior, o dano aumenta em 1d8 para cada círculo do espaço acima do 5º.', '', NULL
FROM public.spells WHERE external_index = 'cone-of-cold'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Confusion
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('confusion', 4, 'enchantment', 'action', 1, 90, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'druid', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Confusion', 'This spell assaults and twists creatures'' minds, spawning delusions and provoking uncontrolled action. Each creature in a 10-foot-radius sphere centered on a point you choose within range must succeed on a Wisdom saving throw when you cast this spell or be affected by it.
An affected target can''t take reactions and must roll a d10 at the start of each of its turns to determine its behavior for that turn.
| d10 | Behavior |
|---|---|
| 1 | The creature uses all its movement to move in a random direction. To determine the direction, roll a d8 and assign a direction to each die face. The creature doesn''t take an action this turn. |
| 2-6 | The creature doesn''t move or take actions this turn. |
| 7-8 | The creature uses its action to make a melee attack against a randomly determined creature within its reach. If there is no creature within its reach, the creature does nothing this turn. |
| 9-10 | The creature can act and move normally. |
At the end of each of its turns, an affected target can make a Wisdom saving throw. If it succeeds, this effect ends for that target.', 'When you cast this spell using a spell slot of 5th level or higher, the radius of the sphere increases by 5 feet for each slot level above 4th.', 'Three walnut shells.'
FROM public.spells WHERE external_index = 'confusion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Confusão', 'Esta magia assalta e distorce a mente das criaturas, implantando delírios e provocando ações descontroladas. Cada criatura em uma esfera de 3 metros de raio [10-foot-radius sphere], centrada em um ponto à sua escolha e dentro do alcance da magia, deve ser bem-sucedida em uma salvaguarda de Sabedoria, ou é afetada por esta magia.
Um alvo afetado não pode executar reações e precisa rolar na tabela de @Compendium[dnd5e.tables.LHEts1oDaDwcehuj]{Confusão} no início de cada um de seus próprios turnos.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 5º círculo ou superior, o raio da esfera aumenta em 1,5 metro [5 ft.] para cada círculo do espaço acima do 4º.', '', NULL
FROM public.spells WHERE external_index = 'confusion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Conjure Animals
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('conjure-animals', 3, 'conjuration', 'action', 1, 60, 'feet', 1, 'hour', true, false, ARRAY['V', 'S'], ARRAY['druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Conjure Animals', 'You summon fey spirits that take the form of beasts and appear in unoccupied spaces that you can see within range. Choose one of the following options for what appears:
- One beast of challenge rating 2 or lower
- Two beasts of challenge rating 1 or lower
- Four beasts of challenge rating 1/2 or lower
- Eight beasts of challenge rating 1/4 or lower
- Each beast is also considered fey, and it disappears when it drops to 0 hit points or when the spell ends.
The summoned creatures are friendly to you and your companions. Roll initiative for the summoned creatures as a group, which has its own turns. They obey any verbal commands that you issue to them (no action required by you). If you don''t issue any commands to them, they defend themselves from hostile creatures, but otherwise take no actions.
The GM has the creatures'' statistics.', 'When you cast this spell using certain higher-level spell slots, you choose one of the summoning options above, and more creatures appear: twice as many with a 5th-level slot, three times as many with a 7th-level.', NULL
FROM public.spells WHERE external_index = 'conjure-animals'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Conjurar Animais', 'Você invoca espíritos feéricos que assumem a forma de feras e surgem em espaços desocupados à sua vista, no alcance da magia. Escolha o que aparece entre as opções a seguir:
Uma fera com nível de desafio 2 ou menor
Duas feras com nível de desafio 1 ou menor
Quatro feras com nível de desafio 1/2 ou menor
Oito feras com nível de desafio 1/4 ou menor
Cada fera também é considerada feérica, desaparecendo ao ficar com 0 pontos de vida ou ao término da magia.
As criaturas invocadas são amistosas com você e seus companheiros. Jogue a iniciativa para as criaturas invocadas como um grupo, que tem seu próprio turno. As criaturas invocadas obedecem a qualquer comando verbal que você lhes direcione (não requer ação sua). Caso não seja dado comando algum, elas se defendem de seres hostis, não executando nenhuma outra ação.Em Círculos Superiores. Ao conjurar esta magia utilizando espaços de magia de círculos superiores, escolha uma das opções de invocação apresentadas anteriormente, e mais criaturas aparecem: o dobro com um espaço de 5º círculo, o triplo com um espaço de 7º círculo e o quádruplo com um espaço de 9º círculo.', '', NULL
FROM public.spells WHERE external_index = 'conjure-animals'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Conjure Celestial
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('conjure-celestial', 7, 'conjuration', 'minute', 1, 90, 'feet', 1, 'hour', true, false, ARRAY['V', 'S'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Conjure Celestial', 'You summon a celestial of challenge rating 4 or lower, which appears in an unoccupied space that you can see within range. The celestial disappears when it drops to 0 hit points or when the spell ends.
The celestial is friendly to you and your companions for the duration. Roll initiative for the celestial, which has its own turns. It obeys any verbal commands that you issue to it (no action required by you), as long as they don''t violate its alignment. If you don''t issue any commands to the celestial, it defends itself from hostile creatures but otherwise takes no actions.
The GM has the celestial''s statistics.', 'When you cast this spell using a 9th-level spell slot, you summon a celestial of challenge rating 5 or lower.', NULL
FROM public.spells WHERE external_index = 'conjure-celestial'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Invocar Celestial', 'Você invoca um celestial com nível de desafio 4 ou menor, que surge em um espaço desocupado à sua vista e no alcance da magia. O celestial desaparece ao atingir 0 pontos de vida ou ao término da magia.O celestial é amistoso com você e seus companheiros enquanto durar a magia. Jogue a iniciativa para o celestial, que tem seus próprios turnos. O celestial obedece a qualquer comando verbal que você lhe direcione (não requer ação sua), desde que isso não viole o alinhamento dele. Caso não seja dado comando algum, ele se defende de seres hostis, não executando nenhuma outra ação.Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 9º círculo, você convoca um celestial de nível de desafio 5 ou menor.', '', NULL
FROM public.spells WHERE external_index = 'conjure-celestial'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Conjure Elemental
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('conjure-elemental', 5, 'conjuration', 'minute', 1, 90, 'feet', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Conjure Elemental', 'You call forth an elemental servant. Choose an area of air, earth, fire, or water that fills a 10-foot cube within range. An elemental of challenge rating 5 or lower appropriate to the area you chose appears in an unoccupied space within 10 feet of it. For example, a fire elemental emerges from a bonfire, and an earth elemental rises up from the ground. The elemental disappears when it drops to 0 hit points or when the spell ends.
The elemental is friendly to you and your companions for the duration. Roll initiative for the elemental, which has its own turns. It obeys any verbal commands that you issue to it (no action required by you). If you don''t issue any commands to the elemental, it defends itself from hostile creatures but otherwise takes no actions.
If your concentration is broken, the elemental doesn''t disappear. Instead, you lose control of the elemental, it becomes hostile toward you and your companions, and it might attack. An uncontrolled elemental can''t be dismissed by you, and it disappears 1 hour after you summoned it.
The GM has the elemental''s statistics.', 'When you cast this spell using a spell slot of 6th level or higher, the challenge rating increases by 1 for each slot level above 5th.', 'Burning incense for air, soft clay for earth, sulfur and phosphorus for fire, or water and sand for water.'
FROM public.spells WHERE external_index = 'conjure-elemental'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Invocar Elemental', 'Você invoca um servo elemental. Escolha uma área de ar, terra, fogo ou água, no alcance da magia, que preencha um cubo de 3 metros [10 ft.]. Um elemental de nível de desafio 5 ou menor, apropriado à área escolhida, aparece em um espaço desocupado a até 3 metros [10 ft.] da área escolhida. Por exemplo, um elemental do fogo emerge de uma fogueira, um elemental da terra se ergue do solo. O elemental desaparece ao ficar com 0 pontos de vida ou ao término da magia.Ele é amistoso com você e seus companheiros enquanto a magia durar. Jogue a iniciativa para o elemental, que tem seus próprios turnos. Ele obedece a qualquer comando verbal que você lhe dê (não requer ação sua), desde que isso não viole o alinhamento dele. Caso não seja dado comando algum, ele se defende de seres hostis, não executando nenhuma outra ação.Caso a sua concentração seja quebrada, o elemental não desaparece. Em vez disso, você perde o controle sobre o elemental, que se torna hostil para com você e seus companheiros. Um elemental descontrolado não pode ser dispensado, porém desaparece uma hora depois de ter sido invocado.Em Círculos Superiores. Ao conjurar esta magia utilizando um espaço de magia de 6º círculo ou superior, o nível de desafio aumenta em 1 para cada círculo do espaço acima do 5º.', '', NULL
FROM public.spells WHERE external_index = 'conjure-elemental'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Conjure Fey
