VALUES ('conjure-fey', 6, 'conjuration', 'minute', 1, 90, 'feet', 1, 'hour', true, false, ARRAY['V', 'S'], ARRAY['druid', 'warlock'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Conjure Fey', 'You summon a fey creature of challenge rating 6 or lower, or a fey spirit that takes the form of a beast of challenge rating 6 or lower. It appears in an unoccupied space that you can see within range. The fey creature disappears when it drops to 0 hit points or when the spell ends.
The fey creature is friendly to you and your companions for the duration. Roll initiative for the creature, which has its own turns. It obeys any verbal commands that you issue to it (no action required by you), as long as they don''t violate its alignment. If you don''t issue any commands to the fey creature, it defends itself from hostile creatures but otherwise takes no actions.
If your concentration is broken, the fey creature doesn''t disappear. Instead, you lose control of the fey creature, it becomes hostile toward you and your companions, and it might attack. An uncontrolled fey creature can''t be dismissed by you, and it disappears 1 hour after you summoned it.
The GM has the fey creature''s statistics.', 'When you cast this spell using a spell slot of 7th level or higher, the challenge rating increases by 1 for each slot level above 6th.', NULL
FROM public.spells WHERE external_index = 'conjure-fey'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Invocar Feérico', 'Você invoca um feérico com nível de desafio 6 ou menor, ou um espírito feérico que assume a forma de uma fera de nível de desafio 6 ou menor. Ele surge em um espaço desocupado à sua vista, no alcance da magia, desaparecendo ao atingir 0 pontos de vida ou ao término da magia.O feérico é amistoso com você e seus companheiros enquanto a magia durar. Jogue a iniciativa para a criatura, que tem seus próprios turnos. Ela obedece a qualquer comando verbal que você lhe dê (não requer ação sua), desde que isso não viole o alinhamento dela. Caso não seja dado comando algum à criatura feérica, ela apenas se defende de seres hostis, não executando outras ações.Caso a sua concentração seja quebrada, o feérico não desaparece. Em vez disso, você perde o controle sobre a criatura feérica, que se torna hostil para com você e seus companheiros. Um feérico descontrolado não pode ser dispensado, porém desaparece 1 hora após você o ter invocado.Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 7º círculo ou superior, o nível de desafio aumenta em 1 para cada círculo do espaço acima do 6º.', '', NULL
FROM public.spells WHERE external_index = 'conjure-fey'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Conjure Minor Elementals
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('conjure-minor-elementals', 4, 'conjuration', 'minute', 1, 90, 'feet', 1, 'hour', true, false, ARRAY['V', 'S'], ARRAY['druid', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Conjure Minor Elementals', 'You summon elementals that appear in unoccupied spaces that you can see within range. You choose one the following options for what appears:
- One elemental of challenge rating 2 or lower
- Two elementals of challenge rating 1 or lower
- Four elementals of challenge rating 1/2 or lower
- Eight elementals of challenge rating 1/4 or lower.
An elemental summoned by this spell disappears when it drops to 0 hit points or when the spell ends.
The summoned creatures are friendly to you and your companions. Roll initiative for the summoned creatures as a group, which has its own turns. They obey any verbal commands that you issue to them (no action required by you). If you don''t issue any commands to them, they defend themselves from hostile creatures, but otherwise take no actions.
The GM has the creatures'' statistics.', 'When you cast this spell using certain higher-level spell slots, you choose one of the summoning options above, and more creatures appear: twice as many with a 6th-level slot and three times as many with an 8th-level slot.', NULL
FROM public.spells WHERE external_index = 'conjure-minor-elementals'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Invocar Elementais Menores', 'Você invoca elementais, que surgem em espaços desocupados à sua vista no alcance da magia. Escolha o que surge entre as opções a seguir:
Um elemental com nível de desafio 2 ou menor
Dois elementais com nível de desafio 1 ou menor
Quatro elementais com nível de desafio 1/2 ou menor
Oito elementais com nível de desafio 1/4 ou menor.
Um elemental desaparece ao ficar com 0 pontos de vida ou ao término da magia.As criaturas invocadas são amistosas com você e seus companheiros. Jogue a iniciativa para as criaturas invocadas como um grupo, que tem seus próprios turnos. Os elementais invocadas obedecem a qualquer comando verbal que você lhes direcionar (não requer ação sua). Caso não seja dado comando algum, elas se defendem de seres hostis, não executando nenhuma outra ação.Em Círculos Superiores. Ao conjurar esta magia utilizando espaços de magia de círculos superiores, escolha uma das opções de invocação apresentadas anteriormente, e mais criaturas aparecem: o dobro com um espaço de 6º círculo e o triplo com um espaço de 8º círculo.', '', NULL
FROM public.spells WHERE external_index = 'conjure-minor-elementals'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
