INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Invocar Seres da Floresta', 'Você invoca feéricos, que surgem em espaços desocupados à sua vista, no alcance da magia. Escolha o que aparece entre as opções a seguir:
Uma criatura feérica com nível de desafio 2 ou menor
Duas criaturas feéricas com nível de desafio 1 ou menor
Quatro criaturas feéricas com nível de desafio 1/2 ou menor
Oito criaturas feéricas com nível de desafio 1/4 ou menor.
Cada criatura invocada desaparece quando cai a 0 ponto de vida ou quando a magia termina.
As criaturas invocadas são amistosas com você e seus companheiros. Jogue a iniciativa para as criaturas invocadas como um grupo, que tem seus próprios turnos. Elas obedecem a qualquer comando verbal que você lhes dê (não requer ação sua). Se você não lhes der comando algum, elas apenas se defendem de criaturas hostis, não executando outras ações.Em Círculos Superiores. Ao conjurar esta magia utilizando espaços de magia de círculos superiores, escolha uma das opções de invocação apresentadas anteriormente, e mais criaturas aparecem: o dobro com um espaço de 6º círculo e o triplo com um espaço de 8º círculo.', '', NULL
FROM public.spells WHERE external_index = 'conjure-woodland-beings'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Contact Other Plane
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('contact-other-plane', 5, 'divination', 'minute', 1, NULL, 'self', 1, 'minute', false, true, ARRAY['V'], ARRAY['warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Contact Other Plane', 'You mentally contact a demigod, the spirit of a long-dead sage, or some other mysterious entity from another plane. Contacting this extraplanar intelligence can strain or even break your mind. When you cast this spell, make a DC 15 intelligence saving throw. On a failure, you take 6d6 psychic damage and are insane until you finish a long rest. While insane, you can''t take actions, can''t understand what other creatures say, can''t read, and speak only in gibberish. A greater restoration spell cast on you ends this effect.
On a successful save, you can ask the entity up to five questions. You must ask your questions before the spell ends. The GM answers each question with one word, such as "yes," "no," "maybe," "never," "irrelevant," or "unclear" (if the entity doesn''t know the answer to the question). If a one-word answer would be misleading, the GM might instead offer a short phrase as an answer.', '', NULL
FROM public.spells WHERE external_index = 'contact-other-plane'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Contato Extraplanar', 'Você estabelece contato mental com um semideus, o espírito de um sábio morto há muito tempo ou alguma outra entidade misteriosa de outro plano. Entrar em contato com essa inteligência extraplanar pode sobrecarregar, ou até mesmo danificar, a sua mente. Ao conjurar esta magia, faça uma salvaguarda de Inteligência com CD 15. Se falhar, sofre 6d6 pontos de dano psíquico e fica insano até terminar um descanso longo. Enquanto estiver insano, você não pode executar ações, não consegue entender o que outras criaturas dizem, não pode ler, e fala apenas inarticuladamente. Uma conjuração da magia restauração maior em você encerra este efeito.
Em caso de sucesso, você pode fazer até 5 perguntas à entidade. Você deve fazer suas perguntas antes da magia terminar. O DM responde cada pergunta com uma palavra, como "sim", "não", "talvez", "nunca", "irrelevante" ou "indeterminado" (quando a entidade não souber a resposta para a pergunta). Se a resposta de uma palavra for dúbia, o DM pode oferecer uma frase curta como resposta.', '', NULL
FROM public.spells WHERE external_index = 'contact-other-plane'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Contagion
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('contagion', 5, 'necromancy', 'action', 1, NULL, 'touch', 7, 'day', false, false, ARRAY['V', 'S'], ARRAY['cleric', 'druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Contagion', 'Your touch inflicts disease. Make a melee spell attack against a creature within your reach. On a hit, you afflict the creature with a disease of your choice from any of the ones described below.
At the end of each of the target''s turns, it must make a constitution saving throw. After failing three of these saving throws, the disease''s effects last for the duration, and the creature stops making these saves. After succeeding on three of these saving throws, the creature recovers from the disease, and the spell ends.
Since this spell induces a natural disease in its target, any effect that removes a disease or otherwise ameliorates a disease''s effects apply to it.
***Blinding Sickness.*** Pain grips the creature''s mind, and its eyes turn milky white. The creature has disadvantage on wisdom checks and wisdom saving throws and is blinded.
***Filth Fever.*** A raging fever sweeps through the creature''s body. The creature has disadvantage on strength checks, strength saving throws, and attack rolls that use Strength.
***Flesh Rot.*** The creature''s flesh decays. The creature has disadvantage on Charisma checks and vulnerability to all damage.
***Mindfire.*** The creature''s mind becomes feverish. The creature has disadvantage on intelligence checks and intelligence saving throws, and the creature behaves as if under the effects of the confusion spell during combat.
***Seizure.*** The creature is overcome with shaking. The creature has disadvantage on dexterity checks, dexterity saving throws, and attack rolls that use Dexterity.
***Slimy Doom.*** The creature begins to bleed uncontrollably. The creature has disadvantage on constitution checks and constitution saving throws. In addition, whenever the creature takes damage, it is stunned until the end of its next turn.', '', NULL
FROM public.spells WHERE external_index = 'contagion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Contágio', 'Seu toque inflige doenças. Faça um ataque mágico corpo a corpo contra uma criatura ao seu alcance. Em caso de acerto, você inflige à criatura uma das doenças descritas abaixo, à sua escolha.No final de cada um dos turnos do alvo, ele deve fazer uma salvaguarda de Constituição. Após falhar em três salvaguardas, a doença continua a surtir efeito enquanto a magia durar, e a criatura deve parar de realizar essas salvaguardas. Após ser bem-sucedida em três dessas salvaguardas, a criatura se recupera da doença e a magia se encerra.Dado esta magia infligir uma doença natural no alvo, qualquer efeito que cure a doença ou alivie seus efeitos, aplica-se igualmente à doença infligida por esta magia.Ardência Mental. A mente da criatura torna-se febril. A criatura tem desvantagem em testes de Inteligência e salvaguardas de Inteligência, além de, em combates, se comportar como se estivesse sob os efeitos da magia Confusão.Doença da Cegueira. A dor aflige a mente da criatura e seus olhos tornam-se brancos e leitosos. A criatura tem desvantagem nos testes e salvaguardas de Sabedoria e está cega.Febre Perniciosa. Uma febre violenta percorre o corpo da criatura. A criatura tem desvantagem nos testes e salvaguardas de Força, bem como nas jogadas de ataque que utilizem Força.Necrose da Carne. A carne da criatura começa a se decompor. A criatura tem desvantagem nos testes de Carisma e vulnerabilidade a todo tipo de dano.Ruína Pegajosa. A criatura começa a sangrar incontrolavelmente. Ela tem desvantagem nos testes e salvaguardas de Constituição. Além disso, sempre que sofrer dano, fica atordoada até o final do próximo turno dela.Tremedeira. A criatura é acometida por espasmos. Ela tem desvantagem nos testes e salvaguardas de Destreza, bem como nas jogadas de ataque que utilizem Destreza.', '', NULL
FROM public.spells WHERE external_index = 'contagion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Contingency
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('contingency', 6, 'evocation', 'minute', 10, NULL, 'self', 10, 'day', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Contingency', 'Choose a spell of 5th level or lower that you can cast, that has a casting time of 1 action, and that can target you. You cast that spell--called the contingent spell--as part of casting contingency, expending spell slots for both, but the contingent spell doesn''t come into effect. Instead, it takes effect when a certain circumstance occurs. You describe that circumstance when you cast the two spells. For example, a contingency cast with water breathing might stipulate that water breathing comes into effect when you are engulfed in water or a similar liquid.
The contingent spell takes effect immediately after the circumstance is met for the first time, whether or not you want it to. and then contingency ends.
The contingent spell takes effect only on you, even if it can normally target others. You can use only one contingency spell at a time. If you cast this spell again, the effect of another contingency spell on you ends. Also, contingency ends on you if its material component is ever not on your person.', '', 'A statuette of yourself carved from ivory and decorated with gems worth at least 1,500 gp.'
FROM public.spells WHERE external_index = 'contingency'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Contingência', 'Escolha uma magia de 5º círculo ou inferior que você possa conjurar, que tenha tempo de conjuração de 1 ação e que possa tê-lo como alvo. Você conjura essa magia - chamada magia contingente - como parte da conjuração de Contingência, usando espaços de magia para ambas. No entanto, a magia contingente não se efetiva. Em vez disso, ela entra em ação quando ocorrer determinada circunstância. Você descreve essa circunstância ao conjurar as duas magias. Por exemplo, uma Contingência conjurada com a magia Respirar na Água pode estipular que esta última entra em vigor quando você está envolto em água ou líquido semelhante.
A magia contingente entra em vigor imediatamente após a circunstância ocorrer pela primeira vez, independentemente da sua escolha ou vontade, e então Contingência termina.
A magia contingente afeta somente você, mesmo que ela normalmente possa ter outros alvos. Você só pode usar uma magia Contingência de cada vez. Caso conjure esta magia novamente, o efeito da Contingência anterior se encerra, o mesmo ocorrendo se o componente material para contingência já não estiver em sua posse.', '', NULL
FROM public.spells WHERE external_index = 'contingency'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Continual Flame
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('continual-flame', 2, 'evocation', 'action', 1, NULL, 'touch', NULL, 'special', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Continual Flame', 'A flame, equivalent in brightness to a torch, springs forth from an object that you touch. The effect looks like a regular flame, but it creates no heat and doesn''t use oxygen. A continual flame can be covered or hidden but not smothered or quenched.', '', 'Ruby dust worth 50 gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'continual-flame'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Chama Contínua', 'Uma chama, brilhante como uma tocha, surge de um objeto que você toca. O efeito assemelha-se ao de uma chama comum, exceto pelo fato de não emitir calor nem consumir oxigênio. Uma chama contínua pode ser coberta ou escondida, mas não apagada ou abafada.', '', NULL
FROM public.spells WHERE external_index = 'continual-flame'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Control Water
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('control-water', 4, 'transmutation', 'action', 1, 300, 'feet', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'druid', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Control Water', 'Until the spell ends, you control any freestanding water inside an area you choose that is a cube up to 100 feet on a side. You can choose from any of the following effects when you cast this spell. As an action on your turn, you can repeat the same effect or choose a different one.
***Flood.*** You cause the water level of all standing water in the area to rise by as much as 20 feet. If the area includes a shore, the flooding water spills over onto dry land.
If you choose an area in a large body of water, you instead create a 20-foot tall wave that travels from one side of the area to the other and then crashes down. Any Huge or smaller vehicles in the wave''s path are carried with it to the other side. Any Huge or smaller vehicles struck by the wave have a 25 percent chance of capsizing.
The water level remains elevated until the spell ends or you choose a different effect. If this effect produced a wave, the wave repeats on the start of your next turn while the flood effect lasts.
***Part Water.*** You cause water in the area to move apart and create a trench. The trench extends across the spell''s area, and the separated water forms a wall to either side. The trench remains until the spell ends or you choose a different effect. The water then slowly fills in the trench over the course of the next round until the normal water level is restored.
***Redirect Flow.*** You cause flowing water in the area to move in a direction you choose, even if the water has to flow over obstacles, up walls, or in other unlikely directions. The water in the area moves as you direct it, but once it moves beyond the spell''s area, it resumes its flow based on the terrain conditions. The water continues to move in the direction you chose until the spell ends or you choose a different effect.
***Whirlpool.*** This effect requires a body of water at least 50 feet square and 25 feet deep. You cause a whirlpool to form in the center of the area. The whirlpool forms a vortex that is 5 feet wide at the base, up to 50 feet wide at the top, and 25 feet tall. Any creature or object in the water and within 25 feet of the vortex is pulled 10 feet toward it. A creature can swim away from the vortex by making a Strength (Athletics) check against your spell save DC.
When a creature enters the vortex for the first time on a turn or starts its turn there, it must make a strength saving throw. On a failed save, the creature takes 2d8 bludgeoning damage and is caught in the vortex until the spell ends. On a successful save, the creature takes half damage, and isn''t caught in the vortex. A creature caught in the vortex can use its action to try to swim away from the vortex as described above, but has disadvantage on the Strength (Athletics) check to do so.
The first time each turn that an object enters the vortex, the object takes 2d8 bludgeoning damage; this damage occurs each round it remains in the vortex.', '', 'A drop of water and a pinch of dust.'
FROM public.spells WHERE external_index = 'control-water'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Controlar Água', 'Você controla qualquer corpo de água parada dentro de uma área à sua escolha, em um cubo de 30 metros [100 ft.] de lado e enquanto esta magia durar. Você pode escolher entre qualquer um dos efeitos a seguir. Ao conjurar esta magia com uma ação em seu turno, você pode repetir o mesmo efeito ou pode escolher outro.
Inundação. Você provoca o aumento do nível de toda a água parada na área, que sobe até 6 metros [20 ft.]. Se a área inclui uma margem, a água transborda sobre a terra seca. Caso você tenha escolhido uma área em um grande corpo de água, em vez de uma inundação, você cria uma onda de 6 metros [20 ft.] de altura que viaja de um lado da área para o outro, até quebrar. Quaisquer veículos de tamanho Grande ou menor no caminho da onda são carregados com ela para o outro lado. Quaisquer veículos de tamanho Grande ou menor atingidos pela onda têm 25% de chance de emborcar.
O nível da água permanece elevado enquanto a magia durar ou caso você escolha um efeito diferente. Se este efeito produziu uma onda, ela se repete no início do seu próximo turno, enquanto durar o efeito da inundação.
Dividir a Água. Você faz com que a água na área se afaste e crie uma trincheira que se estende por toda a área da magia, com a água afastada formando uma parede em cada lado. A trincheira permanece enquanto a magia durar ou até que você escolha um efeito diferente. A água, então, lentamente preenche a trincheira ao longo da próxima rodada, até que o nível normal da água seja restaurado.
Redirecionar Fluxo. Você faz o fluxo de água na área mover-se na direção que você escolher, mesmo que a água tenha que fluir entre obstáculos, subir paredes ou seguir em outras direções improváveis. A água na área move-se de acordo com o seu direcionamento, mas tendo ultrapassado a área da magia, ela retoma o fluxo natural, de acordo com as condições do terreno. A água continua a mover-se na direção que você escolheu enquanto a magia durar ou até que você escolha um efeito diferente.
Redemoinho. Este efeito requer um corpo d''água de pelo menos 15 metros [50 ft.] quadrados e 7,5 metros [25 ft.] de profundidade. Você provoca a formação de um redemoinho no centro da área. O redemoinho forma um vórtice que tem 1,5 metro [5 ft.] de base, até 15 metros [50 ft.] de largura no topo e 7,5 metros [25 ft.] de altura. Qualquer criatura ou objeto na água e a cerca de 7,5 metros [25 ft.] do vórtice é puxado 3 metros [10 ft.] em direção a ele. Uma criatura pode nadar para longe do vórtice sendo bem-sucedida em um teste de Força (Atletismo) contra a CD para evitar sua magia.
Quando uma criatura entra no vórtice pela primeira vez durante um turno ou inicia o turno ali, ela deve fazer uma salvaguarda de Força. Se falhar, sofre 2d8 pontos de dano contundente, sendo aprisionada no vórtice enquanto a magia durar. Em caso de sucesso, sofre metade do dano e não é aprisionada no vórtice. Uma criatura capturada no vórtice pode usar uma ação para tentar nadar para longe dele, como descrito anteriormente, mas tem desvantagem no teste de Força (Atletismo) para fazê-lo.
Quando um objeto entra no vórtice pela primeira vez durante um turno, ele sofre 2d8 pontos de dano contundente; esse dano ocorre a cada rodada em que o objeto permanecer no vórtice.', '', NULL
FROM public.spells WHERE external_index = 'control-water'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Control Weather
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('control-weather', 8, 'transmutation', 'minute', 10, NULL, 'self', 8, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'druid', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Control Weather', 'You take control of the weather within 5 miles of you for the duration. You must be outdoors to cast this spell. Moving to a place where you don''t have a clear path to the sky ends the spell early.
When you cast the spell, you change the current weather conditions, which are determined by the GM based on the climate and season. You can change precipitation, temperature, and wind. It takes 1d4 x 10 minutes for the new conditions to take effect. Once they do so, you can change the conditions again. When the spell ends, the weather gradually returns to normal.
When you change the weather conditions, find a current condition on the following tables and change its stage by one, up or down. When changing the wind, you can change its direction.
##### Precipitation
| Stage | Condition |
|---|---|
| 1 | Clear |
| 2 | Light clouds |
| 3 | Overcast or ground fog |
| 4 | Rain, hail, or snow |
| 5 | Torrential rain, driving hail, or blizzard |
##### Temperature
| Stage | Condition |
|---|---|
| 1 | Unbearable heat |
| 2 | Hot |
| 3 | Warm |
| 4 | Cool |
| 5 | Cold |
| 6 | Arctic cold |
##### Wind
| Stage | Condition |
|---|---|
| 1 | Calm |
| 2 | Moderate wind |
| 3 | Strong wind |
| 4 | Gale |
| 5 | Storm |', '', 'Burning incense and bits of earth and wood mixed in water.'
FROM public.spells WHERE external_index = 'control-weather'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Controlar o Clima', 'Enquanto esta magia durar, você assume o controle do clima no alcance de 8 quilômetros [5 miles]. É preciso estar ao ar livre para conjurar esta magia. Caso você se mova para um lugar onde não tenha um caminho desimpedido até o céu, a magia se encerra antecipadamente.
Ao realizar esta conjuração, você muda as condições climáticas atuais, que são determinadas pelo DM com base no clima e na estação do ano. Você pode mudar a precipitação, a temperatura e o vento. Demora 1d4 x 10 minutos para as novas condições fazerem efeito. Depois que elas se estabelecerem, você pode mudá-las novamente. Quando a magia terminar, o clima gradualmente retorna ao normal.
Ao mudar as condições do clima, encontre a atual condição nas tabelas a seguir e mude o estágio dela em um, para cima ou para baixo. Ao mudar o vento, você pode mudar sua direção.
PRECIPITAÇÃO              Estágio         Condição                   1         Claro                   2         Nuvens leves                   3         Nublado ou com neblina                   4         Chuva, granizo leve ou neve                   5         Chuva torrencial, tempestade de granizo ou nevasca      TEMPERATURA              Estágio         Condição                   1         Calor insuportável                   2         Quente                   3         Ameno                   4         Fresco                   5         Frio                   6         Frio ártico      VENTO              Estágio         Condição                   1         Calmo                   2         Moderado                   3         Vento Forte                   4         Ventania                   5         Tempestade', '', NULL
FROM public.spells WHERE external_index = 'control-weather'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Counterspell
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('counterspell', 3, 'abjuration', 'reaction', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['S'], ARRAY['sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Counterspell', 'You attempt to interrupt a creature in the process of casting a spell. If the creature is casting a spell of 3rd level or lower, its spell fails and has no effect. If it is casting a spell of 4th level or higher, make an ability check using your spellcasting ability. The DC equals 10 + the spell''s level. On a success, the creature''s spell fails and has no effect.', 'When you cast this spell using a spell slot of 4th level or higher, the interrupted spell has no effect if its level is less than or equal to the level of the spell slot you used.', NULL
FROM public.spells WHERE external_index = 'counterspell'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Contramagia', 'Você tenta interromper uma criatura no processo de conjurar uma magia. Se ela estiver conjurando uma magia de 3º círculo ou inferior, a magia falha e não tem efeito. Se ela estiver conjurando uma magia de 4º círculo ou superior, faça um teste de atributo usando o seu atributo de conjuração. A CD é igual a 10 + o círculo da magia conjurada pela criatura. Em caso de sucesso, a magia da criatura falha e não surte efeito.Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 4º círculo ou superior, a magia interrompida não tem efeito se o círculo dela for menor ou igual ao círculo do espaço de magia que você usou.', '', NULL
FROM public.spells WHERE external_index = 'counterspell'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Create Food and Water
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('create-food-and-water', 3, 'conjuration', 'action', 1, 30, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['cleric', 'druid', 'paladin'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Create Food and Water', 'You create 45 pounds of food and 30 gallons of water on the ground or in containers within range, enough to sustain up to fifteen humanoids or five steeds for 24 hours. The food is bland but nourishing, and spoils if uneaten after 24 hours. The water is clean and doesn''t go bad.', '', NULL
FROM public.spells WHERE external_index = 'create-food-and-water'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Criar Comida e Água', 'Você cria 20 quilos [45 pounds] de comida e 120 litros [30 gallons] de água no chão ou em recipientes no alcance da magia, o suficiente para sustentar até quinze humanoides ou cinco montarias por 24 horas. A comida não é temperada, mas é nutritiva e estraga se não for ingerida dentro de 24 horas. A água é limpa e não estraga.', '', NULL
FROM public.spells WHERE external_index = 'create-food-and-water'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Create Undead
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('create-undead', 6, 'necromancy', 'minute', 1, 10, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Create Undead', 'You can cast this spell only at night. Choose up to three corpses of Medium or Small humanoids within range. Each corpse becomes a ghoul under your control. (The GM has game statistics for these creatures.)
As a bonus action on each of your turns, you can mentally command any creature you animated with this spell if the creature is within 120 feet of you (if you control multiple creatures, you can command any or all of them at the same time, issuing the same command to each one). You decide what action the creature will take and where it will move during its next turn, or you can issue a general command, such as to guard a particular chamber or corridor. If you issue no commands, the creature only defends itself against hostile creatures. Once given an order, the creature continues to follow it until its task is complete.
The creature is under your control for 24 hours, after which it stops obeying any command you have given it. To maintain control of the creature for another 24 hours, you must cast this spell on the creature before the current 24-hour period ends. This use of the spell reasserts your control over up to three creatures you have animated with this spell, rather than animating new ones.', 'When you cast this spell using a 7th-level spell slot, you can animate or reassert control over four ghouls. When you cast this spell using an 8th-level spell slot, you can animate or reassert control over five ghouls or two ghasts or wights. When you cast this spell using a 9th-level spell slot, you can animate or reassert control over six ghouls, three ghasts or wights, or two mummies.', 'One clay pot filled with grave dirt, one clay pot filled with brackish water, and one 150 gp black onyx stone for each corpse.'
FROM public.spells WHERE external_index = 'create-undead'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Criar Mortos-Vivos', 'Esta magia só pode ser conjurada à noite. Escolha até três cadáveres de humanoides Pequenos ou Médios dentro do alcance da magia. Cada corpo se torna um carniçal sob o seu controle (O DM fornece as estatísticas dessas criaturas).Com uma ação bônus em cada um dos seus turnos, você pode comandar mentalmente qualquer criatura animada por você com esta magia, se ela estiver a até 36 metros [120 ft.] de você (se várias criaturas forem controladas, é possível controlar qualquer uma ou todas ao mesmo tempo, desde que seja dado o mesmo comando para todas delas). Você decide qual ação a criatura tomará e para onde se moverá durante o próximo turno dela, ou você pode emitir um comando geral, como manter a guarda de uma câmara ou corredor. Se você não emitir nenhum comando, a criatura apenas se defende de criaturas hostis. Uma vez dada a ordem, a criatura continua a segui-la até que a tarefa esteja completa.A criatura estará sob seu controle por 24 horas e, depois, não obedece mais a qualquer comando que você tenha dado. Para manter o controle por mais 24 horas, você deve conjurar novamente esta magia na criatura antes que o período atual de 24 horas acabe. Esse uso da magia reafirma seu controle sobre até três mortos-vivos que tenham sido animados por você com esta magia, em vez de animar outros.Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 7º círculo, você pode animar ou reafirmar o controle sobre até quatro carniçais. Ao conjurar esta magia usando um espaço de magia de 8º círculo, você pode animar ou reafirmar o controle sobre até cinco carniçais ou dois lívidos ou inumanos. Ao conjurar esta magia usando um espaço de magia de 9º círculo, você pode animar ou reafirmar o controle sobre até cinco carniçais ou três lívidos ou inumanos, ou duas múmias.', '', NULL
FROM public.spells WHERE external_index = 'create-undead'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Create or Destroy Water
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('create-or-destroy-water', 1, 'transmutation', 'action', 1, 30, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Create or Destroy Water', 'You either create or destroy water.
***Create Water.*** You create up to 10 gallons of clean water within range in an open container. Alternatively, the water falls as rain in a 30-foot cube within range.
***Destroy Water.*** You destroy up to 10 gallons of water in an open container within range. Alternatively, you destroy fog in a 30-foot cube within range.', 'When you cast this spell using a spell slot of 2nd level or higher, you create or destroy 10 additional gallons of water, or the size of the cube increases by 5 feet, for each slot level above 1st.', 'A drop of water if creating water, or a few grains of sand if destroying it.'
FROM public.spells WHERE external_index = 'create-or-destroy-water'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Criar ou Destruir Água', 'Você pode criar ou destruir água.Criar Água. Você cria até 40 litros de água limpa em um recipiente limpo, aberto e no alcance da magia. A água também pode cair como chuva em um cubo de 9 metros [30-foot cube] dentro do alcance da magia, extinguindo chamas expostas dentro dessa área.Destruir Água. Você destrói até 40 litros de água em um recipiente aberto dentro do alcance da magia. Ou você pode dispersar névoa em um cubo de 9 metros [30-foot cube] dentro do alcance da magia.Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, você pode criar ou destruir 40 litros de água adicionais, ou o tamanho do cubo aumenta em 1,5 metro [5 ft.] para cada círculo de magia acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'create-or-destroy-water'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Creation
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('creation', 5, 'illusion', 'minute', 1, 30, 'feet', NULL, 'special', false, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Creation', 'You pull wisps of shadow material from the Shadowfell to create a nonliving object of vegetable matter within range: soft goods, rope, wood, or something similar. You can also use this spell to create mineral objects such as stone, crystal, or metal. The object created must be no larger than a 5-foot cube, and the object must be of a form and material that you have seen before.
The duration depends on the object''s material. If the object is composed of multiple materials, use the shortest duration.
| Material | Duration |
|---|---|
| Vegetable matter | 1 day |
| Stone or crystal | 12 hours |
| Precious metals | 1 hour |
| Gems | 10 minutes |
| Adamantine or mithral | 1 minute |
Using any material created by this spell as another spell''s material component causes that spell to fail.', 'When you cast this spell using a spell slot of 6th level or higher, the cube increases by 5 feet for each slot level above 5th.', 'A tiny piece of matter of the same type of the item you plan to create.'
FROM public.spells WHERE external_index = 'creation'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Criação', 'Você puxa mechas de material sombrio vindo do Sombral para criar, dentro do alcance da magia, um objeto inanimado, feito de matéria vegetal: tecido, madeira ou algo similar. Você também pode usar esta magia para criar objetos minerais, como rocha, cristal ou metal. O item criado deve ser menor que um cubo de 1,5 metro [5 ft.] de lado e deve ter uma forma e material que você já tenha visto.A duração depende do componente do objeto. Se o objeto for composto de vários materiais, use a menor duração.
Vegetal - 1 dia
Rocha ou cristal - 12 horas
Metais preciosos - 1 hora
Pedras preciosas - 10 minutos
Adamantina ou mithral - 1 minuto
Usar qualquer material criado por esta magia como material componente de outra faz com que aquela magia falhe.Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 6º círculo ou superior, o cubo aumenta em 1,5 metro [5 ft.] para cada círculo do espaço acima do 5º.', '', NULL
FROM public.spells WHERE external_index = 'creation'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Cure Wounds
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('cure-wounds', 1, 'evocation', 'action', 1, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['bard', 'cleric', 'druid', 'paladin', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Cure Wounds', 'A creature you touch regains a number of hit points equal to 1d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d8 for each slot level above 1st.', NULL
FROM public.spells WHERE external_index = 'cure-wounds'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Curar Ferimentos', 'Uma criatura tocada por você recupera um número de pontos de vida igual a 1d8 + o modificador do seu atributo de conjuração. Esta magia não tem efeito sobre mortos-vivos ou constructos.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, a cura aumenta em 1d8 para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'cure-wounds'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Dancing Lights
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('dancing-lights', 0, 'evocation', 'action', 1, 120, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Dancing Lights', 'You create up to four torch-sized lights within range, making them appear as torches, lanterns, or glowing orbs that hover in the air for the duration. You can also combine the four lights into one glowing vaguely humanoid form of Medium size. Whichever form you choose, each light sheds dim light in a 10-foot radius.
As a bonus action on your turn, you can move the lights up to 60 feet to a new spot within range. A light must be within 20 feet of another light created by this spell, and a light winks out if it exceeds the spell''s range.', '', 'A bit of phosphorus or wychwood, or a glowworm.'
FROM public.spells WHERE external_index = 'dancing-lights'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Luzes Dançantes', 'Você cria até quatro luzes no alcance da magia, fazendo com que se pareçam com tochas, lanternas ou globos brilhantes que pairam no ar por toda a duração da magia. Você também pode combinar as quatro luzes para que brilhem em uma forma vagamente humanoide de tamanho Médio. Qualquer que seja a forma escolhida, cada luz emite meia-luz em um raio de 3 metros [10-foot radius].Com uma ação bônus em seu turno, você pode mover as luzes até 18 metros [60 ft.] para um novo lugar dentro do alcance da magia. Uma luz deve estar a até 6 metros [20 ft.] de outra luz criada por esta magia, e uma se apaga quando ultrapassa o alcance da magia.', '', NULL
FROM public.spells WHERE external_index = 'dancing-lights'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Darkness
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('darkness', 2, 'evocation', 'action', 1, 60, 'feet', 10, 'minute', true, false, ARRAY['V', 'M'], ARRAY['sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Darkness', 'Magical darkness spreads from a point you choose within range to fill a 15-foot-radius sphere for the duration. The darkness spreads around corners. A creature with darkvision can''t see through this darkness, and nonmagical light can''t illuminate it.
If the point you choose is on an object you are holding or one that isn''t being worn or carried, the darkness emanates from the object and moves with it. Completely covering the source of the darkness with an opaque object, such as a bowl or a helm, blocks the darkness.
If any of this spell''s area overlaps with an area of light created by a spell of 2nd level or lower, the spell that created the light is dispelled.', '', 'Bat fur and a drop of pitch or piece of coal.'
FROM public.spells WHERE external_index = 'darkness'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Escuridão', 'Uma esfera de escuridão mágica, com raio de 4,5 m [15-foot radius], se alastra a partir de um ponto à sua escolha, no alcance da magia e permanece enquanto a magia durar. A escuridão se alastra, contornando os cantos. Uma criatura com visão no escuro não pode ver através dessa escuridão, e uma luz não mágica não pode iluminá-la.
Se o ponto escolhido estiver em um objeto que você está segurando ou que não esteja sendo usado ou carregado, a escuridão emana do objeto e move-se com ele. Cobrir completamente a origem da escuridão com um objeto opaco, como uma tigela ou elmo, bloqueia a escuridão.
Se alguma parte da área da magia se sobrepuser a uma área de luz criada por uma magia de 2º círculo ou inferior, a magia que criou a luz é anulada.', '', NULL
FROM public.spells WHERE external_index = 'darkness'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Darkvision
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('darkvision', 2, 'transmutation', 'action', 1, NULL, 'touch', 8, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'ranger', 'sorcerer', 'wizard'], 'dnd_5e')
