INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Darkvision', 'You touch a willing creature to grant it the ability to see in the dark. For the duration, that creature has darkvision out to a range of 60 feet.', '', 'Either a pinch of dried carrot or an agate.'
FROM public.spells WHERE external_index = 'darkvision'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Visão no Escuro', 'Ao tocar uma criatura voluntária você lhe concede a capacidade de enxergar no escuro. O alvo ganha visão no escuro com alcance de até 18 metros [60 ft.] enquanto a magia durar.', '', NULL
FROM public.spells WHERE external_index = 'darkvision'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Daylight
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('daylight', 3, 'evocation', 'action', 1, 60, 'feet', 1, 'hour', false, false, ARRAY['V', 'S'], ARRAY['cleric', 'druid', 'paladin', 'ranger', 'sorcerer'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Daylight', 'A 60-foot-radius sphere of light spreads out from a point you choose within range. The sphere is bright light and sheds dim light for an additional 60 feet.
If you chose a point on an object you are holding or one that isn''t being worn or carried, the light shines from the object and moves with it. Completely covering the affected object with an opaque object, such as a bowl or a helm, blocks the light.
If any of this spell''s area overlaps with an area of darkness created by a spell of 3rd level or lower, the spell that created the darkness is dispelled.', '', NULL
FROM public.spells WHERE external_index = 'daylight'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Luz do Dia', 'Uma esfera de luz com raio de 18 metros [60 ft.] se expande a partir de um ponto à sua escolha e no alcance da magia. A esfera é de luz plena e emite meia-luz por mais 18 metros [60 ft.].Se o ponto escolhido for um objeto que você está segurando ou que não esteja sendo usado ou carregado, a luz brilha a partir do objeto e move-se com ele. Cobrir completamente o objeto afetado com algo opaco, como uma tigela ou um elmo, bloqueia a luz.Se qualquer área desta magia se sobrepuser a uma área de escuridão criada por uma magia de 3º círculo ou inferior, a magia que criou a escuridão é anulada.', '', NULL
FROM public.spells WHERE external_index = 'daylight'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Death Ward
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('death-ward', 4, 'abjuration', 'action', 1, NULL, 'touch', 8, 'hour', false, false, ARRAY['V', 'S'], ARRAY['cleric', 'paladin'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Death Ward', 'You touch a creature and grant it a measure of protection from death.
The first time the target would drop to 0 hit points as a result of taking damage, the target instead drops to 1 hit point, and the spell ends.
If the spell is still in effect when the target is subjected to an effect that would kill it instantaneously without dealing damage, that effect is instead negated against the target, and the spell ends.', '', NULL
FROM public.spells WHERE external_index = 'death-ward'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Proteção Contra Morte', 'Ao tocar uma criatura você lhe concede alguma medida de proteção contra a morte.Na primeira vez que ela sofrer dano e isso reduzir-lhe os pontos de vida a 0, ela volta a ter 1 ponto de vida e a magia termina.Se a magia ainda estiver em ação quando a criatura for submetida a um efeito que a mataria instantaneamente sem causar dano, esse efeito é anulado e a magia termina.', '', NULL
FROM public.spells WHERE external_index = 'death-ward'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Delayed Blast Fireball
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('delayed-blast-fireball', 7, 'evocation', 'action', 1, 150, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Delayed Blast Fireball', 'A beam of yellow light flashes from your pointing finger, then condenses to linger at a chosen point within range as a glowing bead for the duration. When the spell ends, either because your concentration is broken or because you decide to end it, the bead blossoms with a low roar into an explosion of flame that spreads around corners. Each creature in a 20-foot-radius sphere centered on that point must make a dexterity saving throw. A creature takes fire damage equal to the total accumulated damage on a failed save, or half as much damage on a successful one.
The spell''s base damage is 12d6. If at the end of your turn the bead has not yet detonated, the damage increases by 1d6.
If the glowing bead is touched before the interval has expired, the creature touching it must make a dexterity saving throw. On a failed save, the spell ends immediately, causing the bead to erupt in flame. On a successful save, the creature can throw the bead up to 40 feet. When it strikes a creature or a solid object, the spell ends, and the bead explodes.
The fire damages objects in the area and ignites flammable objects that aren''t being worn or carried.', 'When you cast this spell using a spell slot of 8th level or higher, the base damage increases by 1d6 for each slot level above 7th.', 'A tiny ball of bat guano and sulfur.'
FROM public.spells WHERE external_index = 'delayed-blast-fireball'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Bola de Fogo Adiável', 'Um facho de luz amarela dispara do seu dedo em riste, condensando-se na forma de uma conta brilhante num ponto escolhido dentro do alcance da magia por toda a duração. Quando a magia se encerra, seja porque sua concentração foi quebrada ou por decisão sua, a conta desabrocha, com um rugido baixo, em uma explosão de chamas que se alastram pelos cantos. Cada criatura em uma esfera com raio de 6 metros [20-foot-radius sphere] centrada na conta deve fazer uma salvaguarda de Destreza. Se falhar, sofre dano ígneo equivalente ao total acumulado de dano, ou metade do dano, em caso de sucesso.
O dano base da magia é 12d6. Se ao final do seu turno a conta ainda não tiver sido detonada, o dano aumenta em 1d6.
Se a conta brilhante for tocada antes que o intervalo expire, a criatura que a tocar precisa fazer uma salvaguarda de Destreza. Se falhar, a magia encerra imediatamente e a conta explode em chamas; se for bem-sucedida, a criatura pode arremessar a conta a até 12 metros [40 ft.] de distância. Se a conta atingir uma criatura ou objeto sólido, a magia se encerra e ela explode.
O fogo danifica objetos na área e incendeia objetos inflamáveis que não estejam sendo usados ou carregados.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 8º círculo ou superior, o dano aumenta em 1d6 para cada círculo do espaço acima do 7º.', '', NULL
FROM public.spells WHERE external_index = 'delayed-blast-fireball'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Demiplane
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('demiplane', 8, 'conjuration', 'action', 1, 60, 'feet', 1, 'hour', false, false, ARRAY['S'], ARRAY['warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Demiplane', 'You create a shadowy door on a flat solid surface that you can see within range. The door is large enough to allow Medium creatures to pass through unhindered. When opened, the door leads to a demiplane that appears to be an empty room 30 feet in each dimension, made of wood or stone. When the spell ends, the door disappears, and any creatures or objects inside the demiplane remain trapped there, as the door also disappears from the other side.
Each time you cast this spell, you can create a new demiplane, or have the shadowy door connect to a demiplane you created with a previous casting of this spell. Additionally, if you know the nature and contents of a demiplane created by a casting of this spell by another creature, you can have the shadowy door connect to its demiplane instead.', '', NULL
FROM public.spells WHERE external_index = 'demiplane'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Semiplano', 'Você cria uma porta de sombras em uma superfície sólida e plana, à sua vista e dentro do alcance da magia. A porta é grande o suficiente para permitir que uma criatura Média passe sem impedimento. Quando aberta, a porta leva para um semiplano que parece ser um quarto vazio, com 9 metros [30 ft.] em cada dimensão, feito de madeira ou pedra. Quando a magia termina, a porta desaparece e quaisquer criaturas ou objetos dentro do semiplano ficam presos ali, já que a porta também desaparece do outro lado.Todas as vezes que conjurar esta magia, você pode criar um novo semiplano ou fazer a porta de sombras se conectar a um semiplano que tenha criado em uma conjuração anterior desta magia. Além disso, se você conhecer a natureza e o conteúdo de um semiplano criado por uma conjuração desta magia por outra criatura, você pode fazer a porta de sombras se conectar a esse semiplano e não ao seu.', '', NULL
FROM public.spells WHERE external_index = 'demiplane'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Detect Evil and Good
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('detect-evil-and-good', 1, 'divination', 'action', 1, NULL, 'self', 10, 'minute', true, false, ARRAY['V', 'S'], ARRAY['cleric', 'paladin'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Detect Evil and Good', 'For the duration, you know if there is an aberration, celestial, elemental, fey, fiend, or undead within 30 feet of you, as well as where the creature is located. Similarly, you know if there is a place or object within 30 feet of you that has been magically consecrated or desecrated.
The spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.', '', NULL
FROM public.spells WHERE external_index = 'detect-evil-and-good'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Detectar o Bem e o Mal', 'Enquanto a magia durar, você pode sentir a presença e localização de uma criatura do tipo aberração, celestial, elemental, feérico, ínfero ou morto-vivo que encontre-se a até 9 metros [30 ft.] de distância. Da mesma forma, você sabe se existe um lugar ou objeto a até 9 metros [30 ft.] que tenha sido magicamente consagrado ou profanado.A magia pode atravessar a maioria das barreiras, sendo bloqueada, no entanto, por 30 centímetros [1 foot] de pedra, 2,5 centímetros [1 inch] de metal comum, uma folha fina de chumbo ou 1 metro [3 ft.] de madeira ou terra.', '', NULL
FROM public.spells WHERE external_index = 'detect-evil-and-good'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Detect Magic
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('detect-magic', 1, 'divination', 'action', 1, NULL, 'self', 10, 'minute', true, true, ARRAY['V', 'S'], ARRAY['bard', 'cleric', 'druid', 'paladin', 'ranger', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Detect Magic', 'For the duration, you sense the presence of magic within 30 feet of you. If you sense magic in this way, you can use your action to see a faint aura around any visible creature or object in the area that bears magic, and you learn its school of magic, if any.
The spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.', '', NULL
FROM public.spells WHERE external_index = 'detect-magic'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Detectar Magia', 'Enquanto a magia durar, você pode sentir a presença de energia mágica a até 9 metros [30 ft.]. Caso seja bem-sucedido ao fazê-lo, você pode usar sua ação para ver uma tênue aura ao redor de qualquer criatura ou objeto que possuam energia mágica e que estejam visíveis na área, distinguindo, inclusive, a escola da magia, caso ela pertença a alguma.A magia pode atravessar a maioria das barreiras, sendo bloqueada, no entanto, por 30 centímetros [1 foot] de pedra, 2,5 centímetros [1 inch] de metal comum, uma folha fina de chumbo ou 1 metro [3 ft.] de madeira ou terra.', '', NULL
FROM public.spells WHERE external_index = 'detect-magic'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Detect Poison and Disease
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('detect-poison-and-disease', 1, 'divination', 'action', 1, NULL, 'self', 10, 'minute', true, true, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'druid', 'paladin', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Detect Poison and Disease', 'For the duration, you can sense the presence and location of poisons, poisonous creatures, and diseases within 30 feet of you. You also identify the kind of poison, poisonous creature, or disease in each case.
The spell can penetrate most barriers, but it is blocked by 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood or dirt.', '', 'A yew leaf.'
FROM public.spells WHERE external_index = 'detect-poison-and-disease'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Detectar Veneno e Doença', 'Enquanto a magia durar, você pode sentir a presença e a localização de venenos, criaturas venenosas e doenças a até 9 metros [30 ft.] de distância. Você também pode identificar o tipo de veneno, criatura venenosa ou doença em cada caso.A magia pode atravessar a maioria das barreiras, sendo bloqueada, no entanto, por 30 centímetros [1 foot] de pedra, 2,5 centímetros [1 inch] de metal comum, uma folha fina de chumbo ou 1 metro [3 ft.] de madeira ou terra.', '', NULL
FROM public.spells WHERE external_index = 'detect-poison-and-disease'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Detect Thoughts
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('detect-thoughts', 2, 'divination', 'action', 1, NULL, 'self', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Detect Thoughts', 'For the duration, you can read the thoughts of certain creatures. When you cast the spell and as your action on each turn until the spell ends, you can focus your mind on any one creature that you can see within 30 feet of you. If the creature you choose has an Intelligence of 3 or lower or doesn''t speak any language, the creature is unaffected.
You initially learn the surface thoughts of the creature - what is most on its mind in that moment. As an action, you can either shift your attention to another creature''s thoughts or attempt to probe deeper into the same creature''s mind. If you probe deeper, the target must make a Wisdom saving throw. If it fails, you gain insight into its reasoning (if any), its emotional state, and something that looms large in its mind (such as something it worries over, loves, or hates). If it succeeds, the spell ends. Either way, the target knows that you are probing into its mind, and unless you shift your attention to another creature''s thoughts, the creature can use its action on its turn to make an Intelligence check contested by your Intelligence check; if it succeeds, the spell ends.
Questions verbally directed at the target creature naturally shape the course of its thoughts, so this spell is particularly effective as part of an interrogation.
You can also use this spell to detect the presence of thinking creatures you can''t see. When you cast the spell or as your action during the duration, you can search for thoughts within 30 feet of you. The spell can penetrate barriers, but 2 feet of rock, 2 inches of any metal other than lead, or a thin sheet of lead blocks you. You can''t detect a creature with an Intelligence of 3 or lower or one that doesn''t speak any language.
Once you detect the presence of a creature in this way, you can read its thoughts for the rest of the duration as described above, even if you can''t see it, but it must still be within range.', '', 'A copper coin.'
FROM public.spells WHERE external_index = 'detect-thoughts'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Detectar Pensamentos', 'Enquanto a magia durar, você pode ler os pensamentos de certas criaturas. Ao conjurar esta magia, e com uma ação em cada um de seus turnos enquanto a magia durar, você pode focar sua mente em qualquer criatura à sua vista e que esteja a até 9 metros [30 ft.] de distância de você. Se a criatura que você escolher tiver uma Inteligência igual ou menor que 3, ou não falar qualquer idioma, ela não é afetada.Inicialmente, você descobre os pensamentos superficiais da criatura - o que está mais evidente na mente dela naquele momento. Com uma ação, você pode mudar sua atenção para os pensamentos de outra criatura ou tentar sondar mais profundamente a mente da mesma criatura. Se sondar mais profundamente, o alvo deve fazer uma salvaguarda de Sabedoria. Se falhar, você ganha acesso aos raciocínios (se houver), estado emocional e qualquer coisa que ocupe grande parte da mente dele (como alguma coisa com a qual ele se preocupa, ame ou odeie). Se o alvo for bem-sucedido, a magia se encerra. De qualquer forma, o alvo sabe que você está sondando a mente dele e, a menos que você mude sua atenção para os pensamentos de outra criatura, a criatura pode usar uma ação para fazer um teste de Inteligência resistido por um teste de Inteligência seu; se ela for bem-sucedida, a magia se encerra.Perguntas verbais dirigidas à criatura alvo moldam naturalmente o curso dos pensamentos dela, o que torna esta magia particularmente eficaz como parte de um interrogatório.Você também pode usar esta magia para detectar a presença de criaturas pensantes que você não possa ver. Ao conjurar esta magia ou como sua ação, enquanto a magia durar, você pode procurar por pensamentos em uma área de 9 metros [30 ft.] de distância de você. A magia pode penetrar barreiras,sendo bloqueada, no entanto, por 60 centímetros [2 ft.] de rocha, 5 centímetros [2 inches] de qualquer metal ou uma folha fina de chumbo. Você não pode detectar uma criatura com Inteligência igual a 3 ou menor, ou que não fale nenhum idioma.Depois de detectar a presença de uma criatura desse modo, você pode ler os pensamentos dela pelo restante da duração da magia, conforme descrito acima, mesmo que não possa vê-la, embora ela ainda precise estar dentro do alcance da magia.', '', NULL
FROM public.spells WHERE external_index = 'detect-thoughts'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Dimension Door
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('dimension-door', 4, 'conjuration', 'action', 1, 500, 'feet', NULL, 'instantaneous', false, false, ARRAY['V'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Dimension Door', 'You teleport yourself from your current location to any other spot within range. You arrive at exactly the spot desired. It can be a place you can see, one you can visualize, or one you can describe by stating distance and direction, such as "200 feet straight downward" or "upward to the northwest at a 45-degree angle, 300 feet."
You can bring along objects as long as their weight doesn''t exceed what you can carry. You can also bring one willing creature of your size or smaller who is carrying gear up to its carrying capacity. The creature must be within 5 feet of you when you cast this spell.
If you would arrive in a place already occupied by an object or a creature, you and any creature traveling with you each take 4d6 force damage, and the spell fails to teleport you.', '', NULL
FROM public.spells WHERE external_index = 'dimension-door'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Porta Dimensional', 'Você pode se teleportar a partir de sua localização atual para qualquer outro local dentro do alcance da magia. Você chega exatamente no local desejado. Pode se tratar de um lugar que você possa ver, visualizar ou descrever, relatando a distância e a direção, como "60 metros [200 ft.] em linha reta para baixo" ou "para cima e para o noroeste a um ângulo de 45 graus, a 90 metros [300 ft.]."
Você pode levar consigo objetos, desde que o peso deles não exceda aquele que você consiga carregar. Você também pode levar uma criatura voluntária, do seu tamanho ou menor, que esteja portando equipamentos até a capacidade de carga dela. A criatura deve estar a até 1,5 metro [5 ft.] de você quando você conjurar esta magia.
Se você ou qualquer criatura que você leve junto chegarem a um local ocupado por um objeto ou outra criatura, sofrerão, cada, 4d6 pontos de dano energético, e a magia falha em teleportá-los.', '', NULL
FROM public.spells WHERE external_index = 'dimension-door'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Disguise Self
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('disguise-self', 1, 'illusion', 'action', 1, NULL, 'self', 1, 'hour', false, false, ARRAY['V', 'S'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Disguise Self', 'You make yourself--including your clothing, armor, weapons, and other belongings on your person--look different until the spell ends or until you use your action to dismiss it. You can seem 1 foot shorter or taller and can appear thin, fat, or in between. You can''t change your body type, so you must adopt a form that has the same basic arrangement of limbs. Otherwise, the extent of the illusion is up to you.
The changes wrought by this spell fail to hold up to physical inspection. For example, if you use this spell to add a hat to your outfit, objects pass through the hat, and anyone who touches it would feel nothing or would feel your head and hair. If you use this spell to appear thinner than you are, the hand of someone who reaches out to touch you would bump into you while it was seemingly still in midair.
To discern that you are disguised, a creature can use its action to inspect your appearance and must succeed on an Intelligence (Investigation) check against your spell save DC.', '', NULL
FROM public.spells WHERE external_index = 'disguise-self'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Disfarçar-se', 'Você faz com que você mesmo - incluindo suas roupas, armaduras, armas e outros pertences que esteja carregando - ganhe outra aparência, enquanto a magia durar ou até que você use sua ação para encerrá-la. Você pode parecer 30 centímetros [1 ft.] mais baixo ou mais alto, e parecer magro, gordo ou algo entre os dois. Você não pode alterar o seu tipo de corpo, portanto, deve adotar uma forma que tenha a mesma disposição básica de membros. No mais, a extensão da ilusão cabe a você.As alterações feitas por esta magia não se sustentam diante de uma inspeção física. Por exemplo, se você usar esta magia para adicionar um chapéu à sua indumentária, objetos atravessam o chapéu, e quem o tocar não sentirá nada ou sentirá sua cabeça e cabelos. Se você usar esta magia para parecer mais magro do que é, alguém que estenda a mão para tocá-lo pode esbarrar em você enquanto ela ainda estiver, aparentemente, tocando o ar.Para descobrir que você está disfarçado, uma criatura pode usar a ação dela para inspecionar sua aparência, devendo ser bem-sucedida em um teste de Inteligência (Investigação) contra a CD para evitar sua magia.', '', NULL
FROM public.spells WHERE external_index = 'disguise-self'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Disintegrate
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('disintegrate', 6, 'transmutation', 'action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Disintegrate', 'A thin green ray springs from your pointing finger to a target that you can see within range. The target can be a creature, an object, or a creation of magical force, such as the wall created by wall of force.
A creature targeted by this spell must make a dexterity saving throw. On a failed save, the target takes 10d6 + 40 force damage. If this damage reduces the target to 0 hit points, it is disintegrated.
A disintegrated creature and everything it is wearing and carrying, except magic items, are reduced to a pile of fine gray dust. The creature can be restored to life only by means of a true resurrection or a wish spell.
This spell automatically disintegrates a Large or smaller nonmagical object or a creation of magical force. If the target is a Huge or larger object or creation of force, this spell disintegrates a 10-foot-cube portion of it. A magic item is unaffected by this spell.', 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 3d6 for each slot level above 6th.', 'A lodestone and a pinch of dust.'
FROM public.spells WHERE external_index = 'disintegrate'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Desintegrar', 'Um pequeno raio verde sai da ponta do seu dedo, dirigindo-se a um alvo à sua vista, no alcance da magia. O alvo deve ser uma criatura, um objeto ou uma criação de força mágica, como a barreira criada por Muralha de Energia.
Uma criatura atingida por esta magia deve fazer uma salvaguarda de Destreza. Se falhar, o alvo sofre 10d6+40 pontos de dano energético, sendo desintegrado caso seus pontos de vida sejam reduzidos a 0.
Uma criatura desintegrada e tudo que ela estiver usando e carregando, exceto itens mágicos, são reduzidos a uma pilha de poeira cinza. A criatura pode ter a vida restaurada apenas por meio da magia true Ressurreição Verdadeira ou Desejo.
Esta magia desintegra automaticamente um objeto não mágico de tamanho Grande ou menor ou uma criação de força mágica. Se o alvo for um objeto ou criação de força mágica de tamanho Enorme ou maior, esta magia desintegra uma porção equivalente a um cubo de 3 metros [10-foot cube] de lado dela. Itens mágicos não são afetados por esta magia.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 7º círculo ou superior, o dano da magia aumenta em 3d6 para cada círculo do espaço acima do 6º.', '', NULL
FROM public.spells WHERE external_index = 'disintegrate'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Dispel Evil and Good
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('dispel-evil-and-good', 5, 'abjuration', 'action', 1, NULL, 'self', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'paladin'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Dispel Evil and Good', 'Shimmering energy surrounds and protects you from fey, undead, and creatures originating from beyond the Material Plane. For the duration, celestials, elementals, fey, fiends, and undead have disadvantage on attack rolls against you.
You can end the spell early by using either of the following special functions.
***Break Enchantment.*** As your action, you touch a creature you can reach that is charmed, frightened, or possessed by a celestial, an elemental, a fey, a fiend, or an undead. The creature you touch is no longer charmed, frightened, or possessed by such creatures.
***Dismissal.*** As your action, make a melee spell attack against a celestial, an elemental, a fey, a fiend, or an undead you can reach. On a hit, you attempt to drive the creature back to its home plane. The creature must succeed on a charisma saving throw or be sent back to its home plane (if it isn''t there already). If they aren''t on their home plane, undead are sent to the Shadowfell, and fey are sent to the Feywild.', '', 'Holy water or powdered silver and iron.'
FROM public.spells WHERE external_index = 'dispel-evil-and-good'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Dissipar o Bem e o Mal', 'Uma energia cintilante o envolve e protege contra feéricos, mortos-vivos e criaturas originárias de além do Plano Material. Enquanto a magia durar, celestiais, elementais, feéricos, ínferos e mortos-vivos têm desvantagem nas jogadas de ataque contra você.
Você pode encerrar precocemente a magia usando qualquer uma das funções especiais abaixo.
Quebrar Encantamento. Utilize sua ação para tocar uma criatura, dentro do alcance da magia, que esteja amedrontada, enfeitiçada ou possuída por um celestial, elemental, feérico, ínfero ou morto-vivo. A criatura tocada não está mais encantada, amedrontada ou possuída por tais criaturas.
Regressar. Utilize sua ação para executar um ataque mágico corpo a corpo contra um celestial, elemental, feérico, ínfero ou morto-vivo ao seu alcance. Em caso de sucesso, você força a criatura a retornar ao próprio plano de origem. Ela deve ser bem-sucedida em uma salvaguarda de Carisma ou é mandada de volta (se já não estiver lá). Caso já não estejam nos próprios planos, mortos-vivos são enviados para o Sombral e feéricos para a Faéria.', '', NULL
FROM public.spells WHERE external_index = 'dispel-evil-and-good'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Dispel Magic
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('dispel-magic', 3, 'abjuration', 'action', 1, 120, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['bard', 'cleric', 'druid', 'paladin', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Dispel Magic', 'Choose one creature, object, or magical effect within range. Any spell of 3rd level or lower on the target ends. For each spell of 4th level or higher on the target, make an ability check using your spellcasting ability. The DC equals 10 + the spell''s level. On a successful check, the spell ends.', 'When you cast this spell using a spell slot of 4th level or higher, you automatically end the effects of a spell on the target if the spell''s level is equal to or less than the level of the spell slot you used.', NULL
FROM public.spells WHERE external_index = 'dispel-magic'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Dissipar Magia', 'Escolha uma criatura, objeto ou efeito mágico no alcance da magia. Quaisquer magias de 3º círculo ou inferiores que afetam o alvo se encerram. Para cada magia de 4º círculo ou superior que esteja afetando o alvo, faça um teste de atributo usando seu atributo de conjuração. A CD é igual a 10 + o círculo desta magia. Em caso de sucesso, a magia se encerra.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 4º círculo ou superior, você automaticamente encerra os efeitos de uma magia que esteja afetando o alvo, se o círculo da magia for igual ou menor ao círculo do espaço de magia que você usou.', '', NULL
FROM public.spells WHERE external_index = 'dispel-magic'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Divination
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('divination', 4, 'divination', 'action', 1, NULL, 'self', NULL, 'instantaneous', false, true, ARRAY['V', 'S', 'M'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Divination', 'Your magic and an offering put you in contact with a god or a god''s servants. You ask a single question concerning a specific goal, event, or activity to occur within 7 days. The GM offers a truthful reply. The reply might be a short phrase, a cryptic rhyme, or an omen.
The spell doesn''t take into account any possible circumstances that might change the outcome, such as the casting of additional spells or the loss or gain of a companion.
If you cast the spell two or more times before finishing your next long rest, there is a cumulative 25 percent chance for each casting after the first that you get a random reading. The GM makes this roll in secret.', '', 'Incense and a sacrificial offering appropriate to your religion, together worth at least 25gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'divination'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Presságio', 'Sua magia e uma oferenda colocam-no em contato com um deus ou um dos servos dele. Você faz uma única pergunta a respeito de um objetivo específico, evento ou atividade que ocorrerá no prazo de 7 dias. O DM oferece uma resposta verdadeira. A resposta pode ser uma frase curta, uma rima enigmática ou um presságio.A magia não leva em conta quaisquer circunstâncias que possam mudar o resultado futuro, como a conjuração de magias adicionais ou a perda ou chegada de um companheiro.Se você conjurar a magia duas ou mais vezes antes de concluir seu próximo descanso longo, há uma chance cumulativa de 25% para cada conjuração após a primeira de você obter uma resposta aleatória. O DM faz essa jogada em segredo.', '', NULL
FROM public.spells WHERE external_index = 'divination'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
