INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Divine Favor', 'Your prayer empowers you with divine radiance. Until the spell ends, your weapon attacks deal an extra 1d4 radiant damage on a hit.', '', NULL
FROM public.spells WHERE external_index = 'divine-favor'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Favor Divino', 'Sua oração o fortalece com o resplendor divino. Enquanto a magia durar, seus ataques com armas causam 1d4 pontos de dano radiante adicional em caso de acerto.', '', NULL
FROM public.spells WHERE external_index = 'divine-favor'
