INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Divine Word', 'You utter a divine word, imbued with the power that shaped the world at the dawn of creation. Choose any number of creatures you can see within range. Each creature that can hear you must make a Charisma saving throw. On a failed save, a creature suffers an effect based on its current hit points:
- 50 hit points or fewer: deafened for 1 minute
- 40 hit points or fewer: deafened and blinded for 10 minutes
- 30 hit points or fewer: blinded, deafened, and stunned for 1 hour
- 20 hit points or fewer: killed instantly
Regardless of its current hit points, a celestial, an elemental, a fey, or a fiend that fails its save is forced back to its plane of origin (if it isn''t there already) and can''t return to your current plane for 24 hours by any means short of a wish spell.', '', NULL
FROM public.spells WHERE external_index = 'divine-word'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Palavra Sagrada', 'Você profere uma palavra sagrada, imbuída com o poder que moldou o mundo na aurora da criação. Escolha qualquer número de criaturas à sua vista, no alcance da magia. Cada criatura que puder ouvi-lo deve fazer uma salvaguarda de Carisma. Se falhar, uma criatura sofre um efeito baseado nos pontos de vida atuais dela:
50 pontos de vida ou menos: surda por 1 minuto
40 pontos de vida ou menos: surda e cega por 10 minutos
30 pontos de vida ou menos: cega, surda e atordoada por 1 hora
20 pontos de vida ou menos: morta instantaneamente
Independentemente dos seus pontos de vida atuais, um celestial, elemental, feérico ou ínfero que falhe na salvaguarda é forçado a voltar para o plano de origem dele (se já não estiver lá), não podendo voltar ao seu plano atual durante 24 horas por qualquer meio inferior à magia Desejo.', '', NULL
FROM public.spells WHERE external_index = 'divine-word'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Dominate Beast
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('dominate-beast', 4, 'enchantment', 'action', 1, 60, 'feet', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['druid', 'sorcerer'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Dominate Beast', 'You attempt to beguile a creature that you can see within range. It must succeed on a wisdom saving throw or be charmed by you for the duration. If you or creatures that are friendly to you are fighting it, it has advantage on the saving throw.
While the creature is charmed, you have a telepathic link with it as long as the two of you are on the same plane of existence. You can use this telepathic link to issue commands to the creature while you are conscious (no action required), which it does its best to obey. You can specify a simple and general course of action, such as "Attack that creature," "Run over there," or "Fetch that object." If the creature completes the order and doesn''t receive further direction from you, it defends and preserves itself to the best of its ability.
You can use your action to take total and precise control of the target. Until the end of your next turn, the creature takes only the actions you choose, and doesn''t do anything that you don''t allow it to do. During this time, you can also cause the creature to use a reaction, but this requires you to use your own reaction as well. Each time the target takes damage, it makes a new wisdom saving throw against the spell. If the saving throw succeeds, the spell ends.', 'When you cast this spell with a 9th level spell slot, the duration is concentration, up to 8 hours.', NULL
FROM public.spells WHERE external_index = 'dominate-beast'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Dominar Fera', 'Você tenta cativar uma fera à sua vista, dentro do alcance da magia. Ela deve ser bem-sucedida em uma salvaguarda de Sabedoria ou fica enfeitiçada enquanto durar a magia. Se você ou criaturas amigáveis a você estiverem lutando contra a fera, ela tem vantagem na salvaguarda.
Você possui um elo telepático com a criatura, permanecendo conectados enquanto ela estiver enfeitiçada e ambos estejam no mesmo plano de existência. Você pode usar este elo telepático para enviar comandos para a criatura, enquanto você estiver consciente (nenhuma ação é necessária) e ela faz o possível para obedecer. Pode ser especificado um curso de ação genérico e simples, como "Ataque aquela criatura", "Corra para cá" ou "Pegue aquele objeto". Se a criatura completar a ordem e não receber novas instruções suas, ela se defende e se preserva o melhor que puder.
Você pode usar sua ação para assumir controle total e preciso do alvo. Até o fim do seu turno, a criatura executa apenas as ações que você escolher e não faz nada que você não permita. Durante esse tempo, você também pode fazer com que a criatura use a reação dela, mas isso requer que você use sua reação também.
Toda vez que o alvo sofrer dano, ele deve fazer uma nova salvaguarda de Sabedoria contra CD para evitar a sua magia. Em caso de sucesso, a magia se encerra.
Em Círculos Superiores. Ao conjurar esta magia com um espaço de magia de 5º círculo, a duração será concentração, até 10 minutos. Ao conjurar esta magia com um espaço de magia de 6º círculo, a duração será concentração, até 1 hora. Ao conjurar esta magia utilizando um espaço de magia de 7º círculo, a duração será concentração, até 8 horas.', '', NULL
FROM public.spells WHERE external_index = 'dominate-beast'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Dominate Monster
