INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Dominar Monstro', 'Você tenta cativar uma criatura à sua vista e no alcance da magia. Ela deve ser bem-sucedida em uma salvaguarda de Sabedoria ou fica enfeitiçada enquanto a magia durar. Se você ou criaturas amigáveis a você estiverem lutando contra a criatura alvo, ela tem vantagem na salvaguarda.
Você possui um elo telepático com a criatura, permanecendo conectados enquanto ela estiver enfeitiçada e ambos estejam no mesmo plano de existência. Você pode usar este elo telepático para enviar comandos para a criatura, enquanto você estiver consciente (nenhuma ação é necessá­ria) e ela faz o possível para obedecer. Pode ser especificado um curso de ação genérico e simples, como "Ataque aquela criatura", "Corra para cá" ou "Pegue aquele objeto". Se a criatura completar a ordem e não receber novas instruções suas, ela se defende e se preserva o melhor que puder.
Você pode usar sua ação para assumir controle total e preciso do alvo. Até o fim do seu turno, a criatura executa apenas as ações que você escolher e não faz nada que você não permita. Durante esse tempo, você também pode fazer com que a criatura use a reação dela, mas isso requer que você use sua reação também.
Toda vez que o alvo sofrer dano, ele deve fazer uma nova salvaguarda de Sabedoria contra CD para evitar a sua magia. Em caso de sucesso, a magia se encerra.
Em Círculos Superiores. Ao conjurar esta magia com um espaço de magia de 9º círculo, a duração será de concentração, até 8 horas.', '', NULL
FROM public.spells WHERE external_index = 'dominate-monster'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Dominate Person
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('dominate-person', 5, 'enchantment', 'action', 1, 60, 'feet', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Dominate Person', 'You attempt to beguile a humanoid that you can see within range. It must succeed on a wisdom saving throw or be charmed by you for the duration. If you or creatures that are friendly to you are fighting it, it has advantage on the saving throw.
While the target is charmed, you have a telepathic link with it as long as the two of you are on the same plane of existence. You can use this telepathic link to issue commands to the creature while you are conscious (no action required), which it does its best to obey. You can specify a simple and general course of action, such as "Attack that creature," "Run over there," or "Fetch that object." If the creature completes the order and doesn''t receive further direction from you, it defends and preserves itself to the best of its ability.
You can use your action to take total and precise control of the target. Until the end of your next turn, the creature takes only the actions you choose, and doesn''t do anything that you don''t allow it to do. During this time you can also cause the creature to use a reaction, but this requires you to use your own reaction as well.
Each time the target takes damage, it makes a new wisdom saving throw against the spell. If the saving throw succeeds, the spell ends.', 'When you cast this spell using a 6th-level spell slot, the duration is concentration, up to 10 minutes. When you use a 7th-level spell slot, the duration is concentration, up to 1 hour. When you use a spell slot of 8th level or higher, the duration is concentration, up to 8 hours.', NULL
FROM public.spells WHERE external_index = 'dominate-person'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Dominar Pessoa', 'Você tenta influenciar um humanoide à sua vista no alcance da magia. Ele deve ser bem-sucedido em uma salvaguarda de Sabedoria ou está enfeitiçado por você enquanto a magia durar. Se você ou criaturas amigáveis a você estiverem lutando contra o alvo, ele tem vantagem na salvaguarda.
Enquanto o alvo estiver enfeitiçado, você tem um elo telepático com ele desde que ambos estejam no mesmo plano de existência. Enquanto estiver consciente, você pode usar o elo telepático para enviar comandos para a criatura (nenhuma ação é necessária), que faz o possível para obedecer. Você pode especificar um curso de ação genérico e simples, como "Ataque aquela criatura", "Corra para cá" ou "Pegue aquele objeto". Se a criatura completar a ordem e não receber novas instruções suas, ela se defende e se preserva o melhor que puder.
Você pode usar sua ação para assumir controle total e preciso do alvo. Até o fim do seu turno, a criatura executa apenas as ações que você escolher e não faz nada que você não permita. Durante esse tempo, você também pode fazer com que a criatura use a reação dela, mas isso requer que você use sua reação também.
Toda vez que o alvo sofre dano, ele faz uma salvaguarda de Sabedoria contra a magia. Em caso de sucesso, a magia se encerra.
Em Círculos Superiores. Ao conjurar esta magia com um espaço de magia de 6º círculo, a duração será concentração, até 10 minutos. Ao conjurar esta magia com um espaço de magia de 7º círculo, a duração será concentração, até 1 hora. Ao conjurar esta magia com um espaço de magia de 8º círculo, a duração será concentração, até 8 horas.', '', NULL
FROM public.spells WHERE external_index = 'dominate-person'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Dream
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('dream', 5, 'illusion', 'minute', 1, NULL, 'unlimited', 8, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Dream', 'This spell shapes a creature''s dreams. Choose a creature known to you as the target of this spell. The target must be on the same plane of existence as you. Creatures that don''t sleep, such as elves, can''t be contacted by this spell. You, or a willing creature you touch, enters a trance state, acting as a messenger.
While in the trance, the messenger is aware of his or her surroundings, but can''t take actions or move.
If the target is asleep, the messenger appears in the target''s dreams and can converse with the target as long as it remains asleep, through the duration of the spell. The messenger can also shape the environment of the dream, creating landscapes, objects, and other images. The messenger can emerge from the trance at any time, ending the effect of the spell early. The target recalls the dream perfectly upon waking. If the target is awake when you cast the spell, the messenger knows it, and can either end the trance (and the spell) or wait for the target to fall asleep, at which point the messenger appears in the target''s dreams.
You can make the messenger appear monstrous and terrifying to the target. If you do, the messenger can deliver a message of no more than ten words and then the target must make a wisdom saving throw. On a failed save, echoes of the phantasmal monstrosity spawn a nightmare that lasts the duration of the target''s sleep and prevents the target from gaining any benefit from that rest. In addition, when the target wakes up, it takes 3d6 psychic damage.
If you have a body part, lock of hair, clipping from a nail, or similar portion of the target''s body, the target makes its saving throw with disadvantage.', '', 'A handful of sand, a dab of ink, and a writing quill plucked from a sleeping bird.'
FROM public.spells WHERE external_index = 'dream'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Sonho', 'Esta magia molda os sonhos de uma criatura. Escolha uma criatura conhecida como alvo. Ela deve estar no mesmo plano de existência que você. Criaturas que não dormem, como elfos, não podem ser contatadas por esta magia. Você ou uma criatura voluntária tocada por você, entra em um estado de transe, atuando como mensageira. Enquanto estiver em transe, o mensageiro está ciente do que acontece ao redor dele, mas não pode executar ações ou mover-se.Se o alvo estiver dormindo, o mensageiro aparece nos sonhos dele e, enquanto a magia durar e o sono persistir, pode conversar com ele. O mensageiro também pode moldar o ambiente do sonho, criando paisagens, objetos e outras imagens, podendo ainda sair do transe a qualquer momento, o que encerra previamente o efeito da magia. O alvo recorda perfeitamente o sonho ao acordar. Se o alvo estiver acordado quando você conjurar a magia, o mensageiro ficará ciente, podendo terminar o transe (e a magia), ou aguardar o alvo cair no sono até o ponto no qual ele aparece nos sonhos do alvo.Você pode fazer o mensageiro parecer monstruoso e aterrador para o alvo. Se fizer isso, o mensageiro só poderá entregar uma mensagem com não mais do que dez palavras e, em seguida, o alvo deverá fazer uma salvaguarda de Sabedoria. Se falhar, ecos da monstruosidade fantasmagórica geram um pesadelo que dura por todo o tempo de sono, impedindo o alvo de obter qualquer benefício com o descanso. Além disso, quando o alvo acorda, sofre 3d6 pontos de dano psíquico.Caso você tenha uma parte do corpo do alvo, tal como uma mecha de cabelo, pedaço de unha, pele ou parte semelhante, a salvaguarda é feita com desvantagem.', '', NULL
FROM public.spells WHERE external_index = 'dream'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Druidcraft
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('druidcraft', 0, 'transmutation', 'action', 1, 30, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Druidcraft', 'Whispering to the spirits of nature, you create one of the following effects within ''range'':
- You create a tiny, harmless sensory effect that predicts what the weather will be at your location for the next 24 hours. The effect might manifest as a golden orb for clear skies, a cloud for rain, falling snowflakes for snow, and so on. This effect persists for 1 round.
- You instantly make a flower bloom, a seed pod open, or a leaf bud bloom.
- You create an instantaneous, harmless sensory effect, such as falling leaves, a puff of wind, the sound of a small animal, or the faint order of skunk. The effect must fit in a 5-foot cube.
- You instantly light or snuff out a candle, a torch, or a small campfire.', '', NULL
FROM public.spells WHERE external_index = 'druidcraft'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Arte Druídica', 'Sussurando para os espirítos da natureza, você cria um dos seguintes efeitos dentro do alcance:
Um pequeno e inofensivo efeito sensorial que prevê qual será o clima na sua localização nas próximas 24 horas. O efeito pode se manifestar como uma esfera dourada para céu claro, uma nuvem para chuva, flocos de neve caindo para neve, e assim por diante. Esse efeito persiste por uma rodada.
Uma flor desabrocha, uma semente amadurece ou um broto de folha se abre.
Um efeito sensorial inofensivo e instantâneo, como folhas caindo, um sopro de vento, o som de um pequeno animal ou o fraco odor de um gambá. O efeito deve caber em um cubo de 1,5 metro [5-foot cube].
Uma vela, tocha ou fogueira pequena acende ou apaga imediatamente.', '', NULL
FROM public.spells WHERE external_index = 'druidcraft'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Earthquake
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('earthquake', 8, 'evocation', 'action', 1, 500, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'druid', 'sorcerer'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Earthquake', 'You create a seismic disturbance at a point on the ground that you can see within range. For the duration, an intense tremor rips through the ground in a 100-foot-radius circle centered on that point and shakes creatures and structures in contact with the ground in that area.
The ground in the area becomes difficult terrain. Each creature on the ground that is concentrating must make a constitution saving throw. On a failed save, the creature''s concentration is broken.
When you cast this spell and at the end of each turn you spend concentrating on it, each creature on the ground in the area must make a dexterity saving throw. On a failed save, the creature is knocked prone.
This spell can have additional effects depending on the terrain in the area, as determined by the GM.
Fissures. Fissures open throughout the spell''s area at the start of your next turn after you cast the spell. A total of 1d6 such fissures open in locations chosen by the GM. Each is 1d10 x 10 feet deep, 10 feet wide, and extends from one edge of the spell''s area to the opposite side. A creature standing on a spot where a fissure opens must succeed on a dexterity saving throw or fall in. A creature that successfully saves moves with the fissure''s edge as it opens.
A fissure that opens beneath a structure causes it to automatically collapse (see below).
Structures. The tremor deals 50 bludgeoning damage to any structure in contact with the ground in the area when you cast the spell and at the start of each of your turns until the spell ends. If a structure drops to 0 hit points, it collapses and potentially damages nearby creatures. A creature within half the distance of a structure''s height must make a dexterity saving throw. On a failed save, the creature takes 5d6 bludgeoning damage, is knocked prone, and is buried in the rubble, requiring a DC 20 Strength (Athletics) check as an action to escape. The GM can adjust the DC higher or lower, depending on the nature of the rubble. On a successful save, the creature takes half as much damage and doesn''t fall prone or become buried.', '', 'A pinch of dirt, a piece of rock, and a lump of clay.'
FROM public.spells WHERE external_index = 'earthquake'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Terremoto', 'Você pode criar uma perturbação sísmica em um ponto no chão, à sua vista e no alcance da magia. Enquanto a magia durar, um intenso tremor rasga o chão em um círculo com raio de 30 metros [100-foot radius] centrado nesse ponto, sacudindo as criaturas e estruturas em contato com o solo nessa área.O terreno na área se torna terreno difícil. Cada criatura em solo afetado e que esteja se concentrando, deve fazer uma salvaguarda de Constituição. Se falhar, a criatura terá a concentração quebrada.Ao conjurar esta magia, e ao final de cada turno que gastar concentrando-se nela, cada criatura no solo da área deve fazer uma salvaguarda de Destreza. Se falhar, a criatura ficará caída.Esta magia pode ter efeitos adicionais, dependendo do terreno na área, conforme determinado pelo DM.Fissuras. Fissuras se abrem por toda a área da magia no início de seu próximo turno, após você ter conjurado a magia. Um total de 1d6 fissuras se abrem em locais escolhidos pelo DM. Cada uma possui 1d10 x 3 metros [10 ft.] de profundidade, 3 metros [10 ft.] de largura, e estendem-se de uma borda da área da magia até o lado oposto. Uma criatura em pé em um lugar onde a fissura se abre deve ser bem-sucedida em uma salvaguarda de Destreza ou cairá nela. Uma criatura bem-sucedida move-se com a borda da fissura quando esta se abre.Uma fissura que se abre debaixo de uma estrutura provoca automaticamente o seu colapso (veja a seguir).Estruturas. Assim que você conjura a magia e no começo de cada um dos seus turnos, enquanto a magia durar, o tremor causa 50 pontos de dano contundente em qualquer estrutura em contato com o chão na área atingida. Se uma estrutura chegar a 0 pontos de vida, ela entra em colapso e, potencialmente, provoca danos às criaturas próximas. Uma criatura dentro da metade da distância da altura da estrutura deve fazer uma salvaguarda de Destreza. Se falhar, sofre 5d6 pontos de dano contundente, fica caída e soterrada nos escombros, exigindo um teste de Força com CD 20 (Atletismo) como uma ação para escapar. O DM pode ajustar a CD para mais ou para menos, dependendo da natureza dos escombros. Com um teste bem-sucedido, a criatura sofre metade do dano e não fica caída ou soterrada.', '', NULL
FROM public.spells WHERE external_index = 'earthquake'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Eldritch Blast
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('eldritch-blast', 0, 'evocation', 'action', 1, 120, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['warlock'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Eldritch Blast', 'A beam of crackling energy streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 force damage. The spell creates more than one beam when you reach higher levels: two beams at 5th level, three beams at 11th level, and four beams at 17th level. You can direct the beams at the same target or at different ones. Make a separate attack roll for each beam.', '', NULL
FROM public.spells WHERE external_index = 'eldritch-blast'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Raio Místico', 'Um raio de energia crepitante salta na direção de uma criatura dentro do alcance da magia. Faça um ataque mágico à distância contra o alvo. Se acertar, o alvo sofre 1d10 pontos de dano energético.
A magia cria mais de um raio quando você atinge níveis mais elevados: dois raios no 5º nível, três raios no 11º nível, e quatro raios no 17º nível. Você pode direcionar os raios contra o mesmo alvo ou contra alvos diferentes. Faça uma jogada de ataque separada para cada raio.', '', NULL
FROM public.spells WHERE external_index = 'eldritch-blast'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Enhance Ability
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('enhance-ability', 2, 'transmutation', 'action', 1, NULL, 'touch', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'druid', 'sorcerer'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Enhance Ability', 'You touch a creature and bestow upon it a magical enhancement. Choose one of the following effects; the target gains that effect until the spell ends.
***Bear''s Endurance.*** The target has advantage on constitution checks. It also gains 2d6 temporary hit points, which are lost when the spell ends.
***Bull''s Strength.*** The target has advantage on strength checks, and his or her carrying capacity doubles.
***Cat''s Grace.*** The target has advantage on dexterity checks. It also doesn''t take damage from falling 20 feet or less if it isn''t incapacitated.
***Eagle''s Splendor.*** The target has advantage on Charisma checks.
***Fox''s Cunning.*** The target has advantage on intelligence checks.
***Owl''s Wisdom.*** The target has advantage on wisdom checks.', 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.', 'Fur or a feather from a beast.'
FROM public.spells WHERE external_index = 'enhance-ability'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Aprimorar Atributo', 'Você toca uma criatura e lança sobre ela um aperfeiçoamento mágico. Escolha um dos efeitos a seguir; o alvo ganha esse efeito enquanto a magia durar.
Astúcia da Raposa. O alvo tem vantagem nos testes de Inteligência.
Elegância do Gato. O alvo tem vantagem nos testes de Destreza. Ele também não sofre dano por queda ao cair 6 metros [20 ft.] ou menos, caso não esteja incapacitado.
Esplendor da Águia. O alvo tem vantagem nos testes de Carisma.
Força do Touro. O alvo tem vantagem nos testes de Força e dobra a capacidade de carga.
Resistência do Urso. O alvo tem vantagem nos testes de Constituição. Ele também ganha 2d6 pontos de vida temporários que são perdidos ao término da magia.
Sabedoria da Coruja. O alvo tem vantagem nos testes de Sabedoria.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 3º círculo ou superior, você pode atingir uma criatura adicional para cada círculo do espaço acima do 2º.', '', NULL
FROM public.spells WHERE external_index = 'enhance-ability'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Enlarge/Reduce
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('enlarge-reduce', 2, 'transmutation', 'action', 1, 30, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Enlarge/Reduce', 'You cause a creature or an object you can see within range to grow larger or smaller for the duration. Choose either a creature or an object that is neither worn nor carried. If the target is unwilling, it can make a Constitution saving throw. On a success, the spell has no effect.
If the target is a creature, everything it is wearing and carrying changes size with it. Any item dropped by an affected creature returns to normal size at once.
***Enlarge.*** The target''s size doubles in all dimensions, and its weight is multiplied by eight. This growth increases its size by one category-from Medium to Large, for example. If there isn''t enough room for the target to double its size, the creature or object attains the maximum possible size in the space available. Until the spell ends, the target also has advantage on Strength checks and Strength saving throws. The target''s weapons also grow to match its new size. While these weapons are enlarged, the target''s attacks with them deal 1d4 extra damage.
***Reduce.*** The target''s size is halved in all dimensions, and its weight is reduced to one-eighth of normal. This reduction decreases its size by one category-from Medium to Small, for example. Until the spell ends, the target also has disadvantage on Strength checks and Strength saving throws. The target''s weapons also shrink to match its new size. While these weapons are reduced, the target''s attacks with them deal 1d4 less damage (this can''t reduce the damage below 1).', '', 'A pinch iron powder.'
FROM public.spells WHERE external_index = 'enlarge-reduce'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Aumentar/Reduzir', 'Você faz com que uma criatura ou um objeto, à sua vista e dentro do alcance da magia, fique maior ou menor enquanto a magia durar. Escolha uma criatura ou um objeto que não esteja sendo usado ou carregado. Se o alvo não for voluntário, ele pode fazer uma salvaguarda de Constituição. Em caso de sucesso, a magia não surte efeito.
Se o alvo for uma criatura, tudo o que estiver usando e carregando muda de tamanho junto com ela. Qualquer item descartado por uma criatura afetada por esta magia retorna, imediatamente, ao tamanho normal.
Aumentar. O tamanho do alvo dobra em todas as dimensões, e o peso é multiplicado por oito. O tamanho aumenta em uma categoria - de Médio para Grande, por exemplo. Se não houver espaço suficiente para o alvo dobrar o próprio tamanho, ele atinge o tamanho máximo possível no espaço disponível. Enquanto a magia durar, o alvo também tem vantagem em testes de Força e salvaguardas de Força. As armas dele também crescem para combinar com o novo tamanho. Se o alvo realizar um ataque bem-sucedido com essas armas, elas causam 1d4 pontos de dano a mais do que o normal da arma enquanto estiverem ampliadas.
Reduzir. O tamanho do alvo é reduzido à metade em todas as dimensões, e o peso é reduzido para um oitavo do normal. Essa redução diminui o tamanho do alvo em uma categoria - de Médio para Pequeno, por exemplo. Enquanto a magia durar, o alvo tem desvantagem em testes de Força e salvaguardas de Força. As armas dele também encolhem para combinar com o novo tamanho. Se o alvo realizar um ataque bem-sucedido com essas armas, elas causam 1d4 pontos de dano a menos que o normal da arma enquanto estiverem reduzidas (o dano mínimo é 1).', '', NULL
FROM public.spells WHERE external_index = 'enlarge-reduce'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Entangle
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('entangle', 1, 'conjuration', 'action', 1, 90, 'feet', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Entangle', 'Grasping weeds and vines sprout from the ground in a 20-foot square starting form a point within range. For the duration, these plants turn the ground in the area into difficult terrain.
A creature in the area when you cast the spell must succeed on a strength saving throw or be restrained by the entangling plants until the spell ends. A creature restrained by the plants can use its action to make a Strength check against your spell save DC. On a success, it frees itself.
When the spell ends, the conjured plants wilt away.', '', NULL
FROM public.spells WHERE external_index = 'entangle'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Emaranhar', 'Ervas daninhas e vinhas aderentes brotam do chão em um quadrado de 6 metros de lado [20-foot square] a partir de um ponto no alcance da magia. Enquanto a magia durar, as plantas transformam o solo da área em terreno difícil.
Qualquer criatura na área, que não for bem-sucedida em uma salvaguarda de Força, fica contida pelas plantas constritoras enquanto a magia durar. Uma criatura contida pelas plantas pode usar uma ação para fazer um teste de Força contra a CD para evitar sua magia. Em caso de sucesso, ela se liberta.
Quando a magia termina, as plantas invocadas murcham.', '', NULL
FROM public.spells WHERE external_index = 'entangle'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Enthrall
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('enthrall', 2, 'enchantment', 'action', 1, 60, 'feet', 1, 'minute', false, false, ARRAY['V', 'S'], ARRAY['bard', 'warlock'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Enthrall', 'You weave a distracting string of words, causing creatures of your choice that you can see within range and that can hear you to make a wisdom saving throw. Any creature that can''t be charmed succeeds on this saving throw automatically, and if you or your companions are fighting a creature, it has advantage on the save. On a failed save, the target has disadvantage on Wisdom (Perception) checks made to perceive any creature other than you until the spell ends or until the target can no longer hear you. The spell ends if you are incapacitated or can no longer speak.', '', NULL
FROM public.spells WHERE external_index = 'enthrall'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Cativar', 'Você dita uma sequência de palavras dispersivas, fazendo com que criaturas à sua escolha, à sua vista, dentro do alcance da magia e que possam ouvi-lo, façam uma salvaguarda de Sabedoria. Qualquer criatura que não possa ser enfeitiçada é automaticamente bem-sucedida na salvaguarda, e se você ou seus companheiros estiverem combatendo a criatura alvo, ela tem vantagem nesse teste. Se falhar, o alvo tem desvantagem nos testes de Sabedoria (Percepção) para perceber qualquer outra criatura que não seja o conjurador, enquanto a magia durar ou até que o alvo não consiga mais ouvi-lo. A magia termina se você estiver incapacitado ou se não puder mais falar.', '', NULL
FROM public.spells WHERE external_index = 'enthrall'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Etherealness
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('etherealness', 7, 'transmutation', 'action', 1, NULL, 'self', 8, 'hour', false, false, ARRAY['V', 'S'], ARRAY['bard', 'cleric', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Etherealness', 'You step into the border regions of the Ethereal Plane, in the area where it overlaps with your current plane. You remain in the Border Ethereal for the duration or until you use your action to dismiss the spell. During this time, you can move in any direction. If you move up or down, every foot of movement costs an extra foot. You can see and hear the plane you originated from, but everything there looks gray, and you can''t see anything more than 60 feet away.
While on the Ethereal Plane, you can only affect and be affected by other creatures on that plane. Creatures that aren''t on the Ethereal Plane can''t perceive you and can''t interact with you, unless a special ability or magic has given them the ability to do so.
You ignore all objects and effects that aren''t on the Ethereal Plane, allowing you to move through objects you perceive on the plane you originated from.
When the spell ends, you immediately return to the plane you originated from in the spot you currently occupy. If you occupy the same spot as a solid object or creature when this happens, you are immediately shunted to the nearest unoccupied space that you can occupy and take force damage equal to twice the number of feet you are moved.
This spell has no effect if you cast it while you are on the Ethereal Plane or a plane that doesn''t border it, such as one of the Outer Planes.', 'When you cast this spell using a spell slot of 8th level or higher, you can target up to three willing creatures (including you) for each slot level above 7th. The creatures must be within 10 feet of you when you cast the spell.', NULL
FROM public.spells WHERE external_index = 'etherealness'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Forma Etérea', 'Você adentra as regiões fronteiriças de Plano Etéreo, na área onde ele se sobrepõe ao seu plano atual. Você permanece na Fronteira Etérea enquanto a magia durar ou até que você use sua ação para dispensar a magia. Durante esse tempo, você pode se mover em qualquer direção. Se você se mover para cima ou para baixo, cada 0,3 metro [1 foot] de deslocamento custa 0,6 metro [2 ft.]. Você pode ver e ouvir o plano do qual é originário, mas tudo parece cinza e nada pode ser visto a mais de 18 metros [60 ft.] de distância.
Enquanto estiver no Plano Etéreo, você só pode afetar e ser afetado por outras criaturas nesse plano. Criaturas que não estejam no Plano Etéreo não podem percebê-lo e nem interagir com você, a menos que uma habilidade especial ou mágica lhes dê essa capacidade.
Você ignora todos os objetos e efeitos que não estejam no Plano Etéreo, o que lhe permite mover-se através de objetos que você perceba no plano do qual é originário.
Ao término da magia, você retorna imediatamente ao seu plano de origem, no lugar que está ocupando no momento. Se ocupar o mesmo lugar de um objeto ou criatura quando isso acontecer, você é imediatamente desviado para o espaço desocupado mais próximo que puder ocupar, sofrendo 10 pontos de dano energético a cada 1,5 metro [5 ft.] percorrido.
Esta magia não tem nenhum efeito se você conjurá-la enquanto estiver no Plano Etéreo ou em um plano que não faça fronteira com ele, como um dos Planos Externos.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 8º círculo ou superior, você pode atingir até três criaturas (incluindo você mesmo) para cada círculo do espaço acima do 7º. As criaturas devem estar a até 3 metros [10 ft.] de você quando esta magia for conjurada.', '', NULL
FROM public.spells WHERE external_index = 'etherealness'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Expeditious Retreat
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('expeditious-retreat', 1, 'transmutation', 'bonus_action', 1, NULL, 'self', 10, 'minute', true, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Expeditious Retreat', 'This spell allows you to move at an incredible pace. When you cast this spell, and then as a bonus action on each of your turns until the spell ends, you can take the Dash action.', '', NULL
FROM public.spells WHERE external_index = 'expeditious-retreat'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Retirada Acelerada', 'Esta magia permite que você se mova em um ritmo incrível. Ao conjurá-la, e depois com uma ação bônus em cada um dos seus turnos até a magia se encerrar, você pode executar a ação Correr.', '', NULL
FROM public.spells WHERE external_index = 'expeditious-retreat'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Eyebite
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('eyebite', 6, 'necromancy', 'action', 1, NULL, 'self', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Eyebite', 'For the spell''s duration, your eyes become an inky void imbued with dread power. One creature of your choice within 60 feet of you that you can see must succeed on a wisdom saving throw or be affected by one of the following effects of your choice for the duration. On each of your turns until the spell ends, you can use your action to target another creature but can''t target a creature again if it has succeeded on a saving throw against this casting of eyebite.
***Asleep.*** The target falls unconscious. It wakes up if it takes any damage or if another creature uses its action to shake the sleeper awake.
***Panicked.*** The target is frightened of you. On each of its turns, the frightened creature must take the Dash action and move away from you by the safest and shortest available route, unless there is nowhere to move. If the target moves to a place at least 60 feet away from you where it can no longer see you, this effect ends.
***Sickened.*** The target has disadvantage on attack rolls and ability checks. At the end of each of its turns, it can make another wisdom saving throw. If it succeeds, the effect ends.', '', NULL
FROM public.spells WHERE external_index = 'eyebite'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Mau Olhado', 'Enquanto a magia durar, seus olhos tornam-se um vazio escuro imbuído com um poder aterrorizante. Escolha uma criatura à sua vista e que esteja a até 18 metros [60 ft.] de você, que deverá ser bem-sucedida em uma salvaguarda de Sabedoria ou será afetada por um dos efeitos a seguir, à sua escolha, enquanto a magia durar. Em cada um de seus turnos, até a magia terminar, você pode usar sua ação para atingir outra criatura, mas não pode ter como alvo uma criatura novamente se ela for bem-sucedida em uma salvaguarda contra esta conjuração de Mau Olhado.
Adormecer. O alvo fica inconsciente. Ele acorda ao sofrer algum dano ou se outra criatura usar a ação dela para sacudi-lo até acordá-lo.
Apavorard. O alvo fica amedrontado por você. Em cada um dos turnos dele, o alvo amedrontado deve executar a ação Correr e afastar-se de você pela rota mais segura e curta disponível, a menos que não haja nenhum lugar para onde ir. Se ele se dirigir para um local a pelo menos 18 metros [60 ft.] de você, de onde não possa mais vê-lo, este efeito termina.
Adoecer. O alvo tem desvantagem nas jogadas de ataque e testes de atributo. No final de cada um dos turnos dele, o alvo pode fazer outra salvaguarda de Sabedoria. Se for bem-sucedido, o efeito termina.', '', NULL
FROM public.spells WHERE external_index = 'eyebite'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Fabricate
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('fabricate', 4, 'transmutation', 'minute', 10, 120, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Fabricate', 'You convert raw materials into products of the same material. For example, you can fabricate a wooden bridge from a clump of trees, a rope from a patch of hemp, and clothes from flax or wool.
Choose raw materials that you can see within range. You can fabricate a Large or smaller object (contained within a 10-foot cube, or eight connected 5-foot cubes), given a sufficient quantity of raw material. If you are working with metal, stone, or another mineral substance, however, the fabricated object can be no larger than Medium (contained within a single 5-foot cube). The quality of objects made by the spell is commensurate with the quality of the raw materials.
Creatures or magic items can''t be created or transmuted by this spell. You also can''t use it to create items that ordinarily require a high degree of craftsmanship, such as jewelry, weapons, glass, or armor, unless you have proficiency with the type of artisan''s tools used to craft such objects.', '', NULL
FROM public.spells WHERE external_index = 'fabricate'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Fabricar', 'Você transforma matérias-primas em produtos do mesmo material. Por exemplo, você pode fabricar uma ponte de madeira a partir de um monte de árvores, uma corda a partir de um pedaço de cânhamo, e roupas a partir do linho ou lã.
Escolha uma matéria prima à sua vista e no alcance da magia. Você pode fabricar um objeto de tamanho Grande ou menor (que caiba dentro de um cubo de 3 metros [10 ft.], ou oito cubos de 1,5 metro [5 ft.] conectados), desde que haja matéria prima suficiente. Se você estiver trabalhando com metal, pedra ou outra substância mineral, todavia, o objeto fabricado não pode ser maior que Médio (contido em um cubo de 1,5 [5 ft.] metro). A qualidade dos objetos feitos pela magia depende da qualidade da matéria-prima.
Criaturas ou itens mágicos não podem ser criados ou transmutados por meio desta magia. Você também não pode usá-la para criar itens que ordinariamente exijam alto grau de manufatura, como joias, armas, vidro ou armadura, a não ser que tenha proficiência com o tipo de ferramentas de artesão necessárias para fabricar tais objetos.', '', NULL
FROM public.spells WHERE external_index = 'fabricate'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
