INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Faerie Fire', 'Each object in a 20-foot cube within range is outlined in blue, green, or violet light (your choice). Any creature in the area when the spell is cast is also outlined in light if it fails a dexterity saving throw. For the duration, objects and affected creatures shed dim light in a 10-foot radius.
Any attack roll against an affected creature or object has advantage if the attacker can see it, and the affected creature or object can''t benefit from being invisible.', '', NULL
FROM public.spells WHERE external_index = 'faerie-fire'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Fogo das Fadas', 'Todos os objetos em um cubo de 6 metros [20-foot cube] no alcance da magia se tornam delineados por uma luz azul, verde ou violeta (à sua escolha). Qualquer criatura que esteja na área quando a magia for conjurada também é delineada pela luz, caso falhe em uma salvaguarda de Destreza. Enquanto a magia durar, objetos e criaturas afetadas por ela emitem uma luz tênue, criando meia-luz em um raio de 3 metros [10-foot radius].
Qualquer jogada de ataque contra uma criatura ou objeto afetado tem vantagem, caso o atacante possa vê-los. Objetos e criaturas afetados não podem se beneficiar por estarem invisíveis.', '', NULL
FROM public.spells WHERE external_index = 'faerie-fire'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Faithful Hound
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('faithful-hound', 4, 'conjuration', 'action', 1, 30, 'feet', 8, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Faithful Hound', 'You conjure a phantom watchdog in an unoccupied space that you can see within range, where it remains for the duration, until you dismiss it as an action, or until you move more than 100 feet away from it.
The hound is invisible to all creatures except you and can''t be harmed. When a Small or larger creature comes within 30 feet of it without first speaking the password that you specify when you cast this spell, the hound starts barking loudly. The hound sees invisible creatures and can see into the Ethereal Plane. It ignores illusions.
At the start of each of your turns, the hound attempts to bite one creature within 5 feet of it that is hostile to you. The hound''s attack bonus is equal to your spellcasting ability modifier + your proficiency bonus. On a hit, it deals 4d8 piercing damage.', '', 'A tiny silver whistle, a piece of bone, and a thread'
FROM public.spells WHERE external_index = 'faithful-hound'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Cão Fiel', 'Você conjura um cão de guarda fantasma em um espaço desocupado à sua vista, no alcance da magia, onde ele permanece enquanto a magia durar, até você dispensá-lo com uma ação, ou até você se mover a mais de 30 metros [100 ft.] dele.
O cão é invisível para todas as criaturas, exceto para você e não pode ser ferido. Quando uma criatura Pequena ou maior se aproximar a até 9 metros [30 ft.] do cão, sem primeiro dizer a senha que você especifica ao conjurar a magia, ele começa a latir alto. O cão enxerga criaturas invisíveis e pode ver no Plano Etéreo. Ele ignora ilusões.
No início de cada um de seus turnos, o cão tenta morder uma criatura hostil à você que esteja a até 1,5 metro [5 ft.] dele. O bônus de ataque do cão é igual ao seu modificador de atributo de conjuração + seu bônus de proficiência. Se acertar, ele causa 4d8 pontos de dano perfurante.', '', NULL
FROM public.spells WHERE external_index = 'faithful-hound'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- False Life
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('false-life', 1, 'necromancy', 'action', 1, NULL, 'self', 1, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
