INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'False Life', 'Bolstering yourself with a necromantic facsimile of life, you gain 1d4 + 4 temporary hit points for the duration.', 'When you cast this spell using a spell slot of 2nd level or higher, you gain 5 additional temporary hit points for each slot level above 1st.', 'A small amount of alcohol or distilled spirits.'
FROM public.spells WHERE external_index = 'false-life'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Vitalidade Vazia', 'Você instila em si mesmo um arremedo necromântico de vida, ganhando 1d4+4 pontos de vida temporários enquanto a magia durar.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, você ganha 5 pontos de vida temporários para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'false-life'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
