INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('fear', 3, 'illusion', 'action', 1, NULL, 'self', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Fear', 'You project a phantasmal image of a creature''s worst fears. Each creature in a 30-foot cone must succeed on a wisdom saving throw or drop whatever it is holding and become frightened for the duration.
While frightened by this spell, a creature must take the Dash action and move away from you by the safest available route on each of its turns, unless there is nowhere to move. If the creature ends its turn in a location where it doesn''t have line of sight to you, the creature can make a wisdom saving throw. On a successful save, the spell ends for that creature.', '', 'A white feather or the heart of a hen.'
FROM public.spells WHERE external_index = 'fear'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Medo', 'Você projeta uma imagem fantasmagórica dos piores medos de uma criatura. Cada criatura num cone de 9 metros [30 ft.] deve ser bem-sucedida numa salvaguarda de Sabedoria ou derrubará o que estiver segurando e ficará amedrontada enquanto a magia durar.
Em cada um dos turnos dela, a criatura deve executar a ação Correr e distanciar-se o máximo que puder de você pela rota mais segura disponível, a menos que não haja para onde ir. Se a criatura finalizar o turno dela em um local onde não possa mais vê-lo, ela pode fazer uma salvaguarda de Sabedoria. Em caso de sucesso, a magia se encerra para ela.', '', NULL
FROM public.spells WHERE external_index = 'fear'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
