INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('feather-fall', 1, 'transmutation', 'reaction', 1, 60, 'feet', 1, 'minute', false, false, ARRAY['V', 'M'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Feather Fall', 'Choose up to five falling creatures within range. A falling creature''s rate of descent slows to 60 feet per round until the spell ends. If the creature lands before the spell ends, it takes no falling damage and can land on its feet, and the spell ends for that creature.', '', 'A small feather or a piece of down.'
FROM public.spells WHERE external_index = 'feather-fall'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Queda Suave', 'Escolha até cinco criaturas no alcance da magia e que estejam caindo. A velocidade de queda de uma criatura é reduzida para 18 metros [60 ft.] por rodada enquanto a magia durar. Se a criatura pousar antes do fim da magia, não sofrerá dano por queda, podendo aterrissar em pé, e a magia se encerra para ela.', '', NULL
FROM public.spells WHERE external_index = 'feather-fall'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Feeblemind
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('feeblemind', 8, 'enchantment', 'action', 1, 150, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'druid', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Feeblemind', 'You blast the mind of a creature that you can see within range, attempting to shatter its intellect and personality. The target takes 4d6 psychic damage and must make an intelligence saving throw.
On a failed save, the creature''s Intelligence and Charisma scores become 1. The creature can''t cast spells, activate magic items, understand language, or communicate in any intelligible way. The creature can, however, identify its friends, follow them, and even protect them.
At the end of every 30 days, the creature can repeat its saving throw against this spell. If it succeeds on its saving throw, the spell ends.
The spell can also be ended by greater restoration, heal, or wish.', '', 'A handful of clay, crystal, glass, or mineral spheres.'
FROM public.spells WHERE external_index = 'feeblemind'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Enfraquecer Intelecto', 'Você assola a mente de uma criatura à sua vista e no alcance da magia, tentando despedaçar o intelecto e a personalidade dela. O alvo sofre 4d6 pontos de dano psíquico e deve fazer uma salvaguarda de Inteligência.
Se falhar, o valor da Inteligência e do Carisma da criatura passa a ser 1. A criatura não pode conjurar magias, ativar itens mágicos, compreender idiomas ou se comunicar de forma inteligível. Ela pode identificar seus próprios amigos, segui-los e até protegê-los.
Ao final de um período de 30 dias, a criatura pode repetir a salvaguarda contra a magia. Em caso de sucesso, a magia se encerra.
Ela também pode ser anulada por Restauração Maior, Cura Completa ou Desejo.', '', NULL
FROM public.spells WHERE external_index = 'feeblemind'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Find Familiar
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('find-familiar', 1, 'conjuration', 'hour', 1, 10, 'feet', NULL, 'instantaneous', false, true, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Find Familiar', 'You gain the service of a familiar, a spirit that takes an animal form you choose: bat, cat, crab, frog (toad), hawk, lizard, octopus, owl, poisonous snake, fish (quipper), rat, raven, sea horse, spider, or weasel. Appearing in an unoccupied space within range, the familiar has the statistics of the chosen form, though it is a celestial, fey, or fiend (your choice) instead of a beast.
Your familiar acts independently of you, but it always obeys your commands. In combat, it rolls its own initiative and acts on its own turn. A familiar can''t attack, but it can take other actions as normal.
When the familiar drops to 0 hit points, it disappears, leaving behind no physical form. It reappears after you cast this spell again.
While your familiar is within 100 feet of you, you can communicate with it telepathically. Additionally, as an action, you can see through your familiar''s eyes and hear what it hears until the start of your next turn, gaining the benefits of any special senses that the familiar has. During this time, you are deaf and blind with regard to your own senses.
As an action, you can temporarily dismiss your familiar. It disappears into a pocket dimension where it awaits your summons. Alternatively, you can dismiss it forever. As an action while it is temporarily dismissed, you can cause it to reappear in any unoccupied space within 30 feet of you.
You can''t have more than one familiar at a time. If you cast this spell while you already have a familiar, you instead cause it to adopt a new form. Choose one of the forms from the above list. Your familiar transforms into the chosen creature.
Finally, when you cast a spell with a range of touch, your familiar can deliver the spell as if it had cast the spell. Your familiar must be within 100 feet of you, and it must use its reaction to deliver the spell when you cast it. If the spell requires an attack roll, you use your action modifier for the roll.', '', '10gp worth of charcoal, incense, and herbs that must be consumed by fire in a brass brazier.'
FROM public.spells WHERE external_index = 'find-familiar'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Convocar Familiar', 'Você passa a contar com os serviços de um familiar, um espírito que assume a forma de um animal à sua escolha: morcego, gato, caranguejo, sapo (rã), falcão, lagarto, polvo, coruja, cobra venenosa, peixe (piranha), rato, corvo, cavalo marinho, aranha ou furão. Aparecendo em um espaço desocupado dentro do alcance da magia, o familiar tem as estatísticas da forma escolhida, apesar de ser um celestial, feérico ou ínfero (à sua escolha), em vez de uma fera.
Seu familiar age independentemente de você, mas ele sempre obedece aos seus comandos. Em combate, joga a própria iniciativa e age no próprio turno. Um familiar não pode atacar, mas pode realizar outras ações normalmente.
Ao ficar com 0 pontos de vida, ele desaparece, não deixando forma física alguma para trás. O familiar reaparece após você conjurar esta magia novamente.
Enquanto seu familiar estiver a até 30 metros [100 ft.] de você, é possível se comunicar telepaticamente com ele. Além disso, com uma ação, você pode ver através dos olhos dele e ouvir o que ele ouve até o começo de seu próximo turno, ganhando os benefícios de quaisquer sentidos especiais que ele tenha. Durante este tempo, você fica surdo e cego no que diz respeito aos seus próprios sentidos.
Com uma ação, você pode dispensar seu familiar temporariamente. Ele desaparece em um bolsão dimensional onde aguarda a sua convocação. Se preferir, você pode dispensá-lo permanentemente. Enquanto o familiar estiver temporariamente dispensado, com uma ação você pode fazer com que ele reapareça em qualquer espaço desocupado a até 9 metros [30 ft.] de você.
Você não pode ter mais de um familiar por vez. Se conjurar esta magia quando já tiver um familiar, você apenas fará com que o seu familiar adote uma nova forma. Escolha uma das formas da lista acima. O seu familiar se transforma na criatura escolhida.
Por fim, quando conjurar uma magia com alcance de toque, seu familiar pode lançar a magia como se ele mesmo a tivesse conjurado. Ele deve estar a até 30 metros [100 ft.] de você, e você deve usar a reação dele para lançar a magia quando a conjurar. Se a magia pedir uma jogada de ataque, use o seu modificador de ataque.', '', NULL
FROM public.spells WHERE external_index = 'find-familiar'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Find Steed
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('find-steed', 2, 'conjuration', 'minute', 10, 30, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['paladin'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Find Steed', 'You summon a spirit that assumes the form of an unusually intelligent, strong, and loyal steed, creating a long-lasting bond with it. Appearing in an unoccupied space within range, the steed takes on a form that you choose, such as a warhorse, a pony, a camel, an elk, or a mastiff. (Your GM might allow other animals to be summoned as steeds.) The steed has the statistics of the chosen form, though it is a celestial, fey, or fiend (your choice) instead of its normal type. Additionally, if your steed has an Intelligence of 5 or less, its Intelligence becomes 6, and it gains the ability to understand one language of your choice that you speak.
Your steed serves you as a mount, both in combat and out, and you have an instinctive bond with it that allows you to fight as a seamless unit. While mounted on your steed, you can make any spell you cast that targets only you also target your steed.
When the steed drops to 0 hit points, it disappears, leaving behind no physical form. You can also dismiss your steed at any time as an action, causing it to disappear. In either case, casting this spell again summons the same steed, restored to its hit point maximum.
While your steed is within 1 mile of you, you can communicate with it telepathically.
You can''t have more than one steed bonded by this spell at a time. As an action, you can release the steed from its bond at any time, causing it to disappear.', '', NULL
FROM public.spells WHERE external_index = 'find-steed'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Convocar Montaria', 'Você invoca um espírito que assume a forma de uma montaria especialmente inteligente, forte e fiel, criando um vínculo de longa duração com ela. Aparecendo em um espaço desocupado dentro do alcance, a montaria toma uma forma à sua escolha: um alce, um camelo, um cavalo de guerra, um mastim ou um pônei (seu DM pode permitir que outros animais sejam conjurados como montarias). A montaria tem as estatísticas da forma escolhida, mas é um celestial, feérico ou ínfero (à sua escolha), em vez do tipo normal. Além disso, se a criatura tiver uma Inteligência igual ou menor que 5, esta se torna 6 e ela adquire a capacidade de entender um idioma que você possa falar, à sua escolha.
Ela serve como sua montaria, tanto em combate quanto fora dele, e vocês têm um elo instintivo que lhes permite lutar como uma unidade perfeita. Enquanto estiver montado na criatura, qualquer magia que você conjurar e que tenha a si mesmo como alvo, afeta também a sua montaria.
Quando a criatura ficar com 0 pontos de vida, ela desaparece, não deixando corpo algum para trás. Você também pode dispensar sua montaria a qualquer momento com uma ação, fazendo-a desaparecer. Em ambos os casos, conjurar esta magia novamente invoca o mesmo animal, restaurado com pontos de vida máximos.
Enquanto sua montaria estiver a até 1,5 quilômetro [1 mile] de você, é possível se comunicar telepaticamente com ela.
Não é possível ter mais de uma montaria vinculada por esta magia ao mesmo tempo. Com uma ação, você pode liberar a montaria de seu vínculo a qualquer momento, fazendo-a desaparecer.', '', NULL
FROM public.spells WHERE external_index = 'find-steed'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Find Traps
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('find-traps', 2, 'divination', 'action', 1, 120, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['cleric', 'druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Find Traps', 'You sense the presence of any trap within range that is within line of sight. A trap, for the purpose of this spell, includes anything that would inflict a sudden or unexpected effect you consider harmful or undesirable, which was specifically intended as such by its creator. Thus, the spell would sense an area affected by the alarm spell, a glyph of warding, or a mechanical pit trap, but it would not reveal a natural weakness in the floor, an unstable ceiling, or a hidden sinkhole.
This spell merely reveals that a trap is present. You don''t learn the location of each trap, but you do learn the general nature of the danger posed by a trap you sense.', '', NULL
FROM public.spells WHERE external_index = 'find-traps'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Encontrar Armadilhas', 'Você sente a presença de qualquer armadilha em sua linha de visão e no alcance da magia. Uma armadilha, para os fins desta magia, inclui qualquer coisa que causaria um efeito repentino ou inesperado que você considera danoso ou indesejado, e que tenha sido especificamente projetada como tal por quem a criou. Assim, a magia sentiria uma área afetada pelas magias Alarme, Glifo de Proteção ou uma armadilha mecânica de fosso, mas não revela uma fraqueza natural no piso, um teto instável ou um sumidouro escondido.O efeito revela apenas se há uma armadilha presente. Você não descobre a localização de cada armadilha, mas passa a saber a natureza geral do perigo imposto pela armadilha que você sente.', '', NULL
FROM public.spells WHERE external_index = 'find-traps'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Find the Path
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('find-the-path', 6, 'divination', 'minute', 1, NULL, 'self', 24, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Find the Path', 'This spell allows you to find the shortest, most direct physical route to a specific fixed location that you are familiar with on the same plane of existence. If you name a destination on another plane of existence, a destination that moves (such as a mobile fortress), or a destination that isn''t specific (such as "a green dragon''s lair"), the spell fails.
For the duration, as long as you are on the same plane of existence as the destination, you know how far it is and in what direction it lies. While you are traveling there, whenever you are presented with a choice of paths along the way, you automatically determine which path is the shortest and most direct route (but not necessarily the safest route) to the destination.', '', 'A set of divinatory tools--such as bones, ivory sticks, cards, teeth, or carved runes--worth 100gp and an object from the location you wish to find.'
FROM public.spells WHERE external_index = 'find-the-path'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Encontrar o Caminho', 'Esta magia permite que você encontre a rota física mais curta e direta até uma localidade específica que lhe seja familiar, no mesmo plano de existência. Se você nomear um destino em outro plano, um destino móvel (uma fortaleza móvel) ou uma localidade não específica (como "um covil de um dragão verde" ), a magia falha.
Enquanto a magia durar e você estiver no mesmo plano de existência que seu destino, você sabe quão longe e em qual direção ele está. Enquanto estiver a caminho de lá, toda vez que lhe for apresentada uma escolha de caminhos, você automaticamente sabe determinar qual o mais curto e direto (mas não necessariamente o mais seguro) até o destino.', '', NULL
FROM public.spells WHERE external_index = 'find-the-path'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Finger of Death
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('finger-of-death', 7, 'necromancy', 'action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Finger of Death', 'You send negative energy coursing through a creature that you can see within range, causing it searing pain. The target must make a constitution saving throw. It takes 7d8 + 30 necrotic damage on a failed save, or half as much damage on a successful one.
A humanoid killed by this spell rises at the start of your next turn as a zombie that is permanently under your command, following your verbal orders to the best of its ability.', '', NULL
FROM public.spells WHERE external_index = 'finger-of-death'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Dedo da Morte', 'Você descarrega energia negativa em uma criatura à sua vista e no alcance da magia, causando-lhe fortes dores. O alvo deve fazer uma salvaguarda de Constituição. Se falhar, sofre 7d8+30 pontos de dano necrótico, ou metade do dano em caso de sucesso.
Um humanoide morto por esta magia levanta-se, no início do seu próximo turno, como um zumbi que esta permanentemente sob o seu comando, seguindo suas ordens verbais da melhor forma possível.', '', NULL
FROM public.spells WHERE external_index = 'finger-of-death'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Fire Bolt
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('fire-bolt', 0, 'evocation', 'action', 1, 120, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Fire Bolt', 'You hurl a mote of fire at a creature or object within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 fire damage. A flammable object hit by this spell ignites if it isn''t being worn or carried.
This spell''s damage increases by 1d10 when you reach 5th level (2d10), 11th level (3d10), and 17th level (4d10).', '', NULL
FROM public.spells WHERE external_index = 'fire-bolt'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Raio de Fogo', 'Você lança uma faísca de fogo em uma criatura ou objeto no alcance da magia. Faça um ataque mágico à distância contra o alvo. Se acertar, o alvo sofre 1d1O pontos de dano ígneo. Um objeto inflamável atingido por esta magia inflama-se caso não esteja sendo vestido ou carregado.
O dano desta magia aumenta em 1d10 quando você alcança o 5º nível (2d10), o 11º nível (3d10) e o 17º nível (4d10).', '', NULL
FROM public.spells WHERE external_index = 'fire-bolt'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Fire Shield
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('fire-shield', 4, 'evocation', 'action', 1, NULL, 'self', 10, 'minute', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Fire Shield', 'Thin and vaporous flame surround your body for the duration of the spell, radiating a bright light bright light in a 10-foot radius and dim light for an additional 10 feet. You can end the spell using an action to make it disappear.
The flames are around you a heat shield or cold, your choice. The heat shield gives you cold damage resistance and the cold resistance to fire damage.
In addition, whenever a creature within 5 feet of you hits you with a melee attack, flames spring from the shield. The attacker then suffers 2d8 points of fire damage or cold, depending on the model.', '', 'A little phosphorus or a firefly.'
FROM public.spells WHERE external_index = 'fire-shield'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Escudo Ardente', 'Chamas finas e bruxuleantes recobrem seu corpo enquanto a magia durar, emitindo luz plena em um raio de 3 metros [10 ft.] e meia-luz por 3 metros adicionais. A magia termina antecipadamente quando você usa uma ação para dissipá-la.
As labaredas proporcionam a você um escudo ígneo ou um escudo gélido, à sua escolha. O escudo ígneo lhe confere resistência contra dano gélido e o escudo gélido fornece resistência contra dano ígneo.
Além disso, sempre que uma criatura a menos de 1,5 metros [5 ft.] de você acertá-lo com um ataque corpo a corpo, o escudo entra em erupção flamejante. O atacante sofre 2d8 pontos de dano ígneo de um escudo ígneo e 2d8 pontos de dano gélido de um escudo gélido.', '', NULL
FROM public.spells WHERE external_index = 'fire-shield'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Fire Storm
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('fire-storm', 7, 'evocation', 'action', 1, 150, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['cleric', 'druid', 'sorcerer'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Fire Storm', 'A storm made up of sheets of roaring flame appears in a location you choose within range. The area of the storm consists of up to ten 10-foot cubes, which you can arrange as you wish. Each cube must have at least one face adjacent to the face of another cube. Each creature in the area must make a dexterity saving throw. It takes 7d10 fire damage on a failed save, or half as much damage on a successful one.
The fire damages objects in the area and ignites flammable objects that aren''t being worn or carried. If you choose, plant life in the area is unaffected by this spell.', '', NULL
FROM public.spells WHERE external_index = 'fire-storm'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Tempestade de Fogo', 'Uma tempestade feita de camadas crepitantes de chamas aparece em uma localização à sua escolha e no alcance da magia. A área da tempestade consiste em até 10 cubos de 3 metros [10-foot cubes], que você pode arranjar como quiser. Cada cubo deve ter ao menos uma face adjacente à face de outro cubo. Cada criatura na área deve fazer uma salvaguarda de Destreza. Se falhar, sofre 7d10 pontos de dano ígneo, ou metade do dano em caso de sucesso.
O fogo danifica objetos na área e incendeia objetos inflamáveis que não estejam sendo usados ou carregados. Você pode determinar que a vida vegetal na área não seja afetada por esta magia.', '', NULL
FROM public.spells WHERE external_index = 'fire-storm'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Fireball
