ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Fireball', 'A bright streak flashes from your pointing finger to a point you choose within range and then blossoms with a low roar into an explosion of flame. Each creature in a 20-foot-radius sphere centered on that point must make a dexterity saving throw. A target takes 8d6 fire damage on a failed save, or half as much damage on a successful one.
The fire spreads around corners. It ignites flammable objects in the area that aren''t being worn or carried.', 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', 'A tiny ball of bat guano and sulfur.'
FROM public.spells WHERE external_index = 'fireball'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Bola de Fogo', 'Um rastro brilhante lampeja do seu dedo apontado para um local à sua escolha e no alcance da magia, onde desabrocha com um estrondo grave em uma explosão de chamas. Cada criatura em uma esfera com raio de 6 metros [20-foot-radius sphere], centrada naquele ponto, deve fazer uma salvaguarda de Destreza. Se falhar, sofre 8d6 pontos de dano ígneo, ou metade do dano em caso de sucesso.
O fogo se alastra, contornando os cantos. Ele incendeia objetos inflamáveis na área que não estejam sendo usados ou carregados.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 4º círculo ou superior, o dano aumenta em 1d6 para cada círculo do espaço acima do 3º.', '', NULL
FROM public.spells WHERE external_index = 'fireball'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Flame Blade
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('flame-blade', 2, 'evocation', 'bonus_action', 1, NULL, 'self', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Flame Blade', 'You evoke a fiery blade in your free hand. The blade is similar in size and shape to a scimitar, and it lasts for the duration. If you let go of the blade, it disappears, but you can evoke the blade again as a bonus action.
You can use your action to make a melee spell attack with the fiery blade. On a hit, the target takes 3d6 fire damage.
The flaming blade sheds bright light in a 10-foot radius and dim light for an additional 10 feet.', 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for every two slot levels above 2nd.', 'Leaf of sumac.'
FROM public.spells WHERE external_index = 'flame-blade'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Lâmina Flamejante', 'Você evoca uma lâmina de fogo em sua mão livre. A lâmina é semelhante em tamanho e forma a uma cimitarra e permanece enquanto a magia durar. Se você soltar a lâmina, ela desaparece, mas você pode evocá-la novamente com uma ação bônus.
A lâmina de fogo pode ser usada para fazer um ataque mágico corpo a corpo, usando uma ação. Se acertar, o alvo sofre 3d6 pontos de dano ígneo.
A lâmina flamejante emite luz plena em um raio de 3 metros [10 ft.] e cria meia-luz por 3 metros adicionais.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 4º círculo ou superior, o dano aumenta em 1d6 para cada dois círculos do espaço de magia acima do 2º.', '', NULL
FROM public.spells WHERE external_index = 'flame-blade'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Flame Strike
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('flame-strike', 5, 'evocation', 'action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Flame Strike', 'A vertical column of divine fire roars down from the heavens in a location you specify. Each creature in a 10-foot-radius, 40-foot-high cylinder centered on a point within range must make a dexterity saving throw. A creature takes 4d6 fire damage and 4d6 radiant damage on a failed save, or half as much damage on a successful one.', 'When you cast this spell using a spell slot of 6th level or higher, the fire damage or the radiant damage (your choice) increases by 1d6 for each slot level above 5th.', 'Pinch of sulfur.'
FROM public.spells WHERE external_index = 'flame-strike'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Coluna de Chamas', 'Uma coluna vertical de fogo divino ressoa, caindo dos céus sobre um local que você especifica. Cada criatura dentro de um cilindro de 3 metros de raio e 12 metros de altura [10-foot-radius, 40-foot-tall cylinder], centrado em um ponto no alcance da magia, deve fazer uma salvaguarda de Destreza. Se falhar, sofre 4d6 pontos de dano ígneo e 4d6 pontos de dano radiante, ou metade do dano em caso de sucesso.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 6º círculo ou superior, o dano ígneo ou o dano radiante aumenta em 1d6 para cada círculo do espaço acima do 5º.', '', NULL
FROM public.spells WHERE external_index = 'flame-strike'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Flaming Sphere
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('flaming-sphere', 2, 'conjuration', 'action', 1, 60, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Flaming Sphere', 'A 5-foot-diameter sphere of fire appears in an unoccupied space of your choice within range and lasts for the duration. Any creature that ends its turn within 5 feet of the sphere must make a dexterity saving throw. The creature takes 2d6 fire damage on a failed save, or half as much damage on a successful one.
As a bonus action, you can move the sphere up to 30 feet. If you ram the sphere into a creature, that creature must make the saving throw against the sphere''s damage, and the sphere stops moving this turn.
When you move the sphere, you can direct it over barriers up to 5 feet tall and jump it across pits up to 10 feet wide. The sphere ignites flammable objects not being worn or carried, and it sheds bright light in a 20-foot radius and dim light for an additional 20 feet.', 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d6 for each slot level above 2nd.', 'A bit of tallow, a pinch of brimstone, and a dusting of powdered iron.'
FROM public.spells WHERE external_index = 'flaming-sphere'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Esfera Flamejante', 'Uma esfera de fogo com 1,5 metro de diâmetro [5-foot-diameter sphere] aparece em um espaço desocupado à sua escolha, no alcance da magia e permanece enquanto esta durar. Qualquer criatura que termine seu próprio turno no alcance de 1,5 metro [5 ft.] da esfera deve fazer uma salvaguarda de Destreza. Se falhar, sofre 2d6 pontos de dano ígneo, ou metade do dano em caso de sucesso.
Com uma ação bônus, você pode mover a esfera até 9 metros [30 ft.]. Se forçá-la contra uma criatura, esta deve fazer uma salvaguarda contra o dano da esfera, que fica imóvel neste turno.
Ao mover a esfera, você pode direcioná-la sobre barreiras de até 1,5 metro [5 ft.] de altura e fazê-la saltar sobre fossos de até 3 metros [10 ft.] de largura. A esfera incendeia objetos inflamáveis que não estejam sendo usados ou carregados, emitindo luz plena em um raio de 6 metros e meia-luz por mais 6 metros.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 3º círculo ou superior, o dano aumenta em 1d6 para cada círculo do espaço acima do 2º.', '', NULL
FROM public.spells WHERE external_index = 'flaming-sphere'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Flesh to Stone
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('flesh-to-stone', 6, 'transmutation', 'action', 1, 60, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Flesh to Stone', 'You attempt to turn one creature that you can see within range into stone. If the target''s body is made of flesh, the creature must make a constitution saving throw. On a failed save, it is restrained as its flesh begins to harden. On a successful save, the creature isn''t affected.
A creature restrained by this spell must make another constitution saving throw at the end of each of its turns. If it successfully saves against this spell three times, the spell ends. If it fails its saves three times, it is turned to stone and subjected to the petrified condition for the duration. The successes and failures don''t need to be consecutive; keep track of both until the target collects three of a kind.
If the creature is physically broken while petrified, it suffers from similar deformities if it reverts to its original state.
If you maintain your concentration on this spell for the entire possible duration, the creature is turned to stone until the effect is removed.', '', 'A pinch of lime, water, and earth.'
FROM public.spells WHERE external_index = 'flesh-to-stone'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'De Carne Para Pedra', 'Você tenta transformar em pedra uma criatura à sua vista e no alcance da magia. Se o corpo do alvo for feito de carne, ele deve fazer uma salvaguarda de Constituição. Se falhar, fica contida imediatamente, conforme sua carne começa a endurecer. Em caso de sucesso, a criatura não é afetada.
Uma criatura contida por esta magia deve fazer outra salvaguarda de Constituição ao final de cada um dos turnos dela. Se for bem-sucedida três vezes, a magia se encerra. Se falhar três vezes, é transformada em pedra, passando a ser considerada com a condição petrificada, enquanto a magia durar. Os sucessos e falhas não precisam ser consecutivos; mantenha registro de ambos até que o alvo tenha três de um tipo.
Se a criatura for quebrada fisicamente enquanto petrificada, ela sofre deformações semelhantes, caso reverta para o estado original.
Se você mantiver sua concentração nesta magia durante toda a duração, a criatura permanece petrificada até que o efeito seja removido.', '', NULL
FROM public.spells WHERE external_index = 'flesh-to-stone'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Floating Disk
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('floating-disk', 1, 'conjuration', 'action', 1, 30, 'feet', 1, 'hour', false, true, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Floating Disk', 'This spell creates a circular, horizontal plane of force, 3 feet in diameter and 1 inch thick, that floats 3 feet above the ground in an unoccupied space of your choice that you can see within range. The disk remains for the duration, and can hold up to 500 pounds. If more weight is placed on it, the spell ends, and everything on the disk falls to the ground.
The disk is immobile while you are within 20 feet of it. If you move more than 20 feet away from it, the disk follows you so that it remains within 20 feet of you. If can move across uneven terrain, up or down stairs, slopes and the like, but it can''t cross an elevation change of 10 feet or more. For example, the disk can''t move across a 10-foot-deep pit, nor could it leave such a pit if it was created at the bottom.
If you move more than 100 feet away from the disk (typically because it can''t move around an obstacle to follow you), the spell ends.', '', 'A drop of mercury.'
FROM public.spells WHERE external_index = 'floating-disk'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Disco Flutuante', 'Esta magia cria um disco circular horizontal feito de energia com 1 metro de diâmetro e 2,5 centímetros de altura, que flutua a 1 metro [3 ft] do chão em um espaço desocupado à sua escolha, à sua vista e no alcance da magia. O disco permanece enquanto a magia durar, e pode carregar até 225 quilos. Se mais peso for colocado sobre ele, a magia se encerra e tudo oque está no disco cai.
O disco é imóvel enquanto você estiver a até 6 metros [20 ft] dele. Se você se mover para mais de 6 metros [20 ft] de distância dele, o disco segue você, permanecendo a até 6 metros [20 ft] de distância de você. Ele pode atravessar terrenos irregulares, subir ou descer escadas, declives e afins, mas não pode atravessar uma mudança de elevação de 3 metros [10 ft] ou mais. Por exemplo, o disco não pode se mover através de um fosso de 3 metros [10 ft] de profundidade, nem poderia deixar tal fosso se fosse criado no fundo dele.
Se você se mover a mais de 30 metros [100 ft] do disco (geralmente por ele não poder se mover através de um obstáculo para seguir você), a magia se encerra.', '', NULL
FROM public.spells WHERE external_index = 'floating-disk'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Fly
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('fly', 3, 'transmutation', 'action', 1, NULL, 'touch', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Fly', 'You touch a willing creature. The target gains a flying speed of 60 feet for the duration. When the spell ends, the target falls if it is still aloft, unless it can stop the fall.', 'When you cast this spell using a spell slot of 4th level or higher, you can target one additional creature for each slot level above 3rd.', 'A wing feather from any bird.'
FROM public.spells WHERE external_index = 'fly'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Voo', 'Você toca uma criatura voluntária. O alvo ganha um deslocamento de voo de 18 metros [60 ft.] enquanto a magia durar. Ao término da magia, caso o alvo ainda esteja no ar, ele cai, a menos que possa parar a queda.
Em Círculos Superiores. Ao conjurar esta magia utilizando um espaço de magia de 4º círculo ou superior, você pode escolher uma criatura alvo adicional para cada círculo do espaço acima do 3º.', '', NULL
FROM public.spells WHERE external_index = 'fly'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Fog Cloud
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('fog-cloud', 1, 'conjuration', 'action', 1, 120, 'feet', 1, 'hour', true, false, ARRAY['V', 'S'], ARRAY['druid', 'ranger', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Fog Cloud', 'You create a 20-foot-radius sphere of fog centered on a point within range. The sphere spreads around corners, and its area is heavily obscured. It lasts for the duration or until a wind of moderate or greater speed (at least 10 miles per hour) disperses it.', 'When you cast this spell using a spell slot of 2nd level or higher, the radius of the fog increases by 20 feet for each slot level above 1st.', NULL
FROM public.spells WHERE external_index = 'fog-cloud'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Névoa Obscurecente', 'Você cria uma esfera de nevoeiro com raio de 6 metros [20-foot radius], centrado em um ponto no alcance da magia. A esfera se alastra, contornando os cantos e a área afetada fica totalmente obscurecida. Ele permanece enquanto a magia durar ou até que um vento de velocidade moderada (de pelo menos 15 quilômetros por hora) ou maior a disperse.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, o raio da esfera aumenta em 6 metros para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'fog-cloud'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Forbiddance
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('forbiddance', 6, 'abjuration', 'minute', 10, NULL, 'touch', 24, 'hour', false, true, ARRAY['V', 'S', 'M'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Forbiddance', 'You create a ward against magical travel that protects up to 40,000 square feet of floor space to a height of 30 feet above the floor. For the duration, creatures can''t teleport into the area or use portals, such as those created by the gate spell, to enter the area. The spell proofs the area against planar travel, and therefore prevents creatures from accessing the area by way of the Astral Plane, Ethereal Plane, Feywild, Shadowfell, or the plane shift spell.
In addition, the spell damages types of creatures that you choose when you cast it. Choose one or more of the following: celestials, elementals, fey, fiends, and undead. When a chosen creature enters the spell''s area for the first time on a turn or starts its turn there, the creature takes 5d10 radiant or necrotic damage (your choice when you cast this spell).
When you cast this spell, you can designate a password. A creature that speaks the password as it enters the area takes no damage from the spell.
The spell''s area can''t overlap with the area of another forbiddance spell. If you cast forbiddance every day for 30 days in the same location, the spell lasts until it is dispelled, and the material components are consumed on the last casting.', '', 'A sprinkling of holy water, rare incense, and powdered ruby worth at least 1,000 gp.'
FROM public.spells WHERE external_index = 'forbiddance'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Proibição', 'Você cria uma defesa contra viagem mágica que protege uma área de até 3.500 metros quadrados [40.000 square feet] e até 9 metros [30 ft.] de altura, a partir do chão. Enquanto a magia durar, nenhuma criatura pode se teleportar para dentro dessa área ou usar portais, como aqueles criados pela magia Portal, para adentrá-la. A magia bloqueia a área contra viagens planares e, portanto, impede que criaturas acessem a área por meio do Plano Astral, Plano Etéreo, Faéria, Sombral ou pela magia Transição Planar.
Além disso, esta magia causa dano a tipos de criaturas escolhidos por você. Ao conjurá-la, escolha um ou mais dos seguintes tipos: celestiais, elementais, feéricos, ínferos e mortos-vivos. Quando uma criatura do tipo escolhido entra na área da magia pela primeira vez ou inicia o próprio turno dentro da área, ela sofre 5d10 pontos de dano radiante ou necrótico (à sua escolha).
Ao conjurar esta magia, você pode designar uma senha. Uma criatura que diga a senha ao adentrar a área não sofre nenhum dano da magia.
A área mágica não pode se sobrepor com a área de outra magia Proibição. Se você conjurar Proibição todos os dias no mesmo local, durante 30 dias, a magia dura até ser dissipada e os componentes materiais são consumidos ao término da última conjuração.', '', NULL
FROM public.spells WHERE external_index = 'forbiddance'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Forcecage
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('forcecage', 7, 'evocation', 'action', 1, 100, 'feet', 1, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Forcecage', 'An immobile, invisible, cube-shaped prison composed of magical force springs into existence around an area you choose within range. The prison can be a cage or a solid box, as you choose.
A prison in the shape of a cage can be up to 20 feet on a side and is made from 1/2-inch diameter bars spaced 1/2 inch apart.
A prison in the shape of a box can be up to 10 feet on a side, creating a solid barrier that prevents any matter from passing through it and blocking any spells cast into or out from the area.
When you cast the spell, any creature that is completely inside the cage''s area is trapped. Creatures only partially within the area, or those too large to fit inside the area, are pushed away from the center of the area until they are completely outside the area.
A creature inside the cage can''t leave it by nonmagical means. If the creature tries to use teleportation or interplanar travel to leave the cage, it must first make a charisma saving throw. On a success, the creature can use that magic to exit the cage. On a failure, the creature can''t exit the cage and wastes the use of the spell or effect. The cage also extends into the Ethereal Plane, blocking ethereal travel.
This spell can''t be dispelled by dispel magic.', '', 'Ruby dust worth 1,500 gp.'
FROM public.spells WHERE external_index = 'forcecage'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Cárcere de Energia', 'Uma prisão com a forma de um cubo invisível e imóvel, composta de força mágica, surge ao redor de uma área à sua escolha e no alcance da magia. Ela pode ser uma jaula ou uma caixa sólida, à sua escolha.
A jaula pode ter até 6 metros [20 ft.] de lado, sendo feita de barras de 1,5 centímetros [1/2 inch] de espessura com espaços de 1,5 centímetros [1/2 inch] entre elas.
A caixa pode ter 3 metros [10 ft.] de lado e cria uma barreira sólida que impede qualquer matéria de passar através dela, bloqueando quaisquer magias conjuradas dentro ou fora da área.
Quando a magia é conjurada, qualquer criatura que estiver completamente dentro da área afetada fica aprisionada. Criaturas que estejam apenas parcialmente na área, ou que sejam grandes demais para caber dentro da área, são empurradas para longe do centro da área, até ficarem completamente fora dela.
Uma criatura dentro da prisão não pode deixá-la por meios não-mágicos. Se a criatura tenta usar alguma forma de teleporte ou viagem extraplanar para sair da prisão, precisa primeiro fazer uma salvaguarda de Carisma. Se falhar, ela não pode sair e desperdiça o uso da magia ou efeito; se for bem-sucedida, ela pode usar a magia para deixar a prisão. A prisão também se estende ao Plano Etéreo, bloqueando viagens etéreas
Esta magia não pode ser dissipada por Dissipar Magia.', '', NULL
FROM public.spells WHERE external_index = 'forcecage'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Foresight
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('foresight', 9, 'divination', 'minute', 1, NULL, 'touch', 8, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'druid', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Foresight', 'You touch a willing creature and bestow a limited ability to see into the immediate future. For the duration, the target can''t be surprised and has advantage on attack rolls, ability checks, and saving throws. Additionally, other creatures have disadvantage on attack rolls against the target for the duration.
This spell immediately ends if you cast it again before its duration ends.', '', 'A hummingbird feather.'
FROM public.spells WHERE external_index = 'foresight'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Sexto Sentido', 'Você toca uma criatura voluntária. O alvo ganha uma capacidade limitada de ver o futuro imediato. Enquanto a magia durar, o alvo não pode ser surpreendido e tem vantagem em jogadas de ataque, testes de atributos e salvaguardas. Além disso, outras criaturas têm desvantagem em jogadas de ataque contra o alvo enquanto a magia durar.
Esta magia se encerra imediatamente se você conjurá-la novamente antes que a duração inicial tenha terminado.', '', NULL
FROM public.spells WHERE external_index = 'foresight'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Freedom of Movement
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('freedom-of-movement', 4, 'abjuration', 'action', 1, NULL, 'touch', 1, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Freedom of Movement', 'You touch a willing creature. For the duration, the target''s movement is unaffected by difficult terrain, and spells and other magical effects can neither reduce the target''s speed nor cause the target to be paralyzed or restrained.
The target can also spend 5 feet of movement to automatically escape from nonmagical restraints, such as manacles or a creature that has it grappled. Finally, being underwater imposes no penalties on the target''s movement or attacks.', '', 'A leather strap, bound around the arm or a similar appendage.'
FROM public.spells WHERE external_index = 'freedom-of-movement'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Movimentação Livre', 'Você toca uma criatura voluntária. Enquanto a magia durar, o movimento do alvo não é afetado por terreno difícil, e magias e outros efeitos mágicos não podem reduzir o deslocamento, paralisar ou conter o alvo.
O alvo também pode gastar 1,5 metro [5 ft.] de movimento para escapar automaticamente de impedimentos não-mágicos, como algemas ou o agarramento de uma criatura. Por fim, estar debaixo d''água não impõe penalidades ao movimento do alvo ou aos seus ataques.', '', NULL
FROM public.spells WHERE external_index = 'freedom-of-movement'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Freezing Sphere
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('freezing-sphere', 6, 'evocation', 'action', 1, 300, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Freezing Sphere', 'A frigid globe of cold energy streaks from your fingertips to a point of your choice within range, where it explodes in a 60-foot-radius sphere. Each creature within the area must make a constitution saving throw. On a failed save, a creature takes 10d6 cold damage. On a successful save, it takes half as much damage.
If the globe strikes a body of water or a liquid that is principally water (not including water-based creatures), it freezes the liquid to a depth of 6 inches over an area 30 feet square. This ice lasts for 1 minute. Creatures that were swimming on the surface of frozen water are trapped in the ice. A trapped creature can use an action to make a Strength check against your spell save DC to break free.
You can refrain from firing the globe after completing the spell, if you wish. A small globe about the size of a sling stone, cool to the touch, appears in your hand. At any time, you or a creature you give the globe to can throw the globe (to a range of 40 feet) or hurl it with a sling (to the sling''s normal range). It shatters on impact, with the same effect as the normal casting of the spell. You can also set the globe down without shattering it. After 1 minute, if the globe hasn''t already shattered, it explodes.', 'When you cast this spell using a spell slot of 7th level or higher, the damage increases by 1d6 for each slot level above 6th.', 'A small crystal sphere.'
FROM public.spells WHERE external_index = 'freezing-sphere'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Esfera Congelante', 'Um globo frígido de energia gélida é disparado da ponta de seus dedos até um ponto à sua escolha, no alcance da magia, onde explode em uma esfera de 18 metros de raio [60-foot-radius sphere]. Cada criatura na área deve fazer uma salvaguarda de Constituição. Se falhar, sofre 10d6 pontos de dano gélido, ou metade do dano em caso de sucesso.
Se o globo acertar um corpo de água ou um líquido formado principalmente de água (isso não inclui criaturas baseadas em água), ele congela o líquido até uma profundidade de 15 centímetros [6 inches] sobre uma área de 9 metros [30 ft.] quadrados. O gelo dura 1 minuto. Criaturas que estavam nadando na superfície de água congelada ficam presas no gelo. Uma criatura pode usar uma ação para fazer um teste de Força contra a CD para evitar sua magia para se libertar.
Você pode abster-se de disparar o globo depois de completar a magia, se assim desejar. Um pequeno globo com o tamanho aproximado de uma pedra de funda, frio ao toque, aparece em sua mão. A qualquer momento, você ou a criatura a quem você der o globo pode jogá-lo (a um alcance de 12 metros [40 ft.]) ou arremessá-lo com uma funda (no alcance normal da funda). Ele se despedaça no impacto com o mesmo efeito que a conjuração normal da magia. Você também pode colocar o globo no chão sem quebrá-lo. Depois de 1 minuto, se o globo já não estiver despedaçado, ele explode.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 7º círculo ou superior, o dano aumenta em 1d6 para cada círculo do espaço acima do 6º.', '', NULL
FROM public.spells WHERE external_index = 'freezing-sphere'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Gaseous Form
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('gaseous-form', 3, 'transmutation', 'action', 1, NULL, 'touch', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Gaseous Form', 'You transform a willing creature you touch, along with everything it''s wearing and carrying, into a misty cloud for the duration. The spell ends if the creature drops to 0 hit points. An incorporeal creature isn''t affected.
While in this form, the target''s only method of movement is a flying speed of 10 feet. The target can enter and occupy the space of another creature. The target has resistance to nonmagical damage, and it has advantage on Strength, Dexterity, and constitution saving throws. The target can pass through small holes, narrow openings, and even mere cracks, though it treats liquids as though they were solid surfaces. The target can''t fall and remains hovering in the air even when stunned or otherwise incapacitated.
While in the form of a misty cloud, the target can''t talk or manipulate objects, and any objects it was carrying or holding can''t be dropped, used, or otherwise interacted with. The target can''t attack or cast spells.', '', 'A bit of gauze and a wisp of smoke.'
FROM public.spells WHERE external_index = 'gaseous-form'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Forma Gasosa', 'Você toca uma criatura voluntária. O alvo, junto com tudo aquilo que estiver usando e carregando, é transformado em uma nuvem de neblina, enquanto a magia durar. A magia termina se os pontos de vida da criatura forem reduzidos a 0. Criaturas incorpóreas não são afetadas.
Enquanto estiver nesta forma, o único método de movimento do alvo é o voo com deslocamento de 3 metros [10 ft.]. O alvo pode entrar e ocupar o espaço de outra criatura. O alvo tem resistência a danos não-mágicos e vantagem em salvaguardas de Força, Destreza e Constituição. O alvo pode passar através de pequenos orifícios, aberturas estreitas e até mesmo por meras rachaduras, embora trate líquidos como se fossem superfícies sólidas. O alvo não é afetado por queda, e continua pairando no ar mesmo quando atordoado ou incapacitado.
Enquanto estiver sob a forma de nuvem, o alvo não pode falar ou manipular objetos, aqueles que estiver carregando ou segurando não podem ser descartados ou usados, e nenhuma forma de interação pode ser estabelecida com eles. O alvo não pode atacar ou conjurar magias.', '', NULL
FROM public.spells WHERE external_index = 'gaseous-form'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Gate
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('gate', 9, 'conjuration', 'action', 1, 60, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Gate', 'You conjure a portal linking an unoccupied space you can see within range to a precise location on a different plane of existence. The portal is a circular opening, which you can make 5 to 20 feet in diameter. You can orient the portal in any direction you choose. The portal lasts for the duration.
The portal has a front and a back on each plane where it appears. Travel through the portal is possible only by moving through its front. Anything that does so is instantly transported to the other plane, appearing in the unoccupied space nearest to the portal.
Deities and other planar rulers can prevent portals created by this spell from opening in their presence or anywhere within their domains.
When you cast this spell, you can speak the name of a specific creature (a pseudonym, title, or nickname doesn''t work). If that creature is on a plane other than the one you are on, the portal opens in the named creature''s immediate vicinity and draws the creature through it to the nearest unoccupied space on your side of the portal. You gain no special power over the creature, and it is free to act as the GM deems appropriate. It might leave, attack you, or help you.', '', 'A diamond worth at least 5,000gp.'
FROM public.spells WHERE external_index = 'gate'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Portal', 'Você conjura um portal ligando um espaço desocupado, à sua vista, a um lugar específico em outro plano de existência. O portal é uma abertura circular, que pode ter de 1,5 [5 ft.] a 6 metros [20 ft.] de diâmetro. Você pode orientá-lo em qualquer direção que escolher. Ele permanece aberto enquanto a magia durar.
O portal tem uma frente e um verso em cada plano onde aparecer. É possível viajar simplesmente atravessando-o pela frente. Qualquer coisa que atravessá-lo será transportada instantaneamente para o outro plano, aparecendo no espaço desocupado mais próximo ao portal.
Divindades e outros regentes planares podem evitar que portais criados por esta magia abram-se em sua presença ou em qualquer lugar dos seus domínios.
Ao conjurar esta magia, você pode citar o nome de uma criatura específica (um pseudônimo, um título ou apelido não servem). Se essa criatura estiver em um plano diferente do seu, o portal abre-se em um espaço imediatamente ao lado da criatura citada e a arrasta através dele para o lugar desocupado mais próximo do seu lado do portal. Você não ganha poder especial algum sobre a criatura, e ela é livre para agir conforme o DM achar apropriado. A criatura pode ir embora, atacá-lo ou ajudá-lo.', '', NULL
FROM public.spells WHERE external_index = 'gate'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Geas
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('geas', 5, 'enchantment', 'minute', 1, 60, 'feet', 30, 'day', false, false, ARRAY['V'], ARRAY['bard', 'cleric', 'druid', 'paladin', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Geas', 'You place a magical command on a creature that you can see within range, forcing it to carry out some service or refrain from some action or course of activity as you decide. If the creature can understand you, it must succeed on a wisdom saving throw or become charmed by you for the duration. While the creature is charmed by you, it takes 5d10 psychic damage each time it acts in a manner directly counter to your instructions, but no more than once each day. A creature that can''t understand you is unaffected by the spell.
You can issue any command you choose, short of an activity that would result in certain death. Should you issue a suicidal command, the spell ends.
You can end the spell early by using an action to dismiss it. A remove curse, greater restoration, or wish spell also ends it.', 'When you cast this spell using a spell slot of 7th or 8th level, the duration is 1 year. When you cast this spell using a spell slot of 9th level, the spell lasts until it is ended by one of the spells mentioned above.', NULL
FROM public.spells WHERE external_index = 'geas'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Missão', 'Você lança um comando mágico sobre uma criatura à sua vista e no alcance da magia, forçando-a a realizar algum serviço ou impedindo-a de executar alguma ação ou curso de atividade, conforme você desejar. Se a criatura for capaz de entendê-lo ela deve ser bem-sucedida em uma salvaguarda de Sabedoria ou ficará enfeitiçada por você enquanto a magia durar. Enquanto a criatura estiver enfeitiçada por você, ela sofre 5d10 pontos de dano psíquico ao agir de maneira diretamente contraditória às suas instruções, mas não mais do que uma vez ao dia. Uma criatura que não for capaz de entendê-lo não é afetada por esta magia.
Você pode emitir qualquer comando que desejar, a não ser um que resulte em morte certa. Se você emitir um comando suicida, a magia se encerra.
A magia termina antecipadamente se você usar a sua ação para dissipá-la. Uma magia Remover Maldição, Restauração Maior ou Desejo também a encerra.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 7º ou 8º círculo, a duração é de 1 ano. Ao conjurar esta magia usando um espaço de magia de 9º círculo, a magia dura até ser encerrada por uma das magias mencionadas acima.', '', NULL
FROM public.spells WHERE external_index = 'geas'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Gentle Repose
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('gentle-repose', 2, 'necromancy', 'action', 1, NULL, 'touch', 10, 'day', false, true, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Gentle Repose', 'You touch a corpse or other remains. For the duration, the target is protected from decay and can''t become undead.
The spell also effectively extends the time limit on raising the target from the dead, since days spent under the influence of this spell don''t count against the time limit of spells such as raise dead.', '', 'A pinch of salt and one copper piece placed on each of the corpse''s eyes, which must remain there for the duration.'
FROM public.spells WHERE external_index = 'gentle-repose'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Repouso Tranquilo', 'Você toca um cadáver ou outros restos mortais. Enquanto a magia durar, o alvo está protegido da decomposição e não pode se tornar um morto-vivo.A magia também estende efetivamente o tempo limite para trazer o alvo dos mortos, pois os dias passados sob a influência desta magia não contam contra o tempo limite de magias como Reviver os Mortos.', '', NULL
FROM public.spells WHERE external_index = 'gentle-repose'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Giant Insect
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('giant-insect', 4, 'transmutation', 'action', 1, 30, 'feet', 10, 'minute', true, false, ARRAY['V', 'S'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Giant Insect', 'You transform up to ten centipedes, three spiders, five wasps, or one scorpion within range into giant versions of their natural forms for the duration. A centipede becomes a giant centipede, a spider becomes a giant spider, a wasp becomes a giant wasp, and a scorpion becomes a giant scorpion.
Each creature obeys your verbal commands, and in combat, they act on your turn each round. The GM has the statistics for these creatures and resolves their actions and movement.
A creature remains in its giant size for the duration, until it drops to 0 hit points, or until you use an action to dismiss the effect on it.
The GM might allow you to choose different targets. For example, if you transform a bee, its giant version might have the same statistics as a giant wasp.', '', NULL
FROM public.spells WHERE external_index = 'giant-insect'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Inseto Gigante', 'Você transforma até dez centopeias, três aranhas, cinco vespas ou um escorpião no alcance da magia, em versões gigantes de suas formas naturais, enquanto a magia durar. Uma centopeia torna-se uma centopeia gigante, uma aranha, uma aranha gigante, uma vespa, uma vespa gigante e um escorpião, um escorpião gigante.
Cada criatura obedece aos seus comandos verbais e, em combate, age no mesmo turno que você, em cada rodada. O DM fornece as estatísticas para essas criaturas, sendo responsável por resolver ações e movimentos delas.
Uma criatura permanece em tamanho gigante enquanto a magia durar, enquanto não chegar a 0 ponto de vida ou até você usar uma ação para dispensar o efeito sobre ela.
O DM pode permitir que você escolha alvos diferentes dos listados. Se você transformar uma abelha, a versão gigante desta pode ter as mesmas estatísticas de uma vespa gigante, por exemplo.', '', NULL
FROM public.spells WHERE external_index = 'giant-insect'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
