INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Glibness', 'Until the spell ends, when you make a Charisma check, you can replace the number you roll with a 15. Additionally, no matter what you say, magic that would determine if you are telling the truth indicates that you are being truthful.', '', NULL
FROM public.spells WHERE external_index = 'glibness'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Loquacidade', 'Enquanto a magia durar, quando você realiza um teste de Carisma, pode substituir o número que tirou por 15. Além disso, não importa o que diga, uma magia que determinaria se você está falando a verdade indica que você está sendo honesto.', '', NULL
FROM public.spells WHERE external_index = 'glibness'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
