VALUES ('globe-of-invulnerability', 6, 'abjuration', 'action', 1, NULL, 'self', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Globe of Invulnerability', 'An immobile, faintly shimmering barrier springs into existence in a 10-foot radius around you and remains for the duration.
Any spell of 5th level or lower cast from outside the barrier can''t affect creatures or objects within it, even if the spell is cast using a higher level spell slot. Such a spell can target creatures and objects within the barrier, but the spell has no effect on them. Similarly, the area within the barrier is excluded from the areas affected by such spells.', 'When you cast this spell using a spell slot of 7th level or higher, the barrier blocks spells of one level higher for each slot level above 6th.', 'A glass or crystal bead that shatters when the spell ends.'
FROM public.spells WHERE external_index = 'globe-of-invulnerability'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Globo de Invulnerabilidade', 'Uma barreira imóvel e levemente cintilante surge a 3 metros de raio [10-foot radius] em volta de você e permanece enquanto durar a magia.
Qualquer magia de 5º círculo ou inferior conjurada do lado de fora da barreira não poderá afetar criaturas ou objetos dentro dela, mesmo se for conjurada usando um espaço de magia superior. A magia pode atingir criaturas e objetos dentro da barreira, mas não terá efeito sobre eles. Da mesma forma, a área dentro da barreira é excluída das zonas afetadas por essa magia.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 7º círculo ou superior, a barreira bloqueia magias um círculo superior para cada círculo do espaço acima do 6º.', '', NULL
FROM public.spells WHERE external_index = 'globe-of-invulnerability'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Glyph of Warding
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('glyph-of-warding', 3, 'abjuration', 'hour', 1, NULL, 'touch', NULL, 'special', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Glyph of Warding', 'When you cast this spell, you inscribe a glyph that harms other creatures, either upon a surface (such as a table or a section of floor or wall) or within an object that can be closed (such as a book, a scroll, or a treasure chest) to conceal the glyph. If you choose a surface, the glyph can cover an area of the surface no larger than 10 feet in diameter. If you choose an object, that object must remain in its place; if the object is moved more than 10 feet from where you cast this spell, the glyph is broken, and the spell ends without being triggered.
The glyph is nearly invisible and requires a successful Intelligence (Investigation) check against your spell save DC to be found.
You decide what triggers the glyph when you cast the spell. For glyphs inscribed on a surface, the most typical triggers include touching or standing on the glyph, removing another object covering the glyph, approaching within a certain distance of the glyph, or manipulating the object on which the glyph is inscribed. For glyphs inscribed within an object, the most common triggers include opening that object, approaching within a certain distance of the object, or seeing or reading the glyph. Once a glyph is triggered, this spell ends.
You can further refine the trigger so the spell activates only under certain circumstances or according to physical characteristics (such as height or weight), creature kind (for example, the ward could be set to affect aberrations or drow), or alignment. You can also set conditions for creatures that don''t trigger the glyph, such as those who say a certain password.
When you inscribe the glyph, choose *explosive runes* or a *spell glyph*.
***Explosive Runes.*** When triggered, the glyph erupts with magical energy in a 20-foot-radius sphere centered on the glyph. The sphere spreads around corners. Each creature in the area must make a Dexterity saving throw. A creature takes 5d8 acid, cold, fire, lightning, or thunder damage on a failed saving throw (your choice when you create the glyph), or half as much damage on a successful one.
***Spell Glyph.*** You can store a prepared spell of 3rd level or lower in the glyph by casting it as part of creating the glyph. The spell must target a single creature or an area. The spell being stored has no immediate effect when cast in this way. When the glyph is triggered, the stored spell is cast. If the spell has a target, it targets the creature that triggered the glyph. If the spell affects an area, the area is centered on that creature. If the spell summons hostile creatures or creates harmful objects or traps, they appear as close as possible to the intruder and attack it. If the spell requires concentration, it lasts until the end of its full duration.', 'When you cast this spell using a spell slot of 4th level or higher, the damage of an explosive runes glyph increases by 1d8 for each slot level above 3rd. If you create a spell glyph, you can store any spell of up to the same level as the slot you use for the glyph of warding.', 'Incense and powdered diamond worth at least 200 gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'glyph-of-warding'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Glifo de Proteção', 'Ao conjurar esta magia, você inscreve um glifo que mais tarde desencadeia um efeito mágico. Você o inscreve em uma superfície (como uma mesa, uma seção de piso ou parede) ou dentro de um objeto que possa ser fechado (como um livro, um pergaminho ou uma arca de tesouro) e onde o glifo possa ser escondido. O símbolo pode cobrir uma área de até 3 metros de diâmetro [10-foot diameter]. Se a superfície ou objeto for movido mais de 3 metros [10 ft.] de onde você conjurou esta magia, o símbolo é quebrado e a magia se encerra, sem efeito.
O glifo é quase invisível, exigindo um teste de Inteligência (Investigação) contra a CD para evitar sua magia para encontrá-lo.
Ao conjurar esta magia, você decide o gatilho do glifo. Para os glifos que foram inscritos em uma superfície, os gatilhos mais típicos incluem tocar ou pisar no glifo, remover um objeto que o cubra, aproximar-se a uma certa distância dele ou manipular um objeto que o contenha. Para os que forem inscritos dentro de um objeto, as condições podem ser a abertura deste, aproximar-se a uma certa distância, ou ainda ver ou ler o glifo. Uma vez que um glifo seja disparado, esta magia termina.
Você pode refinar o gatilho para que a magia seja ativada apenas sob certas circunstâncias ou de acordo com as características físicas (como altura ou peso), tipo de criatura (por exemplo, a proteção poderia ser programada para afetar aberrações ou drow) ou alinhamento. Podem também ser especificadas condições para que não se dispare o glifo, como dizer uma palavra-chave, por exemplo.
Quando você inscrever o glifo, escolha entre runas explosivas ou glifo arcano.
Runas Explosivas. Quando acionada, a runa explode com energia mística em uma esfera de 6 metros [20 ft.] centrada no glifo. A esfera se alastra, contornando os cantos. Cada criatura na área deve fazer uma salvaguarda de Destreza. Se falhar, sofre 5d8 pontos de dano ácido, elétrico, gélido, ígneo ou trovejante (à sua escolha, ao conjurar a magia), ou metade do dano em caso de sucesso.
Glifo Arcano. Você pode armazenar uma magia preparada de 3º círculo ou inferior junto ao glifo, se conjurar esta magia como parte do processo. Ela deve ter como alvo uma única criatura, ou uma área. A magia que foi conjurada não tem efeito imediato nesta modalidade. Ela se ativa quando o glifo for disparado. Se a magia tiver um alvo, quem acionou o glifo é atingido. Se a magia afetar uma área, o centro é a criatura. Se a magia invocar criaturas hostis ou criar objetos nocivos ou armadilhas, eles surgem o mais próximo possível do intruso e o atacam. Se a magia exigir concentra­ção, ela permanece até o fim de sua duração total.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 4º círculo ou superior, o dano por um símbolo de runas explosivas aumenta em 1d8 para cada círculo do espaço acima do 3º. Se criar um glifo arcano, você pode armazenar qualquer magia até o mesmo círculo que o espaço que foi usado para conjurar o Glifo de Proteção.', '', NULL
FROM public.spells WHERE external_index = 'glyph-of-warding'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
