INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Bom Fruto', 'Até dez frutos aparecem na sua mão, tornando-se magicamente infundidos. Uma criatura pode usar uma ação para comer um fruto. Comer um fruto restaura 1 ponto de vida, além de fornecer nutrição suficiente para sustentar uma criatura por um dia.Os frutos perdem sua potência se não tiverem sido consumidos após 24 horas da conjuração desta magia.', '', NULL
