INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Graxa', 'Uma graxa escorregadia recobre uma área de 3 metros quadrados [10-foot square] de chão em um ponto dentro do alcance da magia, tornando-a terreno difícil enquanto esta durar.Quando a graxa aparece, cada criatura parada na área precisa ser bem-sucedida em uma salvaguarda de Destreza ou é considerada caída. Uma criatura que entre ou termine seu próprio turno na área também precisa ser bem-sucedida em uma salvaguarda de Destreza, ou fica caída.', '', NULL
