INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Restauração Maior', 'Você toca uma criatura, imbuindo-a com energia positiva que desfaz um efeito debilitante. Você pode reduzir o nível de exaustão dela em 1 ou cancelar algum dos efeitos a seguir:
Um efeito que enfeitiçou ou petrificou o alvo;
Uma maldição, incluindo a sintonia do indivíduo com um item mágico amaldiçoado;
Qualquer redução de um dos valores de atributo do alvo;
Um efeito que reduza os pontos de vida máximos do alvo.', '', NULL
FROM public.spells WHERE external_index = 'greater-restoration'
