INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Guardian of Faith', 'A Large spectral guardian appears and hovers for the duration in an unoccupied space of your choice that you can see within range. The guardian occupies that space and is indistinct except for a gleaming sword and shield emblazoned with the symbol of your deity.
Any creature hostile to you that moves to a space within 10 feet of the guardian for the first time on a turn must succeed on a dexterity saving throw. The creature takes 20 radiant damage on a failed save, or half as much damage on a successful one. The guardian vanishes when it has dealt a total of 60 damage.', '', NULL
FROM public.spells WHERE external_index = 'guardian-of-faith'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Defensor da Fé', 'Uma sentinela espectral de tamanho Grande aparece e flutua em um espaço desocupado à sua escolha, à sua vista e no alcance da magia. Ele permanece enquanto a magia durar. A sentinela é indistinta exceto por uma espada brilhante e um escudo ornado com o símbolo da sua divindade.
Qualquer criatura hostil a você que se mova para um espaço a até 3 metros [10 ft.] da sentinela pela primeira vez em um turno deve ser bem-sucedida em uma salvaguarda de Destreza. Se falhar, sofre 20 pontos de dano radiante, ou metade do dano em caso de sucesso. A sentinela desaparece quando tiver causado um total de 60 pontos de dano.', '', NULL
FROM public.spells WHERE external_index = 'guardian-of-faith'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Guards and Wards
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('guards-and-wards', 6, 'abjuration', 'minute', 10, NULL, 'touch', 24, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Guards and Wards', 'You create a ward that protects up to 2,500 square feet of floor space (an area 50 feet square, or one hundred 5-foot squares or twenty-five 10-foot squares). The warded area can be up to 20 feet tall, and shaped as you desire. You can ward several stories of a stronghold by dividing the area among them, as long as you can walk into each contiguous area while you are casting the spell.
When you cast this spell, you can specify individuals that are unaffected by any or all of the effects that you choose. You can also specify a password that, when spoken aloud, makes the speaker immune to these effects.
Guards and wards creates the following effects within the warded area.
***Corridors.*** Fog fills all the warded corridors, making them heavily obscured. In addition, at each intersection or branching passage offering a choice of direction, there is a 50 percent chance that a creature other than you will believe it is going in the opposite direction from the one it chooses.
***Doors.*** All doors in the warded area are magically locked, as if sealed by an arcane lock spell. In addition, you can cover up to ten doors with an illusion (equivalent to the illusory object function of the minor illusion spell) to make them appear as plain sections of wall.
***Stairs.*** Webs fill all stairs in the warded area from top to bottom, as the web spell. These strands regrow in 10 minutes if they are burned or torn away while guards and wards lasts.
***Other Spell Effect.*** You can place your choice of one of the following magical effects within the warded area of the stronghold.
- Place dancing lights in four corridors. You can designate a simple program that the lights repeat as long as guards and wards lasts.
- Place magic mouth in two locations.
- Place stinking cloud in two locations. The vapors appear in the places you designate; they return within 10 minutes if dispersed by wind while guards and wards lasts.
- Place a constant gust of wind in one corridor or room.
- Place a suggestion in one location. You select an area of up to 5 feet square, and any creature that enters or passes through the area receives the suggestion mentally.
The whole warded area radiates magic. A dispel magic cast on a specific effect, if successful, removes only that effect.
You can create a permanently guarded and warded structure by casting this spell there every day for one year.', '', 'Burning incense, a small measure of brimstone and oil, a knotted string, a small amount of umber hulk blood, and a small silver rod worth at least 10 gp.'
FROM public.spells WHERE external_index = 'guards-and-wards'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Proteger Fortaleza', 'Você cria uma defesa que protege até 225 metros quadrados [2.500 square feet] de área útil (uma área quadrada de 15 metros [50 ft.] de lado, ou cem quadrados de 1,5 metro [5 ft.], ou 25 quadrados de 3 metros [10 ft.]). A área defendida pode ter até 6 metros [20 ft.] de altura e assumir a forma que você desejar. Você pode defender várias secções de uma fortaleza, dividindo a área entre elas na medida em que puder andar em cada área contígua, enquanto está conjurando a magia.
Ao conjurar esta magia, você pode especificar os indiví­duos que não são afetados por um ou por todos os efeitos. Você também pode especificar uma senha que, dita em voz alta, torna imune aos efeitos aquele que a proferir.
Ao conjurar Proteger Fortaleza trate a área defendida como sendo alvo dos seguintes efeitos:
Corredores. Um nevoeiro preenche todos os corredores defendidos, tornando-os fortemente obscurecidos. Além disso, em cada interseção ou passagem que ofereça uma escolha de direção, há uma chance de 50 por cento de uma criatura, que não seja você, acreditar que segue na direção oposta à que escolheu.
Portas. Todas as portas da área protegida são bloqueadas magicamente, como se estivessem seladas pela magia Tranca Arcana. Além disso, você pode cobrir até dez portas com uma ilusão (equivalente à função objeto ilusório da magia Ilusão Menor), para fazer com que se pareçam como seções contínuas da parede.
Escadas. Teias preenchem todas as escadas da área defendida, de cima a baixo, como a magia Teia. Essas teias voltam a crescer em 10 minutos se forem queimadas ou arrancadas enquanto a magia Proteger Fortaleza durar.
Outros Efeitos Mágicos. Você pode colocar, à sua escolha, um dos seguintes efeitos mágicos dentro da área defendida.
Luzes Dançantes em quatro corredores. Você pode definir um programa simples que as luzes repetirão enquanto a magia Proteger Fortaleza durar.
Boca Encantada em dois locais.
Núvem Fétida em dois locais. Os vapores aparecem nos lugares que você designar; eles retornam dentro de 10 minutos se dispersados pelo vento, enquanto a magia Proteger Fortaleza durar.
Uma Lufada de Vento soprando constantemente em um corredor ou aposento.
Sugestão em um lugar. Você deve selecionar uma área de 1,5 metro [5 ft.] quadrado, e qualquer criatura que entrar ou passar através dessa área recebe a sugestão mentalmente.
Toda a área defendida irradia magia. Uma conjuração bem-sucedida de Dissipar Magia sobre determinado efeito remove apenas esse efeito.
Você pode criar uma estrutura permanentemente protegida e defendida ao conjurar esta magia nela, todos os dias, durante um ano.', '', NULL
FROM public.spells WHERE external_index = 'guards-and-wards'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Guidance
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('guidance', 0, 'divination', 'action', 1, NULL, 'touch', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['cleric', 'druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Guidance', 'You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one ability check of its choice. It can roll the die before or after making the ability check. The spell then ends.', '', NULL
FROM public.spells WHERE external_index = 'guidance'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Orientação', 'Você toca uma criatura voluntária. Uma vez antes que a magia termine, o alvo pode jogar 1d4 e somar resultado a um teste de atributo da escolha dele. Ele pode jogar o dado antes ou depois de fazer o teste. A magia, então, se encerra.', '', NULL
FROM public.spells WHERE external_index = 'guidance'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Guiding Bolt
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('guiding-bolt', 1, 'evocation', 'action', 1, 120, 'feet', 1, 'round', false, false, ARRAY['V', 'S'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Guiding Bolt', 'A flash of light streaks toward a creature of your choice within range. Make a ranged spell attack against the target. On a hit, the target takes 4d6 radiant damage, and the next attack roll made against this target before the end of your next turn has advantage, thanks to the mystical dim light glittering on the target until then.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d6 for each slot level above 1st.', NULL
FROM public.spells WHERE external_index = 'guiding-bolt'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Raio Guia', 'Um lampejo de luz dispara em direção a uma criatura à sua escolha e dentro do alcance da magia. Faça um ataque mágico à distância contra o alvo. Se acertar, o alvo sofre 4d6 pontos de dano radiante, e a próxima jogada de ataque feita contra ele, antes do final do seu próximo turno, tem vantagem graças à meia-luz mística brilhando no alvo.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, o dano aumenta em 1d6 para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'guiding-bolt'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Gust of Wind
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('gust-of-wind', 2, 'evocation', 'action', 1, NULL, 'self', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Gust of Wind', 'A line of strong wind 60 feet long and 10 feet wide blasts from you in a direction you choose for the spell''s duration. Each creature that starts its turn in the line must succeed on a strength saving throw or be pushed 15 feet away from you in a direction following the line.
Any creature in the line must spend 2 feet of movement for every 1 foot it moves when moving closer to you.
The gust disperses gas or vapor, and it extinguishes candles, torches, and similar unprotected flames in the area. It causes protected flames, such as those of lanterns, to dance wildly and has a 50 percent chance to extinguish them.
As a bonus action on each of your turns before the spell ends, you can change the direction in which the line blasts from you.', '', 'A legume seed.'
FROM public.spells WHERE external_index = 'gust-of-wind'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Lufada de Vento', 'Uma linha de vento forte, com 18 metros [60 ft.] de comprimento e 3 metros [10 ft.] de largura, é soprada a partir de você em uma direção à sua escolha, enquanto a magia durar. Cada criatura que comece seu próprio turno na linha deve ser bem-sucedida em uma salvaguarda de Força ou é empurrada 4,5 metros [15 ft.] para longe de você, a favor da linha de vento.Qualquer criatura na linha deve gastar 3 metros [10 ft.] de deslocamento para cada 1,5 metro [5 ft.] que se movimentar na sua direção.A lufada dispersa gases ou vapor e apaga velas, tochas e chamas semelhantes que estejam desprotegidas na área. Ela faz com que chamas protegidas, como as de lanternas, oscilem descontroladamente e tenham 50 por cento de chance de se extinguirem.Com uma ação bônus em cada um dos seus turnos antes do final da magia, você pode mudar a direção na qual a linha sopra a partir de você.', '', NULL
FROM public.spells WHERE external_index = 'gust-of-wind'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Hallow
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('hallow', 5, 'evocation', 'hour', 24, NULL, 'touch', NULL, 'special', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Hallow', 'You touch a point and infuse an area around it with holy (or unholy) power. The area can have a radius up to 60 feet, and the spell fails if the radius includes an area already under the effect a hallow spell. The affected area is subject to the following effects.
First, celestials, elementals, fey, fiends, and undead can''t enter the area, nor can such creatures charm, frighten, or possess creatures within it. Any creature charmed, frightened, or possessed by such a creature is no longer charmed, frightened, or possessed upon entering the area. You can exclude one or more of those types of creatures from this effect.
Second, you can bind an extra effect to the area. Choose the effect from the following list, or choose an effect offered by the GM. Some of these effects apply to creatures in the area; you can designate whether the effect applies to all creatures, creatures that follow a specific deity or leader, or creatures of a specific sort, such as ores or trolls. When a creature that would be affected enters the spell''s area for the first time on a turn or starts its turn there, it can make a charisma saving throw. On a success, the creature ignores the extra effect until it leaves the area.
***Courage.*** Affected creatures can''t be frightened while in the area.
***Darkness.*** Darkness fills the area. Normal light, as well as magical light created by spells of a lower level than the slot you used to cast this spell, can''t illuminate the area.
***Daylight.*** Bright light fills the area. Magical darkness created by spells of a lower level than the slot you used to cast this spell can''t extinguish the light.
***Energy Protection.*** Affected creatures in the area have resistance to one damage type of your choice, except for bludgeoning, piercing, or slashing.
***Energy Vulnerability.*** Affected creatures in the area have vulnerability to one damage type of your choice, except for bludgeoning, piercing, or slashing.
***Everlasting Rest.*** Dead bodies interred in the area can''t be turned into undead.
***Extradimensional Interference.*** Affected creatures can''t move or travel using teleportation or by extradimensional or interplanar means.
***Fear.*** Affected creatures are frightened while in the area.
***Silence.*** No sound can emanate from within the area, and no sound can reach into it.
***Tongues.*** Affected creatures can communicate with any other creature in the area, even if they don''t share a common language.', '', 'Herbs, oils, and incense worth at least 1,000 gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'hallow'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Consagrar', 'Você toca um ponto e infunde uma área em torno dele com poder sagrado (ou profano). A área pode ter um raio de até 18 metros [60 ft.], e a magia falha se o raio incluir uma área já sob o efeito de uma magia consagrar. A área afetada está sujeita aos efeitos a seguir.
Primeiro, celestiais, elementais, feéricos, ínferos e mortos-vivos não podem entrar na área, tampouco essas criaturas podem enfeitiçar, amedrontar ou possuir outras criaturas na área. Qualquer criatura enfeitiçada, amedrontada ou possuída por tais criaturas já não está mais sob quaisquer dessas condições ao entrar na área. Você pode excluir um ou mais desses tipos de criaturas deste efeito.
Segundo, você pode vincular um efeito adicional à área. Escolha o efeito da lista a seguir, ou escolha um efeito oferecido pelo DM. Alguns destes efeitos aplicam-se às criaturas na área; você pode determinar se o efeito se aplica a todas as criaturas, a criaturas que seguem um líder ou divindade específicos, ou a criaturas de um determinado tipo, como orcs e trolls. Quando uma criatura que deveria ser afetada entra na área da magia pela primeira vez durante um turno, ou inicia o próprio turno ali, deve fazer uma salvaguarda de Carisma. Se for bem-sucedida, a criatura ignora o efeito adicional até sair da área.
Coragem. Criaturas afetadas não podem ser amedrontadas enquanto estiverem na área.
Descanso Eterno. Cadáveres enterrados na área não podem ser transformados em mortos-vivos.
Escuridão. Escuridão preenche a área. Luz normal, bem como luz mágica criada por feitiços de um círculo inferior ao do espaço de magia que você usou para conjurar esta magia não podem iluminar a área.
Idiomas. Criaturas afetadas por esta magia podem se comunicar com qualquer outra criatura na área, mesmo se não compartilharem um idioma comum.
Interferência Extradimensional. Criaturas afetadas por esta magia não podem se mover ou viajar usando teleporte ou meios extradimensionais ou interplanares.
Luz do Dia. Luz plena preenche a área. Escuridão mágica criada por feitiços de um círculo inferior ao do espaço de magia que você usou para conjurar esta magia não pode extinguir a luz.
Medo. Criaturas afetadas por esta magia ficam amedrontadas enquanto estiverem na área.
Proteção Contra Energia. Criaturas afetadas na área têm resistência a um tipo de dano à sua escolha, exceto contundente, cortante e perfurante.
Silêncio. Nenhum som pode emanar de dentro da área, e nenhum som pode adentrá-la.
Vulnerabilidade a Energia. Criaturas afetadas na área têm vulnerabilidade a um tipo de dano à sua escolha, exceto contundente, cortante e perfurante.', '', NULL
FROM public.spells WHERE external_index = 'hallow'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Hallucinatory Terrain
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('hallucinatory-terrain', 4, 'illusion', 'minute', 10, 300, 'feet', 24, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'druid', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Hallucinatory Terrain', 'You make natural terrain in a 150-foot cube in range look, sound, and smell like some other sort of natural terrain. Thus, open fields or a road can be made to resemble a swamp, hill, crevasse, or some other difficult or impassable terrain. A pond can be made to seem like a grassy meadow, a precipice like a gentle slope, or a rock-strewn gully like a wide and smooth road. Manufactured structures, equipment, and creatures within the area aren''t changed in appearance.
The tactile characteristics of the terrain are unchanged, so creatures entering the area are likely to see through the illusion. If the difference isn''t obvious by touch, a creature carefully examining the illusion can attempt an Intelligence (Investigation) check against your spell save DC to disbelieve it. A creature who discerns the illusion for what it is, sees it as a vague image superimposed on the terrain.', '', 'A stone, a twig, and a bit of green plant.'
FROM public.spells WHERE external_index = 'hallucinatory-terrain'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Terreno Alucinatório', 'Você faz com que um terreno natural em um cubo de 45 metros [150-foot cube] no alcance da magia pareça, soe e cheire como outro tipo de terreno natural. Assim, campos abertos ou um caminho podem ser modificados para que se assemelhem a um pântano, montanha, fenda ou algum outro terreno difícil ou intransitável. Uma lagoa pode ser modificada para se parecer com um prado verdejante, um precipício com um declive suave, ou um barranco pedregoso com uma estrada larga e plana. Estruturas manufaturadas, equipamentos e criaturas dentro da área não mudam a aparência.
As características táteis do terreno não são alteradas, portanto criaturas entrando na área são propensas a ver através da ilusão. Se a diferença não for óbvia ao toque, uma criatura examinando cuidadosamente a ilusão pode tentar um teste de Inteligência (Investigação) contra a CD para evitar suas magias, assim desacreditando a magia. Uma criatura que perceba a ilusão pelo o que é ela é, verá uma imagem difusa, sobreposta ao terreno.', '', NULL
FROM public.spells WHERE external_index = 'hallucinatory-terrain'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Harm
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('harm', 6, 'necromancy', 'action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Harm', 'You unleash a virulent disease on a creature that you can see within range. The target must make a constitution saving throw. On a failed save, it takes 14d6 necrotic damage, or half as much damage on a successful save. The damage can''t reduce the target''s hit points below 1. If the target fails the saving throw, its hit point maximum is reduced for 1 hour by an amount equal to the necrotic damage it took. Any effect that removes a disease allows a creature''s hit point maximum to return to normal before that time passes.', '', NULL
FROM public.spells WHERE external_index = 'harm'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Moléstia', 'Você transmite uma doença virulenta a uma criatura à sua vista e dentro do alcance da magia. O alvo deve fazer uma salvaguarda de Constituição. Se falhar, sofre 14d6 pontos de dano necrótico, ou metade do dano se bem-sucedido. O dano não pode reduzir os pontos de vida do alvo a menos de 1. Se o alvo falhar na salvaguarda, o valor de seus pontos de vida máximos é reduzido durante 1 hora em uma quantidade equivalente ao dano necrótico sofrido. Qualquer efeito que remova uma doença permite que o valor dos pontos de vida máximos do alvo retorne ao normal, antes do tempo de encerramento desta magia.', '', NULL
FROM public.spells WHERE external_index = 'harm'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Haste
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('haste', 3, 'transmutation', 'action', 1, 30, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Haste', 'Choose a willing creature that you can see within range. Until the spell ends, the target''s speed is doubled, it gains a +2 bonus to AC, it has advantage on dexterity saving throws, and it gains an additional action on each of its turns. That action can be used only to take the Attack (one weapon attack only), Dash, Disengage, Hide, or Use an Object action.
When the spell ends, the target can''t move or take actions until after its next turn, as a wave of lethargy sweeps over it.', '', 'A shaving of licorice root.'
FROM public.spells WHERE external_index = 'haste'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Celeridade', 'Escolha uma criatura voluntária, à sua vista e dentro do alcance da magia. Enquanto a magia durar, o alvo tem deslocamento dobrado, ganha +2 na CA, tem vantagem nas salvaguardas de Destreza e ganha uma ação adicional em cada um dos próprios turnos. Essa ação pode ser usada apenas como as ações Atacar (ataque armado, apenas), Correr, Desengajar, Esconder ou Usar um Objeto.
Quando a magia termina, o alvo é dominado por uma onda de letargia e não pode se mover ou executar ações até o final do próximo turno dele.', '', NULL
FROM public.spells WHERE external_index = 'haste'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Heal
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('heal', 6, 'evocation', 'action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['cleric', 'druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Heal', 'Choose a creature that you can see within range. A surge of positive energy washes through the creature, causing it to regain 70 hit points. This spell also ends blindness, deafness, and any diseases affecting the target. This spell has no effect on constructs or undead.', 'When you cast this spell using a spell slot of 7th level or higher, the amount of healing increases by 10 for each slot level above 6th.', NULL
FROM public.spells WHERE external_index = 'heal'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Cura Completa', 'Escolha uma criatura à sua vista e no alcance da magia. Uma onda de energia positiva a preenche, fazendo com que recupere 70 pontos de vida. Esta magia também põe fim a cegueira, surdez ou a qualquer doença que afete o alvo. Esta magia não tem efeito sobre constructos ou mortos-vivos.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 7º círculo ou superior, a quantidade de pontos de vida recuperados aumenta em 10 para cada círculo do espaço acima do 6º.', '', NULL
FROM public.spells WHERE external_index = 'heal'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Healing Word
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('healing-word', 1, 'evocation', 'bonus_action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V'], ARRAY['bard', 'cleric', 'druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Healing Word', 'A creature of your choice that you can see within range regains hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', 'When you cast this spell using a spell slot of 2nd level or higher, the healing increases by 1d4 for each slot level above 1st.', NULL
FROM public.spells WHERE external_index = 'healing-word'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Palavra Curativa', 'Escolha uma criatura à sua vista e no alcance da magia. Ela recupera uma quantidade de pontos de vida igual a 1d4 + seu modificador de atributo de conjuração. Esta magia não tem efeito sobre mortos-vivos ou constructos.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, a cura aumenta em 1d4 para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'healing-word'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Heat Metal
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('heat-metal', 2, 'transmutation', 'action', 1, 60, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Heat Metal', 'Choose a manufactured metal object, such as a metal weapon or a suit of heavy or medium metal armor, that you can see within range. You cause the object to glow red-hot. Any creature in physical contact with the object takes 2d8 fire damage when you cast the spell. Until the spell ends, you can use a bonus action on each of your subsequent turns to cause this damage again.
If a creature is holding or wearing the object and takes the damage from it, the creature must succeed on a constitution saving throw or drop the object if it can. If it doesn''t drop the object, it has disadvantage on attack rolls and ability checks until the start of your next turn.', 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for each slot level above 2nd.', 'A piece of iron and a flame.'
FROM public.spells WHERE external_index = 'heat-metal'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Esquentar Metal', 'Escolha um objeto metálico manufaturado, como uma arma de metal ou uma armadura de metal pesada ou média, à sua vista e no alcance da magia. Você faz com que o objeto brilhe em um tom vermelho incandescente. Qualquer criatura que esteja em contato físico com o objeto sofre 2d8 pontos de dano ígneo no momento da conjuração. Enquanto a magia durar, você pode usar sua ação bônus em cada um dos seus turnos subsequentes para causar esse dano novamente.
Se uma criatura estiver segurando ou usando o objeto e sofrer o dano, ela deve ser bem-sucedida em uma salvaguarda de Constituição ou derruba o objeto, se puder. Caso não o faça, ela tem desvantagem nas jogadas de ataque e em testes de atributo até o início do próximo turno do conjurador desta magia.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 3º círculo ou superior, o dano aumenta em 1d8 para cada círculo do espaço acima do 2º.', '', NULL
FROM public.spells WHERE external_index = 'heat-metal'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Hellish Rebuke
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('hellish-rebuke', 1, 'evocation', 'reaction', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['warlock'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Hellish Rebuke', 'You point your finger, and the creature that damaged you is momentarily surrounded by hellish flames. The creature must make a dexterity saving throw. It takes 2d10 fire damage on a failed save, or half as much damage on a successful one.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.', NULL
FROM public.spells WHERE external_index = 'hellish-rebuke'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Repreensão Diabólica', 'Você aponta o seu dedo e a criatura que lhe causou dano é momentaneamente cercada por chamas infernais. Ela deve fazer uma salvaguarda de Destreza. Se falhar, sofre 2d10 pontos de dano ígneo, ou metade do dano em caso de sucesso.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, o dano aumenta em 1d10 para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'hellish-rebuke'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Heroes' Feast
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('heroes-feast', 6, 'conjuration', 'minute', 10, 30, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Heroes'' Feast', 'You bring forth a great feast, including magnificent food and drink. The feast takes 1 hour to consume and disappears at the end of that time, and the beneficial effects don''t set in until this hour is over. Up to twelve other creatures can partake of the feast.
A creature that partakes of the feast gains several benefits. The creature is cured of all diseases and poison, becomes immune to poison and being frightened, and makes all wisdom saving throws with advantage. Its hit point maximum also increases by 2d10, and it gains the same number of hit points. These benefits last for 24 hours.', '', 'A gem-encrusted bowl worth at least 1,000gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'heroes-feast'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Banquete de Heróis', 'Você faz surgir um grande banquete, incluindo comida e bebida magníficas. O banquete leva 1 hora para ser consumido e desaparece no final desse tempo; os efeitos benéficos não aparecem até que essa hora se passe. Até doze outras criaturas podem partilhar o banquete.
Uma criatura que partilhe do banquete ganha vários benefícios. A criatura é curada de todas as doenças e envenenamentos, torna-se imune a veneno e a ficar amedrontada, e faz todas as salvaguardas de Sabedoria com vantagem. O valor dos pontos de vida máximos dela também aumenta em 2d10, ganhando esse mesmo número em pontos de vida. Estes benefícios duram 24 horas.', '', NULL
FROM public.spells WHERE external_index = 'heroes-feast'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Heroism
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('heroism', 1, 'enchantment', 'action', 1, NULL, 'touch', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['bard', 'paladin'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Heroism', 'A willing creature you touch is imbued with bravery. Until the spell ends, the creature is immune to being frightened and gains temporary hit points equal to your spellcasting ability modifier at the start of each of its turns. When the spell ends, the target loses any remaining temporary hit points from this spell.', '', NULL
FROM public.spells WHERE external_index = 'heroism'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Heroísmo', 'Você toca uma criatura voluntária que torna-se imbuída de bravura. Enquanto a magia durar, o alvo está imune a ser amedrontado e ganha uma quantidade de pontos de vida temporários igual ao seu modificador do atributo de conjuração, no início de cada um dos turnos dela. Quando a magia terminar, o alvo perde quaisquer pontos de vida temporários remanescentes derivados desta magia.
Em Círculos Superiores. Ao conjurar esta magia utilizando um espaço de magia de 2º círculo ou superior, você pode escolher uma criatura adicional como alvo para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'heroism'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Hideous Laughter
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('hideous-laughter', 1, 'enchantment', 'action', 1, 30, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Hideous Laughter', 'A creature of your choice that you can see within range perceives everything as hilariously funny and falls into fits of laughter if this spell affects it. The target must succeed on a wisdom saving throw or fall prone, becoming incapacitated and unable to stand up for the duration. A creature with an Intelligence score of 4 or less isn''t affected.
At the end of each of its turns, and each time it takes damage, the target can make another wisdom saving throw. The target had advantage on the saving throw if it''s triggered by damage. On a success, the spell ends.', '', 'Tiny tarts and a feather that is waved in the air.'
FROM public.spells WHERE external_index = 'hideous-laughter'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Gargalhada Nefasta', 'Você escolhe uma criatura à sua vista e no alcance da magia, que passa a perceber tudo como hilariantemente engraçado, sofrendo ataques de riso, caso seja afetada pela magia. O alvo deve ser bem-sucedido em uma salvaguarda de Sabedoria ou fica caído, incapacitado e incapaz de se levantar enquanto a magia durar. Uma criatura de Inteligência 4 ou menos não pode ser afetada.
Ao final de cada turno, e em cada ocasião que sofrer dano, o alvo pode tentar outra salvaguarda de Sabedoria. O alvo tem vantagem se a salvaguarda for disparada por dano sofrido. Em caso de sucesso, a magia se encerra.', '', NULL
FROM public.spells WHERE external_index = 'hideous-laughter'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Hold Monster
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('hold-monster', 5, 'enchantment', 'action', 1, 90, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Hold Monster', 'Choose a creature you can see and reach. The target must make a saving throw of Wisdom or be paralyzed for the duration of the spell. This spell has no effect against the undead. At the end of each round, the target can make a new saving throw of Wisdom. If successful, the spell ends for the creature.', 'When you cast this spell using a level 6 or higher location, you can target an additional creature for each level of location beyond the fifth. The creatures must be within 30 feet o f each other when you target them.', 'A small piece of iron.'
FROM public.spells WHERE external_index = 'hold-monster'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Imobilizar Monstro', 'Escolha uma criatura à sua vista e no alcance da magia. O alvo deve ser bem-sucedido em uma salvaguarda de Sabedoria ou fica paralisado enquanto a magia durar. Esta magia não tem efeito sobre mortos-vivos. No final de cada um dos turnos dele, o alvo pode fazer uma nova salvaguarda de Sabedoria. Em caso de sucesso, a magia se encerra sobre o alvo.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 6º círculo ou superior, você pode atingir uma criatura adicional para cada círculo do espaço acima do 5º. As criaturas devem estar a até 9 metros umas das outras quando você as atingir.', '', NULL
FROM public.spells WHERE external_index = 'hold-monster'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
