VALUES ('hold-person', 2, 'enchantment', 'action', 1, 60, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'druid', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Hold Person', 'Choose a humanoid that you can see within range. The target must succeed on a wisdom saving throw or be paralyzed for the duration. At the end of each of its turns, the target can make another wisdom saving throw. On a success, the spell ends on the target.', 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional humanoid for each slot level above 2nd. The humanoids must be within 30 feet of each other when you target them.', 'A small, straight piece of iron.'
FROM public.spells WHERE external_index = 'hold-person'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Imobilizar Pessoa', 'Escolha um humanoide à sua vista e no alcance da magia. O alvo deve ser bem-sucedido em uma salvaguarda de Sabedoria ou fica paralisado enquanto a magia durar. No final de cada um dos turnos dele, o alvo pode fazer outra salvaguarda de Sabedoria. Em caso de sucesso, a magia se encerra sobre o alvo.Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 3º círculo ou superior, você pode atingir um humanoide adicional para cada círculo do espaço acima do 2º. Os humanoides devem estar a até de 9 metros [30 ft.] uns dos outros quando você os atingir.', '', NULL
FROM public.spells WHERE external_index = 'hold-person'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Holy Aura
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('holy-aura', 8, 'abjuration', 'action', 1, NULL, 'self', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Holy Aura', 'Divine light washes out from you and coalesces in a soft radiance in a 30-foot radius around you. Creatures of your choice in that radius when you cast this spell shed dim light in a 5-foot radius and have advantage on all saving throws, and other creatures have disadvantage on attack rolls against them until the spell ends. In addition, when a fiend or an undead hits an affected creature with a melee attack, the aura flashes with brilliant light. The attacker must succeed on a constitution saving throw or be blinded until the spell ends.', '', 'A tiny reliquary worth at least 1,000gp containing a sacred relic, such as a scrap of cloth from a saint''s robe or a piece of parchment from a religious text.'
FROM public.spells WHERE external_index = 'holy-aura'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Aura Sagrada', 'Uma luz divina emana de você e se manifesta em um brilho suave por um raio de 9 metros [30 ft.] ao seu redor. Criaturas dentro do raio e à sua escolha emitem meia-luz em um raio de 1,5 metro [5 ft.] e têm vantagem em todas as salvaguardas, as demais criaturas têm desvantagem em jogadas de ataque contra as primeiras enquanto a magia durar. Além disso, quando um ínfero ou um morto-vivo atinge uma criatura afetada por esta magia com um ataque corpo a corpo, a aura cintila com uma luz brilhante. O atacante deve ser bem-sucedido em uma salvaguarda de Constituição ou fica cego enquanto a magia durar.', '', NULL
FROM public.spells WHERE external_index = 'holy-aura'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Hunter's Mark
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('hunters-mark', 1, 'divination', 'bonus_action', 1, 90, 'feet', 1, 'hour', true, false, ARRAY['V'], ARRAY['ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Hunter''s Mark', 'You choose a creature you can see within range and mystically mark it as your quarry. Until the spell ends, you deal an extra 1d6 damage to the target whenever you hit it with a weapon attack, and you have advantage on any Wisdom (Perception) or Wisdom (Survival) check you make to find it. If the target drops to 0 hit points before this spell ends, you can use a bonus action on a subsequent turn of yours to mark a new creature.', 'When you cast this spell using a spell slot of 3rd or 4th level, you can maintain your concentration on the spell for up to 8 hours. When you use a spell slot of 5th level or higher, you can maintain your concentration on the spell for up to 24 hours.', NULL
FROM public.spells WHERE external_index = 'hunters-mark'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Marca do Predador', 'Escolha uma criatura à sua vista e no alcance e da magia, marcando-a misticamente como sua presa. Enquanto a magia durar, você causa 1d6 pontos de dano adicionais no alvo sempre que o atingir com um ataque armado, e tem vantagem em qualquer teste de Sabedoria (Percepção) ou Sabedoria (Sobrevivência) feito para encontrá-lo. Se os pontos de vida do alvo forem reduzidos a 0 antes desta magia se encerrar, você pode usar uma ação bônus em um turno subsequente seu para marcar uma nova criatura.
Em Círculos Superiores. Ao conjurar esta magia com um espaço de magia de 3º ou 4º círculo, você pode manter a sua concentração por até 8 horas. Ao usar um espaço de magia de 5º círculo ou maior, você pode manter a sua concentração na magia por até 24 horas.', '', NULL
FROM public.spells WHERE external_index = 'hunters-mark'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Hypnotic Pattern
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('hypnotic-pattern', 3, 'illusion', 'action', 1, 120, 'feet', 1, 'minute', true, false, ARRAY['S', 'M'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Hypnotic Pattern', 'You create a twisting pattern of colors that weaves through the air inside a 30-foot cube within range. The pattern appears for a moment and vanishes. Each creature in the area who sees the pattern must make a wisdom saving throw. On a failed save, the creature becomes charmed for the duration. While charmed by this spell, the creature is incapacitated and has a speed of 0.
The spell ends for an affected creature if it takes any damage or if someone else uses an action to shake the creature out of its stupor.', '', 'A glowing stick of incense or a crystal vial filled with phosphorescent material.'
FROM public.spells WHERE external_index = 'hypnotic-pattern'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Padrão Hipnótico', 'Você cria um padrão distorcido de cores o qual serpenteia no ar dentro de um cubo de 9 metros de lado [30-foot cube], no alcance da magia. O padrão aparece por um momento e desaparece. Cada criatura na área, e que seja capaz de ver o padrão, deve fazer uma salvaguarda de Sabedoria. Se falhar, a criatura fica enfeitiçada enquanto a magia durar. Criaturas afetadas por esta magia estão incapacitadas e tem deslocamento igual a 0.Uma criatura afetada por esta magia terá os efeitos encerrados sobre si caso venha a sofrer qualquer tipo de dano ou se alguém usar uma ação para sacudi-la, removendo-a de seu estupor.', '', NULL
FROM public.spells WHERE external_index = 'hypnotic-pattern'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Ice Storm
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('ice-storm', 4, 'evocation', 'action', 1, 300, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'sorcerer', 'wizard'], 'dnd_5e')
