INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Ice Storm', 'A hail of rock-hard ice pounds to the ground in a 20-foot-radius, 40-foot-high cylinder centered on a point within range. Each creature in the cylinder must make a dexterity saving throw. A creature takes 2d8 bludgeoning damage and 4d6 cold damage on a failed save, or half as much damage on a successful one.
Hailstones turn the storm''s area of effect into difficult terrain until the end of your next turn.', 'When you cast this spell using a spell slot of 5th level or higher, the bludgeoning damage increases by 1d8 for each slot level above 4th.', 'A pinch of dust and a few drops of water.'
FROM public.spells WHERE external_index = 'ice-storm'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Tempestade Glacial', 'Uma saraivada de pedras de gelo bate no chão em um cilindro de 6 metros de raio por 12 metros de altura [20-foot-radius, 40-foot-tall cylinder], centrado em um ponto no alcance da magia. Cada criatura na área afetada deve fazer uma salvaguarda de Destreza. Se falhar, sofre 2d8 pontos de dano contundente e 4d6 pontos de dano gélido, ou metade do dano em caso de sucesso.
O granizo transforma a área da tempestade em terreno difícil até o final do seu próximo turno.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 5º círculo ou superior, o dano contundente aumenta em 1d8 para cada círculo do espaço acima do 4º círculo.', '', NULL
FROM public.spells WHERE external_index = 'ice-storm'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Identify
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('identify', 1, 'divination', 'minute', 1, NULL, 'touch', NULL, 'instantaneous', false, true, ARRAY['V', 'S', 'M'], ARRAY['bard', 'wizard'], 'dnd_5e')
