INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Identify', 'You choose one object that you must touch throughout the casting of the spell. If it is a magic item or some other magic-imbued object, you learn its properties and how to use them, whether it requires attunement to use, and how many charges it has, if any. You learn whether any spells are affecting the item and what they are. If the item was created by a spell, you learn which spell created it.
If you instead touch a creature throughout the casting, you learn what spells, if any, are currently affecting it.', '', 'A pearl worth at least 100gp and an owl feather.'
FROM public.spells WHERE external_index = 'identify'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Indentificar', 'Escolha um objeto que você deve tocar durante a conjuração da magia. Se for um item mágico ou algum outro tipo de objeto imbuído de magia, você descobre as propriedades dele e como usá-las, se ele exige sintonização para ser usado e quantas cargas tem, caso as tenha. Você também descobre se alguma magia está afetando o objeto e que magia é essa. Se o item foi criado por uma magia, você também identifica qual magia o criou.Se em vez disso você tocar uma criatura durante a conjuração, você descobre quais magias a estão afetando, caso estejam.', '', NULL
FROM public.spells WHERE external_index = 'identify'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Illusory Script
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('illusory-script', 1, 'illusion', 'minute', 1, NULL, 'touch', 10, 'day', false, true, ARRAY['S', 'M'], ARRAY['bard', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Illusory Script', 'You write on parchment, paper, or some other suitable writing material and imbue it with a potent illusion that lasts for the duration.
To you and any creatures you designate when you cast the spell, the writing appears normal, written in your hand, and conveys whatever meaning you intended when you wrote the text. To all others, the writing appears as if it were written in an unknown or magical script that is unintelligible. Alternatively, you can cause the writing to appear to be an entirely different message, written in a different hand and language, though the language must be one you know.
Should the spell be dispelled, the original script and the illusion both disappear.
A creature with truesight can read the hidden message.', '', 'A lead-based ink worth at least 10gp, which this spell consumes.'
FROM public.spells WHERE external_index = 'illusory-script'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Escrita Ilusória', 'Você escreve em um pergaminho, papel ou algum material apropriado para escrita, infundindo-o com uma ilusão potente enquanto a magia durar.
Para você e quaisquer criaturas escolhidas quando a magia é conjurada a escrita parece com sua caligrafia normal e expressa qualquer significado de sua intenção quando o texto foi escrito. Para todos os demais, as palavras aparecem como se fossem escritas em um alfabeto · desconhecido ou mágico, tornando-as ininteligíveis. Se preferir, você pode fazer com que a escrita tenha a aparência de um texto completamente diferente, escrito em outra caligrafia e idioma, apesar de ser necessário que você conheça o idioma.
Caso a magia seja dissipada, tanto o texto original quanto o ilusório desaparecem.
Uma criatura com visão verdadeira pode ler a mensagem escondida.', '', NULL
FROM public.spells WHERE external_index = 'illusory-script'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Imprisonment
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('imprisonment', 9, 'abjuration', 'minute', 1, 30, 'feet', NULL, 'special', false, false, ARRAY['V', 'S', 'M'], ARRAY['warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Imprisonment', 'You create a magical restraint to hold a creature that you can see within range. The target must succeed on a wisdom saving throw or be bound by the spell; if it succeeds, it is immune to this spell if you cast it again. While affected by this spell, the creature doesn''t need to breathe, eat, or drink, and it doesn''t age. Divination spells can''t locate or perceive the target.
When you cast the spell, you choose one of the following forms of imprisonment.
***Burial.*** The target is entombed far beneath the earth in a sphere of magical force that is just large enough to contain the target. Nothing can pass through the sphere, nor can any creature teleport or use planar travel to get into or out of it.
The special component for this version of the spell is a small mithral orb.
***Chaining.*** Heavy chains, firmly rooted in the ground, hold the target in place. The target is restrained until the spell ends, and it can''t move or be moved by any means until then.
The special component for this version of the spell is a fine chain of precious metal.
***Hedged Prison.*** The spell transports the target into a tiny demiplane that is warded against teleportation and planar travel. The demiplane can be a labyrinth, a cage, a tower, or any similar confined structure or area of your choice.
The special component for this version of the spell is a miniature representation of the prison made from jade.
***Minimus Containment.*** The target shrinks to a height of 1 inch and is imprisoned inside a gemstone or similar object. Light can pass through the gemstone normally (allowing the target to see out and other creatures to see in), but nothing else can pass through, even by means of teleportation or planar travel. The gemstone can''t be cut or broken while the spell remains in effect.
The special component for this version of the spell is a large, transparent gemstone, such as a corundum, diamond, or ruby.
***Slumber.*** The target falls asleep and can''t be awoken.
The special component for this version of the spell consists of rare soporific herbs.
***Ending the Spell.*** During the casting of the spell, in any of its versions, you can specify a condition that will cause the spell to end and release the target. The condition can be as specific or as elaborate as you choose, but the GM must agree that the condition is reasonable and has a likelihood of coming to pass. The conditions can be based on a creature''s name, identity, or deity but otherwise must be based on observable actions or qualities and not based on intangibles such as level, class, or hit points.
A dispel magic spell can end the spell only if it is cast as a 9th-level spell, targeting either the prison or the special component used to create it.
You can use a particular special component to create only one prison at a time. If you cast the spell again using the same component, the target of the first casting is immediately freed from its binding.', '', 'A vellum depiction or a carved statuette in the likeness of the target, and a special component that varies according to the version of the spell you choose, worth at least 500gp per Hit Die of the target.'
FROM public.spells WHERE external_index = 'imprisonment'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Aprisionamento', 'Você cria um dispositivo de retenção mágica para aprisionar uma criatura à sua vista e no alcance da magia. O alvo deve fazer uma salvaguarda de Sabedoria. Se falhar, fica preso pela magia; se for bem-sucedido, fica imune a esta magia caso você a conjure novamente. A criatura não precisa respirar, comer ou beber, e não envelhece enquanto estiver afetada por esta magia. Magias de adivinhação não podem localizar ou perceber o alvo.
Ao conjurar esta magia, você escolhe uma das seguintes formas de aprisionamento.
Acorrentar. Pesadas correntes firmemente enraizadas ao chão prendem o alvo no lugar. O alvo fica contido enquanto a magia durar, e não pode mover-se ou ser movido por quaisquer meios antes disso. O componente especial para esta versão da magia é uma corrente fina feita de algum metal precioso.
Contenção Reduzida. O alvo é encolhido até uma altura de 2,5 centímetros [1 inch] e fica preso dentro de uma pedra preciosa ou objeto similar. Luz pode passar através da pedra preciosa normalmente (permitindo que o alvo possa ver o que há fora e que outras criaturas de fora possam vê-lo), porém nada mais pode passar, mesmo por meio de teleporte ou viagem planar. A pedra preciosa não pode ser lapidada ou quebrada enquanto a magia permanecer em vigor. O componente especial para esta versão da magia é uma grande gema transparente, como uma safira, diamante ou rubi.
Enterrar. O alvo é enterrado bem fundo no solo em uma esfera de força mágica grande o suficiente para contê-lo. Nada pode passar através da esfera, nem qualquer criatura pode teleportar ou usar viagem planar para entrar ou sair dela. O componente especial para esta versão da magia é um pequeno orbe de mitral.
Prisão Cercada. A magia transporta o alvo para um minúsculo semiplano protegido contra teleporte e viagens planares. O semiplano pode ser um labirinto, uma gaiola, uma torre ou qualquer estrutura confinada ou área semelhante, à sua escolha. O componente especial para esta versão da magia é uma representação em miniatura da prisão feita em jade.
Torpor. O alvo fica inconsciente e não pode ser despertado. O componente especial para esta versão da magia consiste em raras ervas soníferas.
Terminando a Magia. Durante a conjuração desta magia, qualquer que seja a versão dela, você pode especificar uma condição que fará com que ela termine e o alvo seja liberado. A condição pode ser tão específica ou tão elaborada quanto você desejar, mas o DM deve concordar que a condição seja razoável e que tenha uma probabilidade de vir a acontecer. As condições podem ser baseadas no nome, identidade ou divindade de uma criatura, mas seja como for, deve ser baseada em ações ou qualidades observáveis e não em coisas intangíveis como nível, classe ou pontos de vida.
Uma magia Dissipar Magia pode encerrar esta magia somente se for conjurada como uma magia de 9º círculo, tendo como alvo seja a prisão ou o componente especial usado para criá-lo.
Você pode usar um determinado componente especial para criar apenas uma prisão de cada vez. Se você conjurar a magia novamente usando o mesmo componente, o alvo da primeira conjuração é imediatamente liberado de sua prisão.', '', NULL
FROM public.spells WHERE external_index = 'imprisonment'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Incendiary Cloud
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('incendiary-cloud', 8, 'conjuration', 'action', 1, 150, 'feet', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Incendiary Cloud', 'A swirling cloud of smoke shot through with white-hot embers appears in a 20-foot-radius sphere centered on a point within range. The cloud spreads around corners and is heavily obscured. It lasts for the duration or until a wind of moderate or greater speed (at least 10 miles per hour) disperses it.
When the cloud appears, each creature in it must make a dexterity saving throw. A creature takes 10d8 fire damage on a failed save, or half as much damage on a successful one. A creature must also make this saving throw when it enters the spell''s area for the first time on a turn or ends its turn there.
The cloud moves 10 feet directly away from you in a direction that you choose at the start of each of your turns.', '', NULL
FROM public.spells WHERE external_index = 'incendiary-cloud'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Nuvem Incendiária', 'Uma nuvem rodopiante de fumaça que atira brasas quentes aparece em uma esfera com raio de 6 metros [20-foot-radius sphere], centrada em um ponto à sua escolha e no alcance da magia. A nuvem se alastra, contornando os cantos e a área afetada fica totalmente obscurecida. Ela permanece enquanto a magia durar ou até que um vento de velocidade moderada (de ao menos 15 quilômetros [10 miles] por hora) ou maior a disperse.
Quando a nuvem aparece, cada criatura dentro dela deve fazer uma salvaguarda de Destreza. Se falhar, sofre 10d8 pontos de dano ígneo, ou metade do dano em caso de sucesso. Uma criatura deve fazer esta salvaguarda quando entra na área da magia pela primeira vez ou inicia o pró­prio turno ali.
A nuvem se distancia 3 metros [10 ft.] de você em uma direção à sua escolha no início de cada um de seus turnos.', '', NULL
FROM public.spells WHERE external_index = 'incendiary-cloud'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Inflict Wounds
