INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Inflict Wounds', 'Make a melee spell attack against a creature you can reach. On a hit, the target takes 3d10 necrotic damage.', 'When you cast this spell using a spell slot of 2nd level or higher, the damage increases by 1d10 for each slot level above 1st.', NULL
FROM public.spells WHERE external_index = 'inflict-wounds'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Infligir Ferimentos', 'Faça um ataque mágico corpo a corpo contra uma criatura ao seu alcance. Se acertar, o alvo sofre 3d10 pontos de dano necrótico.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, o dano aumenta em 1d10 para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'inflict-wounds'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Insect Plague
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('insect-plague', 5, 'conjuration', 'action', 1, 300, 'feet', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'druid', 'sorcerer'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Insect Plague', 'Swarming, biting locusts fill a 20-foot-radius sphere centered on a point you choose within range. The sphere spreads around corners. The sphere remains for the duration, and its area is lightly obscured. The sphere''s area is difficult terrain.
When the area appears, each creature in it must make a constitution saving throw. A creature takes 4d10 piercing damage on a failed save, or half as much damage on a successful one. A creature must also make this saving throw when it enters the spell''s area for the first time on a turn or ends its turn there.', 'When you cast this spell using a spell slot of 6th level or higher, the damage increases by 1d10 for each slot level above 5th.', 'A few grains of sugar, some kernels of grain, and a smear of fat.'
FROM public.spells WHERE external_index = 'insect-plague'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Praga de Insetos', 'Um enxame de gafanhotos vorazes preenche uma esfera com raio de 6 metros [20 ft.], centrada em um ponto à sua escolha e no alcance da magia. A esfera de insetos se alastra, contornando os cantos. Enquanto a magia durar, a área afetada torna-se parcialmente obscurecida e terreno difícil.
Quando o enxame surge, cada criatura no local do efeito deve ser bem-sucedida em uma salvaguarda de Constitui­ção. Se falhar, sofre 4d10 pontos de dano perfurante, ou metade do dano em caso de sucesso. Uma criatura também deve fazer esta salvaguarda ao entrar pela primeira vez, ou ao terminar o próprio turno na área da magia.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 6º círculo ou superior, o dano aumenta em 1d10 para cada círculo do espaço acima do 5º.', '', NULL
FROM public.spells WHERE external_index = 'insect-plague'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Instant Summons
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('instant-summons', 6, 'conjuration', 'minute', 1, NULL, 'touch', NULL, 'special', false, true, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Instant Summons', 'You touch an object weighing 10 pounds or less whose longest dimension is 6 feet or less. The spell leaves an invisible mark on its surface and invisibly inscribes the name of the item on the sapphire you use as the material component. Each time you cast this spell, you must use a different sapphire.
At any time thereafter, you can use your action to speak the item''s name and crush the sapphire. The item instantly appears in your hand regardless of physical or planar distances, and the spell ends.
If another creature is holding or carrying the item, crushing the sapphire doesn''t transport the item to you, but instead you learn who the creature possessing the object is and roughly where that creature is located at that moment.
Dispel magic or a similar effect successfully applied to the sapphire ends this spell''s effect.', '', 'A sapphire worth 1,000 gp.'
FROM public.spells WHERE external_index = 'instant-summons'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Convocação Instantânea', 'Você toca um objeto pesando não mais do que 5 quilos [10 pounds], cuja maior dimensão seja de 1,8 metro [6 ft.] ou menor. Esta magia deixa uma marca invisível na superfície do objeto e, de maneira invisível, inscreve o nome do item na safira que você usou como componente material. Cada vez que conjurar esta magia, você deve usar uma safira diferente.
Em qualquer momento posterior, você pode usar sua ação para dizer o nome do item e esmagar a safira. O item aparece imediatamente na sua mão, independentemente de qualquer distância física ou planar, o que encerra a magia.
Se alguma outra criatura estiver segurando ou transportando o item, esmagar a safira não o transporta até você, em vez disso você descobre quem é a criatura de posse do objeto e, aproximadamente, onde ela se encontra naquele momento.
Dissipar Magia ou um efeito similar aplicado com sucesso na safira encerra o efeito desta magia.', '', NULL
FROM public.spells WHERE external_index = 'instant-summons'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Invisibility
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('invisibility', 2, 'illusion', 'action', 1, NULL, 'touch', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Invisibility', 'A creature you touch becomes invisible until the spell ends. Anything the target is wearing or carrying is invisible as long as it is on the target''s person. The spell ends for a target that attacks or casts a spell.', 'When you cast this spell using a spell slot of 3rd level or higher, you can target one additional creature for each slot level above 2nd.', 'An eyelash encased in gum arabic.'
FROM public.spells WHERE external_index = 'invisibility'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Invisibilidade', 'Uma criatura que você tocar torna-se invisível enquanto a magia durar. Qualquer coisa que o alvo estiver usando ou carregando torna-se invisível enquanto estiver em sua posse. A magia se encerra quando o alvo efetuar um ataque ou conjurar uma magia.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 3º círculo ou superior, você pode atingir uma criatura adicional para cada círculo do espaço acima do 2º.', '', NULL
FROM public.spells WHERE external_index = 'invisibility'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Irresistible Dance
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('irresistible-dance', 6, 'enchantment', 'action', 1, 30, 'feet', 1, 'minute', true, false, ARRAY['V'], ARRAY['bard', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Irresistible Dance', 'Choose one creature that you can see within range. The target begins a comic dance in place: shuffling, tapping its feet, and capering for the duration. Creatures that can''t be charmed are immune to this spell.
A dancing creature must use all its movement to dance without leaving its space and has disadvantage on dexterity saving throws and attack rolls. While the target is affected by this spell, other creatures have advantage on attack rolls against it. As an action, a dancing creature makes a wisdom saving throw to regain control of itself. On a successful save, the spell ends.', '', NULL
FROM public.spells WHERE external_index = 'irresistible-dance'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Dança Irresistível', 'Escolha uma criatura à sua vista, no alcance da magia. O alvo começa a dançar comicamente onde estiver: balançando-se, batendo os pés e se contorcendo enquanto a magia durar. Criaturas que não podem ser enfeitiçadas são imunes a esta magia.
Uma criatura sob o efeito da magia deve usar todo o movimento para dançar sem sair do próprio espaço, além de ter desvantagem em salvaguardas de Destreza e jogadas de ataque. Enquanto o alvo estiver afetado por esta magia, outras criaturas têm vantagem nas jogadas de ataque contra ele. Usando uma ação, uma criatura afetada pode fazer uma salvaguarda de Sabedoria para recuperar o controle sobre si mesma. Em caso de sucesso, a magia termina.', '', NULL
FROM public.spells WHERE external_index = 'irresistible-dance'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
