-- Knock
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('knock', 2, 'transmutation', 'action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Knock', 'Choose an object that you can see within range. The object can be a door, a box, a chest, a set of manacles, a padlock, or another object that contains a mundane or magical means that prevents access.
A target that is held shut by a mundane lock or that is stuck or barred becomes unlocked, unstuck, or unbarred. If the object has multiple locks, only one of them is unlocked.
If you choose a target that is held shut with arcane lock, that spell is suppressed for 10 minutes, during which time the target can be opened and shut normally.
When you cast the spell, a loud knock, audible from as far away as 300 feet, emanates from the target object.', '', NULL
FROM public.spells WHERE external_index = 'knock'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Arrombar', 'Escolha um objeto à sua vista e no alcance da magia. O objeto pode ser uma porta, uma caixa, um baú, um par de algemas, um cadeado ou outro objeto que contenha um meio mundano ou mágico que impeça o acesso.
Um alvo que seja mantido fechado por uma fechadura mundana ou que esteja emperrado ou obstruído torna-se destrancado, desemperrado ou desobstruído. Se o objeto possui várias fechaduras, apenas uma delas é destrancada.
Se você escolher um alvo mantido fechado com tranca arcana, os efeitos sobre ele ficam suprimidos por 10 minutos, durante os quais o alvo pode ser aberto e fechado normalmente.
Ao conjurar a magia, um estrondo, audível a até 90 metros [300 ft.], emana do objeto escolhido como alvo.', '', NULL
FROM public.spells WHERE external_index = 'knock'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Legend Lore
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('legend-lore', 5, 'divination', 'minute', 10, NULL, 'self', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Legend Lore', 'Name or describe a person, place, or object. The spell brings to your mind a brief summary of the significant lore about the thing you named. The lore might consist of current tales, forgotten stories, or even secret lore that has never been widely known. If the thing you named isn''t of legendary importance, you gain no information. The more information you already have about the thing, the more precise and detailed the information you receive is.
The information you learn is accurate but might be couched in figurative language. For example, if you have a mysterious magic axe on hand the spell might yield this information: "Woe to the evildoer whose hand touches the axe, for even the haft slices the hand of the evil ones. Only a true Child of Stone, lover and beloved of Moradin, may awaken the true powers of the axe, and only with the sacred word *Rudnogg* on the lips."', '', 'Incense worth at least 250 gp, which the spell consumes, and four ivory strips worth at least 50 gp each.'
FROM public.spells WHERE external_index = 'legend-lore'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Lendas e Histórias', 'Nomeie ou descreva uma pessoa, local ou objeto. A magia traz à sua mente um breve resumo de conhecimento significativo sobre aquilo que você nomeou. O conhecimento pode consistir de contos atuais, histórias esquecidas ou até mesmo conhecimento secreto que nunca foi amplamente sabido. Se aquilo que nomeou não for de importância lendária, você não obtém nenhuma informação. Quanto mais informação você já tiver sobre a coisa, mais precisa e detalhada é a informação que recebe.Essa informação é precisa, mas pode ser expressa em linguagem figurada. Por exemplo, se você tem um misterioso machado mágico na mão, a magia pode produzir esta informação: "Ai do malfeitor cuja mão tocar o machado, pois mesmo o cabo dele decepa a mão dos ímpios. Apenas um verdadeiro Filho da Pedra, um adorador de Moradin e por ele amado poderá evocar os verdadeiros poderes do machado, e apenas com a palavra sagrada Rudnogg nos lábios".', '', NULL
FROM public.spells WHERE external_index = 'legend-lore'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
