ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Restauração Menor', 'Você toca uma criatura e pode tanto curar uma doença quanto remover uma condição que a aflija. A condição pode ser cego, envenenado, paralisado ou surdo.', '', NULL
