-- Levitate
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('levitate', 2, 'transmutation', 'action', 1, 60, 'feet', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Levitate', 'One creature or object of your choice that you can see within range rises vertically, up to 20 feet, and remains suspended there for the duration. The spell can levitate a target that weighs up to 500 pounds. An unwilling creature that succeeds on a constitution saving throw is unaffected.
The target can move only by pushing or pulling against a fixed object or surface within reach (such as a wall or a ceiling), which allows it to move as if it were climbing. You can change the target''s altitude by up to 20 feet in either direction on your turn. If you are the target, you can move up or down as part of your move. Otherwise, you can use your action to move the target, which must remain within the spell''s range.
When the spell ends, the target floats gently to the ground if it is still aloft.', '', 'Either a small leather loop or a piece of golden wire bent into a cup shape with a long shank on one end.'
FROM public.spells WHERE external_index = 'levitate'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Levitação', 'Escolha um criatura ou objeto à sua vista e no alcance da magia. O alvo sobe verticalmente a até 6 metros [20 ft.] de altura, permanecendo suspenso enquanto a magia durar. A magia pode levitar um alvo que pese até 225 quilos [500 pounds]. Uma criatura involuntária que seja bem-sucedida em uma salvaguarda de Constituição não é afetada.
O alvo pode se mover apenas ao empurrar ou puxar um objeto fixo ou superfície ao alcance dele (como uma parede ou teto), o que permite que ele se mova como se estivesse escalando. No seu turno, você pode mudar a altitude do alvo em até 6 metros [20 ft.] em qualquer direção. Se você for o alvo, pode mover-se para cima ou para baixo como parte do seu deslocamento. Caso contrário, você pode usar sua ação para mover o alvo, que deve permanecer no alcance da magia.
Quando esta magia terminar, caso ainda esteja no ar, o alvo inicia uma descida suave, flutuando em direção ao solo.', '', NULL
FROM public.spells WHERE external_index = 'levitate'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Light
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('light', 0, 'evocation', 'action', 1, NULL, 'touch', 1, 'hour', false, false, ARRAY['V', 'M'], ARRAY['bard', 'cleric', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Light', 'You touch one object that is no larger than 10 feet in any dimension. Until the spell ends, the object sheds bright light in a 20-foot radius and dim light for an additional 20 feet. The light can be colored as you like. Completely covering the object with something opaque blocks the light. The spell ends if you cast it again or dismiss it as an action.
If you target an object held or worn by a hostile creature, that creature must succeed on a dexterity saving throw to avoid the spell.', '', 'A firefly or phosphorescent moss.'
FROM public.spells WHERE external_index = 'light'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Luz', 'Você toca um objeto que não seja maior do que 3 metros [10 ft.] em qualquer dimensão. Até o fim da magia, o objeto emite luz plena em um raio de 6 metros [20-foot radius] e cria meia-luz por 6 metros [20 ft.] adicionais. Essa luz pode ser da cor de sua preferência. Cobrir completamente o objeto afetado com algo opaco bloqueia a luz. A magia termina se você conjurá-la novamente ou se a dispensar com uma ação.Caso você designe como alvo um objeto que esteja sendo carregado ou usado por uma criatura hostil, a criatura deve ser bem-sucedida em uma salvaguarda de Destreza para evitar a magia.', '', NULL
FROM public.spells WHERE external_index = 'light'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Lightning Bolt
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('lightning-bolt', 3, 'evocation', 'action', 1, NULL, 'self', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Lightning Bolt', 'A stroke of lightning forming a line 100 feet long and 5 feet wide blasts out from you in a direction you choose. Each creature in the line must make a dexterity saving throw. A creature takes 8d6 lightning damage on a failed save, or half as much damage on a successful one.
The lightning ignites flammable objects in the area that aren''t being worn or carried.', 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', 'A bit of fur and a rod of amber, crystal, or glass.'
FROM public.spells WHERE external_index = 'lightning-bolt'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Relâmpago', 'Um raio formando uma linha de 30 metros [100 ft.] de comprimento por 1,5 metro [5 ft.] de largura dispara a partir de você em uma direção à sua escolha. Cada criatura na linha deve fazer uma salvaguarda de Destreza. Se falhar, sofre 8d6 pontos de dano elétrico, ou metade do dano em caso de sucesso.
O raio incendeia objetos inflamáveis na área que não estejam sendo usados ou carregados.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 4º círculo ou superior, o dano aumenta em 1d6 para cada círculo do espaço acima do 3º.', '', NULL
FROM public.spells WHERE external_index = 'lightning-bolt'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Locate Animals or Plants
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('locate-animals-or-plants', 2, 'divination', 'action', 1, NULL, 'self', NULL, 'instantaneous', false, true, ARRAY['V', 'S', 'M'], ARRAY['bard', 'druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Locate Animals or Plants', 'Describe or name a specific kind of beast or plant. Concentrating on the voice of nature in your surroundings, you learn the direction and distance to the closest creature or plant of that kind within 5 miles, if any are present.', '', 'A bit of fur from a bloodhound.'
FROM public.spells WHERE external_index = 'locate-animals-or-plants'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Localizar Animais ou Plantas', 'Descreva ou nomeie um tipo específico de animal ou planta. Concentrando-se na voz da natureza ao seu redor, você descobre a direção e a distância (até 7,5 quilômetros [5 miles]) em que a criatura ou planta mais próxima daquele tipo se encontra, caso exista alguma na área.', '', NULL
FROM public.spells WHERE external_index = 'locate-animals-or-plants'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Locate Creature
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('locate-creature', 4, 'divination', 'action', 1, NULL, 'self', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'druid', 'paladin', 'ranger', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Locate Creature', 'Describe or name a creature that is familiar to you. You sense the direction to the creature''s location, as long as that creature is within 1,000 feet of you. If the creature is moving, you know the direction of its movement.
The spell can locate a specific creature known to you, or the nearest creature of a specific kind (such as a human or a unicorn), so long as you have seen such a creature up close--within 30 feet--at least once. If the creature you described or named is in a different form, such as being under the effects of a polymorph spell, this spell doesn''t locate the creature.
This spell can''t locate a creature if running water at least 10 feet wide blocks a direct path between you and the creature.', '', 'A bit of fur from a bloodhound.'
FROM public.spells WHERE external_index = 'locate-creature'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Localizar Criatura', 'Descreva ou nomeie uma criatura que lhe seja familiar. Você sente a direção do local onde ela se encontra, caso esteja a, no máximo, 300 metros [1000 ft.] de distância. Se a criatura estiver se movendo, você sabe em que direção.Esta magia pode localizar uma criatura específica que você conheça, ou a criatura mais próxima de um tipo específico (como um humano ou unicórnio), contanto que você já tenha visto tal criatura de perto - a até 9 metros [30 ft.] - ao menos uma vez. Se a criatura que você descreveu ou nomeou está com uma forma diferente, como sob o efeito da magia Polimorfia, esta magia não a localiza.Esta magia também não pode localizar uma criatura se água corrente, com pelo menos 3 metros [10 ft.] de largura, bloquear o caminho direto entre você e ela.', '', NULL
FROM public.spells WHERE external_index = 'locate-creature'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Locate Object
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('locate-object', 2, 'divination', 'action', 1, NULL, 'self', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'druid', 'paladin', 'ranger', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Locate Object', 'Describe or name an object that is familiar to you. You sense the direction to the object''s location, as long as that object is within 1,000 feet of you. If the object is in motion, you know the direction of its movement.
The spell can locate a specific object known to you, as long as you have seen it up close--within 30 feet--at least once. Alternatively, the spell can locate the nearest object of a particular kind, such as a certain kind of apparel, jewelry, furniture, tool, or weapon.
This spell can''t locate an object if any thickness of lead, even a thin sheet, blocks a direct path between you and the object.', '', 'A forked twig.'
FROM public.spells WHERE external_index = 'locate-object'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Localizar Objeto', 'Descreva ou nomeie um objeto que lhe seja familiar. Você sente a direção do local onde ele se encontra, caso esteja a, no máximo, 300 metros [1000 ft.] de distância. Se o objeto estiver se movendo, você sabe em que direção.A magia pode localizar um objeto específico que você conheça, desde que você já o tenha visto de perto - a até 9 metros [30 ft.] - ao menos uma vez. Se preferir, a magia pode localizar um objeto de um tipo específico, como certo tipo de traje, joia, mobília, ferramenta ou arma.Esta magia não pode localizar um objeto se qualquer espessura de chumbo, até mesmo uma folha fina, bloquear o caminho direto entre você ele.', '', NULL
FROM public.spells WHERE external_index = 'locate-object'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
