INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Longstrider', 'You touch a creature. The target''s speed increases by 10 feet until the spell ends.', 'When you cast this spell using a spell slot of 2nd level or higher, you can target one additional creature for each spell slot above 1st.', 'A pinch of dirt.'
FROM public.spells WHERE external_index = 'longstrider'
