INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Passos Largos', 'Você toca uma criatura. O deslocamento do alvo aumenta em 3 metros [10 ft.] enquanto a magia durar.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, você pode enfeitiçar uma criatura adicional para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'longstrider'
