-- Mage Armor
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('mage-armor', 1, 'abjuration', 'action', 1, NULL, 'touch', 8, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Mage Armor', 'You touch a willing creature who isn''t wearing armor, and a protective magical force surrounds it until the spell ends. The target''s base AC becomes 13 + its Dexterity modifier. The spell ends if the target dons armor or if you dismiss the spell as an action.', '', 'A piece of cured leather.'
FROM public.spells WHERE external_index = 'mage-armor'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Armadura Arcana', 'Você toca uma criatura voluntária que não esteja usando armadura. Uma força mágica protetora circunda-a enquanto a magia durar. A CA base do alvo se torna 13 + o modificador de Destreza dele. A magia termina se o alvo vestir uma armadura ou se você a dispensar com uma ação.', '', NULL
FROM public.spells WHERE external_index = 'mage-armor'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Mage Hand
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('mage-hand', 0, 'conjuration', 'action', 1, 30, 'feet', 1, 'minute', false, false, ARRAY['V', 'S'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Mage Hand', 'A spectral, floating hand appears at a point you choose within range. The hand lasts for the duration or until you dismiss it as an action. The hand vanishes if it is ever more than 30 feet away from you or if you cast this spell again.
You can use your action to control the hand. You can use the hand to manipulate an object, open an unlocked door or container, stow or retrieve an item from an open container, or pour the contents out of a vial. You can move the hand up to 30 feet each time you use it.
The hand can''t attack, activate magic items, or carry more than 10 pounds.', '', NULL
FROM public.spells WHERE external_index = 'mage-hand'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Mãos Mágicas', 'Uma mão flutuante e espectral aparece em um ponto à sua escolha e no alcance da magia. A mão permanece enquanto a magia durar ou até você dispensá-la com uma ação. A mão desaparece caso se distancie mais de 9 metros [30 ft.] de você ou se você conjurar a magia novamente.
Você pode usar sua ação para controlar a mão. Você pode fazer com que ela manipule objetos, abra portas ou recipientes destrancados, guarde ou pegue itens de recipientes abertos, ou derrame o conteúdo de frascos. Você pode movê-la até 9 metros [30 ft.] a cada vez que a usa.
 Ela não pode atacar, ativar itens mágicos ou carregar mais de 4,5 quilos [10 pounds].', '', NULL
FROM public.spells WHERE external_index = 'mage-hand'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Magic Circle
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('magic-circle', 3, 'abjuration', 'minute', 1, 10, 'feet', 1, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'paladin', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Magic Circle', 'You create a 10-foot radius, 20-foot-tall cylinder of magical energy centered on a point on the ground that you can see within range. Glowing runes appear whenever the cylinder intersects with the floor or other surface.
Choose one or more of the following types of creatures: celestials, elementals, fey, fiends, or undead. The circle affects a creature of the chosen type in the following ways:
- The creature can''t willingly enter the cylinder by nonmagical means. If the creature tries to use teleportation or interplanar travel to do so, it must first succeed on a charisma saving throw.
- The creature has disadvantage on attack rolls against targets within the cylinder.
- Targets within the cylinder can''t be charmed, frightened, or possessed by the creature.
When you cast this spell, you can elect to cause its magic to operate in the reverse direction, preventing a creature of the specified type from leaving the cylinder and protecting targets outside it.', 'When you cast this spell using a spell slot of 4th level or higher, the duration increases by 1 hour for each slot level above 3rd.', 'Holy water or powdered silver and iron worth at least 100 gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'magic-circle'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Círculo Mágico', 'Você cria um cilindro de 3 metros de raio e 6 metros de altura [10-foot-radius, 20-foot-tall cylinder] feito de energia mágica, centrado em um ponto no solo à sua vista e no alcance da magia. Runas brilhantes aparecem onde quer que o cilindro toque, seja o solo ou outra superfície.
Escolha um ou mais dentre os seguintes tipos de criaturas: celestiais, elementais, feéricos, ínferos ou mortos-vivos. O círculo afeta criaturas do(s) tipo(s) escolhido(s) dos seguintes modos:
A criatura não pode entrar voluntariamente no cilindro por meios não-mágicos. Caso tente usar teleporte ou viagem interplanar para fazê-lo, ela precisa primeiro ser bem-sucedida em uma salvaguarda de Carisma.
A criatura tem desvantagem nas jogadas de ataque contra alvos dentro do cilindro.
Alvos dentro do cilindro não podem ser amedrontados, enfeitiçados ou possuídos pela criatura.
Ao conjurar esta magia, você pode escolher que ela funcione na direção reversa, evitando que uma criatura do tipo especificado saia do cilindro, protegendo alvos fora dele.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 4º círculo ou superior, a duração aumenta em 1 hora para cada círculo do espaço acima do 3º.', '', NULL
FROM public.spells WHERE external_index = 'magic-circle'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Magic Jar
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('magic-jar', 6, 'necromancy', 'minute', 1, NULL, 'self', NULL, 'special', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Magic Jar', 'Your body falls into a catatonic state as your soul leaves it and enters the container you used for the spell''s material component. While your soul inhabits the container, you are aware of your surroundings as if you were in the container''s space. You can''t move or use reactions. The only action you can take is to project your soul up to 100 feet out of the container, either returning to your living body (and ending the spell) or attempting to possess a humanoids body.
You can attempt to possess any humanoid within 100 feet of you that you can see (creatures warded by a protection from evil and good or magic circle spell can''t be possessed). The target must make a charisma saving throw. On a failure, your soul moves into the target''s body, and the target''s soul becomes trapped in the container. On a success, the target resists your efforts to possess it, and you can''t attempt to possess it again for 24 hours.
Once you possess a creature''s body, you control it. Your game statistics are replaced by the statistics of the creature, though you retain your alignment and your Intelligence, Wisdom, and Charisma scores. You retain the benefit of your own class features. If the target has any class levels, you can''t use any of its class features.
Meanwhile, the possessed creature''s soul can perceive from the container using its own senses, but it can''t move or take actions at all.
While possessing a body, you can use your action to return from the host body to the container if it is within 100 feet of you, returning the host creature''s soul to its body. If the host body dies while you''re in it, the creature dies, and you must make a charisma saving throw against your own spellcasting DC. On a success, you return to the container if it is within 100 feet of you. Otherwise, you die.
If the container is destroyed or the spell ends, your soul immediately returns to your body. If your body is more than 100 feet away from you or if your body is dead when you attempt to return to it, you die. If another creature''s soul is in the container when it is destroyed, the creature''s soul returns to its body if the body is alive and within 100 feet. Otherwise, that creature dies.
When the spell ends, the container is destroyed.', '', 'A gem, crystal, reliquary, or some other ornamental container worth at least 500 gp.'
FROM public.spells WHERE external_index = 'magic-jar'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Receptáculo Arcano', 'Seu corpo cai em estado catatônico enquanto sua alma sai dele e entra no receptáculo que você usou como componente material da magia. Enquanto sua alma habitar o receptáculo, você percebe seus arredores como se estivesse no lugar do receptáculo. Você não pode se mover ou usar reações. A única ação que você pode executar é projetar a sua alma a até 30 metros [100 ft.] do receptáculo, seja retornando para o seu corpo vivo (e encerrando a magia) ou tentando possuir um corpo humanoide.
Você pode tentar possuir qualquer criatura humanoide a até 30 metros [100 ft.] do seu alcance e que esteja à sua vista (criaturas protegidas pela magia Proteção Contra o Bem e o Mal ou Círculo Mágico não podem ser possuídas). O alvo deve fazer uma salvaguarda de Carisma. Se falhar,sua alma projeta-se do receptáculo para dentro do corpo do alvo, expulsando a alma dele, que agora ficará aprisionada no receptáculo. Em caso de sucesso, o alvo resiste aos seus esforços para possuí-lo, e você não pode tentar fazê-lo novamente por 24 horas.
Uma vez que possua o corpo de uma criatura, você o controla. Suas estatísticas de jogo são substituídas pelas da criatura, apesar de você manter seu alinhamento e seus valores de Inteligência, Sabedoria e Carisma. Você também mantém os benefícios das suas próprias características de classe. Se o alvo tiver níveis de classe, você não pode usar nenhuma das características de classe dele.
Enquanto isso, a alma da criatura possuída pode perceber os arredores, a partir do receptáculo, usando seus próprios sentidos, mas não pode se mover ou executar ações.
Enquanto estiver possuindo um corpo, você pode usar uma das suas ações para retornar do corpo do hospedeiro para o receptáculo, se este estiver a até 30 metros [100 ft.] de distância, devolvendo a alma do hospedeiro para o corpo dele. Se o corpo do hospedeiro morrer enquanto você estiver nele, a criatura morre e você deve fazer uma salvaguarda de Carisma contra a CD do seu próprio atributo de conjuração. Em caso de sucesso e o receptáculo estiver a até 30 metros [100 ft.] de distância, sua alma retorna a ele. Caso contrário, você morre.
Se o receptáculo for destruído ou a magia terminar, sua alma retorna imediatamente para seu próprio corpo. Se o seu corpo estiver a mais de 30 metros [100 ft.] de você ou se ele estiver morto quando sua alma tentar retornar para ele, você morre. Se a alma de outra criatura estiver no receptáculo quando ele for destruído, ela retorna para o próprio corpo se ele estiver vivo e a até 30 metros [100 ft.] de distância. Caso contrário, a criatura morre.
Quando a magia termina, o receptáculo é destruído.', '', NULL
FROM public.spells WHERE external_index = 'magic-jar'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Magic Missile
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('magic-missile', 1, 'evocation', 'action', 1, 120, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Magic Missile', 'You create three glowing darts of magical force. Each dart hits a creature of your choice that you can see within range. A dart deals 1d4 + 1 force damage to its target. The darts all strike simultaneously, and you can direct them to hit one creature or several.', 'When you cast this spell using a spell slot of 2nd level or higher, the spell creates one more dart for each slot level above 1st.', NULL
FROM public.spells WHERE external_index = 'magic-missile'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Mísseis Mágicos', 'Você cria três dardos brilhantes feitos de pura energia mágica. Cada dardo acerta uma criatura à sua escolha, à sua vista e no alcance da magia. Um dardo causa 1d4+1 pontos de dano energético no alvo. Os dardos acertam ao mesmo tempo, e você pode direcioná-los para uma mesma criatura ou várias.Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, você cria um dardo a mais para cada círculo do espaço acima do 1º.', '', NULL
FROM public.spells WHERE external_index = 'magic-missile'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Magic Mouth
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('magic-mouth', 2, 'illusion', 'minute', 1, 30, 'feet', NULL, 'special', false, true, ARRAY['V', 'S', 'M'], ARRAY['bard', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Magic Mouth', 'You plant a message to an object in the range of the spell. The message is verbalized when the trigger conditions are met. Choose an object that you see, and that is not worn or carried by another creature. Then say the message, which should not exceed 25 words but listening can take up to 10 minutes. Finally, establish the circumstances that trigger the spell to deliver your message.
When these conditions are satisfied, a magical mouth appears on the object and it articulates the message imitating your voice, the same tone used during implantation of the message. If the selected object has a mouth or something that approaches such as the mouth of a statue, the magic mouth come alive at this point, giving the illusion that the words come from the mouth of the object.
When you cast this spell, you may decide that the spell ends when the message is delivered or it can persist and repeat the message whenever circumstances occur.
The triggering circumstance can be as general or as detailed as you like, though it must be based on visual or audible conditions that occur within 30 feet of the object. For example, you could instruct the mouth to speak when any creature moves within 30 feet of the object or when a silver bell rings within 30 feet of it.', '', 'A honeycomb and jade dust of at least 10 inches, the spell consumes.'
FROM public.spells WHERE external_index = 'magic-mouth'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Boca Encantada', 'Você implanta uma mensagem em um objeto que esteja no alcance da magia. Essa mensagem é revelada quando uma circunstância de disparo ocorrer. Escolha um objeto à sua vista e que não esteja sendo usado ou carregado por outra criatura. Fale, então, a mensagem, que deve ter 25 palavras ou menos, embora ela possa ser emitida ao longo de um período de até 10 minutos. Por fim, determine a circunstância de disparo para magia revelar a mensagem.Quando tal circunstância ocorrer, uma boca encantada aparece no objeto e recita a mensagem com a sua voz e no mesmo volume que você falou. Se o objeto escolhido tiver uma boca ou algo que se assemelhe (por exemplo, a boca de uma estátua), a boca encantada se sobrepõe de forma a parecer que as palavras saem da boca do próprio objeto. Ao conjurar a magia, você determina se ela se encerra após entregar a mensagem ou se permanece para repetir o conteúdo sempre que a circunstância de disparo ocorrer.A circunstância de disparo pode ser tão abrangente ou específica quanto você quiser, mas deve ser baseada em condições visuais ou auditivas que ocorram a até 9 metros [30 ft.] do objeto. Por exemplo, você pode instruir a boca a falar sempre que uma criatura se aproxime a até 9 metros [30 ft.] do objeto, ou quando um sino de prata soar a até 9 metros [30 ft.] de distância do objeto.', '', NULL
FROM public.spells WHERE external_index = 'magic-mouth'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Magic Weapon
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('magic-weapon', 2, 'transmutation', 'bonus_action', 1, NULL, 'touch', 1, 'hour', true, false, ARRAY['V', 'S'], ARRAY['paladin', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Magic Weapon', 'You touch a nonmagical weapon. Until the spell ends, that weapon becomes a magic weapon with a +1 bonus to attack rolls and damage rolls.', 'When you cast this spell using a spell slot of 4th level or higher, the bonus increases to +2. When you use a spell slot of 6th level or higher, the bonus increases to +3.', NULL
FROM public.spells WHERE external_index = 'magic-weapon'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Arma Mágica', 'Você toca uma arma não-mágica. Enquanto a magia durar, essa arma se torna uma arma mágica com bônus de +1 para jogadas de ataque e dano.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 4º círculo ou superior, o bônus aumenta para +2. Quando você usa um espaço de magia de 6º círculo ou superior, o bônus aumenta para +3.', '', NULL
FROM public.spells WHERE external_index = 'magic-weapon'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Magnificent Mansion
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('magnificent-mansion', 7, 'conjuration', 'minute', 1, 300, 'feet', 24, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Magnificent Mansion', 'You conjure an extradimensional dwelling in range that lasts for the duration. You choose where its one entrance is located. The entrance shimmers faintly and is 5 feet wide and 10 feet tall. You and any creature you designate when you cast the spell can enter the extradimensional dwelling as long as the portal remains open. You can open or close the portal if you are within 30 feet of it. While closed, the portal is invisible.
Beyond the portal is a magnificent foyer with numerous chambers beyond. The atmosphere is clean, fresh, and warm.
You can create any floor plan you like, but the space can''t exceed 50 cubes, each cube being 10 feet on each side. The place is furnished and decorated as you choose. It contains sufficient food to serve a nine course banquet for up to 100 people. A staff of 100 near-transparent servants attends all who enter. You decide the visual appearance of these servants and their attire. They are completely obedient to your orders. Each servant can perform any task a normal human servant could perform, but they can''t attack or take any action that would directly harm another creature. Thus the servants can fetch things, clean, mend, fold clothes, light fires, serve food, pour wine, and so on. The servants can go anywhere in the mansion but can''t leave it. Furnishings and other objects created by this spell dissipate into smoke if removed from the mansion. When the spell ends, any creatures inside the extradimensional space are expelled into the open spaces nearest to the entrance.', '', 'A miniature portal carved from ivory, a small piece of polished marble, and a tiny silver spoon, each item worth at least 5 gp.'
FROM public.spells WHERE external_index = 'magnificent-mansion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Mansão Magnífica', 'Você conjura uma habitação extradimensional, no alcance da magia e que permanece enquanto esta durar. Você escolhe onde a única entrada está localizada. A entrada brilha fracamente e possui 1,5 metro [5 ft.] de largura e 3 metros [10 ft.] de altura. Você e qualquer criatura que designar ao conjurar a magia podem entrar na habitação extradimensional enquanto o portal permanecer aberto. Você pode abrir ou fechar o portal se estiver a até 9 metros [30 ft.] dele. Quando está fechado, o portal é invisível.
Além do portal, existe um magnífico saguão com numerosas câmaras além dele. O ambiente é limpo, fresco e aquecido.
Você pode criar qualquer projeto que desejar, mas o espaço não pode exceder 50 cubos, cada cubo tendo 3 metros [10 ft.] de lado. O lugar é mobiliado e decorado como você escolher. Ele contém comida o suficiente para servir um banquete de nove pratos para até 100 pessoas. Uma equipe de 100 servos semi transparentes auxiliam a todos os que entram. Você decide a aparência visual desses servos e seus trajes. Eles são completamente obedientes às suas ordens. Cada servo pode realizar qualquer tarefa que um servo humano normal poderia executar, mas não podem atacar ou executar qualquer ação que possa diretamente ferir outra criatura. Assim sendo, os servos podem buscar coisas, limpar, consertar, dobrar roupas, acender o fogo, servir comida, oferecer vinho e assim por diante. Os servos podem ir a qualquer lugar da mansão, mas não podem deixá-la. Mobiliário e outros objetos criados por esta magia dissipam-se em fumaça se forem retirados da mansão. Quando a magia termina, quaisquer criaturas dentro do espaço extradimensional são expelidas em espaços abertos o mais próximo da entrada.', '', NULL
FROM public.spells WHERE external_index = 'magnificent-mansion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Major Image
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('major-image', 3, 'illusion', 'action', 1, 120, 'feet', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Major Image', 'You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 20-foot cube. The image appears at a spot that you can see within range and lasts for the duration. It seems completely real, including sounds, smells, and temperature appropriate to the thing depicted. You can''t create sufficient heat or cold to cause damage, a sound loud enough to deal thunder damage or deafen a creature, or a smell that might sicken a creature (like a troglodyte''s stench).
As long as you are within range of the illusion, you can use your action to cause the image to move to any other spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking. Similarly, you can cause the illusion to make different sounds at different times, even making it carry on a conversation, for example.
Physical interaction with the image reveals it to be an illusion, because things can pass through it. A creature that uses its action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and its other sensory qualities become faint to the creature.', 'When you cast this spell using a spell slot of 6th level or higher, the spell lasts until dispelled, without requiring your concentration.', 'A bit of fleece.'
FROM public.spells WHERE external_index = 'major-image'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Imagem Maior', 'Você cria a imagem de um objeto, criatura ou algum fenômeno visível que não seja maior do que um cubo de 6 metros [20-foot cube]. A imagem surge em um ponto à sua vista dentro do alcance da magia e permanece enquanto a magia durar. Ela parece ser real, incluindo sons, cheiros e temperatura apropriados à coisa retratada. Você não pode criar calor ou frio suficientes a ponto de causar dano, um som tão alto que cause dano trovejante ou que deixe uma criatura surda, ou um odor tão forte que cause enjoo (como o fedor de um troglodita).Enquanto você estiver no alcance da ilusão, você pode usar sua ação para fazer a imagem se mover para qualquer outro local dentro do alcance da magia. À medida que a imagem muda de lugar, é possível alterar a aparência dela para que os movimentos pareçam naturais. Por exemplo, se você criar a imagem de uma criatura e movê-la, é possível alterar a imagem para que ela pareça estar andando. De forma semelhante, é possível fazer a ilusão emitir sons diferentes em momentos distintos, possibilitando inclusive que ela participe de uma conversa, por exemplo.Interação física com a imagem revelará que se trata de uma ilusão porque coisas podem passar através dela. Uma criatura que usar sua ação para examinar a imagem, pode determinar que é uma ilusão com um teste bem-sucedido de Inteligência (Investigação) contra a CD para evitar sua magia. Se uma criatura discernir a ilusão pelo que ela é, a criatura enxerga através da imagem e qualquer som emitido torna-se abafado para a criatura.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 6º círculo ou superior, ela dura até ser dissipada, não necessitando de concentração.', '', NULL
FROM public.spells WHERE external_index = 'major-image'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Mass Cure Wounds
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('mass-cure-wounds', 5, 'conjuration', 'action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['bard', 'cleric', 'druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Mass Cure Wounds', 'A wave of healing energy washes out from a point of your choice within range. Choose up to six creatures in a 30-foot-radius sphere centered on that point. Each target regains hit points equal to 3d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', 'When you cast this spell using a spell slot of 6th level or higher, the healing increases by 1d8 for each slot level above 5th.', NULL
FROM public.spells WHERE external_index = 'mass-cure-wounds'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Curar Ferimentos em Massa', 'Uma onda de energia curativa banha uma área a partir de um ponto à sua escolha e no alcance da magia. Escolha até seis criaturas em uma esfera com raio de 9 metros [30 ft.] e centrada neste ponto. Cada alvo recupera pontos de vida equivalente a 3d8 + seu modificador de atributo de conjuração. Esta magia não tem efeito sobre mortos-vivos ou constructos.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 6º círculo ou superior,, a cura aumenta em 1d8 para cada círculo do espaço acima do 5º.', '', NULL
FROM public.spells WHERE external_index = 'mass-cure-wounds'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Mass Heal
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('mass-heal', 9, 'conjuration', 'action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Mass Heal', 'A flood of healing energy flows from you into injured creatures around you. You restore up to 700 hit points, divided as you choose among any number of creatures that you can see within range. Creatures healed by this spell are also cured of all diseases and any effect making them blinded or deafened. This spell has no effect on undead or constructs.', '', NULL
FROM public.spells WHERE external_index = 'mass-heal'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Cura Completa em Massa', 'Uma onda de energia curativa flui a partir de você para todas as criaturas feridas ao seu redor. Você restaura até 700 pontos de vida, divididos como desejar entre qualquer número de criaturas à sua vista e no alcance da magia. Criaturas curadas por esta magia também são curadas de todas as doenças e quaisquer efeitos que as deixem cegas ou surdas. Esta magia não tem efeito sobre mortos-vivos ou constructos.', '', NULL
FROM public.spells WHERE external_index = 'mass-heal'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Mass Healing Word
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('mass-healing-word', 3, 'evocation', 'bonus_action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Mass Healing Word', 'As you call out words of restoration, up to six creatures of your choice that you can see within range regain hit points equal to 1d4 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', 'When you cast this spell using a spell slot of 4th level or higher, the healing increases by 1d4 for each slot level above 3rd.', NULL
FROM public.spells WHERE external_index = 'mass-healing-word'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Palavra Curativa em Massa', 'Conforme você diz palavras de restauração, até seis criaturas à sua escolha, à sua vista e no alcance da magia, recuperam uma quantidade de pontos de vida igual a 1d4 + seu modificador de atributo de conjuração. Essa magia não tem efeito sobre mortos-vivos ou constructos.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 4º círculo ou superior, a cura aumenta em 1d4 para cada círculo do espaço acima do 3º.', '', NULL
FROM public.spells WHERE external_index = 'mass-healing-word'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Mass Suggestion
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('mass-suggestion', 6, 'enchantment', 'action', 1, 60, 'feet', 24, 'hour', false, false, ARRAY['V', 'M'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Mass Suggestion', 'You suggest a course of activity (limited to a sentence or two) and magically influence up to twelve creatures of your choice that you can see within range and that can hear and understand you. Creatures that can''t be charmed are immune to this effect. The suggestion must be worded in such a manner as to make the course of action sound reasonable. Asking the creature to stab itself, throw itself onto a spear, immolate itself, or do some other obviously harmful act automatically negates the effect of the spell.
Each target must make a wisdom saving throw. On a failed save, it pursues the course of action you described to the best of its ability. The suggested course of action can continue for the entire duration. If the suggested activity can be completed in a shorter time, the spell ends when the subject finishes what it was asked to do.
You can also specify conditions that will trigger a special activity during the duration. For example, you might suggest that a group of soldiers give all their money to the first beggar they meet. If the condition isn''t met before the spell ends, the activity isn''t performed.
If you or any of your companions damage a creature affected by this spell, the spell ends for that creature.', 'When you cast this spell using a 7th-level spell slot, the duration is 10 days. When you use an 8th-level spell slot, the duration is 30 days. When you use a 9th-level spell slot, the duration is a year and a day.', 'A snake''s tongue and either a bit of honeycomb or a drop of sweet oil.'
FROM public.spells WHERE external_index = 'mass-suggestion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Sugestão em Massa', 'Você sugere um curso de ação (limitado a uma sentença ou duas) e magicamente influencia até doze criaturas à sua escolha, à sua vista e no alcance da magia, que possam ouvi-lo e compreendê-lo. Criaturas que não podem ser enfeitiçadas são imunes a este efeito. A sugestão precisa ser dita de uma forma que faça o curso de ação parecer razoável. Pedir à criatura que se esfaqueie, jogue-se contra uma lança, imole-se ou faça algum outro ato evidentemente danoso, automaticamente cancela o efeito da magia.
Cada alvo deve fazer uma salvaguarda de Sabedoria. Se falhar, ele seguirá os atos sugeridos da melhor forma, dentro das suas próprias habilidades. O curso de ação sugerido é seguido enquanto a magia durar. Se ele puder ser completado em um período menor, a magia se encerra assim que isso ocorrer.
Você também pode especificar condições que ativarão uma atividade especial enquanto a magia durar. Por exemplo, pode ser sugerido que um grupo de soldados dê todo o dinheiro em sua posse ao primeiro mendigo que encontrar. Se a condição não for realizada antes do fim dos efeitos da magia, a atividade não é concluída.
Se você ou algum de seus companheiros causar dano a uma criatura afetada por esta magia, esta se encerra.
Em Círculos Superiores. Ao conjurar esta magia com um espaço de magia de 7º círculo, a duração será 10 dias. Usando um espaço de magia de 8º círculo, a duração será 30 dias. Ao usar um espaço de magia de 9º círculo, a duração será um ano e um dia.', '', NULL
FROM public.spells WHERE external_index = 'mass-suggestion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Maze
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('maze', 8, 'conjuration', 'action', 1, 60, 'feet', 10, 'minute', true, false, ARRAY['V', 'S'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Maze', 'You banish a creature that you can see within range into a labyrinthine demiplane. The target remains there for the duration or until it escapes the maze.
The target can use its action to attempt to escape. When it does so, it makes a DC 20 Intelligence check. If it succeeds, it escapes, and the spell ends (a minotaur or goristro demon automatically succeeds).
When the spell ends, the target reappears in the space it left or, if that space is occupied, in the nearest unoccupied space.', '', NULL
FROM public.spells WHERE external_index = 'maze'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Labirinto', 'Você bane uma criatura à sua vista e no alcance da magia, para um semiplano labiríntico. O alvo permanece nesse lugar enquanto a magia durar ou até escapar do labirinto.
Ele pode usar uma ação para tentar escapar. Para fazê-lo, é necessário ser bem-sucedido em um teste de Inteligência com CD 20. Em caso de sucesso, ele escapa e a magia se encerra (um minotauro ou demônio goristro têm sucesso automático).
Quando esta magia termina, o alvo reaparece no espaço que estava ou, se esse espaço estiver ocupado, no espaço desocupado mais próximo.', '', NULL
FROM public.spells WHERE external_index = 'maze'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Meld Into Stone
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('meld-into-stone', 3, 'transmutation', 'action', 1, NULL, 'touch', 8, 'hour', false, true, ARRAY['V', 'S'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Meld Into Stone', 'You step into a stone object or surface large enough to fully contain your body, melding yourself and all the equipment you carry with the stone for the duration. Using your movement, you step into the stone at a point you can touch. Nothing of your presence remains visible or otherwise detectable by nonmagical senses.
While merged with the stone, you can''t see what occurs outside it, and any Wisdom (Perception) checks you make to hear sounds outside it are made with disadvantage. You remain aware of the passage of time and can cast spells on yourself while merged in the stone. You can use your movement to leave the stone where you entered it, which ends the spell. You otherwise can''t move.
Minor physical damage to the stone doesn''t harm you, but its partial destruction or a change in its shape (to the extent that you no longer fit within it) expels you and deals 6d6 bludgeoning damage to you. The stone''s complete destruction (or transmutation into a different substance) expels you and deals 50 bludgeoning damage to you. If expelled, you fall prone in an unoccupied space closest to where you first entered.', '', NULL
FROM public.spells WHERE external_index = 'meld-into-stone'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Mending
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('mending', 0, 'transmutation', 'minute', 1, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'bard', 'druid', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Mending', 'This spell repairs a single break or tear in an object you touch, such as a broken key, a torn cloak, or a leaking wineskin. As long as the break or tear is no longer than 1 foot in any dimension, you mend it, leaving no trace of the former damage.
This spell can physically repair a magic item or construct, but the spell can''t restore magic to such an object.', '', 'Two lodestones.'
FROM public.spells WHERE external_index = 'mending'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Reparar', 'Esta magia repara um objeto quebrado ou rompido que você toque, como um elo de corrente quebrado, duas metades de uma chave quebrada, um manto rasgado ou um odre vazando. Se a quebra ou ruptura não for maior que 30 centímetros [1 ft.] em qualquer direção, você a repara sem deixar traços do ano anterior.
Esta magia pode reparar um item mágico ou constructo, mas não pode restaurar a magia de tal objeto.', '', NULL
FROM public.spells WHERE external_index = 'mending'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Message
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('message', 0, 'transmutation', 'action', 1, 120, 'feet', 1, 'round', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Message', 'You point your finger toward a creature within range and whisper a message. The target (and only the target) hears the message and can reply in a whisper that only you can hear.
You can cast this spell through solid objects if you are familiar with the target and know it is beyond the barrier. Magical silence, 1 foot of stone, 1 inch of common metal, a thin sheet of lead, or 3 feet of wood blocks the spell. The spell doesn''t have to follow a straight line and can travel freely around corners or through openings.', '', 'A short piece of copper wire.'
FROM public.spells WHERE external_index = 'message'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Mensagem', 'Você aponta seu dedo para uma criatura no alcance da magia e sussurra uma mensagem. O alvo (e somente ele) ouve a sua mensagem e pode responder ao sussurrar uma réplica que apenas você será capaz de ouvir.
Você pode conjurar esta magia através de objetos sólidos se for familiar com o alvo e souber que ele está atrás da barreira. Silêncio mágico, 30 centímetros [1 foot] de pedra, 3 centímetros [1 inch] de metal comum, uma folha fina de chumbo ou 90 centímetros [3 ft.] de madeira bloqueia a magia. A magia não precisa seguir uma linha reta, podendo viajar livremente ao redor de cantos ou através de aberturas.', '', NULL
FROM public.spells WHERE external_index = 'message'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Meteor Swarm
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('meteor-swarm', 9, 'evocation', 'action', 1, 1, 'mile', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Meteor Swarm', 'Blazing orbs of fire plummet to the ground at four different points you can see within range. Each creature in a 40-foot-radius sphere centered on each point you choose must make a dexterity saving throw. The sphere spreads around corners. A creature takes 20d6 fire damage and 20d6 bludgeoning damage on a failed save, or half as much damage on a successful one. A creature in the area of more than one fiery burst is affected only once.
The spell damages objects in the area and ignites flammable objects that aren''t being worn or carried.', '', NULL
FROM public.spells WHERE external_index = 'meteor-swarm'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Chuva de Meteoros', 'Esferas em chamas, feitas de pura brasa, atingem o solo em quatro pontos diferentes à sua vista e dentro do alcance da magia. A esfera se alastra, contornando os cantos. Cada criatura em um raio de 12 metros [40 ft.], centrado em cada ponto escolhido, precisa fazer uma salvaguarda de Destreza. Se falhar, sofre 20d6 pontos de dano ígneo e 20d6 pontos de dano contundente, ou metade do dano em caso de sucesso. Uma criatura na área afetada por mais de uma esfera, sofre os efeitos de apenas uma.
A magia danifica objetos na área e inflama objetos que não estão sendo usados ou carregados.', '', NULL
FROM public.spells WHERE external_index = 'meteor-swarm'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Mind Blank
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('mind-blank', 8, 'abjuration', 'action', 1, NULL, 'touch', 24, 'hour', false, false, ARRAY['V', 'S'], ARRAY['bard', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Mind Blank', 'Until the spell ends, one willing creature you touch is immune to psychic damage, any effect that would sense its emotions or read its thoughts, divination spells, and the charmed condition. The spell even foils wish spells and spells or effects of similar power used to affect the target''s mind or to gain information about the target.', '', NULL
FROM public.spells WHERE external_index = 'mind-blank'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Limpar a Mente', 'Enquanto a magia durar, uma criatura voluntária que você toque fica imune a dano psíquico, a qualquer efeito capaz de sentir suas emoções ou ler seus pensamentos, a magias de adivinhação e à condição enfeitiçado. A magia pode até mesmo evitar a magia Desejo e magias ou efeitos de poder semelhante usadas para afetar a mente do alvo ou para obter informação sobre ele.', '', NULL
FROM public.spells WHERE external_index = 'mind-blank'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Minor Illusion
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('minor-illusion', 0, 'illusion', 'action', 1, 30, 'feet', 1, 'minute', false, false, ARRAY['S', 'M'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Minor Illusion', 'You create a sound or an image of an object within range that lasts for the duration. The illusion also ends if you dismiss it as an action or cast this spell again.
If you create a sound, its volume can range from a whisper to a scream. It can be your voice, someone else''s voice, a lion''s roar, a beating of drums, or any other sound you choose. The sound continues unabated throughout the duration, or you can make discrete sounds at different times before the spell ends.
If you create an image of an object--such as a chair, muddy footprints, or a small chest--it must be no larger than a 5-foot cube. The image can''t create sound, light, smell, or any other sensory effect. Physical interaction with the image reveals it to be an illusion, because things can pass through it.
If a creature uses its action to examine the sound or image, the creature can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the illusion becomes faint to the creature.', '', 'A bit of fleece.'
FROM public.spells WHERE external_index = 'minor-illusion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Ilusão Menor', 'Você cria um som ou uma imagem de um objeto ao alcanceda magia, que permanece enquanto esta durar. A ilusão termina se você a dispensar com uma ação ou conjurá-la novamente.Se você cria um som, o volume emitido pode variar desde um sussurro até um grito. Pode ser a sua voz, a voz de outra pessoa, o rugido de um leão, a batida de tambores ou qualquer outro som à sua escolha. O som continua no mesmo tom enquanto a magia durar, ou você pode fazer sons mais discretos em momentos diferentes, antes que a magia termine.Se você criar uma imagem de um objeto - como uma cadeira, pegadas lamacentas ou uma pequena arca - esta não pode ser maior que um cubo de 1,5 metro [5-foot cube]. A imagem não pode emitir som, luz, odor ou qualquer outro efeito sensorial. Interação física com a imagem revela que se trata de uma ilusão, pois coisas passam através dela.Se uma criatura usar uma ação para examinar o som ou a imagem, a criatura pode determinar que é uma ilusão comum teste bem-sucedido de Inteligência (Investigação) contra a CD para evitar sua magia. A ilusão torna-se desbotada para uma criatura que consiga discerni-la.', '', NULL
FROM public.spells WHERE external_index = 'minor-illusion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Mirage Arcane
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('mirage-arcane', 7, 'illusion', 'minute', 10, NULL, 'unlimited', 10, 'day', false, false, ARRAY['V', 'S'], ARRAY['bard', 'druid', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Mirage Arcane', 'You make terrain in an area up to 1 mile square look, sound, smell, and even feel like some other sort of terrain. The terrain''s general shape remains the same, however. Open fields or a road could be made to resemble a swamp, hill, crevasse, or some other difficult or impassable terrain. A pond can be made to seem like a grassy meadow, a precipice like a gentle slope, or a rock-strewn gully like a wide and smooth road.
Similarly, you can alter the appearance of structures, or add them where none are present. The spell doesn''t disguise, conceal, or add creatures.
The illusion includes audible, visual, tactile, and olfactory elements, so it can turn clear ground into difficult terrain (or vice versa) or otherwise impede movement through the area. Any piece of the illusory terrain (such as a rock or stick) that is removed from the spell''s area disappears immediately.
Creatures with truesight can see through the illusion to the terrain''s true form; however, all other elements of the illusion remain, so while the creature is aware of the illusion''s presence, the creature can still physically interact with the illusion.', '', NULL
FROM public.spells WHERE external_index = 'mirage-arcane'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Miragem Arcana', 'Você faz o terreno em uma área de até 1,5 quilômetro quadrado parecer, soar, cheirar e até passar a sensação de que é outro tipo de terreno. O formato geral do terreno, entretanto, se mantém. Campos abertos ou uma estrada podem ser modificados para se parecerem com um pântano, colina, fenda ou algum outro tipo de terreno difícil ou intransponível. Uma lagoa pode ser modificada para se parecer com um prado verdejante, um precipício com um suave declive ou um barranco pedregoso com uma estrada larga e plana.
Da mesma forma, você pode alterar a aparência das estruturas ou adicioná-las onde nenhuma está presente. A magia não disfarça, oculta ou adiciona criaturas.
A ilusão inclui elementos audíveis, visuais, táteis e olfativos, de modo que pode tornar terreno limpo em terreno difícil (ou vice versa) ou, de outra forma, impedir movimento através da área. Qualquer pedaço do terreno ilusório (como uma rocha ou galho) que seja removido da área da magia desaparece imediatamente.
Criaturas com visão verdadeira podem ver através da ilusão, enxergando a forma real do terreno; porém, todos os outros elementos visuais se mantém, de modo que, mesmo ciente da presença da ilusão, ela ainda pode interagir fisicamente com seus efeitos.', '', NULL
FROM public.spells WHERE external_index = 'mirage-arcane'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Mirror Image
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('mirror-image', 2, 'illusion', 'action', 1, NULL, 'self', 1, 'minute', false, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Mirror Image', 'Three illusory duplicates of yourself appear in your space. Until the spell ends, the duplicates move with you and mimic your actions, shifting position so it''s impossible to track which image is real. You can use your action to dismiss the illusory duplicates.
Each time a creature targets you with an attack during the spell''s duration, roll a d20 to determine whether the attack instead targets one of your duplicates.
If you have three duplicates, you must roll a 6 or higher to change the attack''s target to a duplicate. With two duplicates, you must roll an 8 or higher. With one duplicate, you must roll an 11 or higher.
A duplicate''s AC equals 10 + your Dexterity modifier. If an attack hits a duplicate, the duplicate is destroyed. A duplicate can be destroyed only by an attack that hits it. It ignores all other damage and effects. The spell ends when all three duplicates are destroyed.
A creature is unaffected by this spell if it can''t see, if it relies on senses other than sight, such as blindsight, or if it can perceive illusions as false, as with truesight.', '', NULL
FROM public.spells WHERE external_index = 'mirror-image'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Reflexos', 'Três duplicatas ilusórias de você aparecem no seu espaço. Até a magia acabar, as duplicatas se movem com você e copiam as suas ações, trocando de posição, tornando impossível rastrear qual imagem é real. Você pode usar sua ação para dissipar as duplicatas ilusórias.
Cada vez que uma criatura mirar você com um ataque enquanto a magia durar, role um d20 para determinar se o ataque, em vez de você, mira uma das suas duplicatas.
Se você tiver três duplicatas, você deve rolar um 6 ou maior para mudar o alvo do ataque para uma duplicata. Com duas duplicatas, você deve rolar um 8 ou maior. Com uma duplicata, você deve rolar um 11 ou maior.
A CA de uma duplicata é igual a 10 + seu modificador de Destreza. Se um ataque atingir uma duplicata, ela é destruída. Uma duplicata só pode ser destruída por um ataque que a atinja. Ela ignora todos os outros danos e efeitos. A magia acaba quando todas as três duplicatas forem destruídas.
Uma criatura não pode ser afetada por essa magia se não puder enxergar, se ela contar com outros sentidos além da visão, como percepção às cegas, ou se ela puder perceber ilusões como falsas, como com visão verdadeira.', '', NULL
FROM public.spells WHERE external_index = 'mirror-image'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Mislead
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('mislead', 5, 'illusion', 'action', 1, NULL, 'self', 1, 'hour', true, false, ARRAY['S'], ARRAY['bard', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Mislead', 'You become invisible at the same time that an illusory double of you appears where you are standing. The double lasts for the duration, but the invisibility ends if you attack or cast a spell.
You can use your action to move your illusory double up to twice your speed and make it gesture, speak, and behave in whatever way you choose.
You can see through its eyes and hear through its ears as if you were located where it is. On each of your turns as a bonus action, you can switch from using its senses to using your own, or back again. While you are using its senses, you are blinded and deafened in regard to your own surroundings.', '', NULL
FROM public.spells WHERE external_index = 'mislead'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Despistar', 'Você se torna invisível ao mesmo tempo em que uma duplicata ilusória aparece onde você está. A duplicata permanece enquanto a magia durar, porém a invisibilidade se encerra se você atacar ou conjurar uma magia.
Você pode usar sua ação para mover sua duplicata ilusória a até o dobro do seu deslocamento e fazê-la gesticular, falar e se comportar da maneira que você escolher.
Você pode ver através dos olhos e ouvir através dos ouvidos da duplicata como se estivesse onde ela está. Em cada um de seus turnos, com uma ação bônus, você pode mudar dos sentidos dela para os seus, ou voltar para os dela. Enquanto estiver usando os sentidos de sua duplicata, você está cego e surdo em relação aos seus arredores.', '', NULL
FROM public.spells WHERE external_index = 'mislead'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Misty Step
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('misty-step', 2, 'conjuration', 'bonus_action', 1, NULL, 'self', NULL, 'instantaneous', false, false, ARRAY['V'], ARRAY['sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Misty Step', 'Briefly surrounded by silvery mist, you teleport up to 30 feet to an unoccupied space that you can see.', '', NULL
FROM public.spells WHERE external_index = 'misty-step'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Passo Nebuloso', 'Rodeado brevemente por uma névoa prateada, você se teleporta a até 9 metros [30 ft.] para um espaço desocupado à sua vista.', '', NULL
FROM public.spells WHERE external_index = 'misty-step'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Modify Memory
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('modify-memory', 5, 'enchantment', 'action', 1, 30, 'feet', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['bard', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Modify Memory', 'You attempt to reshape another creature''s memories. One creature that you can see must make a wisdom saving throw. If you are fighting the creature, it has advantage on the saving throw. On a failed save, the target becomes charmed by you for the duration. The charmed target is incapacitated and unaware of its surroundings, though it can still hear you. If it takes any damage or is targeted by another spell, this spell ends, and none of the target''s memories are modified.
While this charm lasts, you can affect the target''s memory of an event that it experienced within the last 24 hours and that lasted no more than 10 minutes. You can permanently eliminate all memory of the event, allow the target to recall the event with perfect clarity and exacting detail, change its memory of the details of the event, or create a memory of some other event.
You must speak to the target to describe how its memories are affected, and it must be able to understand your language for the modified memories to take root. Its mind fills in any gaps in the details of your description. If the spell ends before you have finished describing the modified memories, the creature''s memory isn''t altered. Otherwise, the modified memories take hold when the spell ends.
A modified memory doesn''t necessarily affect how a creature behaves, particularly if the memory contradicts the creature''s natural inclinations, alignment, or beliefs. An illogical modified memory, such as implanting a memory of how much the creature enjoyed dousing itself in acid, is dismissed, perhaps as a bad dream. The GM might deem a modified memory too nonsensical to affect a creature in a significant manner.
A remove curse or greater restoration spell cast on the target restores the creature''s true memory.', 'If you cast this spell using a spell slot of 6th level or higher, you can alter the target''s memories of an event that took place up to 7 days ago (6th level), 30 days ago (7th level), 1 year ago (8th level), or any time in the creature''s past (9th level).', NULL
FROM public.spells WHERE external_index = 'modify-memory'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Modificar Memória', 'Você tenta reformular as memórias de outra criatura. Uma criatura à sua vista deve fazer uma salvaguarda de Sabedoria. Se você estiver lutando contra a criatura, ela tem vantagem na salvaguarda. Se falhar, o alvo se torna enfeitiçado por você enquanto a magia durar. Um alvo enfeitiçado está incapacitado e inconsciente dos seus arredores, apesar de ainda poder ouvir você. Se ele sofrer qualquer dano ou for alvo de outra magia, esta magia se encerra e nenhuma das memórias do alvo é modificada.
Enquanto o alvo estiver enfeitiçado, você pode afetar as memórias de um evento que ele experimentou nas últimas 24 horas e que não tenha durado mais do que 10 minutos. Você pode eliminar permanentemente todas as memórias do evento, permitir que o alvo relembre do evento com perfeita clareza de detalhes, mudar as memórias dos detalhes do evento ou criar uma memória de algum outro evento.
Você deve falar com o alvo para descrever como as memórias dele são afetadas, e ele deve ser capaz de entender seu idioma para a memória modificada se enraizar. A mente dele preenche quaisquer lacunas de detalhes da sua descrição. Se a magia se encerrar antes de você terminar de descrever a memória modificada, a memória da criatura não é alterada. Caso contrário, as memórias modificadas se instalam quando a magia se encerrar.
Uma memória modificada não necessariamente afeta a maneira como o alvo habitualmente se comporta, principalmente se a memória entrar em contradição com as inclinações naturais, alinhamento ou crenças dela. Uma memória modificada ilógica, como implantar uma memória de quanto a criatura gosta de se banhar com ácido, é descartada, talvez como se fosse um sonho ruim. O DM pode julgar uma memória modificada com sendo demasiadamente absurda para afetar o alvo de maneira significativa.
Uma magia Remover Maldição ou Restauração Maior conjurada no alvo restaura a memória original da criatura.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 6º círculo ou maior, você pode alterar as memórias do alvo de um evento que aconteceu a até 7 dias atrás (6º círculo), 30 dias atrás (7º círculo), 1 ano atrás (8º círculo), ou qualquer período no passado da criatura (9º círculo).', '', NULL
FROM public.spells WHERE external_index = 'modify-memory'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Moonbeam
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('moonbeam', 2, 'evocation', 'action', 1, 120, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Moonbeam', 'A silvery beam of pale light shines down in a 5-foot radius, 40-foot-high cylinder centered on a point within range. Until the spell ends, dim light fills the cylinder.
When a creature enters the spell''s area for the first time on a turn or starts its turn there, it is engulfed in ghostly flames that cause searing pain, and it must make a constitution saving throw. It takes 2d10 radiant damage on a failed save, or half as much damage on a successful one.
A shapechanger makes its saving throw with disadvantage. If it fails, it also instantly reverts to its original form and can''t assume a different form until it leaves the spell''s light.
On each of your turns after you cast this spell, you can use an action to move the beam 60 feet in any direction.', 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1dl0 for each slot level above 2nd.', 'Several seeds of any moonseed plant and a piece of opalescent feldspar.'
FROM public.spells WHERE external_index = 'moonbeam'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Raio Lunar', 'Um feixe pálido de luz prateada brilha em um cilindro de 1,5 metro de raio e 12 metros de altura [5-foot-radius, 40-foot-high cilinder], centrado em um ponto no alcance da magia. O cilindro é preenchido por meia-luz enquanto a magia durar.
Quando uma criatura entra pela primeira vez ou inicia o próprio turno na área da magia, ela será engolfada em chamas fantasmagóricas que causam dor lancinante, e deve fazer uma salvaguarda de Constituição. Se falhar, sofre 2d10 pontos de dano radiante, ou metade do dano em caso de sucesso.
Um metamorfo faz esta salvaguarda com desvantagem. Se falhar, ele também reverte para própria forma original, permanecendo incapaz de assumir uma forma diferente até sair da luz da magia.
Em cada um de seus turnos após conjurar esta magia, você pode usar uma ação para mover o feixe a até 18 metros [60 ft.] em qualquer direção.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 3º círculo ou superior, o dano aumenta em 1d10 para cada círculo do espaço acima do 2º.', '', NULL
FROM public.spells WHERE external_index = 'moonbeam'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Move Earth
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('move-earth', 6, 'transmutation', 'action', 1, 120, 'feet', 2, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Move Earth', 'Choose an area of terrain no larger than 40 feet on a side within range. You can reshape dirt, sand, or clay in the area in any manner you choose for the duration. You can raise or lower the area''s elevation, create or fill in a trench, erect or flatten a wall, or form a pillar. The extent of any such changes can''t exceed half the area''s largest dimension. So, if you affect a 40-foot square, you can create a pillar up to 20 feet high, raise or lower the square''s elevation by up to 20 feet, dig a trench up to 20 feet deep, and so on. It takes 10 minutes for these changes to complete.
At the end of every 10 minutes you spend concentrating on the spell, you can choose a new area of terrain to affect.
Because the terrain''s transformation occurs slowly, creatures in the area can''t usually be trapped or injured by the ground''s movement.
This spell can''t manipulate natural stone or stone construction. Rocks and structures shift to accommodate the new terrain. If the way you shape the terrain would make a structure unstable, it might collapse.
Similarly, this spell doesn''t directly affect plant growth. The moved earth carries any plants along with it.', '', 'An iron blade and a small bag containing a mixture of soils--clay, loam, and sand.'
FROM public.spells WHERE external_index = 'move-earth'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Mover Terra', 'Escolha uma área de terreno não maior do que 12 metros [40 ft.] de lado no alcance da magia. Você pode remodelar terra, areia ou argila na área, da maneira que quiser e enquanto a magia durar. Você pode aumentar ou diminuir as elevações da área, criar ou encher um fosso, erguer ou achatar uma muralha ou formar um pilar. A extensão das alterações não pode exceder metade da maior dimensão da área. Sendo assim, caso afete um quadrado de 12 metros [40 ft.], você pode criar um pilar de até 6 metros [20 ft.] de altura, erguer ou abaixar elevações de até 6 metros [20 ft.] no quadrado, cavar um fosso de até 6 metros [20 ft.] e daí por diante. As mudanças levam 10 minutos para sejam totalmente concluídas.
Ao final de cada 10 minutos concentrado na magia, você pode escolher uma nova área de terreno para afetar.
Como a transformação no terreno ocorre lentamente, criaturas na área normalmente não ficam presas nem sofrem dano pela movimentação do solo.
Esta magia não pode manipular rocha natural ou construções de pedra. Pedras e estruturas se movimentam para se acomodar ao novo terreno. Se a maneira como você mudar o terreno causar a instabilidade de estruturas na área, elas podem colapsar.
Da mesma forma, esta magia não afeta diretamente o crescimento de plantas. A terra movida carrega as plantas junto com ela.', '', NULL
FROM public.spells WHERE external_index = 'move-earth'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Nondetection
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('nondetection', 3, 'abjuration', 'action', 1, NULL, 'touch', 8, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'ranger', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Nondetection', 'For the duration, you hide a target that you touch from divination magic. The target can be a willing creature or a place or an object no larger than 10 feet in any dimension. The target can''t be targeted by any divination magic or perceived through magical scrying sensors.', '', 'A pinch of diamond dust worth 25 gp sprinkled over the target, which the spell consumes.'
FROM public.spells WHERE external_index = 'nondetection'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Indetectável', 'Enquanto a magia durar, você oculta um alvo que você toque de magias de adivinhação. O alvo pode ser uma criatura voluntária, um local ou um objeto que não ultrapasse 3 metros em qualquer dimensão. O alvo não pode ser afetado por qualquer magia de adivinhação ou percebido por sensores mágicos de vidência.', '', NULL
FROM public.spells WHERE external_index = 'nondetection'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Pass Without Trace
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('pass-without-trace', 2, 'abjuration', 'action', 1, NULL, 'self', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Pass Without Trace', 'A veil of shadows and silence radiates from you, masking you and your companions from detection. For the duration, each creature you choose within 30 feet of you (including you) has a +10 bonus to Dexterity (Stealth) checks and can''t be tracked except by magical means. A creature that receives this bonus leaves behind no tracks or other traces of its passage.', '', 'Ashes from a burned leaf of mistletoe and a sprig of spruce.'
FROM public.spells WHERE external_index = 'pass-without-trace'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Passwall
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('passwall', 5, 'transmutation', 'action', 1, 30, 'feet', 1, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Passwall', 'A passage appears at a point of your choice that you can see on a wooden, plaster, or stone surface (such as a wall, a ceiling, or a floor) within range, and lasts for the duration. You choose the opening''s dimensions: up to 5 feet wide, 8 feet tall, and 20 feet deep. The passage creates no instability in a structure surrounding it.
When the opening disappears, any creatures or objects still in the passage created by the spell are safely ejected to an unoccupied space nearest to the surface on which you cast the spell.', '', 'A pinch of sesame seeds.'
FROM public.spells WHERE external_index = 'passwall'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Criar Passagem', 'Uma passagem surge numa superfície de madeira, argamassa ou pedra (como uma parede, teto ou chão) escolhida, à sua vista, no alcance da magia e permanece enquanto esta durar. Você escolhe a dimensão da abertura: até 1,5 metro [5 ft.] de largura, 2,5 metros [8 ft.] de altura e 6 metros [20 ft.] de profundidade. A passagem não cria instabilidade na estrutura ao redor dela.
Ao desaparecer, qualquer criatura ou objeto que estiver dentro da passagem criada pela magia é expelido com segurança para um espaço desocupado na superfície na qual você conjurou a magia.', '', NULL
FROM public.spells WHERE external_index = 'passwall'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Phantasmal Killer
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('phantasmal-killer', 4, 'illusion', 'action', 1, 120, 'feet', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Phantasmal Killer', 'You tap into the nightmares of a creature you can see within range and create an illusory manifestation of its deepest fears, visible only to that creature. The target must make a wisdom saving throw. On a failed save, the target becomes frightened for the duration. At the start of each of the target''s turns before the spell ends, the target must succeed on a wisdom saving throw or take 4d10 psychic damage. On a successful save, the spell ends.', 'When you cast this spell using a spell slot of 5th level or higher, the damage increases by 1d10 for each slot level above 4th.', NULL
FROM public.spells WHERE external_index = 'phantasmal-killer'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Assassino Fantasmagórico', 'Você se conecta aos pesadelos de uma criatura à sua vista e dentro do alcance da magia. A criatura é assolada por uma manifestação ilusória dos próprios medos mais profundos, visível apenas para ela. O alvo deve fazer uma salvaguarda de Sabedoria. Se falhar, fica amedrontado enquanto a magia durar. No final de cada turno do alvo, enquanto a magia durar, ele deve fazer uma salvaguarda de Sabedoria. Se falhar, sofre 4d10 pontos de dano psíquico; se for bem-sucedido, a magia termina.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 5º círculo ou superior, o dano aumenta em 1d10 para cada círculo do espaço acima do 4º.', '', NULL
FROM public.spells WHERE external_index = 'phantasmal-killer'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Phantom Steed
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('phantom-steed', 3, 'illusion', 'minute', 1, 30, 'feet', 1, 'hour', false, true, ARRAY['V', 'S'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Phantom Steed', 'A Large quasi-real, horselike creature appears on the ground in an unoccupied space of your choice within range. You decide the creature''s appearance, but it is equipped with a saddle, bit, and bridle. Any of the equipment created by the spell vanishes in a puff of smoke if it is carried more than 10 feet away from the steed.
For the duration, you or a creature you choose can ride the steed. The creature uses the statistics for a riding horse, except it has a speed of 100 feet and can travel 10 miles in an hour, or 13 miles at a fast pace. When the spell ends, the steed gradually fades, giving the rider 1 minute to dismount. The spell ends if you use an action to dismiss it or if the steed takes any damage.', '', NULL
FROM public.spells WHERE external_index = 'phantom-steed'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Montaria Fantasmagórica', 'Uma criatura Grande, quase real, similar a um cavalo, aparece no solo, surgindo num espaço desocupado à sua escolha e no alcance da magia. Você decide a aparência da montaria, mas ela é equipada com sela, estribo e arreio. Qualquer equipamento criado pela magia desaparece em uma nuvem de fumaça se movido a mais de 3 metros [10 ft.] de distância da mesma.Enquanto a magia durar,uma criatura à sua escolha pode fazer uso da montaria. Utilize as estatísticas de um cavalo de montaria, exceto por seu deslocamento de 30 metros [100 ft.] e por poder viajar 16 quilômetros [10 miles] em uma hora ou 20 quilômetros [13 miles] em trote rápido. Quando a magia termina, a montaria desaparece gradualmente, dando ao cavaleiro 1 minuto para desmontar. A magia se encerra se você dispensa a montaria ou se ela sofrer qualquer dano.', '', NULL
FROM public.spells WHERE external_index = 'phantom-steed'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Planar Ally
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('planar-ally', 6, 'conjuration', 'minute', 10, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Planar Ally', 'You beseech an otherworldly entity for aid. The being must be known to you: a god, a primordial, a demon prince, or some other being of cosmic power. That entity sends a celestial, an elemental, or a fiend loyal to it to aid you, making the creature appear in an unoccupied space within range. If you know a specific creature''s name, you can speak that name when you cast this spell to request that creature, though you might get a different creature anyway (GM''s choice).
When the creature appears, it is under no compulsion to behave in any particular way. You can ask the creature to perform a service in exchange for payment, but it isn''t obliged to do so. The requested task could range from simple (fly us across the chasm, or help us fight a battle) to complex (spy on our enemies, or protect us during our foray into the dungeon). You must be able to communicate with the creature to bargain for its services.
Payment can take a variety of forms. A celestial might require a sizable donation of gold or magic items to an allied temple, while a fiend might demand a living sacrifice or a gift of treasure. Some creatures might exchange their service for a quest undertaken by you.
As a rule of thumb, a task that can be measured in minutes requires a payment worth 100 gp per minute. A task measured in hours requires 1,000 gp per hour. And a task measured in days (up to 10 days) requires 10,000 gp per day. The GM can adjust these payments based on the circumstances under which you cast the spell. If the task is aligned with the creature''s ethos, the payment might be halved or even waived. Nonhazardous tasks typically require only half the suggested payment, while especially dangerous tasks might require a greater gift. Creatures rarely accept tasks that seem suicidal.
After the creature completes the task, or when the agreed-upon duration of service expires, the creature returns to its home plane after reporting back to you, if appropriate to the task and if possible. If you are unable to agree on a price for the creature''s service, the creature immediately returns to its home plane.
A creature enlisted to join your group counts as a member of it, receiving a full share of experience points awarded.', '', NULL
FROM public.spells WHERE external_index = 'planar-ally'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Aliado Extraplanar', 'Você suplica a uma entidade extraplanar por ajuda. Você precisa conhecer a entidade, que pode ser: uma divindade, um primordial, um príncipe demônio ou algum outro ser de poder cósmico. A entidade envia um celestial, um elemental ou um ínfero leal a ela para ajudá-lo, fazendo com que a criatura apareça em um espaço desocupado no alcance da magia. Se souber o nome de uma criatura específica, você pode dizer esse nome ao conjurar esta magia, solicitando por essa criatura em particular, embora outra criatura ainda possa ser enviada (à escolha do DM).
Ao aparecer, a criatura enviada não se encontra obrigada a comportar-se de uma forma específica. Você pode pedir para a criatura executar um serviço em troca de pagamento, mas ela não é obrigada a fazê-lo. A tarefa requisitada pode variar, desde coisas simples ("carregue-nos através do abismo" ou "lute conosco em uma batalha") até as mais complexas ("espione nossos inimigos" ou "proteja-nos durante a nossa incursão na masmorra"). Você deve ser capaz de comunicar-se com a criatura para negociar pelos serviços dela.
O pagamento é variável. Um celestial pode exigir uma doação considerável de ouro ou itens mágicos para um templo aliado, enquanto um demônio pode exigir o sacrifício de uma vida ou presentes na forma de tesouros. Algumas criaturas podem trocar o serviço delas por uma missão a ser realizada por você.
Como regra geral, uma tarefa que possa ser medida em minutos requer um pagamento estimado em 100 PO por minuto. Uma tarefa medida em horas requer 1.000 PO por hora. E uma tarefa medida em dias (até 10) requer 10.000 PO por dia. O DM pode ajustar estes pagamentos baseados nas circunstâncias sob as quais você conjura a magia. Se a tarefa estiver em concordância com o alinhamento da criatura, o pagamento pode ser reduzido pela metade ou mesmo desnecessário. Tarefas inofensivas normalmente exigem apenas metade do pagamento sugerido, enquanto tarefas especialmente perigosas podem exigir um presente maior. Criaturas raramente aceitam tarefas que pareçam suicidas.
Após concluir a tarefa ou quando a duração do serviço combinado expirar, a criatura se reportará a você - caso seja apropriado e possível em relação à tarefa -, retornando, então, para o plano de origem dela. Se você for incapaz de chegar a um acordo sobre o valor do serviço, a criatura retorna imediatamente para o plano de origem dela.
Uma criatura alistada junta-se ao seu grupo, contando como um membro e recebendo uma parte dos pontos de experiência ganhos.', '', NULL
FROM public.spells WHERE external_index = 'planar-ally'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Planar Binding
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('planar-binding', 5, 'abjuration', 'hour', 1, 60, 'feet', 24, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'druid', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Planar Binding', 'With this spell, you attempt to bind a celestial, an elemental, a fey, or a fiend to your service. The creature must be within range for the entire casting of the spell. (Typically, the creature is first summoned into the center of an inverted magic circle in order to keep it trapped while this spell is cast.) At the completion of the casting, the target must make a charisma saving throw. On a failed save, it is bound to serve you for the duration. If the creature was summoned or created by another spell, that spell''s duration is extended to match the duration of this spell.
A bound creature must follow your instructions to the best of its ability. You might command the creature to accompany you on an adventure, to guard a location, or to deliver a message. The creature obeys the letter of your instructions, but if the creature is hostile to you, it strives to twist your words to achieve its own objectives. If the creature carries out your instructions completely before the spell ends, it travels to you to report this fact if you are on the same plane of existence. If you are on a different plane of existence, it returns to the place where you bound it and remains there until the spell ends.', 'When you cast this spell using a spell slot of a higher level, the duration increases to 10 days with a 6th-level slot, to 30 days with a 7th-level slot, to 180 days with an 8th-level slot, and to a year and a day with a 9th-level spell slot.', 'A jewel worth at least 1,000 gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'planar-binding'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Âncora Planar', 'Com essa magia, você tenta forçar um celestial, um elemental, um feérico ou um ínfero a servi-lo. A criatura deve estar dentro do alcance da magia durante todo o tempo de conjuração (normalmente, a criatura é convocada primeiro para o centro de um círculo mágico invertido para mantê-la presa, enquanto esta magia é conjurada). Após a conclusão da conjuração, a criatura deve fazer uma salvaguarda de Carisma. Se falhar, fica destinada a lhe servir enquanto a magia durar. Se a criatura foi convocada ou criada por outra magia, a duração daquela é estendida para coincidir com a duração desta magia.
Uma criatura ancorada deve seguir suas instruções tanto quanto possível. Você pode ordenar a criatura a acompanhá-lo em uma aventura, a vigiar um local ou a entregar uma mensagem. A criatura obedece suas instruções à risca, mas se for hostil a você, ela se esforça para distorcer suas palavras de modo a atingir os próprios objetivos. Se a criatura concluir suas instruções antes de terminado o efeito da magia, ela vai até você para relatar o fato. Se você estiver em um plano de existência diferente, ela retorna ao lugar onde você a ancorou, lá permanecendo enquanto a magia durar.
Em Círculos Superiores. Ao conjurar esta magia usando espaço de magia de círculo superior, a duração aumenta para 10 dias com um espaço de 6º círculo, para 30 dias com um espaço de 7º círculo, para 180 dias com um espaço de 8º círculo e para um ano e um dia com um espaço de magia de 9º círculo.', '', NULL
FROM public.spells WHERE external_index = 'planar-binding'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Plane Shift
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('plane-shift', 7, 'conjuration', 'action', 1, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'druid', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Plane Shift', 'You and up to eight willing creatures who link hands in a circle are transported to a different plane of existence. You can specify a target destination in general terms, such as the City of Brass on the Elemental Plane of Fire or the palace of Dispater on the second level of the Nine Hells, and you appear in or near that destination. If you are trying to reach the City of Brass, for example, you might arrive in its Street of Steel, before its Gate of Ashes, or looking at the city from across the Sea of Fire, at the GM''s discretion.
Alternatively, if you know the sigil sequence of a teleportation circle on another plane of existence, this spell can take you to that circle. If the teleportation circle is too small to hold all the creatures you transported, they appear in the closest unoccupied spaces next to the circle.
You can use this spell to banish an unwilling creature to another plane. Choose a creature within your reach and make a melee spell attack against it. On a hit, the creature must make a charisma saving throw. If the creature fails this save, it is transported to a random location on the plane of existence you specify. A creature so transported must find its own way back to your current plane of existence.', '', 'A forked, metal rod worth at least 250 gp, attuned to a particular plane of existence.'
FROM public.spells WHERE external_index = 'plane-shift'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Transição Planar', 'Você e até oito criaturas voluntárias que deem as mãos em um círculo são transportadas para um plano de existência diferente. Você pode especificar um destino, em termos gerais, como a Cidade de Bronze no Plano Elemental do Fogo ou o palácio de Dispáter no segundo nível dos Nove Infernos, e você aparece dentro ou perto do destino. Se estiver tentando chegar até a Cidade de Bronze, por exemplo, você pode chegar na Rua de Aço, diante do Portão de Cinzas, ou pode ver a cidade do outro lado do Mar de Fogo, a critério do DM.Se preferir, e conhecer a sequência de símbolos de um círculo de teleporte em outro plano de existência, esta magia pode levá-lo a este círculo. Se o círculo de teleporte for muito pequeno para conter todas as criaturas que forem transportadas, elas aparecem no local desocupado mais próximo do círculo.Você pode usar essa magia para banir uma criatura involuntária para outro plano. Escolha uma criatura no alcance da magia e faça um ataque mágico corpo a corpo contra ela. Se acertar, a criatura deve fazer uma salvaguarda de Carisma. Se falhar, ela é transportada para um local aleatório no plano de existência que você especificar. Uma criatura transportada desta forma deve encontrar o caminho de volta para o plano de existência em que você se encontre.', '', NULL
FROM public.spells WHERE external_index = 'plane-shift'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Plant Growth
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('plant-growth', 3, 'transmutation', 'action', 1, 150, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['bard', 'druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Plant Growth', 'This spell channels vitality into plants within a specific area. There are two possible uses for the spell, granting either immediate or long-term benefits.
If you cast this spell using 1 action, choose a point within range. All normal plants in a 100-foot radius centered on that point become thick and overgrown. A creature moving through the area must spend 4 feet of movement for every 1 foot it moves.
You can exclude one or more areas of any size within the spell''s area from being affected.
If you cast this spell over 8 hours, you enrich the land. All plants in a half-mile radius centered on a point within range become enriched for 1 year. The plants yield twice the normal amount of food when harvested.', '', NULL
FROM public.spells WHERE external_index = 'plant-growth'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Crescimento de Plantas', 'Esta magia canaliza vitalidade para as plantas dentro de uma área específica. Existem dois usos possíveis para a magia, garantindo tanto benefícios imediatos quanto de longa duração.Se você conjurar esta magia usando uma ação, escolha um ponto dentro do alcance. Todas as plantas normais em um raio de 30 metros [100-foot radius] centradas neste ponto tornam-se espessas e super desenvolvidas. Uma criatura se movendo através da área deve gastar 6 metros [20 ft.] de movimento para cada 1,5 metro [5 ft.] que se mover.Você pode excluir uma ou mais áreas de qualquer tamanho dentro de área da magia a ser afetada.Se você conjurar esta magia ao longo de 8 horas, você enriquece a terra. Todas as plantas em um raio de 1 quilômetro [0,5 mile] centradas em um ponto dentro do alcance se tornam enriquecidas durante 1 ano. As plantas produzem duas vezes a quantidade normal de alimento quando colhidas.', '', NULL
FROM public.spells WHERE external_index = 'plant-growth'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Poison Spray
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('poison-spray', 0, 'conjuration', 'action', 1, 10, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'warlock', 'wizard', 'druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Poison Spray', 'You extend your hand toward a creature you can see within range and project a puff of noxious gas from your palm. The creature must succeed on a constitution saving throw or take 1d12 poison damage.
This spell''s damage increases by 1d12 when you reach 5th level (2d12), 11th level (3d12), and 17th level (4d12).', '', NULL
FROM public.spells WHERE external_index = 'poison-spray'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Rajada de Veneno', 'Você estende a sua mão, projetando um sopro de gás nocivo da sua palma, que segue em direção a uma criatura à sua vista e no alcance da magia. A criatura deve ser bem-sucedida em uma salvaguarda de Constituição ou sofre 1d12 pontos de dano venenoso.
O dano desta magia aumenta em 1d12 quando você alcança o 5º nível (2d12), o 11º nível (3d12) e o 17º nível (4d12).', '', NULL
FROM public.spells WHERE external_index = 'poison-spray'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Polymorph
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('polymorph', 4, 'transmutation', 'action', 1, 60, 'feet', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'druid', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Polymorph', 'This spell transforms a creature that you can see within range into a new form. An unwilling creature must make a wisdom saving throw to avoid the effect. A shapechanger automatically succeeds on this saving throw.
The transformation lasts for the duration, or until the target drops to 0 hit points or dies. The new form can be any beast whose challenge rating is equal to or less than the target''s (or the target''s level, if it doesn''t have a challenge rating). The target''s game statistics, including mental ability scores, are replaced by the statistics of the chosen beast. It retains its alignment and personality.
The target assumes the hit points of its new form. When it reverts to its normal form, the creature returns to the number of hit points it had before it transformed. If it reverts as a result of dropping to 0 hit points, any excess damage carries over to its normal form. As long as the excess damage doesn''t reduce the creature''s normal form to 0 hit points, it isn''t knocked unconscious.
The creature is limited in the actions it can perform by the nature of its new form, and it can''t speak, cast spells, or take any other action that requires hands or speech.
The target''s gear melds into the new form. The creature can''t activate, use, wield, or otherwise benefit from any of its equipment.', '', 'A caterpillar cocoon.'
FROM public.spells WHERE external_index = 'polymorph'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Polimorfia', 'A magia transforma uma criatura à sua vista, no alcance da magia, em uma nova forma. Uma criatura não voluntária deve fazer uma salvaguarda de Sabedoria para evitar o efeito. A magia não tem efeito sobre um Metamorfo ou em uma criatura com 0 pontos de vida.
A transformação permanece enquanto a magia durar, até o alvo cair a 0 pontos de vida ou morrer. A nova forma pode ser qualquer fera cujo nível de desafio seja igual ou menor que o do alvo (ou do nível do alvo, caso este não tenha um nível de desafio). As estatísticas de jogo do alvo, incluindo valores de habilidades mentais, são substituídas pelas estatísticas da fera escolhida. Ele mantém seu alinhamento e personalidade.
O alvo assume os pontos de vida de sua nova forma. Ao retornar à sua forma original, o alvo também retorna para o mesmo número de pontos de vida que tinha antes de se transformar. Se a transformação se reverter como resultado do alvo ter caído para 0 ponto de vida, todo o excesso de dano será transferido para a sua forma original. Contanto que o excesso de dano não reduza a forma original do alvo a 0 ponto de vida, ele não cai inconsciente.
As ações que o alvo pode realizar são limitadas pela natureza de sua nova forma, e ele não pode falar, conjurar magias ou executar qualquer ação que requeira mãos ou fala.
Os equipamentos do alvo se fundem à sua nova forma. A criatura não pode ativar, usar, segurar ou se beneficiar de qualquer outra maneira de seus equipamentos.', '', NULL
FROM public.spells WHERE external_index = 'polymorph'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
