INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Palavra de Poder: Matar', 'Você profere uma palavra de poder que pode forçar uma criatura à sua vista e no alcance da magia, a morrer instantaneamente. Se o alvo tiver 100 pontos de vida ou menos, ele morre. Caso contrário, a magia não tem efeito.', '', NULL
FROM public.spells WHERE external_index = 'power-word-kill'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
