INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Power Word Stun', 'You speak a word of power that can overwhelm the mind of one creature you can see within range, leaving it dumbfounded. If the target has 150 hit points or fewer, it is stunned. Otherwise, the spell has no effect.
The stunned target must make a constitution saving throw at the end of each of its turns. On a successful save, this stunning effect ends.', '', NULL
FROM public.spells WHERE external_index = 'power-word-stun'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Palavra de Poder: Atordoar', 'Você fala uma palavra de poder que pode sobrecarregar a mente de uma criatura à sua vista e no alcance da magia, deixando-a pasma. Se o alvo tiver 150 pontos de vida ou menos, ele fica atordoado. Caso contrário, a magia não tem efeito.
O alvo atordoado deve fazer uma salvaguarda de Constituição no fim de cada um dos próprios turnos. Em caso de sucesso, o efeito de atordoamento se encerra.', '', NULL
FROM public.spells WHERE external_index = 'power-word-stun'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
