INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Prayer of Healing', 'Up to six creatures of your choice that you can see within range each regain hit points equal to 2d8 + your spellcasting ability modifier. This spell has no effect on undead or constructs.', 'When you cast this spell using a spell slot of 3rd level or higher, the healing increases by 1d8 for each slot level above 2nd.', NULL
FROM public.spells WHERE external_index = 'prayer-of-healing'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Oração de Cura', 'Escolha até seis criaturas à sua vista e no alcance da magia. Elas recuperam uma quantidade de pontos de vida igual a 2d8 + seu modificador de atributo de conjuração. Esta magia não tem efeito sobre mortos-vivos ou constructos.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 3º círculo ou superior, a cura aumenta em 1d8 para cada círculo do espaço acima do 2º.', '', NULL
FROM public.spells WHERE external_index = 'prayer-of-healing'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Prestidigitation
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('prestidigitation', 0, 'transmutation', 'action', 1, 10, 'feet', 1, 'hour', false, false, ARRAY['V', 'S'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Prestidigitation', 'This spell is a minor magical trick that novice spellcasters use for practice. You create one of the following magical effects within ''range'':
You create an instantaneous, harmless sensory effect, such as a shower of sparks, a puff of wind, faint musical notes, or an odd odor.
You instantaneously light or snuff out a candle, a torch, or a small campfire.
You instantaneously clean or soil an object no larger than 1 cubic foot.
You chill, warm, or flavor up to 1 cubic foot of nonliving material for 1 hour.
You make a color, a small mark, or a symbol appear on an object or a surface for 1 hour.
You create a nonmagical trinket or an illusory image that can fit in your hand and that lasts until the end of your next turn.
If you cast this spell multiple times, you can have up to three of its non-instantaneous effects active at a time, and you can dismiss such an effect as an action.', '', NULL
FROM public.spells WHERE external_index = 'prestidigitation'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Prestidigitação Arcana', 'Esta magia é um pequeno truque mágico que conjuradores iniciantes usam para praticar. Crie um dos seguintes efeitos mágicos no alcance da magia:
Você cria um efeito sensorial instantâneo e inofensivo como uma chuva de faíscas, um sopro de vento, notas musicais suaves ou um odor característico.
Você faz com que uma vela, tocha ou pequena fogueira seja imediatamente acesa ou apagada.
Você instantaneamente limpa ou suja um objeto que não seja maior que um cubo de 30 centímetros de lado [1 cubic foot].
Você resfria, esquenta ou tempera um objeto que não seja maior que um cubo de até 30 centímetros de lado [1 cubic foot] feito de matéria não-viva por 1 hora.
Você colore, faz uma pequena marca ou um símbolo aparecer em um objeto ou superfície por 1 hora.
Você cria uma bugiganga não-mágica ou uma imagem ilusória que pode caber em sua mão e esta dura até o fim do seu próximo turno.
Se você conjurar esta magia múltiplas vezes, é possível ter três de seus efeitos não instantâneos ativos ao mesmo tempo e qualquer desses efeitos pode ser encerrado com uma ação.', '', NULL
FROM public.spells WHERE external_index = 'prestidigitation'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Prismatic Spray
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('prismatic-spray', 7, 'evocation', 'action', 1, NULL, 'self', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Prismatic Spray', 'Eight multicolored rays of light flash from your hand. Each ray is a different color and has a different power and purpose. Each creature in a 60-foot cone must make a dexterity saving throw. For each target, roll a d8 to determine which color ray affects it.
***1. Red.*** The target takes 10d6 fire damage on a failed save, or half as much damage on a successful one.
***2. Orange.*** The target takes 10d6 acid damage on a failed save, or half as much damage on a successful one.
***3. Yellow.*** The target takes 10d6 lightning damage on a failed save, or half as much damage on a successful one.
***4. Green.*** The target takes 10d6 poison damage on a failed save, or half as much damage on a successful one.
***5. Blue.*** The target takes 10d6 cold damage on a failed save, or half as much damage on a successful one.
***6. Indigo.*** On a failed save, the target is restrained. It must then make a constitution saving throw at the end of each of its turns. If it successfully saves three times, the spell ends. If it fails its save three times, it permanently turns to stone and is subjected to the petrified condition. The successes and failures don''t need to be consecutive; keep track of both until the target collects three of a kind.
***7. Violet.*** On a failed save, the target is blinded. It must then make a wisdom saving throw at the start of your next turn. A successful save ends the blindness. If it fails that save, the creature is transported to another plane of existence of the GM''s choosing and is no longer blinded. (Typically, a creature that is on a plane that isn''t its home plane is banished home, while other creatures are usually cast into the Astral or Ethereal planes.)
***8. Special.*** The target is struck by two rays. Roll twice more, rerolling any 8.', '', NULL
FROM public.spells WHERE external_index = 'prismatic-spray'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Rajada Prismática', 'Oito raios de luz multicoloridos saem da sua mão. Cada raio possui uma cor única, com poder e propósito diferente. Cada criatura em um cone de 18 metros [60 ft.] deve fazer uma salvaguarda de Destreza. Para cada alvo, jogue 1d8 para determinar que raio a afeta.
1. Vermelho. Se falhar, o alvo sofre 10d6 pontos de dano ígneo, ou metade do dano em caso de sucesso.
2. Laranja. Se falhar, o alvo sofre 10d6 pontos de dano ácido, ou metade do dano em caso de sucesso.
3. Amarelo. Se falhar, o alvo sofre 10d6 pontos de dano elétrico, ou metade do dano em caso de sucesso.
4. Verde. Se falhar, o alvo sofre 10d6 pontos de dano venenoso, ou metade do dano em caso de sucesso.
5. Azul. Se falhar, o alvo sofre 10d6 pontos de dano gélido, ou metade do dano em caso de sucesso.
6. Índigo. Se falhar, o alvo está contido. Ele deve, então, fazer uma salvaguarda de Constituição ao final de cada um de seus turnos. Com três sucessos, a magia se encerra. Se falhar três vezes, ele é transformado permanentemente em pedra e se sujeita à condição de petrificado. Os sucessos e falhas não precisam ser consecutivos; mantenha registro de ambos até que o alvo tenha três de um tipo.
7. Violeta. Se falhar, o alvo está cego. Ela deve, então, fazer uma salvaguarda de Sabedoria no começo de seu próximo turno. Um sucesso encerra a cegueira. Se falhar, a criatura é transportada para outro plano de existência à escolha do DM e não está mais cega (normalmente, uma criatura que está em um plano que não é o seu plano natural é banida para casa, enquanto outras criaturas são geralmente lançadas nos Planos Astral ou Etéreo).
8. Especial. O alvo é atingido por dois raios. Jogue mais duas vezes, jogando novamente quaisquer 8.', '', NULL
FROM public.spells WHERE external_index = 'prismatic-spray'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Prismatic Wall
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('prismatic-wall', 9, 'abjuration', 'action', 1, 60, 'feet', 10, 'minute', false, false, ARRAY['V', 'S'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Prismatic Wall', 'A shimmering, multicolored plane of light forms a vertical opaque wall--up to 90 feet long, 30 feet high, and 1 inch thick--centered on a point you can see within range. Alternatively, you can shape the wall into a sphere up to 30 feet in diameter centered on a point you choose within range. The wall remains in place for the duration. If you position the wall so that it passes through a space occupied by a creature, the spell fails, and your action and the spell slot are wasted.
The wall sheds bright light out to a range of 100 feet and dim light for an additional 100 feet. You and creatures you designate at the time you cast the spell can pass through and remain near the wall without harm. If another creature that can see the wall moves to within 20 feet of it or starts its turn there, the creature must succeed on a constitution saving throw or become blinded for 1 minute.
The wall consists of seven layers, each with a different color. When a creature attempts to reach into or pass through the wall, it does so one layer at a time through all the wall''s layers. As it passes or reaches through each layer, the creature must make a dexterity saving throw or be affected by that layer''s properties as described below.
The wall can be destroyed, also one layer at a time, in order from red to violet, by means specific to each layer. Once a layer is destroyed, it remains so for the duration of the spell. A rod of cancellation destroys a prismatic wall, but an antimagic field has no effect on it.
***1. Red.*** The creature takes 10d6 fire damage on a failed save, or half as much damage on a successful one. While this layer is in place, nonmagical ranged attacks can''t pass through the wall. The layer can be destroyed by dealing at least 25 cold damage to it.
***2. Orange.*** The creature takes 10d6 acid damage on a failed save, or half as much damage on a successful one. While this layer is in place, magical ranged attacks can''t pass through the wall. The layer is destroyed by a strong wind.
***3. Yellow.*** The creature takes 10d6 lightning damage on a failed save, or half as much damage on a successful one. This layer can be destroyed by dealing at least 60 force damage to it.
***4. Green.*** The creature takes 10d6 poison damage on a failed save, or half as much damage on a successful one. A passwall spell, or another spell of equal or greater level that can open a portal on a solid surface, destroys this layer.
***5. Blue.*** The creature takes 10d6 cold damage on a failed save, or half as much damage on a successful one. This layer can be destroyed by dealing at least 25 fire damage to it.
***6. Indigo.*** On a failed save, the creature is restrained. It must then make a constitution saving throw at the end of each of its turns. If it successfully saves three times, the spell ends. If it fails its save three times, it permanently turns to stone and is subjected to the petrified condition. The successes and failures don''t need to be consecutive; keep track of both until the creature collects three of a kind.
While this layer is in place, spells can''t be cast through the wall. The layer is destroyed by bright light shed by a daylight spell or a similar spell of equal or higher level.
***7. Violet.*** On a failed save, the creature is blinded. It must then make a wisdom saving throw at the start of your next turn. A successful save ends the blindness. If it fails that save, the creature is transported to another plane of the GM''s choosing and is no longer blinded. (Typically, a creature that is on a plane that isn''t its home plane is banished home, while other creatures are usually cast into the Astral or Ethereal planes.) This layer is destroyed by a dispel magic spell or a similar spell of equal or higher level that can end spells and magical effects.', '', NULL
FROM public.spells WHERE external_index = 'prismatic-wall'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Muralha Prismática', 'Uma superfície cintilante e multicolorida de luz forma uma muralha vertical e opaca de até 27 metros [90 ft.] de comprimento, 9 metros [30 ft.] de altura e 2,5 centímetros [1 inch] de espessura, centrada em um ponto à sua vista, no alcance da magia. Se preferir, você pode moldar a muralha em uma esfera de até 30 metros [100 ft.] de diâmetro, centrada em um ponto à sua escolha, no alcance da magia. A muralha permanece no lugar pela duração da magia. Se você posicionar a muralha de modo que esta passe por um espaço ocupado por uma criatura, a magia falha, e sua ação e o espaço de magia são perdidos.
A muralha emite luz plena por 30 metros [100 ft.] e meia-luz por mais 30 metros [100 ft.]. Você e as criaturas designadas no momento da conjuração podem passar pela muralha e ficar próximas a esta, sem sofrer dano. Se outra criatura que pode ver a muralha se mover a até 6 metros [20 ft.] dela ou começar o turno lá, precisa ser bem-sucedida em uma salvaguarda de Constituição ou fica cega durante 1 minuto.
A muralha tem sete camadas, cada uma de uma cor diferente. Quando uma criatura tenta tocá-la ou passar por ela, o fará uma camada por vez. À cada camada (cor), a criatura precisa fazer uma salvaguarda de Destreza ou será afetada pelas propriedades daquela camada, conforme descrito adiante.
A muralha pode ser destruída, uma camada por vez, na ordem do vermelho para o violeta e de um modo específico para cada uma das camadas. Uma vez que uma camada é destruída, permanece desse modo pela duração da magia. Campo Antimagia não tem efeito sobre a muralha, e Dissipar Magia afeta apenas a camada violeta.
1. Vermelho. Se falhar, a criatura sofre 10d6 pontos de dano ígneo, ou metade do dano em caso de sucesso. Enquanto esta camada estiver ativa, ataques à distância não-mágicos não podem atravessar a muralha. Esta camada é destruída caso sofra ao menos 25 pontos de dano gélido.
2. Laranja. Se falhar, a criatura sofre 10d6 pontos de dano ácido, ou metade do dano em caso de sucesso. Enquanto esta camada estiver ativa, ataques mágicos à distância não podem atravessar a muralha. Esta camada pode ser destruída por um vento forte.
3. Amarelo. Se falhar, a criatura sofre 10d6 pontos de dano elétrico, ou metade do dano em caso de sucesso. Esta camada é destruída caso sofra ao menos 60 pontos de dano energético.
4. Verde. Se falhar, a criatura sofre 10d6 pontos de dano venenoso, ou metade do dano em caso de sucesso. Uma magia Criar Passagem ou outra magia de mesmo círculo ou superior que puder abrir uma porta em uma superfície sólida, destrói esta camada.
5. Azul. Se falhar, a criatura sofre 10d6 pontos de dano gélido, ou metade do dano em caso de sucesso. Esta camada é destruída caso sofra ao menos 25 pontos de dano ígneo.
6. Anil. Se falhar, a criatura é contida. Ela deve, então, fazer uma salvaguarda de Constituição ao final de cada um dos próprios turnos. Se falhar três vezes, a criatura é transformada permanentemente em pedra e está sujeita à condição de petrificada. Se obter três sucessos, a magia se encerra. Os sucessos e falhas não precisam ser consecutivos; mantenha a contagem de ambos até que a criatura tenha três de um tipo.
Enquanto esta camada estiver ativa, magias não podem atravessar a muralha. Esta camada é destruída por luz plena emanada pela magia Luz do Dia ou uma magia similar do mesmo círculo ou superior.
7. Violeta. Se falhar, a criatura fica cega. Ela deve, então, fazer uma salvaguarda de Sabedoria no começo de seu próximo turno. Um sucesso encerra a cegueira. Se falhar, a criatura é transportada para outro plano à escolha do DM e não está mais cega (tipicamente, uma criatura que está em um plano que não é o de origem dela, é banida de volta, enquanto outras criaturas são normalmente lançadas nos Planos Astral ou Etéreo). Esta camada é destruída por Dissipar Magia ou magia semelhante de mesmo círculo ou superior, que seja capaz de encerrar magias ou efeitos mágicos.', '', NULL
FROM public.spells WHERE external_index = 'prismatic-wall'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Private Sanctum
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('private-sanctum', 4, 'abjuration', 'minute', 10, 120, 'feet', 24, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Private Sanctum', 'You make an area within range magically secure. The area is a cube that can be as small as 5 feet to as large as 100 feet on each side. The spell lasts for the duration or until you use an action to dismiss it.
When you cast the spell, you decide what sort of security the spell provides, choosing any or all of the following properties:
- Sound can''t pass through the barrier at the edge of the warded area.
- The barrier of the warded area appears dark and foggy, preventing vision (including darkvision) through it.
- Sensors created by divination spells can''t appear inside the protected area or pass through the barrier at its perimeter.
- Creatures in the area can''t be targeted by divination spells.
- Nothing can teleport into or out of the warded area.
- Planar travel is blocked within the warded area.
Casting this spell on the same spot every day for a year makes this effect permanent.', 'When you cast this spell using a spell slot of 5th level or higher, you can increase the size of the cube by 100 feet for each slot level beyond 4th. Thus you could protect a cube that can be up to 200 feet on one side by using a spell slot of 5th level.', 'A thin sheet of lead, a piece of opaque glass, a wad of cotton or cloth, and powdered chrysolite.'
FROM public.spells WHERE external_index = 'private-sanctum'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Santuário Particular', 'Você transforma uma área no alcance da magia em um local magicamente seguro. Pode ser um cubo de lado tão pequeno quanto 1,5 metro [5 ft.] ou tão grande quanto 30 metros [100 ft.]. A magia permanece pela duração ou até que você a encerre com uma ação.
Ao conjurar a magia, você decide qual tipo de segurança ela fornece, escolhendo quantas desejar entre as seguintes propriedades:
Sons não podem atravessar a barreira na borda da área protegida.
A borda tem aparência escura e opaca, impedindo a visão (incluindo visão no escuro) através dela.
Sensores criados por adivinhação não podem surgir dentro da área protegida, ou passar pelo perímetro.
Criaturas na área não podem ser alvos de magias de adivinhação.
Nada pode se teleportar para dentro da área protegida.
Viagem planar é bloqueada no interior do local.
Conjurar esta magia no mesmo lugar todo dia por um ano torna o seu efeito permanente.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 5º círculo ou superior, você pode aumentar o tamanho do cubo em 30 metros [100 ft.] para cada círculo do espaço acima do 4º. Então, você poderia proteger um cubo que não tenha mais que 60 metros [200 ft.] em um dos lados, usando um espaço de magia de 5º círculo.', '', NULL
FROM public.spells WHERE external_index = 'private-sanctum'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Produce Flame
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('produce-flame', 0, 'conjuration', 'action', 1, NULL, 'self', 10, 'minute', false, false, ARRAY['V', 'S'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Produce Flame', 'A flickering flame appears in your hand. The flame remains there for the duration and harms neither you nor your equipment. The flame sheds bright light in a 10-foot radius and dim light for an additional 10 feet. The spell ends if you dismiss it as an action or if you cast it again.
You can also attack with the flame, although doing so ends the spell. When you cast this spell, or as an action on a later turn, you can hurl the flame at a creature within 30 feet of you. Make a ranged spell attack. On a hit, the target takes 1d8 fire damage.
This spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', '', NULL
FROM public.spells WHERE external_index = 'produce-flame'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Criar Chamas', 'Uma chama bruxuleante surge em sua mão. Ela permanece assim enquanto a magia durar e não causa dano a você ou ao seu equipamento. A labareda emite luz plena em um raio de 3 metros [10-foot radius] e meia-luz por mais 3 metros [10 ft.]. A magia termina se você a dispensar com uma ação ou se conjurá-la novamente.
Você também pode atacar com a chama, embora fazê-lo encerre a magia. Ao conjurar a chama, ou com uma ação em um turno posterior, é possível arremessar a labareda em uma criatura a até 9 metros [30 ft.] de você. Faça um ataque mágico à distância. Se acertar, o alvo sofre 1d8 pontos de dano ígneo.
O dano desta magia aumenta em 1d8 quando você alcança o 5º nível (2d8), 11º nível (3d8) e 17º nível (4d8).', '', NULL
FROM public.spells WHERE external_index = 'produce-flame'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Programmed Illusion
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('programmed-illusion', 6, 'illusion', 'action', 1, 120, 'feet', NULL, 'special', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Programmed Illusion', 'You create an illusion of an object, a creature, or some other visible phenomenon within range that activates when a specific condition occurs. The illusion is imperceptible until then. It must be no larger than a 30-foot cube, and you decide when you cast the spell how the illusion behaves and what sounds it makes. This scripted performance can last up to 5 minutes.
When the condition you specify occurs, the illusion springs into existence and performs in the manner you described. Once the illusion finishes performing, it disappears and remains dormant for 10 minutes. After this time, the illusion can be activated again.
The triggering condition can be as general or as detailed as you like, though it must be based on visual or audible conditions that occur within 30 feet of the area. For example, you could create an illusion of yourself to appear and warn off others who attempt to open a trapped door, or you could set the illusion to trigger only when a creature says the correct word or phrase.
Physical interaction with the image reveals it to be an illusion, because things can pass through it. A creature that uses its action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and any noise it makes sounds hollow to the creature.', '', 'A bit of fleece and jade dust worth at least 25 gp.'
FROM public.spells WHERE external_index = 'programmed-illusion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Ilusão Programada', 'Você cria a ilusão de um objeto, criatura ou outro fenômeno visível no alcance da magia e que é ativado quando uma condição específica ocorre. O efeito ilusório é imperceptível até ser ativado. A ilusão não pode ser maior do que um cubo de 9 metros [30 ft.]. Ao conjurar essa magia você decide como a ilusão se comporta e que sons ela faz. A encenação programada pode durar até 5 minutos.
Quando a condição que você especificou ocorrer, a ilusão surge e age da maneira que você descreveu. Uma vez terminada a encenação, a ilusão desaparece e permanece dormente por 10 minutos. Após esse tempo, a ilusão pode ser ativada novamente.
A condição de ativação pode ser tão específica ou genérica quanto você desejar, no entanto deve basear-se em condições visuais ou sonoras que ocorram a até 9 metros [30 ft.] da área. Por exemplo, você poderia criar uma ilusão de si mesmo para avisar outros que tentem abrir uma porta com armadilha ou poderia programar a ilusão para ser ativada apenas quando uma criatura disser uma determinada palavra ou frase.
Interação física com a imagem revela que se trata de uma ilusão, pois coisas podem passar através dela. Uma criatura que gaste uma ação para examinar a imagem, pode perceber o caráter ilusório desta com um teste bem-sucedido de Inteligência (Investigação) contra a CD para evitar sua magia. Se uma criatura discernir a ilusão pelo que ela é, a criatura pode ver através da imagem, e qualquer som que a ilusão faça se torna abafado para a criatura.', '', NULL
FROM public.spells WHERE external_index = 'programmed-illusion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Project Image
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('project-image', 7, 'illusion', 'action', 1, 500, 'mile', 24, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Project Image', 'You create an illusory copy of yourself that lasts for the duration. The copy can appear at any location within range that you have seen before, regardless of intervening obstacles. The illusion looks and sounds like you but is intangible. If the illusion takes any damage, it disappears, and the spell ends.
You can use your action to move this illusion up to twice your speed, and make it gesture, speak, and behave in whatever way you choose. It mimics your mannerisms perfectly.
You can see through its eyes and hear through its ears as if you were in its space. On your turn as a bonus action, you can switch from using its senses to using your own, or back again. While you are using its senses, you are blinded and deafened in regard to your own surroundings.
Physical interaction with the image reveals it to be an illusion, because things can pass through it. A creature that uses its action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and any noise it makes sounds hollow to the creature.', '', 'A small replica of you made from materials worth at least 5 gp.'
FROM public.spells WHERE external_index = 'project-image'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Projetar Imagem', 'Você cria uma cópia ilusória de si mesmo, que permanece enquanto a magia durar. A cópia pode aparecer em qualquer local que você já tenha visto dentro do alcance da magia, independentemente da interposição de obstáculos. A ilusão se parece e soa como você, mas é intangível. Se a ilusão sofrer qualquer dano, ela desaparece e a magia se encerra.
Você pode usar uma ação para mover a ilusão a até duas vezes o seu deslocamento e fazê-la gesticular, falar e se comportar da maneira que você escolher. Ela imita seus maneirismos perfeitamente.
Você pode ver através dos olhos e ouvir através dos ouvidos de sua cópia como se estivesse no espaço ocupado por ela. No seu turno, com uma ação bônus, você pode parar de usar os sentidos da cópia para usar os seus, ou voltar para os dela novamente. Enquanto estiver usando os sentidos de sua cópia, você estará cego e surdo em relação aos seus arredores.
Interação física com a cópia revela que ela é uma ilusão, pois coisas podem passar através dela. Se uma criatura usar uma ação para examinar a imagem, ela pode determinar que se trata de uma ilusão com um teste bem-sucedido de Inteligência (Investigação) contra a CD para evitar sua magia. Se a criatura discernir a ilusão pelo que realmente é, poderá ver através da imagem, e qualquer som que a ilusão faça se torna abafado para a criatura.', '', NULL
FROM public.spells WHERE external_index = 'project-image'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Protection From Energy
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('protection-from-energy', 3, 'abjuration', 'action', 1, NULL, 'touch', 1, 'hour', true, false, ARRAY['V', 'S'], ARRAY['cleric', 'druid', 'ranger', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Protection From Energy', 'For the duration, the willing creature you touch has resistance to one damage type of your choice: acid, cold, fire, lightning, or thunder.', '', NULL
FROM public.spells WHERE external_index = 'protection-from-energy'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Protection from Evil and Good
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('protection-from-evil-and-good', 1, 'abjuration', 'action', 1, NULL, 'touch', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'paladin', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Protection from Evil and Good', 'Until the spell ends, one willing creature you touch is protected against certain types of creatures: aberrations, celestials, elementals, fey, fiends, and undead.
The protection grants several benefits. Creatures of those types have disadvantage on attack rolls against the target. The target also can''t be charmed, frightened, or possessed by them. If the target is already charmed, frightened, or possessed by such a creature, the target has advantage on any new saving throw against the relevant effect.', '', 'Holy water or powdered silver and iron, which the spell consumes.'
FROM public.spells WHERE external_index = 'protection-from-evil-and-good'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Proteção Contra o Bem e o Mal', 'Enquanto a magia durar, uma criatura voluntária tocada por você passa a ter proteção contra certos tipos de criaturas: aberrações, celestiais, elementais, feéricos, ínferos e mortos-vivos.
A proteção concede vários benefícios. Criaturas destes tipos têm desvantagem nas jogadas de ataque contra o alvo. O alvo não pode ser amedrontado, enfeitiçado ou possuído por elas. Se o alvo já estiver amedrontado, enfeitiçado ou possuído por estas criaturas, ele terá vantagem sobre qualquer nova salvaguarda contra o efeito relevante.', '', NULL
FROM public.spells WHERE external_index = 'protection-from-evil-and-good'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Protection from Poison
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('protection-from-poison', 2, 'abjuration', 'action', 1, NULL, 'touch', 1, 'hour', false, false, ARRAY['V', 'S'], ARRAY['cleric', 'druid', 'paladin', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Protection from Poison', 'You touch a creature. If it is poisoned, you neutralize the poison. If more than one poison afflicts the target, you neutralize one poison that you know is present, or you neutralize one at random.
For the duration, the target has advantage on saving throws against being poisoned, and it has resistance to poison damage.', '', NULL
FROM public.spells WHERE external_index = 'protection-from-poison'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Proteção Contra Veneno', 'Você toca uma criatura. Se ela estiver envenenada, você neutraliza o veneno. Se mais de um veneno afligir o alvo, você neutraliza o veneno que sabe estar presente, ou neutraliza um deles, ao acaso.
Enquanto a magia durar, o alvo tem vantagem nas salvaguardas contra ser envenenado, e resistência a dano venenoso.', '', NULL
FROM public.spells WHERE external_index = 'protection-from-poison'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
