INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Purify Food and Drink', 'All nonmagical food and drink within a 5-foot radius sphere centered on a point of your choice within range is purified and rendered free of poison and disease.', '', NULL
FROM public.spells WHERE external_index = 'purify-food-and-drink'
