INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Purificar Alimentos e Bebidas', 'Toda a comida e bebida não-mágica dentro de uma esfera de 1,5 metro de raio [5-foot radius] centrada em um ponto à sua escolha, no alcance da magia, é purificada e tornada livre de venenos e doenças.', '', NULL
FROM public.spells WHERE external_index = 'purify-food-and-drink'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Raise Dead
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('raise-dead', 5, 'necromancy', 'hour', 1, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'paladin'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Raise Dead', 'You return a dead creature you touch to life, provided that it has been dead no longer than 10 days. If the creature''s soul is both willing and at liberty to rejoin the body, the creature returns to life with 1 hit point.
This spell also neutralizes any poisons and cures nonmagical diseases that affected the creature at the time it died. This spell doesn''t, however, remove magical diseases, curses, or similar effects; if these aren''t first removed prior to casting the spell, they take effect when the creature returns to life. The spell can''t return an undead creature to life.
This spell closes all mortal wounds, but it doesn''t restore missing body parts. If the creature is lacking body parts or organs integral for its survival--its head, for instance--the spell automatically fails.
Coming back from the dead is an ordeal. The target takes a -4 penalty to all attack rolls, saving throws, and ability checks. Every time the target finishes a long rest, the penalty is reduced by 1 until it disappears.', '', 'A diamond worth at least 500gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'raise-dead'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Reviver os Mortos', 'Uma criatura que você toca retorna dos mortos, desde que não tenha falecido há mais de 10 dias. Se a alma dela estiver disposta e livre para retornar ao corpo, ela retorna à vida com 1 ponto de vida.A magia também neutraliza quaisquer venenos e cura doenças não-mágicas que a afetavam no momento em que morreu. Entretanto, a magia não remove doenças mágicas ou efeitos semelhantes; se eles não forem cancelados antes da conjuração, voltam a ter efeito assim que a criatura voltar a viver. Esta magia não retorna um morto-vivo à vida.Todas as lesões mortais são fechadas, mas partes perdidas do corpo não são restauradas. Se o cadáver tiver partes ou órgãos vitais do corpo faltando - como a cabeça, por exemplo, a magia falha automaticamente.Voltar à vida após a morte é uma provação. O alvo sofre -4 de penalidade em todas as jogadas de ataque, salvaguardas e testes de atributo. Toda vez que o alvo completa um descanso longo, a penalidade é reduzida em 1, até desaparecer.', '', NULL
FROM public.spells WHERE external_index = 'raise-dead'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Ray of Enfeeblement
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('ray-of-enfeeblement', 2, 'necromancy', 'action', 1, 60, 'feet', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Ray of Enfeeblement', 'A black beam of enervating energy springs from your finger toward a creature within range. Make a ranged spell attack against the target. On a hit, the target deals only half damage with weapon attacks that use Strength until the spell ends.
At the end of each of the target''s turns, it can make a constitution saving throw against the spell. On a success, the spell ends.', '', NULL
FROM public.spells WHERE external_index = 'ray-of-enfeeblement'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Raio do Enfraquecimento', 'Um feixe negro de energia debilitante brota do seu dedo em direção a uma criatura no alcance da magia. Faça um ataque mágico à distância contra o alvo. Se acertar, enquanto a magia durar, o alvo passa a causar apenas metade do dano em ataques armados que usem Força.No final de cada um dos próprios turnos, o alvo pode fazer uma salvaguarda de Constituição contra a magia. Em caso de sucesso, a magia se encerra.', '', NULL
FROM public.spells WHERE external_index = 'ray-of-enfeeblement'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Ray of Frost
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('ray-of-frost', 0, 'evocation', 'action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Ray of Frost', 'A frigid beam of blue-white light streaks toward a creature within range. Make a ranged spell attack against the target. On a hit, it takes 1d8 cold damage, and its speed is reduced by 10 feet until the start of your next turn.
The spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', '', NULL
FROM public.spells WHERE external_index = 'ray-of-frost'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Raio de Gelo', 'Um feixe branco-azulado, luminoso e gélido parte na direção de uma criatura no alcance da magia. Faça um ataque mágico à distância contra o alvo. Se acertar, o alvo sofre 1d8 pontos de dano gélido e o deslocamento dele é reduzido em 3 metros [10 ft.] até o começo do seu próximo turno.
O dano desta magia aumenta em 1d8 quando você alcança o 5º nível (2d8), 11º nível (3d8) e 17º nível (4d8).', '', NULL
FROM public.spells WHERE external_index = 'ray-of-frost'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Regenerate
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('regenerate', 7, 'transmutation', 'minute', 1, NULL, 'touch', 1, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Regenerate', 'You touch a creature and stimulate its natural healing ability. The target regains 4d8 + 15 hit points. For the duration of the spell, the target regains 1 hit point at the start of each of its turns (10 hit points each minute).
The target''s severed body members (fingers, legs, tails, and so on), if any, are restored after 2 minutes. If you have the severed part and hold it to the stump, the spell instantaneously causes the limb to knit to the stump.', '', 'A prayer wheel and holy water.'
FROM public.spells WHERE external_index = 'regenerate'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Regeneração', 'Você toca uma criatura e estimula sua capacidade natural de cura. O alvo recupera 4d8+15 pontos de vida. Enquanto a magia durar, o alvo recupera 1 ponto de vida no começo de cada turno dele (10 pontos de vida por minuto).
Membros amputados do corpo do alvo (dedos, pernas, cauda e assim por diante), se houver, são restaurados após 2 minutos. Se a parte amputada do corpo for colocada no lugar, a magia instantaneamente faz com que o membro se reconecte.', '', NULL
FROM public.spells WHERE external_index = 'regenerate'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Reincarnate
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('reincarnate', 5, 'transmutation', 'hour', 1, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Reincarnate', 'You touch a dead humanoid or a piece of a dead humanoid. Provided that the creature has been dead no longer than 10 days, the spell forms a new adult body for it and then calls the soul to enter that body. If the target''s soul isn''t free or willing to do so, the spell fails.
The magic fashions a new body for the creature to inhabit, which likely causes the creature''s race to change. The GM rolls a d 100 and consults the following table to determine what form the creature takes when restored to life, or the GM chooses a form.
| d100 | Race |
|---|---|
| 01-04 | Dragonborn |
| 05-13 | Dwarf, hill |
| 14-21 | Dwarf, mountain |
| 22-25 | Elf, dark |
| 26-34 | Elf, high |
| 35-42 | Elf, wood |
| 43-46 | Gnome, forest |
| 47-52 | Gnome, rock |
| 53-56 | Half-elf |
| 57-60 | Half-orc |
| 61-68 | Halfling, lightfoot |
| 69-76 | Halfling, stout |
| 77-96 | Human |
| 97-00 | Tiefling |
The reincarnated creature recalls its former life and experiences. It retains the capabilities it had in its original form, except it exchanges its original race for the new one and changes its racial traits accordingly.', '', 'Rare oils and unguents worth at least 1,000 gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'reincarnate'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Reencarnar', 'Você toca um humanoide morto ou um pedaço de um humanoide morto. Contanto que a criatura não esteja morta há mais de 10 dias, a magia forma um novo corpo adulto para ela e convoca sua alma a entrar no corpo. Se a alma da criatura não estiver livre ou disposta para tal, a magia falha.A magia molda um novo corpo para a criatura habitar, o que pode causar uma mudança de raça da criatura. O DM joga na tabela @Compendium[dnd5e.tables.eXu1QFMsFtTtoJBZ]{Reencarnar} para determinar que forma a criatura assume quando restaurada à vida, ou o DM escolhe uma forma.
A criatura reencarnada recorda sua vida e experiências anteriores. Ela mantém as capacidades que tinha em sua forma original, exceto pela mudança de sua raça original para a nova e dos seus traços raciais, obviamente.', '', NULL
FROM public.spells WHERE external_index = 'reincarnate'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Remove Curse
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('remove-curse', 3, 'abjuration', 'action', 1, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['cleric', 'paladin', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Remove Curse', 'At your touch, all curses affecting one creature or object end. If the object is a cursed magic item, its curse remains, but the spell breaks its owner''s attunement to the object so it can be removed or discarded.', '', NULL
FROM public.spells WHERE external_index = 'remove-curse'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Remover Maldição', 'Ao tocar uma criatura ou objeto, todas as maldições lançadas sobre eles se encerram. Se o objeto for um item mágico amaldiçoado, a maldição se mantém, mas a magia quebra a sintonia do dono com o objeto, de modo que ele pode ser removido ou descartado.', '', NULL
FROM public.spells WHERE external_index = 'remove-curse'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Resilient Sphere
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('resilient-sphere', 4, 'evocation', 'action', 1, 30, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Resilient Sphere', 'A sphere of shimmering force encloses a creature or object of Large size or smaller within range. An unwilling creature must make a dexterity saving throw. On a failed save, the creature is enclosed for the duration.
Nothing--not physical objects, energy, or other spell effects--can pass through the barrier, in or out, though a creature in the sphere can breathe there. The sphere is immune to all damage, and a creature or object inside can''t be damaged by attacks or effects originating from outside, nor can a creature inside the sphere damage anything outside it.
The sphere is weightless and just large enough to contain the creature or object inside. An enclosed creature can use its action to push against the sphere''s walls and thus roll the sphere at up to half the creature''s speed. Similarly, the globe can be picked up and moved by other creatures.
A disintegrate spell targeting the globe destroys it without harming anything inside it.', '', 'A hemispherical piece of clear crystal and a matching hemispherical piece of gum arabic.'
FROM public.spells WHERE external_index = 'resilient-sphere'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Esfera Resiliente', 'Uma esfera de energia cintilante envolve uma criatura ou objeto de tamanho Grande ou menor, no alcance da magia. Uma criatura que estiver na esfera contra a própria vontade deve fazer uma salvaguarda de Destreza. Se falhar, a criatura fica enclausurada enquanto a magia durar.
Nada - nem objetos físicos, energia ou outros efeitos mágicos - pode passar através da barreira, para dentro ou fora, apesar de uma criatura na esfera poder respirar nela. A esfera é imune a todos os danos e qualquer criatura ou objeto dentro dela não pode sofrer dano por ataques ou efeitos provenientes do exterior, tampouco pode causar dano à qualquer coisa do lado de fora.
A esfera não possui peso e é grande o suficiente para conter apenas a criatura ou objeto dentro dela. Uma criatura enclausurada pode usar sua ação, empurrando-se contra a parede da esfera e, assim, rolando-a por até metade do deslocamento da criatura. Da mesma forma, o globo pode ser apanhado e movido por outras criaturas.
Uma magia Desintegrar tendo como alvo o globo, o destrói sem causar dano a qualquer coisa dentro dele.', '', NULL
FROM public.spells WHERE external_index = 'resilient-sphere'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Resistance
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('resistance', 0, 'abjuration', 'action', 1, NULL, 'touch', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'druid'], 'dnd_5e')
