INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Resistance', 'You touch one willing creature. Once before the spell ends, the target can roll a d4 and add the number rolled to one saving throw of its choice. It can roll the die before or after making the saving throw. The spell then ends.', '', 'A miniature cloak.'
FROM public.spells WHERE external_index = 'resistance'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Resistência', 'Você toca uma criatura voluntária. Uma vez antes da magia terminar, o alvo pode jogar 1d4 e adicionar o número a uma salvaguarda à sua escolha. Ele pode jogar o dado antes ou depois de fazer a salvaguarda. A magia, então, se encerra.', '', NULL
FROM public.spells WHERE external_index = 'resistance'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Resurrection
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('resurrection', 7, 'necromancy', 'hour', 1, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Resurrection', 'You touch a dead creature that has been dead for no more than a century, that didn''t die of old age, and that isn''t undead. If its soul is free and willing, the target returns to life with all its hit points.
This spell neutralizes any poisons and cures normal diseases afflicting the creature when it died. It doesn''t, however, remove magical diseases, curses, and the like; if such effects aren''t removed prior to casting the spell, they afflict the target on its return to life.
This spell closes all mortal wounds and restores any missing body parts.
Coming back from the dead is an ordeal. The target takes a -4 penalty to all attack rolls, saving throws, and ability checks. Every time the target finishes a long rest, the penalty is reduced by 1 until it disappears.
Casting this spell to restore life to a creature that has been dead for one year or longer taxes you greatly. Until you finish a long rest, you can''t cast spells again, and you have disadvantage on all attack rolls, ability checks, and saving throws.', '', 'A diamond worth at least 1,000gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'resurrection'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Ressurreição', 'Você toca uma criatura, morta há não mais de um século, que não tenha morrido de causas naturais e que não seja um morto-vivo. Se a alma dela estiver livre e disposta, a criatura retorna à vida com todos os pontos de vida.A magia neutraliza quaisquer venenos e cura doenças normais que afligiam a criatura quando morreu. Entretanto, ela não remove maldições, doenças mágicas ou coisas do gênero; se esses efeitos não forem removidos antes da conjuração da magia, eles voltam a afligir o alvo após o seu retomo à vida.A magia fecha todas as lesões fatais e restaura quaisquer partes corpóreas perdidas.Voltar à vida após a morte é uma provação. O alvo sofre -4 de penalidade em todas as jogadas de ataque, salvaguardas e testes de atributo. Toda vez que o alvo completa um descanso longo, a penalidade é reduzida em 1, até desaparecer completamente.Conjurar esta magia para restaurar vida a um indivíduo que esteja morto por um ano ou mais é algo extenuante para o conjurador. Até terminar um descanso longo, é impossível conjurar magias novamente e também todas as jogadas de ataque, testes de atributo e salvaguardas possuem desvantagem.', '', NULL
FROM public.spells WHERE external_index = 'resurrection'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Reverse Gravity
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('reverse-gravity', 7, 'transmutation', 'action', 1, 100, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Reverse Gravity', 'This spell reverses gravity in a 50-foot-radius, 100-foot high cylinder centered on a point within range. All creatures and objects that aren''t somehow anchored to the ground in the area fall upward and reach the top of the area when you cast this spell. A creature can make a dexterity saving throw to grab onto a fixed object it can reach, thus avoiding the fall.
If some solid object (such as a ceiling) is encountered in this fall, falling objects and creatures strike it just as they would during a normal downward fall. If an object or creature reaches the top of the area without striking anything, it remains there, oscillating slightly, for the duration.
At the end of the duration, affected objects and creatures fall back down.', '', 'A lodestone and iron filings.'
FROM public.spells WHERE external_index = 'reverse-gravity'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Inverter a Gravidade', 'Esta magia inverte a gravidade numa área de 15 metros de raio e 30 metros de altura, formando um cilindro [50-foot-radius, 100-foot high cylinder] centrado em um ponto no alcance da magia. Todas as criaturas e objetos que não estão, de alguma forma, ancorados ao solo nessa área, "caem" para cima e alcançam o topo da área quando a magia é conjurada. Uma criatura pode fazer uma salvaguarda de Destreza para se agarrar a um objeto fixo que possa alcançar, evitando a queda.
Se algum objeto sólido (como um teto) for encontrado durante esta queda, criaturas e objetos caindo se chocam contra ele, como fariam durante uma queda normal para baixo. Se um objeto ou criatura atingir o topo da área sem bater em nada, ele permanece lá, oscilando ligeiramente, enquanto a magia durar.
Ao final da duração, objetos e criaturas afetados caem de volta para baixo.', '', NULL
FROM public.spells WHERE external_index = 'reverse-gravity'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Revivify
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('revivify', 3, 'conjuration', 'action', 1, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'paladin'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Revivify', 'You touch a creature that has died within the last minute. That creature returns to life with 1 hit point. This spell can''t return to life a creature that has died of old age, nor can it restore any missing body parts.', '', 'Diamonds worth 300gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'revivify'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Revivificar', 'Você toca uma criatura que faleceu há menos de um minuto. Aquela criatura volta à vida com 1 ponto de vida. A magia não pode retornar quem morreu de idade avançada, nem pode restaurar quaisquer partes perdidas do corpo.', '', NULL
FROM public.spells WHERE external_index = 'revivify'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Rope Trick
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('rope-trick', 2, 'transmutation', 'action', 1, NULL, 'touch', 1, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Rope Trick', 'You touch a length of rope that is up to 60 feet long. One end of the rope then rises into the air until the whole rope hangs perpendicular to the ground. At the upper end of the rope, an invisible entrance opens to an extradimensional space that lasts until the spell ends.
The extradimensional space can be reached by climbing to the top of the rope. The space can hold as many as eight Medium or smaller creatures. The rope can be pulled into the space, making the rope disappear from view outside the space.
Attacks and spells can''t cross through the entrance into or out of the extradimensional space, but those inside can see out of it as if through a 3-foot-by-5-foot window centered on the rope.
Anything inside the extradimensional space drops out when the spell ends.', '', 'Powdered corn extract and a twisted loop of parchment.'
FROM public.spells WHERE external_index = 'rope-trick'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Corda Extradimensional', 'Você toca um pedaço de corda de até 18 metros [60 ft.] de comprimento. Uma extremidade da corda, em seguida, sobe para o ar, até ficar perpendicular ao solo. Na extremidade superior da corda, uma entrada invisível se abre para um espaço extradimensional enquanto a magia durar.O espaço extradimensional pode ser alcançado escalando-se a corda até o topo. O espaço pode conter até oito criaturas de tamanho Médio ou menores. A corda pode ser puxada para o espaço, fazendo com que desapareça de vista para quem está de fora do espaço.Ataques e magias não podem atravessar a entrada, seja para dentro ou para fora do espaço extradimensional, mas quem está dentro pode ver do lado de fora, como se olhasse através de uma janela de 1,00 x 1,50 metro [3-foot-by-5-foot], tendo a corda como centro.Qualquer coisa dentro do espaço extradimensional cai quando a magia termina.', '', NULL
FROM public.spells WHERE external_index = 'rope-trick'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Sacred Flame
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('sacred-flame', 0, 'evocation', 'action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Sacred Flame', 'Flame-like radiance descends on a creature that you can see within range. The target must succeed on a dexterity saving throw or take 1d8 radiant damage. The target gains no benefit from cover for this saving throw.
The spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', '', NULL
FROM public.spells WHERE external_index = 'sacred-flame'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Chama Sagrada', 'Uma irradiação instantânea semelhante a uma chama irrompe em uma criatura à sua vista, no alcance da magia. O alvo deve fazer uma salvaguarda de Destreza. Se falhar, sofre 1d8 pontos de dano radiante. O alvo não tem benefício algum de cobertura para essa salvaguarda.
O dano desta magia aumenta em 1d8 quando você alcança o 5º nível (2d8), 11º nível (3d8) e 17º nível (4d8).', '', NULL
FROM public.spells WHERE external_index = 'sacred-flame'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Sanctuary
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('sanctuary', 1, 'abjuration', 'bonus_action', 1, 30, 'feet', 1, 'minute', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Sanctuary', 'You ward a creature within range against attack. Until the spell ends, any creature who targets the warded creature with an attack or a harmful spell must first make a wisdom saving throw. On a failed save, the creature must choose a new target or lose the attack or spell. This spell doesn''t protect the warded creature from area effects, such as the explosion of a fireball.
If the warded creature makes an attack or casts a spell that affects an enemy creature, this spell ends.', '', 'A small silver mirror.'
FROM public.spells WHERE external_index = 'sanctuary'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Santuário', 'Você protege uma criatura que esteja dentro do alcance da magia contra ataques. Enquanto a magia durar, qualquer criatura que tenha a criatura protegida como alvo de um ataque ou de uma magia prejudicial deve antes fazer uma salvaguarda de Sabedoria. Se falhar, o atacante deve escolher outro alvo ou perderá o ataque ou magia. Esta magia não garante ao alvo proteção contra efeitos de área, como a explosão de uma bola de fogo.
Se o alvo protegido fizer um ataque ou conjurar uma magia que afete uma criatura inimiga, a magia se encerra.', '', NULL
FROM public.spells WHERE external_index = 'sanctuary'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Scorching Ray
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('scorching-ray', 2, 'evocation', 'action', 1, 120, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Scorching Ray', 'You create three rays of fire and hurl them at targets within range. You can hurl them at one target or several.
Make a ranged spell attack for each ray. On a hit, the target takes 2d6 fire damage.', 'When you cast this spell using a spell slot of 3rd level or higher, you create one additional ray for each slot level above 2nd.', NULL
FROM public.spells WHERE external_index = 'scorching-ray'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Raio Ardente', 'Você cria três raios de fogo e os dispara em alvos que estejam no alcance da magia. Você pode dispará-los contra um alvo ou vários.
Faça um ataque mágico à distância para cada raio. Se acertar, o alvo sofre 2d6 pontos de dano ígneo.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 3º círculo ou superior, você cria um raio adicional para cada círculo do espaço acima do 2º.', '', NULL
FROM public.spells WHERE external_index = 'scorching-ray'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Scrying
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('scrying', 5, 'divination', 'minute', 10, NULL, 'self', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'druid', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Scrying', 'You can see and hear a particular creature you choose that is on the same plane of existence as you. The target must make a wisdom saving throw, which is modified by how well you know the target and the sort of physical connection you have to it. If a target knows you''re casting this spell, it can fail the saving throw voluntarily if it wants to be observed.
| Knowledge | Save Modifier |
|---|---|
| Secondhand (you have heard of the target) | +5 |
| Firsthand (you have met the target) | +0 |
| Familiar (you know the target well) | -5 |
| Connection | Save Modifier |
|---|---|
| Likeness or picture | -2 |
| Possession or garment | -4 |
| Body part, lock of hair, bit of nail, or the like | -10 |
On a successful save, the target isn''t affected, and you can''t use this spell against it again for 24 hours.
On a failed save, the spell creates an invisible sensor within 10 feet of the target. You can see and hear through the sensor as if you were there. The sensor moves with the target, remaining within 10 feet of it for the duration. A creature that can see invisible objects sees the sensor as a luminous orb about the size of your fist.
Instead of targeting a creature, you can choose a location you have seen before as the target of this spell. When you do, the sensor appears at that location and doesn''t move.', '', 'A focus worth at least 1,000 gp, such as a crystal ball, a silver mirror, or a font filled with holy water.'
FROM public.spells WHERE external_index = 'scrying'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Vidência', 'Você pode ver e escutar uma determinada criatura à sua escolha que esteja no mesmo plano de existência. O alvo deve fazer uma salvaguarda de Sabedoria, modificada por quão bem você o conhece e pelo tipo de conexão física com ele. Se um alvo souber que você está conjurando esta magia, ele pode abrir mão da salvaguarda voluntariamente se ele quiser ser observado.
Conhecimento
Modificador de Salvaguarda
Segunda mão (ouviu falar do alvo)
+5
Primeira mão (você conhece o alvo)
+0
Familiar (você conhece bem o alvo)
-5
Conexão
Modificador de Salvaguarda
Semelhança ou imagem
-2
Posse ou vestimenta
-4
Parte do corpo, cacho de cabelo, lasca de unha ou coisa do tipo
-10
Em caso de sucesso, o alvo não é afetado e você não pode usar esta magia contra ele novamente por 24 horas.
Se falhar, a magia cria um sensor invisível no alcance de 3 metros [10 ft.] do alvo. Você pode ver e ouvir através do sensor, como se estivesse no local. O sensor move-se com o alvo, ficando a 3 metros [10 ft.] dele enquanto a magia durar. Uma criatura que possa ver objetos invisíveis, pode ver o sensor como um orbe luminoso do tamanho de um punho.
Em vez de focar em uma criatura, você pode escolher uma localidade que tenha visto antes como alvo desta magia. Quando o fizer, o sensor aparece na localidade e não se move.', '', NULL
FROM public.spells WHERE external_index = 'scrying'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Secret Chest
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('secret-chest', 4, 'conjuration', 'action', 1, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Secret Chest', 'You hide a chest, and all its contents, on the Ethereal Plane. You must touch the chest and the miniature replica that serves as a material component for the spell. The chest can contain up to 12 cubic feet of nonliving material (3 feet by 2 feet by 2 feet).
While the chest remains on the Ethereal Plane, you can use an action and touch the replica to recall the chest. It appears in an unoccupied space on the ground within 5 feet of you. You can send the chest back to the Ethereal Plane by using an action and touching both the chest and the replica.
After 60 days, there is a cumulative 5 percent chance per day that the spell''s effect ends. This effect ends if you cast this spell again, if the smaller replica chest is destroyed, or if you choose to end the spell as an action. If the spell ends and the larger chest is on the Ethereal Plane, it is irretrievably lost.', '', 'An exquisite chest, 3 feet by 2 feet by 2 feet, constructed from rare materials worth at least 5,000 gp, and a Tiny replica made from the same materials worth at least 50 gp.'
FROM public.spells WHERE external_index = 'secret-chest'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Arca Secreta', 'Você esconde uma arca e todo o conteúdo dela no Plano Etéreo. É necessário que você toque a arca e a réplica em miniatura que serve como componente material para a magia. Ela pode armazenar até 340 litros [12 cubic feet] de matéria não viva (1 metro [3 ft.] por 60 centímetros [2 ft.] por 60 centímetros).
Enquanto a arca permanecer no Plano Etéreo, você pode usar uma ação e tocar a réplica para evocá-la. Ela aparece no chão, em um espaço desocupado a até 1,5 metro [5 ft.] de você. Tocando ambas, a arca e a réplica, e usando uma ação, você pode enviar a primeira de volta ao Plano Etéreo.
Após 60 dias, há uma chance cumulativa de 5% por dia de que o efeito da magia termine, o que também ocorre se a magia for conjurada novamente, se a réplica for destruída ou se você escolher encerrar a magia com uma ação. Se a arca estiver no Plano Etéreo ao término da magia, ela está perdida para sempre.', '', NULL
FROM public.spells WHERE external_index = 'secret-chest'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- See Invisibility
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('see-invisibility', 2, 'divination', 'action', 1, NULL, 'self', 1, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'See Invisibility', 'For the duration of the spell, you see invisible creatures and objects as if they were visible, and you can see through Ethereal. The ethereal objects and creatures appear ghostly translucent.', '', 'A dash of talc and a small amount of silver powder.'
FROM public.spells WHERE external_index = 'see-invisibility'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Ver o Invisível', 'Enquanto a magia durar, você vê criaturas e objetos invisíveis, como se eles fossem visíveis, além de poder ver no Plano Etéreo. Criaturas e objetos etéreos parecem fantasmagóricos e translúcidos.', '', NULL
FROM public.spells WHERE external_index = 'see-invisibility'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Seeming
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('seeming', 5, 'illusion', 'action', 1, 30, 'feet', 8, 'hour', false, false, ARRAY['V', 'S'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Seeming', 'This spell allows you to change the appearance of any number of creatures that you can see within range. You give each target you choose a new, illusory appearance. An unwilling target can make a charisma saving throw, and if it succeeds, it is unaffected by this spell.
The spell disguises physical appearance as well as clothing, armor, weapons, and equipment. You can make each creature seem 1 foot shorter or taller and appear thin, fat, or in between. You can''t change a target''s body type, so you must choose a form that has the same basic arrangement of limbs. Otherwise, the extent of the illusion is up to you. The spell lasts for the duration, unless you use your action to dismiss it sooner.
The changes wrought by this spell fail to hold up to physical inspection. For example, if you use this spell to add a hat to a creature''s outfit, objects pass through the hat, and anyone who touches it would feel nothing or would feel the creature''s head and hair. If you use this spell to appear thinner than you are, the hand of someone who reaches out to touch you would bump into you while it was seemingly still in midair.
A creature can use its action to inspect a target and make an Intelligence (Investigation) check against your spell save DC. If it succeeds, it becomes aware that the target is disguised.', '', NULL
FROM public.spells WHERE external_index = 'seeming'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Similaridade', 'Esta magia permite que você altere a aparência de qualquer número de criaturas à sua vista e no alcance da magia. Você dá a cada alvo uma nova aparência ilusória, à sua escolha. Um alvo involuntário pode fazer uma salvaguarda de Carisma e, se for bem-sucedido, não é afetado.A magia disfarça aparência física bem como roupas, armaduras, armas e equipamento. Você pode fazer cada criatura parecer 30 centímetros [1 foot] maior ou menor e aparentar ser gorda, magra ou algo entre. os dois. Não é possível alterar a estrutura do corpo do alvo, então é preciso escolher uma forma que tenha um arranjo de membros semelhante. No mais, a extensão da ilusão cabe a você. A magia permanece pela duração ou até você usar sua ação para dispensá-la.As alterações feitas por esta magia não se sustentam diante de uma inspeção física. Por exemplo, se você usar esta magia para adicionar um chapéu à indumentária da criatura, objetos atravessam-no, e quem o tocar não sentirá nada ou apenas a cabeça e os cabelos da criatura. Se você usar esta magia para parecer mais magro do que é, alguém que estenda a mão para tocá-lo pode esbarrar em você enquanto ela ainda estiver, aparentemente, tocando o ar.Uma criatura pode usar a própria ação para inspecionar um alvo e fazer um teste de Inteligência (Investigação) contra a CD para evitar sua magia. Se tiver êxito, ela torna-se ciente de que o alvo está disfarçado.', '', NULL
FROM public.spells WHERE external_index = 'seeming'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Sending
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('sending', 3, 'evocation', 'action', 1, NULL, 'unlimited', 1, 'round', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Sending', 'You send a short message of twenty-five words or less to a creature with which you are familiar. The creature hears the message in its mind, recognizes you as the sender if it knows you, and can answer in a like manner immediately. The spell enables creatures with Intelligence scores of at least 1 to understand the meaning of your message.
You can send the message across any distance and even to other planes of existence, but if the target is on a different plane than you, there is a 5 percent chance that the message doesn''t arrive.', '', 'A short piece of fine copper wire.'
FROM public.spells WHERE external_index = 'sending'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Remeter', 'Uma mensagem de vinte e cinco palavras ou menos é enviada para uma criatura conhecida. A criatura ouve a mensagem mentalmente, reconhece você como o remetente, caso lhe conheça, e pode responder da mesma maneira imediatamente. A magia permite criaturas com o valor de Inteligência mínimo de 1 entender o sentido da sua mensagem.A mensagem pode ser enviada a qualquer distância e até a outros planos de existência, mas se o alvo estiver em um plano diferente do seu, existe uma chance de 5 por cento de que ela não seja entregue.', '', NULL
FROM public.spells WHERE external_index = 'sending'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Sequester
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('sequester', 7, 'transmutation', 'action', 1, NULL, 'touch', NULL, 'special', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Sequester', 'By means of this spell, a willing creature or an object can be hidden away, safe from detection for the duration. When you cast the spell and touch the target, it becomes invisible and can''t be targeted by divination spells or perceived through scrying sensors created by divination spells.
If the target is a creature, it falls into a state of suspended animation. Time ceases to flow for it, and it doesn''t grow older.
You can set a condition for the spell to end early. The condition can be anything you choose, but it must occur or be visible within 1 mile of the target. Examples include "after 1,000 years" or "when the tarrasque awakens." This spell also ends if the target takes any damage.', '', 'A powder composed of diamond, emerald, ruby, and sapphire dust worth at least 5,000 gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'sequester'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Refugiar', 'Você esconde uma criatura voluntária ou um objeto, tornando-o livre de detecção enquanto a magia durar. Ao conjurar a magia e tocar o alvo, este torna-se invisível e não pode ser alvo de magias de adivinhação ou percebido através de sensores mágicos criados por feitiços de adivinhação.
Se o alvo for uma criatura, ela cai em um estado de animação suspensa. O tempo deixa de passar para ela, que passa a não sofrer os efeitos do envelhecimento.
Você pode definir uma condição para a magia terminar mais cedo. A condição pode ser qualquer coisa que você escolher, mas deve ocorrer ou ser visível no alcance de 1,5 quilômetros [1 mile] do alvo. Exemplos incluem "depois de 1.000 anos" ou "quando o tarrasque despertar". Esta magia também termina se o alvo sofrer qualquer dano.', '', NULL
FROM public.spells WHERE external_index = 'sequester'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Shapechange
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('shapechange', 9, 'transmutation', 'action', 1, NULL, 'self', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Shapechange', 'You assume the form of a different creature for the duration. The new form can be of any creature with a challenge rating equal to your level or lower. The creature can''t be a construct or an undead, and you must have seen the sort of creature at least once. You transform into an average example of that creature, one without any class levels or the Spellcasting trait.
Your game statistics are replaced by the statistics of the chosen creature, though you retain your alignment and Intelligence, Wisdom, and Charisma scores. You also retain all of your skill and saving throw proficiencies, in addition to gaining those of the creature. If the creature has the same proficiency as you and the bonus listed in its statistics is higher than yours, use the creature''s bonus in place of yours. You can''t use any legendary actions or lair actions of the new form.
You assume the hit points and Hit Dice of the new form. When you revert to your normal form, you return to the number of hit points you had before you transformed. If you revert as a result of dropping to 0 hit points, any excess damage carries over to your normal form. As long as the excess damage doesn''t reduce your normal form to 0 hit points, you aren''t knocked unconscious.
You retain the benefit of any features from your class, race, or other source and can use them, provided that your new form is physically capable of doing so. You can''t use any special senses you have (for example, darkvision) unless your new form also has that sense. You can only speak if the creature can normally speak.
When you transform, you choose whether your equipment falls to the ground, merges into the new form, or is worn by it. Worn equipment functions as normal. The GM determines whether it is practical for the new form to wear a piece of equipment, based on the creature''s shape and size. Your equipment doesn''t change shape or size to match the new form, and any equipment that the new form can''t wear must either fall to the ground or merge into your new form. Equipment that merges has no effect in that state.
During this spell''s duration, you can use your action to assume a different form following the same restrictions and rules for the original form, with one exception: if your new form has more hit points than your current one, your hit points remain at their current value.', '', 'A jade circlet worth at least 1,500 gp, which you must place on your head before you cast the spell.'
FROM public.spells WHERE external_index = 'shapechange'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Metamorfose', 'Você assume a forma de uma criatura diferente enquanto a magia durar. A nova forma pode ser de qualquer criatura com um nível de desafio igual ou menor que o seu nível. A criatura não pode ser um constructo ou um morto-vivo, e você deve ter visto este tipo de criatura pelo menos uma vez. Você se transforma em um exemplar aproximado daquela criatura, sem quaisquer níveis de classe e sem a característica Conjuração.
Suas estatísticas de jogo são substituídas pelas estatísticas da criatura escolhida, embora você mantenha seu alinhamento, personalidade e valores de Inteligência, Sabedoria e Carisma. Você também conserva todas as suas perícias e salvaguardas, além de ganhar as da criatura. Se a criatura tiver a mesma proficiência que você e o bônus listado no bloco de estatísticas dela for maior que o seu, use o bônus da criatura em vez do seu. Você não pode usar quaisquer ações lendárias ou de covil da nova forma.
Você assume os pontos de vida e os Dados de Vida da nova forma. Ao retornar à sua forma original, você volta a ter a quantidade de pontos de vida que tinha antes da transformação. Se reverter à sua forma original como resultado de uma queda para 0 pontos de vida, qualquer excesso de dano será transferido para sua forma original. Desde que o excesso de dano não reduza sua forma original a 0 pontos de vida, você não cairá inconsciente.
Você mantém o benefício de todas as características de sua classe, raça ou outra fonte e pode usá-las se a nova forma for fisicamente capaz de fazê-lo. Você não pode usar quaisquer sentidos especiais que tenha (visão no escuro, por exemplo) a menos que a nova forma também tenha esse sentido. Você só pode falar se a criatura puder falar normalmente.
Ao se transformar, você escolhe se seu equipamento cai no chão, funde-se com a nova forma ou se é usado por ela. Equipamento carregado funciona normalmente. O DM decide se é possível para a nova forma usar um item do equipamento, com base no formato e tamanho da criatura. Seu equipamento não muda de tamanho ou formato para coincidir com a nova forma, e qualquer equipamento que a nova forma não puder usar deve cair no chão ou se fundir a ela. Equipamento que se funde não tem efeito nesse estado.
Enquanto a magia durar, você pode usar sua ação para assumir uma forma diferente, seguindo as mesmas restrições e regras para a forma original, com uma exceção: se sua nova forma possuir mais pontos de vida que a sua forma atual, seus pontos de vida permanecem no valor atual.', '', NULL
FROM public.spells WHERE external_index = 'shapechange'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Shatter
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('shatter', 2, 'evocation', 'action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Shatter', 'A sudden loud ringing noise, painfully intense, erupts from a point of your choice within range. Each creature in a 10-foot-radius sphere centered on that point must make a Constitution saving throw. A creature takes 3d8 thunder damage on a failed save, or half as much damage on a successful one. A creature made of inorganic material such as stone, crystal, or metal has disadvantage on this saving throw.
A non-magical item that is not worn or carried also suffers damage if it is in the area of the spell.', 'When you cast this spell using a 3 or higher level spell slot, the damage of the spell increases by 1d8 for each level of higher spell slot 2.', 'A burst of mica.'
FROM public.spells WHERE external_index = 'shatter'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Despedaçar', 'Um ruído súbito e estridente, dolorosamente intenso, irrompe a partir de um ponto à sua escolha, no alcance da magia. Cada criatura em uma esfera de 3 metros de raio [10-foot-radius sphere] centrado naquele ponto deve fazer uma salvaguarda de Constituição. Se falhar, sofre 3d8 pontos de dano trovejante, ou metade do dano em caso de sucesso. Uma criatura feita de material inorgânico, como pedra, cristal ou metal tem desvantagem nesta salvaguarda.
Um objeto não-mágico que não esteja sendo usado ou carregado também sofre o dano se estiver na área da magia.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 3º círculo ou superior, o dano aumenta em 1d8 para cada círculo do espaço acima do 2º.', '', NULL
FROM public.spells WHERE external_index = 'shatter'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
