INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Shield', 'An invisible barrier of magical force appears and protects you. Until the start of your next turn, you have a +5 bonus to AC, including against the triggering attack, and you take no damage from magic missile.', '', NULL
FROM public.spells WHERE external_index = 'shield'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Égide', 'Uma barreira de força mágica invisível surge e protege você. Até o início de seu próximo turno, você terá +5 na CA, incluindo contra o ataque que disparou a reação, e você não sofre dano de Mísseis Mágicos.', '', NULL
FROM public.spells WHERE external_index = 'shield'
