INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Shield of Faith', 'A shimmering field appears and surrounds a creature of your choice within range, granting it a +2 bonus to AC for the duration.', '', 'A small parchment with a bit of holy text written on it.'
FROM public.spells WHERE external_index = 'shield-of-faith'
