INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Escudo da Fé', 'Um campo luminoso surge ao redor de uma criatura à sua escolha e no alcance da magia. A criatura ganha um bônus de +2 à CA enquanto esta magia durar.', '', NULL
FROM public.spells WHERE external_index = 'shield-of-faith'
