INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('shillelagh', 0, 'transmutation', 'bonus_action', 1, NULL, 'touch', 1, 'minute', false, false, ARRAY['V', 'S', 'M'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Shillelagh', 'The wood of a club or a quarterstaff you are holding is imbued with nature''s power. For the duration, you can use your spellcasting ability instead of Strength for the attack and damage rolls of melee attacks using that weapon, and the weapon''s damage die becomes a d8. The weapon also becomes magical, if it isn''t already. The spell ends if you cast it again or if you let go of the weapon.', '', 'Mistletoe, a shamrock leaf, and a club or quarterstaff.'
FROM public.spells WHERE external_index = 'shillelagh'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Bordão Místico', 'A madeira de uma clava ou cajado que você está segurando é imbuída com o poder da natureza. Enquanto a magia durar, seu atributo de conjuração pode ser usado no lugar da Força para as jogadas de ataque e dano corpo a corpo usando aquela arma, e o dado de dano passa a ser 1d8. A arma também se torna mágica, se já não o for. A magia termina se for conjurada novamente ou se você se desfizer da arma.', '', NULL
FROM public.spells WHERE external_index = 'shillelagh'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Shocking Grasp
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('shocking-grasp', 0, 'evocation', 'action', 1, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Shocking Grasp', 'Lightning springs from your hand to deliver a shock to a creature you try to touch. Make a melee spell attack against the target. You have advantage on the attack roll if the target is wearing armor made of metal. On a hit, the target takes 1d8 lightning damage, and it can''t take reactions until the start of its next turn.
The spell''s damage increases by 1d8 when you reach 5th level (2d8), 11th level (3d8), and 17th level (4d8).', '', NULL
FROM public.spells WHERE external_index = 'shocking-grasp'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Toque Chocante', 'Raios saltam de sua mão para transmitir um choque a uma criatura que você tentar tocar. Faça um ataque mágico corpo a corpo contra o alvo. Você tem vantagem na jogada de ataque se o alvo estiver vestindo uma armadura feita de metal. Se acertar, o alvo sofre 1d8 pontos de dano elétrico e não pode executar reações até o início do próximo turno dele.
O dano desta magia aumenta em 1d8 quando você alcança o 5º nível (2d8), 11º nível (3d8) e 17º nível (4d8).', '', NULL
FROM public.spells WHERE external_index = 'shocking-grasp'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Silence
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('silence', 2, 'illusion', 'action', 1, 120, 'feet', 10, 'minute', true, true, ARRAY['V', 'S'], ARRAY['bard', 'cleric', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Silence', 'For the duration, no sound can be created within or pass through a 20-foot-radius sphere centered on a point you choose within range. Any creature or object entirely inside the sphere is immune to thunder damage, and creatures are deafened while entirely inside it.
Casting a spell that includes a verbal component is impossible there.', '', NULL
FROM public.spells WHERE external_index = 'silence'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Silêncio', 'Enquanto a magia durar, nenhum som pode ser criado dentro ou passar através de uma esfera de 6 metros de raio, centrado em um ponto à sua escolha e no alcance da magia. Qualquer criatura ou objeto inteiramente dentro da esfera é imune a dano trovejante, e criaturas ficam surdas enquanto estiverem totalmente dentro dela. Conjurar uma magia que inclua um componente verbal é impossível dentro da área de efeito.', '', NULL
FROM public.spells WHERE external_index = 'silence'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Silent Image
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('silent-image', 1, 'illusion', 'action', 1, 60, 'feet', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Silent Image', 'You create the image of an object, a creature, or some other visible phenomenon that is no larger than a 15-foot cube. The image appears at a spot within range and lasts for the duration. The image is purely visual; it isn''t accompanied by sound, smell, or other sensory effects.
You can use your action to cause the image to move to any spot within range. As the image changes location, you can alter its appearance so that its movements appear natural for the image. For example, if you create an image of a creature and move it, you can alter the image so that it appears to be walking.
Physical interaction with the image reveals it to be an illusion, because things can pass through it. A creature that uses its action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image.', '', 'A bit of fleece.'
FROM public.spells WHERE external_index = 'silent-image'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Imagem Silenciosa', 'Você cria a imagem de um objeto, criatura ou algum fenômeno visual que não seja maior do que um cubo de 4,5 metros [15-foot cube]. A imagem surge em um lugar no alcance da magia e permanece enquanto esta durar. A imagem é puramente visual; ela não é acompanhada de som, cheiro ou outros efeitos sensoriais.Você pode usar sua ação para fazer a imagem se deslocar para qualquer lugar dentro do alcance da magia. À medida que a imagem muda de lugar, você pode alterar a aparência para que movimentos dela pareçam naturais. Por exemplo, se você criar a imagem de uma criatura e movê-la, é possível mudar a imagem para que ela pareça estar andando.Interação física com a imagem revela que ela é uma ilusão, pois coisas podem passar através dela. Uma criatura que use uma ação para examinar a imagem pode determinar que se trata de uma ilusão com um teste bem-sucedido de Inteligência (Investigação) contra a CD para evitar sua magia. Se uma criatura discernir a ilusão pelo que ela é, a criatura pode ver através da imagem.', '', NULL
FROM public.spells WHERE external_index = 'silent-image'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Simulacrum
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('simulacrum', 7, 'illusion', 'hour', 12, NULL, 'touch', NULL, 'special', false, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Simulacrum', 'You shape an illusory duplicate of one beast or humanoid that is within range for the entire casting time of the spell. The duplicate is a creature, partially real and formed from ice or snow, and it can take actions and otherwise be affected as a normal creature. It appears to be the same as the original, but it has half the creature''s hit point maximum and is formed without any equipment. Otherwise, the illusion uses all the statistics of the creature it duplicates.
The simulacrum is friendly to you and creatures you designate. It obeys your spoken commands, moving and acting in accordance with your wishes and acting on your turn in combat. The simulacrum lacks the ability to learn or become more powerful, so it never increases its level or other abilities, nor can it regain expended spell slots.
If the simulacrum is damaged, you can repair it in an alchemical laboratory, using rare herbs and minerals worth 100 gp per hit point it regains. The simulacrum lasts until it drops to 0 hit points, at which point it reverts to snow and melts instantly.
If you cast this spell again, any currently active duplicates you created with this spell are instantly destroyed.', '', 'Snow or ice in quantities sufficient to made a life-size copy of the duplicated creature; some hair, fingernail clippings, or other piece of that creature''s body placed inside the snow or ice; and powdered ruby worth 1,500 gp, sprinkled over the duplicate and consumed by the spell.'
FROM public.spells WHERE external_index = 'simulacrum'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Simulacro', 'Você cria uma duplicata ilusória de uma fera ou de um humanoide que esteja no alcance da magia todo o tempo da conjuração. A duplicata é uma criatura parcialmente real, formada de gelo ou neve, que pode fazer ações e também ser afetada como um ser normal. Ela parece ser idêntica à original, mas tem apenas metade dos pontos de vida máximos da criatura original e é formada sem nenhum equipamento. Além disso, a duplicata usa todas as estatísticas da criatura original, exceto pelo fato de que a duplicata é um constructo.
O simulacro é amigável a você e a quem você designar. Ele obedece seus comandos falados, movendo-se e atuando de acordo com seus desejos, agindo durante o seu turno no combate. O simulacro não tem a habilidade de aprender ou de se tornar mais poderoso, logo nunca eleva seu nível ou outras habilidades, nem pode recuperar espaços de magia perdidos.
Se for danificado, você pode repará-lo em um laboratório alquímico, usando ervas raras e minerais no valor de 100 PO por cada ponto de vida a ser restabelecido. Ele durará até cair a 0 pontos de vida, momento no qual voltará a ser neve e derreterá instantaneamente.
Se esta magia for conjurada novamente, qualquer duplicata atualmente ativa criada por você é imediatamente destruída.', '', NULL
FROM public.spells WHERE external_index = 'simulacrum'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Sleep
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('sleep', 1, 'enchantment', 'action', 1, 90, 'feet', 1, 'minute', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Sleep', 'This spell sends creatures into a magical slumber. Roll 5d8; the total is how many hit points of creatures this spell can affect. Creatures within 20 feet of a point you choose within range are affected in ascending order of their current hit points (ignoring unconscious creatures).
Starting with the creature that has the lowest current hit points, each creature affected by this spell falls unconscious until the spell ends, the sleeper takes damage, or someone uses an action to shake or slap the sleeper awake. Subtract each creature''s hit points from the total before moving on to the creature with the next lowest hit points. A creature''s hit points must be equal to or less than the remaining total for that creature to be affected.
Undead and creatures immune to being charmed aren''t affected by this spell.', 'When you cast this spell using a spell slot of 2nd level or higher, roll an additional 2d8 for each slot level above 1st.', 'A pinch of fine sand, rose petals, or a cricket.'
FROM public.spells WHERE external_index = 'sleep'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Sono', 'Esta magia coloca criaturas em um sono mágico. Jogue 5d8; o resultado equivale a quantos pontos de vida de criaturas esta magia pode afetar. As criaturas que estiverem dentro de um raio de 6 metros [20-foot radius] a partir de um ponto à sua escolha, são afetadas em ordem ascendente de pontos de vida atuais (ignorando criaturas inconscientes).
Começando com quem tiver menos pontos de vida no momento da conjuração, cada indivíduo afetado por esta magia cai Inconsciente até o final do efeito desta, ou até o adormecido sofrer dano ou alguém usar uma ação para chacoalhá-lo ou estapeá-lo para que acorde. Subtraia os pontos de vida de cada criatura do total, antes de continuar para a próxima com os pontos de vida mais baixos. Os pontos de vida da criatura devem ser iguais ou menores que o total remanescente para que aquela criatura seja afetada.
Mortos-vivos e criaturas imunes a serem enfeitiçadas não são afetadas por esta magia.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 2º círculo ou superior, jogue 2d8 adicionais a cada espaço acima do 1º círculo.', '', NULL
FROM public.spells WHERE external_index = 'sleep'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Sleet Storm
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('sleet-storm', 3, 'conjuration', 'action', 1, 150, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Sleet Storm', 'Until the spell ends, freezing rain and sleet fall in a 20-foot-tall cylinder with a 40-foot radius centered on a point you choose within range. The area is heavily obscured, and exposed flames in the area are doused.
The ground in the area is covered with slick ice, making it difficult terrain. When a creature enters the spell''s area for the first time on a turn or starts its turn there, it must make a dexterity saving throw. On a failed save, it falls prone.
If a creature is concentrating in the spell''s area, the creature must make a successful constitution saving throw against your spell save DC or lose concentration.', '', 'A pinch of dust and a few drops of water.'
FROM public.spells WHERE external_index = 'sleet-storm'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Nevasca', 'Enquanto a magia durar, uma chuva congelante e granizo caem sobre um cilindro de 6 metros de altura [20-foot tall] com um raio de 12 metros [40-foot radius], centralizado em um ponto à sua escolha e no alcance da magia. A área fica totalmente obscurecida e as chamas expostas (caso existam na área) são extintas.
O solo da área é coberto com gelo liso, tornando-o terreno difícil. Quando uma criatura entra na área da magia pela primeira vez ou inicia o próprio turno ali, ela deve fazer uma salvaguarda de Destreza. Se falhar, ela fica caída.
Se uma criatura começar o próprio turno na área da magia e estiver se concentrando em uma magia, a criatura deve ser bem-sucedida em uma salvaguarda de Constituição contra a sua CD para evitar magia ou perderá a concentração.', '', NULL
FROM public.spells WHERE external_index = 'sleet-storm'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Slow
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('slow', 3, 'transmutation', 'action', 1, 120, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Slow', 'You alter time around up to six creatures of your choice in a 40-foot cube within range. Each target must succeed on a wisdom saving throw or be affected by this spell for the duration.
An affected target''s speed is halved, it takes a -2 penalty to AC and dexterity saving throws, and it can''t use reactions. On its turn, it can use either an action or a bonus action, not both. Regardless of the creature''s abilities or magic items, it can''t make more than one melee or ranged attack during its turn.
If the creature attempts to cast a spell with a casting time of 1 action, roll a d20. On an 11 or higher, the spell doesn''t take effect until the creature''s next turn, and the creature must use its action on that turn to complete the spell. If it can''t, the spell is wasted.
A creature affected by this spell makes another wisdom saving throw at the end of its turn. On a successful save, the effect ends for it.', '', 'A drop of molasses.'
FROM public.spells WHERE external_index = 'slow'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Lentidão', 'Você altera o tempo ao redor para até seis criaturas à sua escolha em um cubo de 12 metros [40-foot cube] no alcance da magia. Cada alvo deve ser bem-sucedido em uma salvaguarda de Sabedoria ou sofre os efeitos enquanto a magia durar.
Um alvo afetado tem seu deslocamento reduzido à metade, tem uma penalidade de -2 em sua CA e salvaguardas de Destreza, e não pode usar reações. No turno dele, ele pode usar uma ação ou ação bônus, mas não ambas. A despeito dos atributos ou dos itens mágicos de uma criatura, ela não pode fazer mais do que um ataque corpo a corpo ou à distância durante o turno dela.
Se a criatura tentar conjurar uma magia com um tempo de conjuração de 1 ação, jogue 1d20. Em um resultado de 11 ou mais, a magia não tem efeito até o próximo turno da criatura, e ela deve usar sua ação naquele turno para completar a magia. Se não puder, a magia é desperdiçada.
Uma criatura afetada por esta magia faz uma nova salvaguarda de Sabedoria no final de cada um dos turnos dela. Em um sucesso,o efeito se encerra sobre ela.', '', NULL
FROM public.spells WHERE external_index = 'slow'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Spare the Dying
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('spare-the-dying', 0, 'necromancy', 'action', 1, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S'], ARRAY['cleric'], 'dnd_5e')
