INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Spare the Dying', 'You touch a living creature that has 0 hit points. The creature becomes stable. This spell has no effect on undead or constructs.', '', NULL
FROM public.spells WHERE external_index = 'spare-the-dying'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Acudir os Moribundos', 'Você toca uma criatura viva que tenha 0 pontos de vida. A criatura se torna estável. Essa magia não tem efeito sobre mortos-vivos ou constructos.', '', NULL
FROM public.spells WHERE external_index = 'spare-the-dying'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Speak with Animals
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('speak-with-animals', 1, 'divination', 'action', 1, NULL, 'self', 10, 'minute', false, true, ARRAY['V', 'S'], ARRAY['bard', 'druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Speak with Animals', 'You gain the ability to comprehend and verbally communicate with beasts for the duration. The knowledge and awareness of many beasts is limited by their intelligence, but at a minimum, beasts can give you information about nearby locations and monsters, including whatever they can perceive or have perceived within the past day. You might be able to persuade a beast to perform a small favor for you, at the GM''s discretion.', '', NULL
FROM public.spells WHERE external_index = 'speak-with-animals'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Falar com Animais', 'Você adquire a habilidade de compreender e se comunicar verbalmente com feras enquanto a magia durar. O conhecimento e a consciência são limitados pela inteligência delas mas, no mínimo, são capazes de dar informação sobre localidades e monstros próximos, incluindo tudo o que notam ou notaram nas últimas 24 horas. Você pode tentar persuadir uma fera a lhe fazer um pequeno favor, a critério do DM.', '', NULL
FROM public.spells WHERE external_index = 'speak-with-animals'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Speak with Dead
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('speak-with-dead', 3, 'necromancy', 'action', 1, 10, 'feet', 10, 'minute', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Speak with Dead', 'You grant the semblance of life and intelligence to a corpse of your choice within range, allowing it to answer the questions you pose. The corpse must still have a mouth and can''t be undead. The spell fails if the corpse was the target of this spell within the last 10 days.
Until the spell ends, you can ask the corpse up to five questions. The corpse knows only what it knew in life, including the languages it knew. Answers are usually brief, cryptic, or repetitive, and the corpse is under no compulsion to offer a truthful answer if you are hostile to it or it recognizes you as an enemy. This spell doesn''t return the creature''s soul to its body, only its animating spirit. Thus, the corpse can''t learn new information, doesn''t comprehend anything that has happened since it died, and can''t speculate about future events.', '', 'Burning incense.'
FROM public.spells WHERE external_index = 'speak-with-dead'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Falar com Mortos', 'Você concede um arremedo de vida e inteligência a um cadáver à sua escolha, no alcance da magia, permitindo-lhe responder às perguntas feitas a ele. O cadáver ainda deve ter uma boca e não pode ser um morto-vivo. A magia falha se ele já foi alvo desta magia nos últimos 10 dias.Enquanto a magia durar, você pode fazer até cinco perguntas. O cadáver sabe apenas o que sabia em vida, incluindo idiomas que conhecia. As respostas são normalmente curtas, enigmáticas ou repetitivas, e o cadáver não é compelido a dar uma resposta verdadeira se você for hostil ou se ele o reconhecer como um inimigo. Esta magia não devolve a alma ao corpo da criatura, apenas seu espírito animado. Assim, o cadáver não pode aprender novas informações, não compreende qualquer coisa que aconteceu desde que morreu, e não pode especular sobre eventos futuros.', '', NULL
FROM public.spells WHERE external_index = 'speak-with-dead'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Speak with Plants
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('speak-with-plants', 3, 'transmutation', 'action', 1, NULL, 'self', 10, 'minute', false, false, ARRAY['V', 'S'], ARRAY['bard', 'druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Speak with Plants', 'You imbue plants within 30 feet of you with limited sentience and animation, giving them the ability to communicate with you and follow your simple commands. You can question plants about events in the spell''s area within the past day, gaining information about creatures that have passed, weather, and other circumstances.
You can also turn difficult terrain caused by plant growth (such as thickets and undergrowth) into ordinary terrain that lasts for the duration. Or you can turn ordinary terrain where plants are present into difficult terrain that lasts for the duration, causing vines and branches to hinder pursuers, for example.
Plants might be able to perform other tasks on your behalf, at the GM''s discretion. The spell doesn''t enable plants to uproot themselves and move about, but they can freely move branches, tendrils, and stalks.
If a plant creature is in the area, you can communicate with it as if you shared a common language, but you gain no magical ability to influence it.
This spell can cause the plants created by the entangle spell to release a restrained creature.', '', NULL
FROM public.spells WHERE external_index = 'speak-with-plants'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Falar com Plantas', 'Você é capaz de imbuir plantas a até 9 metros [30 ft.] de distância com intelecto limitado e razão, dando-lhes a habilidade de se comunicar e seguir comandos simples. Podem ser feitas perguntas a elas sobre eventos até o dia anterior, na área da magia, sendo possível receber informações sobre as criaturas que passaram, o clima e outras circunstâncias.
Pode-se tornar terreno difícil criado por Crescimento de Plantas (como moitas e vegetação rasteira) em terreno comum enquanto a magia durar. Ou você pode tornar um terreno comum, onde há plantas presentes, em terreno difícil, enquanto a magia durar, fazendo com que vinhas e galhos atrapalhem perseguidores, por exemplo.
Plantas podem praticar outras tarefas para você, a critério do DM. A magia não possibilita que as plantas se soltem de suas raízes ou se desloquem, mas elas podem mover galhos, caules e gavinhas livremente.
Se uma criatura do tipo planta está na área, você pode se comunicar com ela, como se vocês compartilhassem um idioma comum, mas isso não dá nenhuma habilidade mágica de influenciá-la.
Esta magia faz com que plantas criadas pela magia Emaranhar soltem uma criatura contida.', '', NULL
FROM public.spells WHERE external_index = 'speak-with-plants'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Spider Climb
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('spider-climb', 2, 'transmutation', 'action', 1, NULL, 'touch', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Spider Climb', 'Until the spell ends, one willing creature you touch gains the ability to move up, down, and across vertical surfaces and upside down along ceilings, while leaving its hands free. The target also gains a climbing speed equal to its walking speed.', '', 'A drop of bitumen and a spider.'
FROM public.spells WHERE external_index = 'spider-climb'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Escalada de Aranha', 'Enquanto a magia durar, uma criatura voluntária tocada por você ganha a habilidade de se mover para cima, para baixo e ao longo de superfícies verticais e de cabeça para baixo através de tetos, mantendo suas mãos livres. O alvo também ganha um deslocamento de escalada idêntico ao próprio deslocamento de caminhada.', '', NULL
FROM public.spells WHERE external_index = 'spider-climb'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Spike Growth
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('spike-growth', 2, 'transmutation', 'action', 1, 150, 'feet', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Spike Growth', 'The ground in a 20-foot radius centered on a point within range twists and sprouts hard spikes and thorns. The area becomes difficult terrain for the duration. When a creature moves into or within the area, it takes 2d4 piercing damage for every 5 feet it travels.
The transformation of the ground is camouflaged to look natural. Any creature that can''t see the area at the time the spell is cast can make a Wisdom (Perception) check against your spell save DC to recognize the terrain as hazardous before entering it.', '', 'Seven sharp thorns or seven small twigs, each sharpened to a point.'
FROM public.spells WHERE external_index = 'spike-growth'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Crescer Espinhos', 'O chão, em um raio de 6 metros [20-foot radius] centrado em um ponto no alcance da magia, é revirado e dele brotam espigões e espinhos. A área se torna terreno difícil enquanto a magia durar. Quando uma criatura se mover para dentro ou para fora da área, ela sofre 2d4 pontos de dano perfurante para cada 1,5 metro [5 ft.] que se mover.
A transformação do solo é camuflada para parecer natural. Qualquer criatura que não possa ver a área no momento da conjuração da magia deve fazer um teste de Sabedoria (Percepção) contra a CD para evitar sua magia para perceber o terreno como perigoso antes de entrar nele.', '', NULL
FROM public.spells WHERE external_index = 'spike-growth'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Spirit Guardians
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('spirit-guardians', 3, 'conjuration', 'action', 1, NULL, 'self', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Spirit Guardians', 'You call forth spirits to protect you. They flit around you to a distance of 15 feet for the duration. If you are good or neutral, their spectral form appears angelic or fey (your choice). If you are evil, they appear fiendish.
When you cast this spell, you can designate any number of creatures you can see to be unaffected by it. An affected creature''s speed is halved in the area, and when the creature enters the area for the first time on a turn or starts its turn there, it must make a wisdom saving throw. On a failed save, the creature takes 3d8 radiant damage (if you are good or neutral) or 3d8 necrotic damage (if you are evil). On a successful save, the creature takes half as much damage.', 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d8 for each slot level above 3rd.', 'A holy symbol.'
FROM public.spells WHERE external_index = 'spirit-guardians'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Guardiões Espirituais', 'Você convoca espíritos para lhe proteger. Eles vagueiam ao seu redor a uma distância de até 4,5 metros [15 ft.] enquanto a magia durar. Se você for bom ou neutro, os espíritos assumem formas angelicais ou feéricas (à sua escolha). Se seu alinhamento for maligno, eles se assemelham a ínferos.
Ao conjurar esta magia, você pode designar qualquer número de criaturas à sua vista para não serem afetadas por ela. Uma criatura afetada por esta magia possui apenas metade do deslocamento na área. Ao entrar na área pela primeira vez ou iniciar o turno nela, a criatura deve fazer uma salvaguarda de Sabedoria. Se falhar, sofre 3d8 pontos de dano radiante (se você for bom ou neutro) ou 3d8 pontos de dano necrótico (se for mau). Em caso de sucesso, a criatura sofre metade do dano.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 4º círculo ou superior, o dano aumenta em 1d8 para cada círculo do espaço acima do 3º.', '', NULL
FROM public.spells WHERE external_index = 'spirit-guardians'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Spiritual Weapon
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('spiritual-weapon', 2, 'evocation', 'bonus_action', 1, 60, 'feet', 1, 'minute', false, false, ARRAY['V', 'S'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Spiritual Weapon', 'You create a floating, spectral weapon within range that lasts for the duration or until you cast this spell again. When you cast the spell, you can make a melee spell attack against a creature within 5 feet of the weapon. On a hit, the target takes force damage equal to 1d8 + your spellcasting ability modifier.
As a bonus action on your turn, you can move the weapon up to 20 feet and repeat the attack against a creature within 5 feet of it.
The weapon can take whatever form you choose. Clerics of deities who are associated with a particular weapon (as St. Cuthbert is known for his mace and Thor for his hammer) make this spell''s effect resemble that weapon.', 'When you cast this spell using a spell slot of 3rd level or higher, the damage increases by 1d8 for every two slot levels above the 2nd.', NULL
FROM public.spells WHERE external_index = 'spiritual-weapon'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Arma Espiritual', 'Você cria uma arma espectral flutuante, no alcance da magia. A arma permanece enquanto a magia durar, ou até você conjurar essa magia novamente. Ao conjurar a magia, você faz um ataque mágico corpo a corpo contra uma criatura a até 1,5  [5 ft.] da arma. Se acertar, o alvo sofre dano energético igual a 1d8 + seu modificador de atributo de conjuração.
Com uma ação bônus em seu turno, você pode mover a arma até 6 metros [20 ft.] e repetir o ataque contra uma criatura a até 1,5 metro [5 ft.] dela.
A arma pode tomar qualquer forma desejada. Clérigos de divindades associadas a uma arma específica (São Cuthbert é conhecido por sua maça e Thor por seu martelo) fazem o efeito desta magia se assemelhar a esta arma.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 3º círculo ou superior, o dano aumenta em 1d8 para cada dois espaços de magia acima do 2º círculo.', '', NULL
FROM public.spells WHERE external_index = 'spiritual-weapon'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Stinking Cloud
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('stinking-cloud', 3, 'conjuration', 'action', 1, 90, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Stinking Cloud', 'You create a 20-foot-radius sphere of yellow, nauseating gas centered on a point within range. The cloud spreads around corners, and its area is heavily obscured. The cloud lingers in the air for the duration.
Each creature that is completely within the cloud at the start of its turn must make a constitution saving throw against poison. On a failed save, the creature spends its action that turn retching and reeling. Creatures that don''t need to breathe or are immune to poison automatically succeed on this saving throw.
A moderate wind (at least 10 miles per hour) disperses the cloud after 4 rounds. A strong wind (at least 20 miles per hour) disperses it after 1 round.', '', 'A rotten egg or several skunk cabbage leaves.'
FROM public.spells WHERE external_index = 'stinking-cloud'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Nuvem Fétida', 'Você cria uma esfera com raio de 6 metros [20-foot-radius sphere], feita de um gás amarelo e nauseabundo, centrado em um ponto à sua escolha e no alcance da magia. A nuvem se alastra, contornando os cantos e a área afetada fica totalmente obscurecida. Ela persiste enquanto a magia durar.Cada criatura que estiver totalmente dentro da nuvem no início do próprio turno, deve fazer uma salvaguarda de Constituição contra veneno. Se falhar, a criatura gasta uma ação naquele turno vomitando e cambaleando. Criaturas que não precisam respirar ou são imunes a veneno têm sucesso automático nesta salvaguarda.Um vento moderado (de pelo menos 15 quilômetros [10 miles] por hora) dispersa a nuvem após 4 rodadas. Um vento forte (de pelo menos 30 quilômetros [20 miles] por hora) a dispersa após 1 rodada.', '', NULL
FROM public.spells WHERE external_index = 'stinking-cloud'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Stone Shape
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('stone-shape', 4, 'transmutation', 'action', 1, NULL, 'touch', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'druid', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Stone Shape', 'You touch a stone object of Medium size or smaller or a section of stone no more than 5 feet in any dimension and form it into any shape that suits your purpose. So, for example, you could shape a large rock into a weapon, idol, or coffer, or make a small passage through a wall, as long as the wall is less than 5 feet thick. You could also shape a stone door or its frame to seal the door shut. The object you create can have up to two hinges and a latch, but finer mechanical detail isn''t possible.', '', 'Soft clay, to be crudely worked into the desired shape for the stone object.'
FROM public.spells WHERE external_index = 'stone-shape'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Moldar Rochas', 'Você toca um objeto de pedra de tamanho Médio ou menor ou uma secção de rocha com não mais que 1,5 metro [5 ft.] em qualquer direção e a modela em qualquer formato que sirva à seus propósitos. Assim, por exemplo, você poderia modelar uma grande rocha em uma arma, ídolo ou baú, ou fazer uma pequena passagem por uma parede, desde que a parede tenha menos do que 1,5 metro [5 ft.] de espessura. Você também pode moldar uma porta de pedra ou remodelar seu entorno para selar a porta. O objeto que você cria pode ter até duas dobradiças e uma fechadura, porém detalhes mecânicos mais complexos não são possíveis.', '', NULL
FROM public.spells WHERE external_index = 'stone-shape'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Stoneskin
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('stoneskin', 4, 'abjuration', 'action', 1, NULL, 'touch', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'ranger', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Stoneskin', 'This spell turns the flesh of a willing creature you touch as hard as stone. Until the spell ends, the target has resistance to nonmagical bludgeoning, piercing, and slashing damage.', '', 'Diamond dust worth 100 gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'stoneskin'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Pele-rocha', 'Você toca uma criatura voluntária. A magia enrijece toda a pele do alvo, tornando-a tão dura quanto uma rocha. Enquanto a magia durar, o alvo tem resistência contra dano não-mágico contundente, cortante e perfurante.', '', NULL
FROM public.spells WHERE external_index = 'stoneskin'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Storm of Vengeance
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('storm-of-vengeance', 9, 'conjuration', 'action', 1, NULL, 'unlimited', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Storm of Vengeance', 'A churning storm cloud forms, centered on a point you can see and spreading to a radius of 360 feet. Lightning flashes in the area, thunder booms, and strong winds roar. Each creature under the cloud (no more than 5,000 feet beneath the cloud) when it appears must make a constitution saving throw. On a failed save, a creature takes 2d6 thunder damage and becomes deafened for 5 minutes.
Each round you maintain concentration on this spell, the storm produces additional effects on your turn.
***Round 2.*** Acidic rain falls from the cloud. Each creature and object under the cloud takes 1d6 acid damage.
***Round 3.*** You call six bolts of lightning from the cloud to strike six creatures or objects of your choice beneath the cloud. A given creature or object can''t be struck by more than one bolt. A struck creature must make a dexterity saving throw. The creature takes 10d6 lightning damage on a failed save, or half as much damage on a successful one.
***Round 4.*** Hailstones rain down from the cloud. Each creature under the cloud takes 2d6 bludgeoning damage.
***Round 5-10.*** Gusts and freezing rain assail the area under the cloud. The area becomes difficult terrain and is heavily obscured. Each creature there takes 1d6 cold damage. Ranged weapon attacks in the area are impossible. The wind and rain count as a severe distraction for the purposes of maintaining concentration on spells. Finally, gusts of strong wind (ranging from 20 to 50 miles per hour) automatically disperse fog, mists, and similar phenomena in the area, whether mundane or magical.', '', NULL
FROM public.spells WHERE external_index = 'storm-of-vengeance'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Tempestade da Vingança', 'Alcance: visão
Uma agitada nuvem tempestuosa se forma, centrada em um ponto à sua vista, e se alastra em um raio de 108 metros [360 ft.]. Relâmpagos brilham na área, trovões ressoam e ventos fortes rugem. Cada criatura sob a nuvem (a não mais de 1,5 quilômetros [5000 ft.] de altura abaixo da nuvem) deve fazer uma salvaguarda de Constituição, quando ela surge. Se falhar, a criatura sofre 2d6 pontos de dano trovejante e fica surda por 5 minutos.
A cada rodada que você mantiver a concentração nesta magia, a tempestade produz um efeito adicional no seu turno.
Rodada 2. Chuva ácida cai da nuvem. Cada criatura e objeto sob a nuvem sofre 1d6 pontos de dano ácido.
Rodada 3. Você invoca seis raios da nuvem para atingir seis criaturas ou objetos à sua escolha sob as nuvens. Uma criatura não pode ser atingida por mais de um raio. Uma criatura atingida deve fazer uma salvaguarda de Destreza. Se falhar, o alvo sofre 10d6 pontos de dano elétrico, ou metade do dano em caso de sucesso.
Rodada 4. Granizo cai da nuvens. Cada criatura sob a nuvem sofre 2d6 pontos de dano contundente.
Rodada 5–10. Ventos e chuva gélida assolam a área sob a nuvem. A área se torna terreno difícil e fica totalmente obscurecida. Cada criatura na área sofre 1d6 pontos de dano gélido. Ataques com armas de combate à distância na área são impossíveis. O vento e a chuva contam como distração severa para propósitos de manter a concentração em magias. Finalmente, rajadas de vento forte (entre 32 e 80 quilômetros [20 - 50 miles] por hora) dispersam automaticamente neblina, névoa e fenômenos similares na área, sejam mundanos ou mágicos.', '', NULL
FROM public.spells WHERE external_index = 'storm-of-vengeance'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Suggestion
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('suggestion', 2, 'enchantment', 'action', 1, 30, 'feet', 8, 'hour', true, false, ARRAY['V', 'M'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Suggestion', 'You suggest a course of activity (limited to a sentence or two) and magically influence a creature you can see within range that can hear and understand you. Creatures that can''t be charmed are immune to this effect. The suggestion must be worded in such a manner as to make the course of action sound reasonable. Asking the creature to stab itself, throw itself onto a spear, immolate itself, or do some other obviously harmful act ends the spell.
The target must make a wisdom saving throw. On a failed save, it pursues the course of action you described to the best of its ability. The suggested course of action can continue for the entire duration. If the suggested activity can be completed in a shorter time, the spell ends when the subject finishes what it was asked to do.
You can also specify conditions that will trigger a special activity during the duration. For example, you might suggest that a knight give her warhorse to the first beggar she meets. If the condition isn''t met before the spell expires, the activity isn''t performed.
If you or any of your companions damage the target, the spell ends.', '', 'A snake''s tongue and either a bit of honeycomb or a drop of sweet oil.'
FROM public.spells WHERE external_index = 'suggestion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Sugestão', 'Você sugere um curso de ação (limitado a uma sentença ou duas) e influencia magicamente uma criatura à sua vista no alcance da magia e que possa lhe ouvir e compreender. Criaturas que não podem ser enfeitiçadas são imunes a este efeito. A sugestão precisa ser dita de uma forma que faça o curso de ação parecer razoável. Pedir à criatura que se esfaqueie, jogue-se contra uma lança, imole-se ou faça algum outro ato evidentemente danoso, automaticamente cancela o efeito da magia.
O alvo deve fazer uma salvaguarda de Sabedoria. Se falhar, ele segue os atos sugeridos da melhor forma possível, segundo suas habilidades. A continuidade dos atos será feita enquanto a magia durar. Se a atividade sugerida pode ser completada em um período menor, a magia se encerra quando o sujeito termina aquilo que lhe foi sugerido.
Também podem ser especificadas condições que disparam uma atividade especial enquanto estiver dentro da duração da magia. Por exemplo, pode ser sugerido que uma cavaleira dê sua montaria ao primeiro mendigo que ela encontrar. Se a condição não for preenchida antes do fim dos efeitos, a atividade não é concluída.
Se você ou qualquer de seus companheiros causarem dano ao alvo, a magia se encerra.', '', NULL
FROM public.spells WHERE external_index = 'suggestion'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Sunbeam
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('sunbeam', 6, 'evocation', 'action', 1, NULL, 'self', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Sunbeam', 'A beam of brilliant light flashes out from your hand in a 5-foot-wide, 60-foot-long line. Each creature in the line must make a constitution saving throw. On a failed save, a creature takes 6d8 radiant damage and is blinded until your next turn. On a successful save, it takes half as much damage and isn''t blinded by this spell. Undead and oozes have disadvantage on this saving throw.
You can create a new line of radiance as your action on any turn until the spell ends.
For the duration, a mote of brilliant radiance shines in your hand. It sheds bright light in a 30-foot radius and dim light for an additional 30 feet. This light is sunlight.', '', 'A magnifying glass.'
FROM public.spells WHERE external_index = 'sunbeam'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Raio Solar', 'Um feixe de luz brilhante surge da sua mão em uma linha de 1,5 metro [5 ft.] de largura por 18 metros [60 ft.] de comprimento. Cada criatura na linha deve fazer uma salvaguarda de Constituição. Se falhar, sofre 6d8 pontos de dano radiante e está cega até o seu próximo turno, ou metade do dano e não ficará cega em caso de sucesso. Mortos-vivos e gosmas têm desvantagem nesta salvaguarda.
Você pode criar uma nova linha de radiância com uma ação em qualquer turno seu antes da magia terminar.
Enquanto a magia durar, uma fagulha de radiância luminosa brilha na sua mão. Ela emite luz plena em um raio de 9 metros [30 ft.] e meia-luz por mais 9 metros [30 ft.]. Esta luz é considerada luz solar.', '', NULL
FROM public.spells WHERE external_index = 'sunbeam'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Sunburst
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('sunburst', 8, 'evocation', 'action', 1, 150, 'feet', NULL, 'instantaneous', false, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Sunburst', 'Brilliant sunlight flashes in a 60-foot radius centered on a point you choose within range. Each creature in that light must make a constitution saving throw. On a failed save, a creature takes 12d6 radiant damage and is blinded for 1 minute. On a successful save, it takes half as much damage and isn''t blinded by this spell. Undead and oozes have disadvantage on this saving throw.
A creature blinded by this spell makes another constitution saving throw at the end of each of its turns. On a successful save, it is no longer blinded.
This spell dispels any darkness in its area that was created by a spell.', '', 'Fire and a piece of sunstone.'
FROM public.spells WHERE external_index = 'sunburst'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Explosão Solar', 'Luz solar brilhante lampeja em um raio de 18 metros [60 ft.], centrada em um ponto à sua escolha e no alcance da magia. Cada criatura dentro da área da luz deve fazer uma salvaguarda de Constituição. Se falhar, sofre 12d6 pontos de dano radiante e fica cega durante 1 minuto. Em caso de sucesso, ela sofre metade do dano e não fica cega por esta magia. Mortos-vivos e gosmas têm desvantagem nesta salvaguarda.
Uma criatura cega por esta magia deve fazer outra salvaguarda de Constituição ao final de cada um dos próprios turnos. Em caso de sucesso, ela não estará mais cega.
Esta magia desfaz qualquer escuridão na área de efeito, mesmo a que for criada por uma magia.', '', NULL
FROM public.spells WHERE external_index = 'sunburst'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Symbol
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('symbol', 7, 'abjuration', 'minute', 1, NULL, 'touch', NULL, 'special', false, false, ARRAY['V', 'S', 'M'], ARRAY['bard', 'cleric', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Symbol', 'When you cast this spell, you inscribe a harmful glyph either on a surface (such as a section of floor, a wall, or a table) or within an object that can be closed to conceal the glyph (such as a book, a scroll, or a treasure chest). If you choose a surface, the glyph can cover an area of the surface no larger than 10 feet in diameter. If you choose an object, that object must remain in its place; if the object is moved more than 10 feet from where you cast this spell, the glyph is broken, and the spell ends without being triggered.
The glyph is nearly invisible, requiring an Intelligence (Investigation) check against your spell save DC to find it.
You decide what triggers the glyph when you cast the spell. For glyphs inscribed on a surface, the most typical triggers include touching or stepping on the glyph, removing another object covering it, approaching within a certain distance of it, or manipulating the object that holds it. For glyphs inscribed within an object, the most common triggers are opening the object, approaching within a certain distance of it, or seeing or reading the glyph.
You can further refine the trigger so the spell is activated only under certain circumstances or according to a creature''s physical characteristics (such as height or weight), or physical kind (for example, the ward could be set to affect hags or shapechangers). You can also specify creatures that don''t trigger the glyph, such as those who say a certain password.
When you inscribe the glyph, choose one of the options below for its effect. Once triggered, the glyph glows, filling a 60-foot-radius sphere with dim light for 10 minutes, after which time the spell ends. Each creature in the sphere when the glyph activates is targeted by its effect, as is a creature that enters the sphere for the first time on a turn or ends its turn there.
***Death.*** Each target must make a constitution saving throw, taking 10d 10 necrotic damage on a failed save, or half as much damage on a successful save.
***Discord.*** Each target must make a constitution saving throw. On a failed save, a target bickers and argues with other creatures for 1 minute. During this time, it is incapable of meaningful communication and has disadvantage on attack rolls and ability checks.
***Fear.*** Each target must make a wisdom saving throw and becomes frightened for 1 minute on a failed save. While frightened, the target drops whatever it is holding and must move at least 30 feet away from the glyph on each of its turns, if able.
***Hopelessness.*** Each target must make a charisma saving throw. On a failed save, the target is overwhelmed with despair for 1 minute. During this time, it can''t attack or target any creature with harmful abilities, spells, or other magical effects.
***Insanity.*** Each target must make an intelligence saving throw. On a failed save, the target is driven insane for 1 minute. An insane creature can''t take actions, can''t understand what other creatures say, can''t read, and speaks only in gibberish. The GM controls its movement, which is erratic.
***Pain.*** Each target must make a constitution saving throw and becomes incapacitated with excruciating pain for 1 minute on a failed save.
***Sleep.*** Each target must make a wisdom saving throw and falls unconscious for 10 minutes on a failed save. A creature awakens if it takes damage or if someone uses an action to shake or slap it awake.
***Stunning.*** Each target must make a wisdom saving throw and becomes stunned for 1 minute on a failed save.', '', 'Mercury, phosphorus, and powdered diamond and opal with a total value of at least 1,000 gp, which the spell consumes.'
FROM public.spells WHERE external_index = 'symbol'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Símbolo', 'Ao conjurar esta magia, você traça um glifo prejudicial, inscrevendo-o em uma superfície (como uma secção de piso, uma parede ou uma mesa) ou dentro de um objeto que pode ser fechado para escondê-lo (como um livro, um pergaminho ou arca de tesouro). Se você escolher uma superfície, o símbolo pode cobrir uma área de superfície não maior do que 3 metros [10 ft.] de diâmetro. Se a opção for por um objeto, ele precisa permanecer no mesmo lugar; se for movido mais do que 3 metros de onde a magia foi conjurada, o símbolo é quebrado e a magia termina sem ser disparada.
O símbolo é quase invisível, exigindo um teste de Inteligência (Investigação) contra a CD para evitar sua magia para encontrá-lo.
Você decide o que ativa o glifo ao conjurar a magia. Para aqueles que forem inscritos em uma superfície, os gatilhos mais típicos incluem tocar ou pisar no glifo, remover um outro objeto que o cubra, aproximar-se a uma certa distância dele ou manipular um objeto que o contenha. Para os que forem inscritos dentro de algo, as condições podem ser a abertura do objeto, se aproximar a uma certa distância, ou ver ou ler o glifo.
Você pode refinar o gatilho para que a magia seja ativada apenas sob certas circunstâncias ou de acordo com as características físicas da criatura (como altura ou peso), ou tipo físico (por exemplo, a proteção poderia ser programada para afetar megeras ou metamorfos). Você também pode especificar criaturas que não ativarão o glifo, como aquelas que disserem uma palavra-chave específica.
Quando você inscreve o glifo, escolha uma das opções abaixo como efeito. Uma vez ativado, o glifo brilha, preenchendo uma esfera de 18 metros [60 ft.] com meia-luz durante 10 minutos, após isso, a magia termina. Ao ser ativado, cada criatura dentro da esfera será afetada pelo efeito escolhido para o glifo, assim como qualquer criatura que entre na esfera pela primeira vez ou termine o próprio turno ali.
Atordoamento. Cada alvo deve fazer uma salvaguarda de Sabedoria. Se falhar, torna-se atordoado durante 1 minuto.
Desesperança. Cada alvo deve fazer uma salvaguarda de Carisma. Se falhar, torna-se dominado pelo desespero por 1 minuto. Durante este período, o alvo não pode atacar criaturas utilizando habilidades que causem dano, magias ou outros efeitos mágicos.
Discórdia. Cada alvo deve fazer uma salvaguarda de Constituição. Se falhar, o alvo discute e contradiz outra criatura durante 1 minuto. Durante este período, o alvo é incapaz de comunicação coerente e tem desvantagem em jogadas de ataque e testes de atributo.
Dor. Cada alvo deve fazer uma salvaguarda de Constituição. Se falhar, torna-se incapacitado, durante 1 minuto, devido a dores excruciantes.
Insanidade. Cada alvo deve fazer uma salvaguarda de Inteligência. Se falhar, torna-se insano durante 1 minuto. Uma criatura insana não pode executar ações, ler ou entender o que os outros dizem e fala de modo incoerente. O DM controla o movimento dela, o qual é errático.
Medo. Cada alvo deve fazer uma salvaguarda de Sabedoria. Se falhar, torna-se amedrontado por 1 minuto. Uma criatura amedrontada solta tudo que estiver segurando e deve se mover para pelo menos 9 metros [30 ft.] de distância do glifo em cada um de seus turnos, se possível.
Morte. Cada alvo deve fazer uma salvaguarda de Constituição. Se falhar, sofre 10d10 pontos de dano necrótico, ou metade do dano em caso de sucesso.
Sono. Cada alvo deve fazer uma salvaguarda de Sabedoria. Se falhar, cairá inconsciente durante 10 minutos. A criatura acorda se sofrer dano ou se alguém usar uma ação para chacoalhá-la ou estapeá-la até a acordar.', '', NULL
FROM public.spells WHERE external_index = 'symbol'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Telekinesis
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('telekinesis', 5, 'transmutation', 'action', 1, 60, 'feet', 10, 'minute', true, false, ARRAY['V', 'S'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Telekinesis', 'You gain the ability to move or manipulate creatures or objects by thought. When you cast the spell, and as your action each round for the duration, you can exert your will on one creature or object that you can see within range, causing the appropriate effect below. You can affect the same target round after round, or choose a new one at any time. If you switch targets, the prior target is no longer affected by the spell.
***Creature.*** You can try to move a Huge or smaller creature. Make an ability check with your spellcasting ability contested by the creature''s Strength check. If you win the contest, you move the creature up to 30 feet in any direction, including upward but not beyond the range of this spell. Until the end of your next turn, the creature is restrained in your telekinetic grip. A creature lifted upward is suspended in mid-air.
On subsequent rounds, you can use your action to attempt to maintain your telekinetic grip on the creature by repeating the contest.
***Object.*** You can try to move an object that weighs up to 1,000 pounds. If the object isn''t being worn or carried, you automatically move it up to 30 feet in any direction, but not beyond the range of this spell.
If the object is worn or carried by a creature, you must make an ability check with your spellcasting ability contested by that creature''s Strength check. If you succeed, you pull the object away from that creature and can move it up to 30 feet in any direction but not beyond the range of this spell.
You can exert fine control on objects with your telekinetic grip, such as manipulating a simple tool, opening a door or a container, stowing or retrieving an item from an open container, or pouring the contents from a vial.', '', NULL
FROM public.spells WHERE external_index = 'telekinesis'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Telecinese', 'Você ganha a habilidade de mover ou manipular criaturas ou objetos através do pensamento. Ao conjurar a magia e com uma ação a cada rodada enquanto a magia durar, você pode exercer sua vontade em uma criatura ou objeto à sua vista no alcance desta, causando o efeito apropriado a seguir. Você pode afetar o mesmo alvo rodada após rodada ou escolher um novo a qualquer momento. Se mudar de alvo, o anterior deixa de ser afetado pela magia.
Criatura. Você pode tentar mover uma criatura de tamanho Enorme ou menor. Faça um teste de atributo usando sua atributo de conjuração resistido pelo teste de Força da criatura. Se vencer, você move a criatura a até 9 metros [30 ft.] em qualquer direção, inclusive para cima, mas não além do alcance da magia. Até o final do seu próximo turno, a criatura está contida pelo seu agarrão telecinético. Uma criatura erguida está suspensa no ar.
Em rodadas subsequentes, você pode usar sua ação para tentar manter seu agarrão telecinético na criatura repetindo o teste resistido.
Objeto. Você pode tentar mover um objeto que não pese mais do que 450 quilos [1000 pounds]. Se o objeto não estiver sendo usado ou carregado, você o move automaticamente a até 9 metros [30 ft.] em qualquer direção, limitado no alcance da magia.
Se o objeto estiver sendo usado ou carregado por uma criatura, você deve fazer um teste de atributo com seu atributo de conjuração resistido pelo teste de Força da criatura. Se for bem-sucedido, você puxa o objeto para longe da criatura e pode movê-lo a até 9 metros [30 ft.] em qualquer direção, limitado-se ao alcance da magia.
Você pode exercer controle fino em objetos com seu agarrão telecinético, como manipular uma ferramenta simples, abrir uma porta ou recipiente, armazenar ou recuperar um item de um recipiente, ou derramar o conteúdo de um frasco.', '', NULL
FROM public.spells WHERE external_index = 'telekinesis'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Telepathic Bond
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('telepathic-bond', 5, 'divination', 'action', 1, 30, 'feet', 1, 'hour', false, true, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Telepathic Bond', 'You forge a telepathic link among up to eight willing creatures of your choice within range, psychically linking each creature to all the others for the duration. Creatures with Intelligence scores of 2 or less aren''t affected by this spell.
Until the spell ends, the targets can communicate telepathically through the bond whether or not they have a common language. The communication is possible over any distance, though it can''t extend to other planes of existence.', '', 'Pieces of eggshell from two different kinds of creatures'
FROM public.spells WHERE external_index = 'telepathic-bond'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Ligação Telepática', 'Você forja uma ligação telepática com até oito criaturas voluntárias à sua escolha, no alcance da magia, ligando psiquicamente cada criatura com todos os demais, enquanto a magia durar. Criaturas com um valor de Inteligência de 2 ou menos não são afetadas por esta magia.
Enquanto a magia durar, os alvos podem se comunicar telepaticamente através da ligação, independentemente de terem ou não um idioma em comum. A comunicação é possível a qualquer distância, mas não pode se estender para outros planos de existência.', '', NULL
FROM public.spells WHERE external_index = 'telepathic-bond'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Teleport
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('teleport', 7, 'conjuration', 'action', 1, 10, 'feet', NULL, 'instantaneous', false, false, ARRAY['V'], ARRAY['bard', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Teleport', 'This spell instantly transports you and up to eight willing creatures of your choice that you can see within range, or a single object that you can see within range, to a destination you select. If you target an object, it must be able to fit entirely inside a 10-foot cube, and it can''t be held or carried by an unwilling creature.
The destination you choose must be known to you, and it must be on the same plane of existence as you. Your familiarity with the destination determines whether you arrive there successfully. The GM rolls d100 and consults the table.
| Familiarity | Mishap | Similar Area | Off Target | On Target |
|---|---|---|---|---|
| Permanent circle | -- | -- | -- | 01-100 |
| Associated object | -- | -- | -- | 01-100 |
| Very familiar | 01-05 | 06-13 | 14-24 | 25-100 |
| Seen casually | 01-33 | 34-43 | 44-53 | 54-100 |
| Viewed once | 01-43 | 44-53 | 54-73 | 74-100 |
| Description | 01-43 | 44-53 | 54-73 | 74-100 |
| False destination | 01-50 | 51-100 | -- | -- |
***Familiarity.*** "Permanent circle" means a permanent teleportation circle whose sigil sequence you know.
"Associated object" means that you possess an object taken from the desired destination within the last six months, such as a book from a wizard''s library, bed linen from a royal suite, or a chunk of marble from a lich''s secret tomb.
"Very familiar" is a place you have been very often, a place you have carefully studied, or a place you can see when you cast the spell.
"Seen casually" is someplace you have seen more than once but with which you aren''t very familiar.
"Viewed once" is a place you have seen once, possibly using magic.
"Description" is a place whose location and appearance you know through someone else''s description, perhaps from a map.
"False destination" is a place that doesn''t exist. Perhaps you tried to scry an enemy''s sanctum but instead viewed an illusion, or you are attempting to teleport to a familiar location that no longer exists.
***On Target.*** You and your group (or the target object) appear where you want to.
***Off Target.*** You and your group (or the target object) appear a random distance away from the destination in a random direction. Distance off target is 1d10 x 1d10 percent of the distance that was to be traveled. For example, if you tried to travel 120 miles, landed off target, and rolled a 5 and 3 on the two d10s, then you would be off target by 15 percent, or 18 miles. The GM determines the direction off target randomly by rolling a d8 and designating 1 as north, 2 as northeast, 3 as east, and so on around the points of the compass.  If you were teleporting to a coastal city and wound up 18 miles out at sea, you could be in trouble.
***Similar Area.*** You and your group (or the target object) wind up in a different area that''s visually or thematically similar to the target area. If you are heading for your home laboratory, for example, you might wind up in another wizard''s laboratory or in an alchemical supply shop that has many of the same tools and implements as your laboratory. Generally, you appear in the closest similar place, but since the spell has no range limit, you could conceivably wind up anywhere on the plane.
***Mishap.*** The spell''s unpredictable magic results in a difficult journey. Each teleporting creature (or the target object) takes 3d10 force damage, and the GM rerolls on the table to see where you wind up (multiple mishaps can occur, dealing damage each time).', '', NULL
FROM public.spells WHERE external_index = 'teleport'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Teleporte', 'Esta magia transporta instantaneamente você e até oito criaturas voluntárias à sua escolha e à sua vista, no alcance da magia, ou um único objeto sob as mesmas condições, até um destino que escolher. Se o alvo for um objeto, ele deve ser capaz de caber completamente em um cubo de 3 metros [10 ft.], e não pode estar sendo segurado ou carregado por uma criatura não voluntária.
O destino que você escolhe deve ser de seu conhecimento e deve estar no mesmo plano de existência. Sua familiaridade com o destino determina se você chega lá com sucesso. O DM joga um d100 e consulta a tabela.
Familiaridade
