VALUES ('true-strike', 0, 'divination', 'action', 1, 30, 'feet', 1, 'round', true, false, ARRAY['S'], ARRAY['bard', 'sorcerer', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'True Strike', 'You extend your hand and point a finger at a target in range. Your magic grants you a brief insight into the target''s defenses. On your next turn, you gain advantage on your first attack roll against the target, provided that this spell hasn''t ended.', '', NULL
FROM public.spells WHERE external_index = 'true-strike'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Golpe Certeiro', 'Você aponta o seu dedo para um alvo no alcance. Sua magia garante uma leve intuição das defesas do alvo. Em seu próximo turno, você ganha vantagem em sua primeira jogada de ataque contra o alvo, desde que a magia não tenha terminado.', '', NULL
FROM public.spells WHERE external_index = 'true-strike'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Unseen Servant
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('unseen-servant', 1, 'conjuration', 'action', 1, 60, 'feet', 1, 'hour', false, true, ARRAY['V', 'S', 'M'], ARRAY['bard', 'warlock', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Unseen Servant', 'This spell creates an invisible, mindless, shapeless force that performs simple tasks at your command until the spell ends. The servant springs into existence in an unoccupied space on the ground within range. It has AC 10, 1 hit point, and a Strength of 2, and it can''t attack. If it drops to 0 hit points, the spell ends.
Once on each of your turns as a bonus action, you can mentally command the servant to move up to 15 feet and interact with an object. The servant can perform simple tasks that a human servant could do, such as fetching things, cleaning, mending, folding clothes, lighting fires, serving food, and pouring wine. Once you give the command, the servant performs the task to the best of its ability until it completes the task, then waits for your next command.
If you command the servant to perform a task that would move it more than 60 feet away from you, the spell ends.', '', 'A piece of string and a bit of wood.'
FROM public.spells WHERE external_index = 'unseen-servant'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Servo Invisível', 'Esta magia cria uma força invisível, irracional e amorfa que cumpre tarefas simples dadas por você. O servo surge em um espaço desocupado sobre o solo no alcance da magia. Ele tem CA 10, 1 ponto de vida, Força 2 e não pode atacar. Se ele cair para 0 ponto de vida, a magia se encerra.
Uma vez em cada um dos seus turnos, com uma ação bônus, você pode comandar mentalmente o servo a se mover até 4,5 metros [15 ft.] e interagir com um objeto. O servo pode executar tarefas simples que um servo humano poderia fazer, como buscar coisas, limpar, remendar, dobrar roupas, acender fogo, servir comida e servir vinho. Uma vez dado o comando, o servo faz a tarefa da melhor forma, dentro de suas capacidades, até completá-la e, então, aguarda seu próximo comando.
Se for determinado que o servo faça algo que o moveria além de 18 metros [60 ft.] de distância de você, a magia se encerra.', '', NULL
FROM public.spells WHERE external_index = 'unseen-servant'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
