ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Vampiric Touch', 'The touch of your shadow-wreathed hand can siphon life force from others to heal your wounds. Make a melee spell attack against a creature within your reach. On a hit, the target takes 3d6 necrotic damage, and you regain hit points equal to half the amount of necrotic damage dealt. Until the spell ends, you can make the attack again on each of your turns as an action.', 'When you cast this spell using a spell slot of 4th level or higher, the damage increases by 1d6 for each slot level above 3rd.', NULL
FROM public.spells WHERE external_index = 'vampiric-touch'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Toque Vampírico', 'O toque de sua mão, envolta por sombra, pode retirar força vital de outros para curar as suas próprias feridas. Faça um ataque mágico corpo a corpo contra uma criatura no seu alcance. Se o ataque for bem-sucedido, o alvo sofre 3d6 pontos de dano necrótico e você recupera uma quantidade de pontos de vida igual à metade da quantidade de dano necrótico causado. Enquanto a magia durar, você pode fazer o ataque novamente em cada um de seus turnos, com uma ação.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 4º círculo ou superior, o dano 1 aumenta em 1d6 para cada círculo do espaço acima do 3º.', '', NULL
FROM public.spells WHERE external_index = 'vampiric-touch'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Vicious Mockery
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('vicious-mockery', 0, 'enchantment', 'action', 1, 60, 'feet', NULL, 'instantaneous', false, false, ARRAY['V'], ARRAY['bard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Vicious Mockery', 'You unleash a string of insults laced with subtle enchantments at a creature you can see within range. If the target can hear you (though it need not understand you), it must succeed on a wisdom saving throw or take 1d4 psychic damage and have disadvantage on the next attack roll it makes before the end of its next turn.
This spell''s damage increases by 1d4 when you reach 5th level (2d4), 11th level (3d4), and 17th level (4d4).', '', NULL
FROM public.spells WHERE external_index = 'vicious-mockery'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Zombaria Perversa', 'Você lança uma série de insultos carregados com sutis encantamentos contra uma criatura à sua vista e no alcance da magia. Se o alvo puder ouvir você (embora ele não precise lhe entender), ele deve ser bem-sucedido em uma salvaguarda de Sabedoria. Se falhar, sofre 1d4 pontos de dano psíquico e terá desvantagem na próxima jogada de ataque que ele fizer antes do fim do próximo turno dele.
O dano desta magia aumenta em 1d4 quando você alcança o 5º nível (2d4), o 11º nível (3d4) e o 17º nível (4d4).', '', NULL
FROM public.spells WHERE external_index = 'vicious-mockery'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Wall of Fire
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('wall-of-fire', 4, 'evocation', 'action', 1, 120, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Wall of Fire', 'You create a wall of fire on a solid surface within range. You can make the wall up to 60 feet long, 20 feet high, and 1 foot thick, or a ringed wall up to 20 feet in diameter, 20 feet high, and 1 foot thick. The wall is opaque and lasts for the duration.
When the wall appears, each creature within its area must make a Dexterity saving throw. On a failed save, a creature takes 5d8 fire damage, or half as much damage on a successful save.
One side of the wall, selected by you when you cast this spell, deals 5d8 fire damage to each creature that ends its turn within 10 feet o f that side or inside the wall. A creature takes the same damage when it enters the wall for the first time on a turn or ends its turn there. The other side of the wall deals no damage.
The other side of the wall deals no damage.', 'When you cast this spell using a spell slot of 5th level or higher, the damage increases by 1d8 for each slot level above 4th.', 'A small piece of phosphorus.'
FROM public.spells WHERE external_index = 'wall-of-fire'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Muralha de Fogo', 'Você cria uma muralha de fogo sobre uma superfície sólida no alcance da magia. Você pode constituir uma muralha de até 18 metros [60 ft.] de comprimento, 6 metros [20 ft.] de altura e 30 centímetros [1 ft.] de espessura, ou uma parede circular de até 6 metros de diâmetro, 6 metros de altura e 30 centímetros de espessura. Ela é opaca e permanece enquanto a magia durar.
Quando a muralha surge, cada criatura dentro da área deve fazer uma salvaguarda de Destreza. Se falhar, sofre 5d8 pontos de dano ígneo, ou metade do dano em caso de sucesso.
Uma face da muralha, à sua escolha durante a conjuração, causa 5d8 pontos de dano ígneo a cada criatura que termine o próprio turno a menos de 3 metros [10 ft.] daquela face da muralha. Ela sofre o mesmo dano ao entrar na muralha pela primeira vez, ou quando termina o próprio turno lá dentro. A outra face da muralha não causa dano.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 5º círculo ou superior, o dano aumenta em 1d8 para cada círculo do espaço acima do 4º.', '', NULL
FROM public.spells WHERE external_index = 'wall-of-fire'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Wall of Force
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('wall-of-force', 5, 'evocation', 'action', 1, 120, 'feet', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Wall of Force', 'An invisible wall of force springs into existence at a point you choose within range. The wall appears in any orientation you choose, as a horizontal or vertical barrier or at an angle. It can be free floating or resting on a solid surface. You can form it into a hemispherical dome or a sphere with a radius of up to 10 feet, or you can shape a flat surface made up of ten 10-foot-by-10-foot panels. Each panel must be contiguous with another panel. In any form, the wall is 1/4 inch thick. It lasts for the duration. If the wall cuts through a creature''s space when it appears, the creature is pushed to one side of the wall (your choice which side).
Nothing can physically pass through the wall. It is immune to all damage and can''t be dispelled by dispel magic. A disintegrate spell destroys the wall instantly, however. The wall also extends into the Ethereal Plane, blocking ethereal travel through the wall.', '', 'A pinch of powder made by crushing a clear gemstone.'
FROM public.spells WHERE external_index = 'wall-of-force'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Muralha de Energia', 'Uma muralha de força invisível surge em um ponto escolhido e no alcance da magia. Ela aparece em qualquer orientação à sua escolha, como uma barreira vertical ou horizontal, ou em qualquer inclinação. Ela pode flutuar livremente ou repousar sobre uma superfície sólida. Você pode moldá-la no formato de domo hemisférico ou de esfera com até 3 metros de raio [10-foot-radius sphere], ou formar uma superfície plana composta por dez painéis de 3 metros [10 ft.] de lado. Cada painel precisa ser contíguo ao outro. Seja qual for o formato assumido, a muralha possui 6 milímetros [1/4 inch] de espessura. Ela fica ativa enquanto a magia durar. Ao surgir, se a muralha passar por um espaço ocupado por uma criatura, esta última é empurrada para um dos lados da muralha (à sua escolha).
Nada pode passar fisicamente pela muralha. Ela é imune a todo tipo de dano e não pode ser anulada por Dissipar Magia. Entretanto, a magia Desintegrar a destrói instantaneamente. A muralha também se estende para o Plano Etéreo, bloqueando viagens etéreas através dela.', '', NULL
FROM public.spells WHERE external_index = 'wall-of-force'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Wall of Ice
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('wall-of-ice', 6, 'evocation', 'action', 1, 120, 'feet', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Wall of Ice', 'You create a wall of ice on a solid surface within range. You can form it into a hemispherical dome or a sphere with a radius of up to 10 feet, or you can shape a flat surface made up of ten 10-foot-square panels. Each panel must be contiguous with another panel. In any form, the wall is 1 foot thick and lasts for the duration.
If the wall cuts through a creature''s space when it appears, the creature within its area is pushed to one side of the wall and must make a dexterity saving throw. On a failed save, the creature takes 10d6 cold damage, or half as much damage on a successful save.
The wall is an object that can be damaged and thus breached. It has AC 12 and 30 hit points per 10-foot section, and it is vulnerable to fire damage. Reducing a 10-foot section of wall to 0 hit points destroys it and leaves behind a sheet of frigid air in the space the wall occupied. A creature moving through the sheet of frigid air for the first time on a turn must make a constitution saving throw. That creature takes 5d6 cold damage on a failed save, or half as much damage on a successful one.', 'When you cast this spell using a spell slot of 7th level or higher, the damage the wall deals when it appears increases by 2d6, and the damage from passing through the sheet of frigid air increases by 1d6, for each slot level above 6th.', 'A small piece of quartz.'
FROM public.spells WHERE external_index = 'wall-of-ice'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Muralha de Gelo', 'Você cria uma muralha de gelo sobre uma superfície sólida no alcance da magia. Você pode moldá-la no formato de um domo hemisférico ou de esfera com até 3 metros [10 ft.] de raio, ou formar uma superfície plana composta por dez painéis de 3 metros [10 ft.] de lado. Cada painel precisa ser contíguo ao outro. Seja qual for o formato assumido, a muralha possui 30 centímetros [1 foot] de espessura e permanece enquanto a magia durar.
Ao surgir, se muralha passar por um espaço ocupado por uma criatura, esta última é empurrada para um dos lados da muralha e precisa fazer uma salvaguarda de Destreza. Se falhar, sofre 10d6 pontos de dano gélido, ou metade em caso de sucesso.
A muralha é um objeto de gelo que pode ser danificado e, portanto, rompido. Sua CA é 12, tem 30 pontos de vida para cada painel de 3 metros [10 ft.] e é vulnerável a dano ígneo. Reduzir uma seção da muralha para 0 pontos de vida a destrói, deixando no lugar uma fina camada de ar gélido. Uma criatura passando pela camada de ar gélido pela primeira vez no próprio turno deve fazer uma salvaguarda de Constituição. Se falhar, sofre 5d6 pontos de dano gélido, ou metade em caso de sucesso.
Em Círculos Superiores. Ao conjurar esta magia usando espaço de magia de 7º círculo ou superior, o dano que a muralha causa quando aparece aumenta em 2d6, e o dano ao se passar pela camada de ar gélido aumenta em 1d6 para cada círculo do espaço acima do 6º.', '', NULL
FROM public.spells WHERE external_index = 'wall-of-ice'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Wall of Stone
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('wall-of-stone', 5, 'evocation', 'action', 1, 120, 'feet', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Wall of Stone', 'A nonmagical wall of solid stone springs into existence at a point you choose within range. The wall is 6 inches thick and is composed of ten 10-foot-by-10-foot panels. Each panel must be contiguous with at least one other panel. Alternatively, you can create 10-foot-by-20-foot panels that are only 3 inches thick.
If the wall cuts through a creature''s space when it appears, the creature is pushed to one side of the wall (your choice). If a creature would be surrounded on all sides by the wall (or the wall and another solid surface), that creature can make a dexterity saving throw. On a success, it can use its reaction to move up to its speed so that it is no longer enclosed by the wall.
The wall can have any shape you desire, though it can''t occupy the same space as a creature or object. The wall doesn''t need to be vertical or rest on any firm foundation. It must, however, merge with and be solidly supported by existing stone. Thus, you can use this spell to bridge a chasm or create a ramp.
If you create a span greater than 20 feet in length, you must halve the size of each panel to create supports. You can crudely shape the wall to create crenellations, battlements, and so on.
The wall is an object made of stone that can be damaged and thus breached. Each panel has AC 15 and 30 hit points per inch of thickness. Reducing a panel to 0 hit points destroys it and might cause connected panels to collapse at the GM''s discretion.
If you maintain your concentration on this spell for its whole duration, the wall becomes permanent and can''t be dispelled. Otherwise, the wall disappears when the spell ends.', '', 'A small block of granite.'
FROM public.spells WHERE external_index = 'wall-of-stone'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Muralha de Pedra', 'Uma muralha não-mágica, feita de pedra maciça, surge em um ponto à sua vista e no alcance da magia. Ela tem 15 centímetros [6 inches] de espessura e é composta de 10 painéis de 3 metros [10 ft.] de lado. Cada painel deve ser contíguo ao outro. Se preferir, você pode criar painéis de 3 por 6 metros [10-foot-by-20-foot] que têm apenas 7,5 centímetros [3 inches] de espessura.
Ao surgir, se muralha passar por um espaço ocupado por uma criatura, esta última é empurrada para um dos lados da muralha (à sua escolha). Se a criatura estiver prestes a ficar cercada pela muralha (ou entre a muralha e outra superfície sólida), ela pode fazer uma salvaguarda de Destreza. Se for bem-sucedida, ela usa uma reação para se mover até o máximo de seu deslocamento, de modo a não ser enclausurada pela muralha.
A muralha pode ter qualquer forma que você desejar, apesar de não poder ocupar o mesmo espaço que uma criatura ou objeto. Ela não precisa ser vertical ou se apoiar inteiramente em uma fundação sólida. Entretanto, necessita se mesclar e ser solidamente suportada por rochas já existentes. Assim, é possível usar esta magia para criar uma ponte sobre um abismo ou criar uma rampa.
Se for criado algo de amplitude superior a 6 metros [20 ft.] de comprimento, é necessário dividir pela metade o tamanho de cada painel, para criar suportes. É possível fazer com que a muralha tenha, de forma bruta, ameias, parapeitos etc.
A muralha é um objeto de pedra que pode ser danificado e, portanto, rompido. Cada painel tem CA 15 e 30 pontos de vida para cada 2,5 centímetros [1 inch] de espessura. Reduzir um painel a 0 pontos de vida o destrói e pode fazer com que painéis conectados entrem em colapso, a critério do DM.
Se você mantiver sua concentração por toda duração da magia, a muralha se torna permanente e não pode ser dissipada. De outra forma, ela desaparece ao final da magia.', '', NULL
FROM public.spells WHERE external_index = 'wall-of-stone'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Wall of Thorns
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('wall-of-thorns', 6, 'conjuration', 'action', 1, 120, 'feet', 10, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Wall of Thorns', 'You create a wall of tough, pliable, tangled brush bristling with needle-sharp thorns. The wall appears within range on a solid surface and lasts for the duration. You choose to make the wall up to 60 feet long, 10 feet high, and 5 feet thick or a circle that has a 20-foot diameter and is up to 20 feet high and 5 feet thick. The wall blocks line of sight.
When the wall appears, each creature within its area must make a dexterity saving throw. On a failed save, a creature takes 7d8 piercing damage, or half as much damage on a successful save.
A creature can move through the wall, albeit slowly and painfully. For every 1 foot a creature moves through the wall, it must spend 4 feet of movement. Furthermore, the first time a creature enters the wall on a turn or ends its turn there, the creature must make a dexterity saving throw. It takes 7d8 slashing damage on a failed save, or half as much damage on a successful one.', 'When you cast this spell using a spell slot of 7th level or higher, both types of damage increase by 1d8 for each slot level above 6th.', 'A handful of thorns.'
FROM public.spells WHERE external_index = 'wall-of-thorns'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Muralha de Espinhos', 'Você cria uma muralha com o emaranhado de arbustos resistentes, flexíveis e repletos de espinhos que parecem agulhas. Ela aparece em uma superfície sólida, à sua vista, no alcance da magia e permanece enquanto esta durar. É possível escolher entre uma muralha de até 18 metros [60 ft.] de comprimento, 3 metros [10 ft.] de altura e 1,5 metros [5 ft.] de espessura ou uma esfera que tenha até 6 metros [20 ft.] de diâmetro, 6 metros [20 ft.] de altura e 1,5 metro [5 ft.] de espessura. A muralha bloqueia a linha de visão.
Quando a muralha surge, cada criatura dentro da área deve fazer uma salvaguarda de Destreza. Se falhar, sofre 7d8 pontos de dano perfurante, ou metade do dano em caso de sucesso.
Uma criatura pode atravessá-la, embora de forma lenta e dolorosa. Para cada 30 centímetros [1 foot] percorridos através dela, é necessário gastar 1,2 metro [4 ft.] de deslocamento. Se uma criatura entra na muralha pela primeira vez ou termina o próprio turno lá dentro, deve fazer uma salvaguarda de Destreza. Se falhar, sofre 7d8 pontos de dano cortante, ou metade do dano em caso de sucesso.
Em Círculos Superiores. Ao conjurar esta magia usando um espaço de magia de 7º círculo ou superior, ambos os danos aumentam em 1d8 para cada círculo do espaço acima do 6º.', '', NULL
FROM public.spells WHERE external_index = 'wall-of-thorns'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Warding Bond
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('warding-bond', 2, 'abjuration', 'action', 1, NULL, 'touch', 1, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Warding Bond', 'This spell wards a willing creature you touch and creates a mystic connection between you and the target until the spell ends. While the target is within 60 feet of you, it gains a +1 bonus to AC and saving throws, and it has resistance to all damage. Also, each time it takes damage, you take the same amount of damage.
The spell ends if you drop to 0 hit points or if you and the target become separated by more than 60 feet.
It also ends if the spell is cast again on either of the connected creatures. You can also dismiss the spell as an action.', '', 'A pair of platinum rings worth at least 50gp each, which you and the target must wear for the duration.'
FROM public.spells WHERE external_index = 'warding-bond'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Vínculo de Proteção', 'Esta magia protege uma criatura voluntária que você toca, criando uma conexão mística entre o alvo e você enquanto a magia durar. Enquanto o alvo estiver no alcance de 18 metros [60 ft.] do conjurador, ele ganha +1 de bônus na CA e em salvaguardas, e tem resistência contra todo tipo de dano. Além disso, cada vez que ele sofre dano, você sofre a mesma quantidade de dano.
A magia se encerra se você cair a 0 pontos de vida ou se vocês se afastarem a mais de 18 metros [60 ft.] um do outro. Ela também se encerra se for conjurada novamente em qualquer uma das criaturas conectadas. Você também pode dispensar a magia com uma ação.', '', NULL
FROM public.spells WHERE external_index = 'warding-bond'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Water Breathing
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('water-breathing', 3, 'transmutation', 'action', 1, 30, 'feet', 24, 'hour', false, true, ARRAY['V', 'S', 'M'], ARRAY['druid', 'ranger', 'sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Water Breathing', 'This spell gives a maximum of ten willing creatures within range and you can see, the ability to breathe underwater until the end of its term. Affected creatures also retain their normal breathing pattern.', '', 'A short piece of reed or straw.'
FROM public.spells WHERE external_index = 'water-breathing'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Respirar na Água', 'Até dez criaturas voluntárias à sua vista e no alcance da magia, ganham a habilidade de respirar embaixo d''água enquanto a magia durar. As criaturas afetadas pela magia ainda conservam sua forma natural de respiração.', '', NULL
FROM public.spells WHERE external_index = 'water-breathing'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Water Walk
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('water-walk', 3, 'transmutation', 'action', 1, 30, 'feet', 1, 'hour', false, true, ARRAY['V', 'S', 'M'], ARRAY['cleric', 'druid', 'ranger', 'sorcerer'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Water Walk', 'This spell grants the ability to move across any liquid surface--such as water, acid, mud, snow, quicksand, or lava--as if it were harmless solid ground (creatures crossing molten lava can still take damage from the heat). Up to ten willing creatures you can see within range gain this ability for the duration.
If you target a creature submerged in a liquid, the spell carries the target to the surface of the liquid at a rate of 60 feet per round.', '', 'A piece of cork.'
FROM public.spells WHERE external_index = 'water-walk'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Caminhar Sobre as Águas', 'Esta magia concede a capacidade de deslocamento sobre qualquer superfície líquida - como água, ácido, lama, neve, areia movediça ou lava - como se fosse terra firme e inofensiva (criaturas cruzando lava derretida ainda podem sofrer dano devido ao calor). Enquanto esta magia durar, até dez criaturas voluntárias, à sua vista e no alcance da magia, ganham esta habilidade.Se você escolher uma criatura submersa como alvo, a magia carrega o alvo até a superfície do líquido a uma taxa de 18 metros [60 ft.] por rodada.', '', NULL
FROM public.spells WHERE external_index = 'water-walk'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Web
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('web', 2, 'conjuration', 'action', 1, 60, 'feet', 1, 'hour', true, false, ARRAY['V', 'S', 'M'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Web', 'You conjure a mass of thick, sticky webbing at a point of your choice within range. The webs fill a 20-foot cube from that point for the duration. The webs are difficult terrain and lightly obscure their area.
If the webs aren''t anchored between two solid masses (such as walls or trees) or layered across a floor, wall, or ceiling, the conjured web collapses on itself, and the spell ends at the start of your next turn. Webs layered over a flat surface have a depth of 5 feet.
Each creature that starts its turn in the webs or that enters them during its turn must make a dexterity saving throw. On a failed save, the creature is restrained as long as it remains in the webs or until it breaks free.
A creature restrained by the webs can use its action to make a Strength check against your spell save DC. If it succeeds, it is no longer restrained.
The webs are flammable. Any 5-foot cube of webs exposed to fire burns away in 1 round, dealing 2d4 fire damage to any creature that starts its turn in the fire.', '', 'A bit of spiderweb.'
FROM public.spells WHERE external_index = 'web'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Teia', 'Você conjura uma massa de teia espessa e pegajosa em um ponto à sua escolha e no alcance da magia. A teia preenche um cubo de 6 metros [20 ft.] a partir daquele ponto enquanto a magia durar. A teia é considerada terreno difícil e torna a área parcialmente obscurecida.
        Se a teia não estiver sendo sustentada por duas massas sólidas (como paredes ou árvores) ou estiver em camadas, cobrindo o chão, parede ou teto, ela colapsa sobre si mesma, e a magia se encerra no início do seu próximo turno. A cobertura de teias sobre uma superfície possui uma profundidade de 1,5 metro [5 ft.].
        Cada criatura que entrar ou iniciar o próprio turno na teia deve fazer uma salvaguarda de Destreza. Se falhar, a criatura está contida enquanto estiver na teia ou até que consiga se soltar.
        Uma criatura contida pela teia pode usar a própria ação para fazer uma salvaguarda de Força contra a CD para evitar sua magia. Se for bem-sucedida, ela não estará mais contida.
        As teias são inflamáveis. Qualquer cubo de teia de 1,5 metro [5 ft.] que for exposto ao fogo, queima em 1 rodada e causa 2d4 pontos de dano ígneo a qualquer criatura que comece o próprio turno no fogo.', '', NULL
FROM public.spells WHERE external_index = 'web'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Weird
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('weird', 9, 'illusion', 'action', 1, 120, 'feet', 1, 'minute', true, false, ARRAY['V', 'S'], ARRAY['wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Weird', 'Drawing on the deepest fears of a group of creatures, you create illusory creatures in their minds, visible only to them. Each creature in a 30-foot-radius sphere centered on a point of your choice within range must make a wisdom saving throw. On a failed save, a creature becomes frightened for the duration. The illusion calls on the creature''s deepest fears, manifesting its worst nightmares as an implacable threat. At the start of each of the frightened creature''s turns, it must succeed on a wisdom saving throw or take 4d10 psychic damage. On a successful save, the spell ends for that creature.', '', NULL
FROM public.spells WHERE external_index = 'weird'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Encarnação Fantasmagórica', 'Absorvendo os medos mais profundos de um grupo de criaturas, você cria aparições ilusórias nas mentes delas, visíveis apenas para elas. Cada criatura em uma esfera de 9 metros de raio [30-foot-radius sphere] centrada em um ponto à sua escolha e no alcance da magia, deve fazer uma salvaguarda de Sabedoria. Se falhar, a criatura fica amedrontada enquanto a magia durar. A ilusão faz menção aos mais profundos medos da criatura, manifestando os piores pesadelos em forma de uma ameaça implacável. Ao final do turno de cada criatura amedrontada, ela deve fazer uma salvaguarda de Sabedoria. Se falhar, sofre 4d10 pontos de dano psíquico; se for bem­-sucedida, a magia se encerra para a criatura.', '', NULL
FROM public.spells WHERE external_index = 'weird'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Wind Walk
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('wind-walk', 6, 'transmutation', 'minute', 1, 30, 'feet', 8, 'hour', false, false, ARRAY['V', 'S', 'M'], ARRAY['druid'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Wind Walk', 'You and up to ten willing creatures you can see within range assume a gaseous form for the duration, appearing as wisps of cloud. While in this cloud form, a creature has a flying speed of 300 feet and has resistance to damage from nonmagical weapons. The only actions a creature can take in this form are the Dash action or to revert to its normal form. Reverting takes 1 minute, during which time a creature is incapacitated and can''t move. Until the spell ends, a creature can revert to cloud form, which also requires the 1-minute transformation.
If a creature is in cloud form and flying when the effect ends, the creature descends 60 feet per round for 1 minute until it lands, which it does safely. If it can''t land after 1 minute, the creature falls the remaining distance.', '', 'Fire and holy water.'
FROM public.spells WHERE external_index = 'wind-walk'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Caminhar no Vento', 'Você e até dez criaturas voluntárias à sua vista, no alcance da magia, assumem uma forma gasosa - parecendo como tufos de nuvem - enquanto a magia durar. Enquanto permanecer nesta forma de nuvem, uma criatura tem deslocamento de voo de 90 metros [300 ft.] e resistência a dano por armas não mágicas. As únicas ações que uma criatura pode executar nesta forma são Correr ou reverter para sua forma normal. Reverter demora 1 minuto, durante o qual a criatura fica incapacitada e não pode se mover. Enquanto a magia durar, uma criatura pode reverter para a forma de nuvem, que também requer 1 minuto de transformação.
        Se uma criatura estiver em forma de nuvem e voando quando o efeito terminar, ela desce 18 metros [60 ft.] por rodada durante 1 minuto até aterrissar, fazendo-o com segurança. Se não conseguir aterrissar após 1 minuto, ela cai a distância restante.', '', NULL
FROM public.spells WHERE external_index = 'wind-walk'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Wind Wall
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('wind-wall', 3, 'evocation', 'action', 1, 120, 'feet', 1, 'minute', true, false, ARRAY['V', 'S', 'M'], ARRAY['druid', 'ranger'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Wind Wall', 'A wall of strong wind rises from the ground at a point you choose within range. You can make the wall up to 50 feet long, 15 feet high, and 1 foot thick. You can shape the wall in any way you choose so long as it makes one continuous path along the ground. The wall lasts for the duration.
When the wall appears, each creature within its area must make a strength saving throw. A creature takes 3d8 bludgeoning damage on a failed save, or half as much damage on a successful one.
The strong wind keeps fog, smoke, and other gases at bay. Small or smaller flying creatures or objects can''t pass through the wall. Loose, lightweight materials brought into the wall fly upward. Arrows, bolts, and other ordinary projectiles launched at targets behind the wall are deflected upward and automatically miss. (Boulders hurled by giants or siege engines, and similar projectiles, are unaffected.) Creatures in gaseous form can''t pass through it.', '', 'A tiny fan and a feather of exotic origin.'
FROM public.spells WHERE external_index = 'wind-wall'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Muralha de Vento', 'Uma muralha de ventos fortes surge do chão em um ponto à sua escolha, no alcance da magia e permanece enquanto a magia durar. Ela pode ter até 15 metros [50 ft.] de comprimento, 4,5 metros [15 ft.] de altura e 30 centímetros [1 foot] de espessura. Você pode moldá-la à sua escolha, desde que ela percorra um caminho contínuo no chão.
        Quando a muralha surge, cada criatura dentro da área deve fazer uma salvaguarda de Força. Se falhar, sofre 3d8 pontos de dano contundente, ou metade do dano em caso de sucesso.
        O vento forte mantém névoa, fumaça e outros gases à distância. Objetos e criaturas voadoras Pequenas ou menores não conseguem atravessar a muralha. Materiais leves e soltos, trazidos para dentro da muralha, voam para cima. Flechas, virotes e outros projéteis comuns, disparados contra alvos atrás da muralha, são defletidos para cima e erram automaticamente (pedras arremessadas por gigantes, máquinas de sítio ou projéteis similares não são afetados). Criaturas em forma gasosa não conseguem passar através da muralha.', '', NULL
FROM public.spells WHERE external_index = 'wind-wall'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Wish
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('wish', 9, 'conjuration', 'action', 1, NULL, 'self', NULL, 'instantaneous', false, false, ARRAY['V'], ARRAY['sorcerer', 'wizard'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Wish', 'Wish is the mightiest spell a mortal creature can cast. By simply speaking aloud, you can alter the very foundations of reality in accord with your desires.
The basic use of this spell is to duplicate any other spell of 8th level or lower. You don''t need to meet any requirements in that spell, including costly components. The spell simply takes effect.
Alternatively, you can create one of the following effects of your choice:
- You create one object of up to 25,000 gp in value that isn''t a magic item. The object can be no more than 300 feet in any dimension, and it appears in an unoccupied space you can see on the ground.
- You allow up to twenty creatures that you can see to regain all hit points, and you end all effects on them described in the greater restoration spell.
- You grant up to ten creatures that you can see resistance to a damage type you choose.
- You grant up to ten creatures you can see immunity to a single spell or other magical effect for 8 hours. For instance, you could make yourself and all your companions immune to a lich''s life drain attack.
- You undo a single recent event by forcing a reroll of any roll made within the last round (including your last turn). Reality reshapes itself to accommodate the new result. For example, a wish spell could undo an opponent''s successful save, a foe''s critical hit, or a friend''s failed save. You can force the reroll to be made with advantage or disadvantage, and you can choose whether to use the reroll or the original roll.
You might be able to achieve something beyond the scope of the above examples. State your wish to the GM as precisely as possible. The GM has great latitude in ruling what occurs in such an instance; the greater the wish, the greater the likelihood that something goes wrong. This spell might simply fail, the effect you desire might only be partly achieved, or you might suffer some unforeseen consequence as a result of how you worded the wish. For example, wishing that a villain were dead might propel you forward in time to a period when that villain is no longer alive, effectively removing you from the game. Similarly, wishing for a legendary magic item or artifact might instantly transport you to the presence of the item''s current owner.
The stress of casting this spell to produce any effect other than duplicating another spell weakens you. After enduring that stress, each time you cast a spell until you finish a long rest, you take 1d10 necrotic damage per level of that spell. This damage can''t be reduced or prevented in any way. In addition, your Strength drops to 3, if it isn''t 3 or lower already, for 2d4 days. For each of those days that you spend resting and doing nothing more than light activity, your remaining recovery time decreases by 2 days. Finally, there is a 33 percent chance that you are unable to cast wish ever again if you suffer this stress.', '', NULL
FROM public.spells WHERE external_index = 'wish'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Desejo', 'Desejo é a mais poderosa magia que uma criatura mortal pode conjurar. Simplesmente falando em voz alta, você pode alterar os próprios fundamentos da realidade de acordo com seus desejos.
        O uso básico desta magia é duplicar qualquer outra magia de 8º círculo ou inferior. Você não precisa cumprir todos os requisitos da magia duplicada, incluindo componentes dispendiosos. A magia simplesmente tem efeito.
        Como alternativa, você pode criar um dos efeitos a seguir à sua escolha:
        Você cria um objeto de até 25.000 PO em valor que não seja um item mágico. O objeto não pode ser maior do que 90 metros [300 ft.] em qualquer dimensão, e aparece em um espaço desocupado, à sua vista, no chão.
        Você permite que até vinte criaturas à sua vista recuperem todos os pontos de vida e encerra todos os efeitos que estejam agindo sobre elas, conforme descritos na magia Restauração Maior.
        Você concede a até dez criaturas à sua vista resistência a um tipo de dano à sua escolha.
        Você concede a até dez criaturas à sua vista imunidade a uma única magia ou outro efeito mágico por 8 horas. Por exemplo, você poderia tornar a si mesmo e todos os seus companheiros imunes ao ataque drenar vida de um lich.
        Você pode desfazer um acontecimento recente, forçando uma nova jogada de dados feita na última rodada (incluindo o seu último turno). A realidade remodela-se para acomodar o novo resultado. Por exemplo, uma magia Desejo poderia desfazer um teste bem-sucedido de um oponente, o acerto crítico de um inimigo ou a falha em um teste de um amigo. Você pode fazer com que a nova jogada seja feita com vantagem ou desvantagem, e pode escolher se deseja usar a nova jogada ou a jogada original.
        Você pode ser capaz de realizar algo além da gama de exemplos acima. Defina o seu desejo para o DM tão precisamente quanto possível. O DM tem grande liberdade para decidir o que ocorre em tal circunstância; quanto maior o desejo, maior a probabilidade de algo dar errado. A magia pode simplesmente falhar, o efeito que você deseja pode ser apenas parcialmente alcançado ou você pode sofrer alguma consequência imprevista como resultado da forma como formulou o desejo. Por exemplo, desejar que um vilão estivesse morto poderia impulsioná-lo para a frente no tempo, para um período em que o vilão não está mais vivo, removendo você efetivamente do jogo. Da mesma forma, desejar um item mágico lendário ou artefato pode instantaneamente transportá-lo para a presença do atual proprietário do item.
        O esforço necessário para conjurar esta magia de forma a produzir qualquer efeito que não seja a duplicação de outra magia lhe enfraquece. Depois de sofrer essa fadiga, toda vez que conjurar uma magia, até que termine um descanso longo, você sofre 1d10 pontos de dano necrótico por círculo da magia. Este dano não pode ser reduzido ou impedido de nenhuma maneira. Além disso, sua Força cai para 3, se não já for 3 ou inferior, por 2d4 dias. Para cada um desses dias que você gastar em repouso, sem fazer nada além de atividades leves, o tempo de recuperação diminui em 2 dias. Por fim, há uma chance de 33 por cento de que você jamais seja capaz de conjurar Desejo novamente se sofrer esta fadiga.', '', NULL
FROM public.spells WHERE external_index = 'wish'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Word of Recall
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('word-of-recall', 6, 'conjuration', 'action', 1, 5, 'feet', NULL, 'instantaneous', false, false, ARRAY['V'], ARRAY['cleric'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Word of Recall', 'You and up to five willing creatures within 5 feet of you instantly teleport to a previously designated sanctuary. You and any creatures that teleport with you appear in the nearest unoccupied space to the spot you designated when you prepared your sanctuary (see below). If you cast this spell without first preparing a sanctuary, the spell has no effect.
You must designate a sanctuary by casting this spell within a location, such as a temple, dedicated to or strongly linked to your deity. If you attempt to cast the spell in this manner in an area that isn''t dedicated to your deity, the spell has no effect.', '', NULL
FROM public.spells WHERE external_index = 'word-of-recall'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Palavra de Regresso', 'Você e até 5 criaturas voluntárias a até 1,5 metros [5 ft.] a partir de você, são instantaneamente teleportadas para um santuá­rio designado previamente. Você e quaisquer criaturas que se teleportem aparecem em um espaço desocupado mais próximo ao espaço designado no ato de preparação do seu santuário (veja adiante). Ao conjurar esta magia sem preparar um santuário, a magia não tem efeito.Você deve designar um santuário conjurando esta magia em um local, como um templo, seja ele dedicado ou fortemente ligado à sua divindade. Se você tentar conjurar esta magia em uma área que não é dedicada à sua divindade, a magia não tem efeito.', '', NULL
FROM public.spells WHERE external_index = 'word-of-recall'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
-- Zone of Truth
INSERT INTO public.spells (external_index, level, school, casting_time, casting_value, range_value, range_unit, duration_value, duration_unit, concentration, ritual, components, classes, system)
VALUES ('zone-of-truth', 2, 'enchantment', 'action', 1, 60, 'feet', 10, 'minute', false, false, ARRAY['V', 'S'], ARRAY['bard', 'cleric', 'paladin'], 'dnd_5e')
ON CONFLICT (external_index) DO UPDATE SET level = EXCLUDED.level, school = EXCLUDED.school, casting_time = EXCLUDED.casting_time, casting_value = EXCLUDED.casting_value, range_value = EXCLUDED.range_value, range_unit = EXCLUDED.range_unit, duration_value = EXCLUDED.duration_value, duration_unit = EXCLUDED.duration_unit, concentration = EXCLUDED.concentration, ritual = EXCLUDED.ritual, components = EXCLUDED.components, classes = EXCLUDED.classes;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'en', 'Zone of Truth', 'You create a magical zone that guards against deception in a 15-foot-radius sphere centered on a point of your choice within range. Until the spell ends, a creature that enters the spell''s area for the first time on a turn or starts its turn there must make a Charisma saving throw. On a failed save, a creature can''t speak a deliberate lie while in the radius. You know whether each creature succeeds or fails on its saving throw.
An affected creature is aware of the spell and can thus avoid answering questions to which it would normally respond with a lie. Such a creature can remain evasive in its answers as long as it remains within the boundaries of the truth.', '', NULL
FROM public.spells WHERE external_index = 'zone-of-truth'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
INSERT INTO public.spell_translations (spell_id, locale, name, description, higher_level, material)
SELECT id, 'pt', 'Zona da Verdade', 'Você cria uma zona mágica, protegendo contra enganação uma área de esfera com 4,5 metros de raio [15-foot-radius sphere] centrada em um ponto à sua escolha, no alcance da magia. Enquanto a magia durar, quando uma criatura entra pela primeira vez ou inicia o turno na área da magia, ela deve fazer uma salvaguarda de Carisma. Se falhar, a criatura não pode falar uma mentira deliberada enquanto estiver no raio da magia. Você sabe se cada criatura é bem-sucedida ou se falhou na salvaguarda.
        Uma criatura afetada por esta magia está ciente dos efeitos dela e, portanto, pode evitar responder às perguntas que normalmente responderia com uma mentira. A criatura pode ser evasiva em suas respostas enquanto permanecer dentro dos limites da zona da verdade.', '', NULL
FROM public.spells WHERE external_index = 'zone-of-truth'
ON CONFLICT (spell_id, locale) DO UPDATE SET name = EXCLUDED.name, description = EXCLUDED.description, higher_level = EXCLUDED.higher_level, material = EXCLUDED.material;
COMMIT;